{
  "name": "DevBrowser OS",
  "description": "A browser-like environment designed for developers. Write code, execute it instantly, analyze logs, and consult with a built-in Gemini AI assistant in a unified workspace."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Tab {
  id: string;
  title: string;
  type: 'editor' | 'preview' | 'ai';
  content: string; // HTML/JS content for editor
  active: boolean;
}

export interface LogEntry {
  id: string;
  timestamp: string;
  level: 'info' | 'warn' | 'error' | 'log';
  message: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
}

export enum LayoutMode {
  SPLIT = 'SPLIT',
  FULL = 'FULL'
}

import { GoogleGenAI } from "@google/genai";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

export const generateCodeHelp = async (prompt: string, currentCode: string) => {
  try {
    const ai = getClient();
    const systemInstruction = `You are an expert developer assistant inside a web-based IDE called DevBrowser. 
    The user is writing HTML/JS code. 
    Current code context: 
    \`\`\`html
    ${currentCode}
    \`\`\`
    Provide concise, correct, and modern code snippets or explanations. 
    If providing code, wrap it in markdown code blocks.
    Prioritize Tailwind CSS for styling if asked.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

import React, { useEffect, useRef } from 'react';
import { LogEntry } from '../types';
import { Terminal, Trash2, XCircle } from 'lucide-react';

interface ConsoleProps {
  logs: LogEntry[];
  onClear: () => void;
  isOpen: boolean;
  toggleOpen: () => void;
}

const Console: React.FC<ConsoleProps> = ({ logs, onClear, isOpen, toggleOpen }) => {
  const endRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen) {
      endRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs, isOpen]);

  if (!isOpen) {
    return (
      <button 
        onClick={toggleOpen}
        className="fixed bottom-4 right-4 bg-browser-toolbar border border-gray-700 p-2 rounded-full shadow-lg hover:bg-gray-700 transition-colors z-50 text-xs flex items-center gap-2"
      >
        <Terminal size={14} />
        <span>Console ({logs.length})</span>
      </button>
    );
  }

  return (
    <div className="fixed bottom-0 left-0 w-full h-48 bg-browser-bg border-t border-gray-700 flex flex-col z-40 shadow-2xl">
      {/* Console Header */}
      <div className="h-8 bg-browser-toolbar flex items-center justify-between px-4 border-b border-gray-700">
        <div className="flex items-center gap-2 text-xs font-semibold text-gray-400">
          <Terminal size={14} />
          <span>DevTools Console</span>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={onClear} className="text-gray-400 hover:text-white p-1 rounded hover:bg-white/10" title="Clear Console">
            <Trash2 size={14} />
          </button>
          <button onClick={toggleOpen} className="text-gray-400 hover:text-white p-1 rounded hover:bg-white/10" title="Close">
            <XCircle size={14} />
          </button>
        </div>
      </div>

      {/* Logs Area */}
      <div className="flex-1 overflow-y-auto p-2 font-mono text-xs space-y-1">
        {logs.length === 0 && (
          <div className="text-gray-600 italic">Console is empty...</div>
        )}
        {logs.map((log) => (
          <div key={log.id} className={`flex gap-2 border-b border-white/5 pb-1 last:border-0 ${
            log.level === 'error' ? 'text-red-400 bg-red-900/10' : 
            log.level === 'warn' ? 'text-yellow-400 bg-yellow-900/10' : 
            'text-gray-300'
          }`}>
            <span className="text-gray-500 select-none">[{log.timestamp}]</span>
            <span className="break-all whitespace-pre-wrap">{log.message}</span>
          </div>
        ))}
        <div ref={endRef} />
      </div>
    </div>
  );
};

export default Console;

import React from 'react';
import { ArrowLeft, ArrowRight, RotateCw, Lock, Search } from 'lucide-react';

interface AddressBarProps {
