export default AddressBar;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, X, Loader2 } from 'lucide-react';
import { generateCodeHelp } from '../services/geminiService';
import { ChatMessage } from '../types';

interface AIAssistantProps {
  currentCode: string;
  isOpen: boolean;
  onClose: () => void;
}

const AIAssistant: React.FC<AIAssistantProps> = ({ currentCode, isOpen, onClose }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'Hello! I am your DevBrowser Copilot. How can I help you build today?'
    }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      const responseText = await generateCodeHelp(userMsg.text, currentCode);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText || "I couldn't generate a response."
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Error connecting to AI service. Please check your API key.",
        isError: true
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  if (!isOpen) return null;

  return (
    <div className="w-80 h-full bg-browser-toolbar border-l border-gray-700 flex flex-col shadow-xl absolute right-0 top-0 z-30 transform transition-transform duration-300">
      <div className="h-10 flex items-center justify-between px-4 border-b border-gray-700 bg-gray-800/50">
        <div className="flex items-center gap-2 text-browser-accent font-semibold">
          <Sparkles size={16} />
          <span>Gemini Copilot</span>
        </div>
        <button onClick={onClose} className="text-gray-400 hover:text-white">
          <X size={16} />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 font-sans text-sm" ref={scrollRef}>
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
          >
            <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${
              msg.role === 'user' ? 'bg-gray-600' : 'bg-blue-600/20 text-blue-400'
            }`}>
              {msg.role === 'user' ? <User size={14} /> : <Bot size={14} />}
            </div>
            <div className={`p-3 rounded-lg max-w-[85%] ${
              msg.role === 'user' 
                ? 'bg-blue-600 text-white' 
                : msg.isError 
                  ? 'bg-red-900/30 text-red-200 border border-red-800' 
                  : 'bg-gray-700/50 text-gray-200'
            }`}>
              <div className="whitespace-pre-wrap markdown-content">
                {msg.text}
              </div>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex gap-3">
             <div className="w-8 h-8 rounded-full bg-blue-600/20 text-blue-400 flex items-center justify-center flex-shrink-0">
               <Bot size={14} />
             </div>
             <div className="bg-gray-700/50 p-3 rounded-lg flex items-center gap-2 text-gray-400">
               <Loader2 size={14} className="animate-spin" />
               <span>Thinking...</span>
             </div>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-gray-700 bg-gray-800/50">
        <div className="relative">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Ask AI for help..."
            className="w-full bg-gray-900 border border-gray-700 rounded-lg pl-3 pr-10 py-2 text-sm text-white focus:outline-none focus:border-browser-accent resize-none h-20"
          />
          <button
            onClick={handleSend}
            disabled={loading || !input.trim()}
            className="absolute right-2 bottom-2 p-1.5 bg-browser-accent text-white rounded hover:bg-blue-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send size={14} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIAssistant;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Layout, Play, Code2, Globe, Sparkles, SplitSquareHorizontal, Maximize2 } from 'lucide-react';
import { Tab, LogEntry, LayoutMode } from './types';
import Console from './components/Console';
import AddressBar from './components/AddressBar';
import AIAssistant from './components/AIAssistant';

// Initial Demo Code
const DEFAULT_CODE = `<!DOCTYPE html>
<html>
<head>
  <style>
    body { 
      font-family: -apple-system, system-ui, sans-serif;
      background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
      color: white;
      height: 100vh;
      margin: 0;
      display: flex;
      align-items: center;
      justify-content: center;
    }
    .card {
      background: rgba(255, 255, 255, 0.1);
      backdrop-filter: blur(10px);
      padding: 2rem;
      border-radius: 1rem;
      border: 1px solid rgba(255, 255, 255, 0.2);
      text-align: center;
      animation: float 6s ease-in-out infinite;
    }
    h1 { margin: 0 0 1rem 0; font-size: 2.5rem; background: linear-gradient(to right, #4facfe, #00f2fe); -webkit-background-clip: text; color: transparent; }
    p { color: #ccc; }
    button {
      margin-top: 1rem;
      padding: 0.5rem 1.5rem;
      background: #4facfe;
      border: none;
      border-radius: 2rem;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: transform 0.2s;
    }
    button:hover { transform: scale(1.05); background: #00f2fe; }
    @keyframes float {
      0%, 100% { transform: translateY(0); }
      50% { transform: translateY(-20px); }
    }
  </style>
</head>
<body>
  <div class="card">
    <h1>Hello World</h1>
    <p>This is your DevBrowser playground.</p>
    <button onclick="sayHello()">Click Me</button>
  </div>

  <script>
    console.log("System initialized...");
    function sayHello() {
      console.log("Button clicked at " + new Date().toLocaleTimeString());
      const h1 = document.querySelector('h1');
      h1.textContent = "It Works!";
      setTimeout(() => h1.textContent = "Hello World", 2000);
    }
  </script>
</body>
</html>`;

export default function App() {
  const [code, setCode] = useState(DEFAULT_CODE);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [iframeKey, setIframeKey] = useState(0); // Forces iframe reload
  const [layoutMode, setLayoutMode] = useState<LayoutMode>(LayoutMode.SPLIT);
  const [isConsoleOpen, setIsConsoleOpen] = useState(true);
  const [isAIOpen, setIsAIOpen] = useState(false);
  const [activeTab, setActiveTab] = useState('index.html');

  // Handle messages from the iframe (captured console logs)
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'console') {
        const newLog: LogEntry = {
          id: Date.now().toString() + Math.random(),
          timestamp: new Date().toLocaleTimeString(),
          level: event.data.level,
          message: event.data.message.map((m: any) => 
            typeof m === 'object' ? JSON.stringify(m) : String(m)
          ).join(' ')
        };
        setLogs(prev => [...prev, newLog]);
      }
    };

    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  // Run Code Function
  const runCode = useCallback(() => {
    setLogs([]); // Clear logs on run
    setIframeKey(prev => prev + 1);
  }, []);

  const clearLogs = () => setLogs([]);

  // The secret sauce: Injecting a script to capture console.log within the iframe
  const getSrcDoc = () => {
    const consoleHijack = `
      <script>
        const originalLog = console.log;
        const originalWarn = console.warn;
        const originalError = console.error;
        const originalInfo = console.info;

        function sendToParent(level, args) {
          try {
            window.parent.postMessage({
              type: 'console',
              level: level,
              message: Array.from(args)
            }, '*');
          } catch(e) {}
        }

        console.log = function(...args) { originalLog.apply(console, args); sendToParent('log', args); };
        console.warn = function(...args) { originalWarn.apply(console, args); sendToParent('warn', args); };
        console.error = function(...args) { originalError.apply(console, args); sendToParent('error', args); };
        console.info = function(...args) { originalInfo.apply(console, args); sendToParent('info', args); };

        window.onerror = function(msg, url, line) {
           sendToParent('error', [msg + " (Line " + line + ")"]);
        }
      </script>
    `;
    // Insert the hijack script before the closing body or at the end
    if (code.includes('</body>')) {
      return code.replace('</body>', `${consoleHijack}</body>`);
    }
    return code + consoleHijack;
  };

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Navigation Bar (Tabs & Address) */}
      <div className="flex flex-col">
        {/* Tab Bar */}
        <div className="flex items-end px-2 pt-2 gap-2 bg-browser-bg border-b border-browser-toolbar select-none">
           <div 
             className={`flex items-center gap-2 px-4 py-2 rounded-t-lg text-sm cursor-pointer transition-colors ${
               activeTab === 'index.html' ? 'bg-browser-toolbar text-white' : 'hover:bg-browser-toolbar/50 text-gray-500'
             }`}
             onClick={() => setActiveTab('index.html')}
           >
             <Code2 size={14} className="text-orange-400" />
             <span>playground.html</span>
           </div>

           <div className="ml-auto flex items-center gap-2 pb-1 pr-2">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className="p-1 hover:text-white text-gray-500"
                 title="Toggle Split View"
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={14} /> : <SplitSquareHorizontal size={14} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1 hover:text-white transition-colors ${isAIOpen ? 'text-browser-accent' : 'text-gray-500'}`}
                 title="Toggle AI Assistant"
              >
                <Sparkles size={14} />
              </button>
           </div>
        </div>

        {/* Address Bar */}
        <AddressBar url="localhost:3000/playground" onRefresh={runCode} />
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Editor Pane */}
        <div className={`flex flex-col border-r border-gray-800 transition-all duration-300 ${
            layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-0 overflow-hidden'
        }`}>
          <textarea
            className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed"
            value={code}
            onChange={(e) => setCode(e.target.value)}
            spellCheck={false}
          />
          <div className="h-8 bg-browser-toolbar border-t border-gray-800 flex items-center justify-between px-4 text-xs text-gray-500">
             <span>HTML/JS Mode</span>
             <span>{code.length} chars</span>
          </div>
        </div>

        {/* Preview Pane */}
        <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${
             layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'
        }`}>
          <iframe
            key={iframeKey}
            title="Preview"
            srcDoc={getSrcDoc()}
            className="w-full h-full border-none"
            sandbox="allow-scripts allow-modals allow-forms allow-same-origin"
          />
        </div>

        {/* AI Sidebar Overlay */}
        <AIAssistant 
          currentCode={code} 
          isOpen={isAIOpen} 
          onClose={() => setIsAIOpen(false)} 
        />
      </div>

      {/* Console (Fixed at Bottom) */}
      <Console 
        logs={logs} 
        onClear={clearLogs} 
        isOpen={isConsoleOpen} 
        toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} 
      />
    </div>
  );
}

{
  "name": "DevBrowser OS",
  "description": "A browser-like environment designed for developers. Write code, execute it instantly, analyze logs, and consult with a built-in Gemini AI assistant in a unified workspace.",
  "requestFramePermissions": [
    "camera",
    "microphone",
    "geolocation"
  ]
}

export interface Tab {
  id: string;
  title: string;
  type: 'editor' | 'preview' | 'ai';
  content: string;
  active: boolean;
}

export interface LogEntry {
  id: string;
  timestamp: string;
  level: 'info' | 'warn' | 'error' | 'log';
  message: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  image?: string; // base64
  video?: string; // url
  audio?: string; // base64
  isError?: boolean;
}

export enum LayoutMode {
  SPLIT = 'SPLIT',
  FULL = 'FULL'
}

export type ChatMode = 'standard' | 'thinking' | 'search' | 'maps' | 'fast';

export type AspectRatio = "1:1" | "2:3" | "3:2" | "3:4" | "4:3" | "9:16" | "16:9" | "21:9";
export type ImageSize = "1K" | "2K" | "4K";
export type VideoResolution = "720p" | "1080p";

import { GoogleGenAI, Modality, Type } from "@google/genai";

// -- Helpers --

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key is missing");
  return new GoogleGenAI({ apiKey });
};

const getPaidClient = async () => {
  // @ts-ignore
  if (window.aistudio && window.aistudio.hasSelectedApiKey && window.aistudio.openSelectKey) {
     // @ts-ignore
     const hasKey = await window.aistudio.hasSelectedApiKey();
     if (!hasKey) {
         // @ts-ignore
         await window.aistudio.openSelectKey();
     }
  }
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// -- Chat & Text Features --

export const chatWithGemini = async (
  prompt: string, 
  mode: 'standard' | 'thinking' | 'search' | 'maps' | 'fast',
  attachments: { base64: string, mimeType: string }[] = [],
  contextCode?: string
) => {
  const ai = getClient();
  let model = 'gemini-3-pro-preview';
  const config: any = {
    systemInstruction: contextCode 
      ? `You are an expert developer assistant. Current code context:\n\`\`\`\n${contextCode}\n\`\`\`` 
      : 'You are a helpful AI assistant.',
  };

  if (mode === 'fast') {
    model = 'gemini-2.5-flash-lite-latest';
  } else if (mode === 'thinking') {
    model = 'gemini-3-pro-preview';
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else if (mode === 'search') {
    model = 'gemini-3-flash-preview';
    config.tools = [{ googleSearch: {} }];
  } else if (mode === 'maps') {
    model = 'gemini-2.5-flash'; // Maps only on 2.5 Flash
    config.tools = [{ googleMaps: {} }];
    // Try to get location
    try {
      const pos: any = await new Promise((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(resolve, reject, { timeout: 5000 });
      });
      config.toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: pos.coords.latitude,
            longitude: pos.coords.longitude
          }
        }
      };
    } catch (e) {
      console.warn("Could not get location for Maps grounding");
    }
  }

  // Handle attachments (Image/Video Analysis, Audio Transcription)
  // Logic: Analysis uses Pro, Transcription uses Flash. 
  // If attachments exist, override model if necessary for best results, 
  // unless user specifically requested a mode.
  let parts: any[] = [];

  if (attachments.length > 0) {
    // If audio is present, prefer Flash for transcription
    if (attachments.some(a => a.mimeType.startsWith('audio/'))) {
      if (mode === 'standard') model = 'gemini-3-flash-preview';
    }

    parts = attachments.map(a => ({
      inlineData: {
        data: a.base64,
        mimeType: a.mimeType
      }
    }));
  }

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model,
    contents: { parts },
    config
  });

  // Extract grounding metadata if present
  let text = response.text || "";
  const grounding = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (grounding) {
    const links = grounding
      .map((c: any) => c.web?.uri ? `[${c.web.title}](${c.web.uri})` : c.maps?.uri ? `[${c.maps.title}](${c.maps.uri})` : '')
      .filter(Boolean)
      .join('\n');
    if (links) text += `\n\nSources:\n${links}`;
  }

  return text;
};

// -- Audio Features --

export const transcribeAudio = async (audioBase64: string) => {
  const ai = getClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'audio/wav', data: audioBase64 } },
        { text: "Transcribe this audio." }
      ]
    }
  });
  return response.text;
};

export const generateSpeech = async (text: string) => {
  const ai = getClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-preview-tts',
    contents: { parts: [{ text }] },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
      },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
};

// -- Image Features --

export const generateImage = async (
  prompt: string, 
  options: { 
    aspectRatio?: string, 
    imageSize?: string,
    sourceImage?: string // Base64 for editing
  }
) => {
  // If editing (source image present), use 2.5 Flash Image
  if (options.sourceImage) {
    const ai = getClient();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/png', data: options.sourceImage } },
          { text: prompt }
        ]
      },
      config: {
         imageConfig: {
             aspectRatio: options.aspectRatio as any || "1:1"
         }
      }
    });
    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return part.inlineData.data;
    }
    throw new Error("No image generated");
  } else {
    // Generation use 3 Pro Image (requires paid key)
    const ai = await getPaidClient();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: options.aspectRatio as any || "1:1",
          imageSize: options.imageSize as any || "1K"
        }
      }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return part.inlineData.data;
    }
    throw new Error("No image generated");
  }
};

// -- Video Features --

export const generateVideo = async (
  prompt: string,
  options: { aspectRatio: string }
) => {
  const ai = await getPaidClient();
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt,
    config: {
      numberOfVideos: 1,
      aspectRatio: options.aspectRatio as any,
      resolution: '720p'
    }
  });

  // Polling
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({ operation });
  }

  const uri = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!uri) throw new Error("Video generation failed");

  // Fetch with API key
  const response = await fetch(`${uri}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

// -- Live API --

export const connectLive = async (
    onAudioData: (base64: string) => void,
    onClose: () => void
) => {
    const ai = getClient();
    // Audio Context Setup
    const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    // Setup Input Stream
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const source = inputAudioContext.createMediaStreamSource(stream);
    const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);

    // Connect to Live API
    const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
            onopen: () => {
                scriptProcessor.onaudioprocess = (e) => {
                    const inputData = e.inputBuffer.getChannelData(0);
                    // Convert Float32 to PCM Int16
                    const l = inputData.length;
                    const int16 = new Int16Array(l);
                    for (let i = 0; i < l; i++) int16[i] = inputData[i] * 32768;
                    const bytes = new Uint8Array(int16.buffer);
                    let binary = '';
                    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
                    const base64Data = btoa(binary);

                    sessionPromise.then(session => {
                        session.sendRealtimeInput({
                            media: {
                                mimeType: 'audio/pcm;rate=16000',
                                data: base64Data
                            }
                        });
                    });
                };
                source.connect(scriptProcessor);
                scriptProcessor.connect(inputAudioContext.destination);
            },
            onmessage: (msg: any) => {
                const data = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (data) {
                    onAudioData(data);
                    // Play audio
                    const binaryString = atob(data);
                    const len = binaryString.length;
                    const bytes = new Uint8Array(len);
                    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);

                    // Simple decode and play (queueing omitted for brevity in this complex integration, assuming short bursts or simple overlapping)
                    // For production, use the scheduling queue from the docs.
                    // Implementation of scheduling:
                    const ctx = outputAudioContext;
                    const dataInt16 = new Int16Array(bytes.buffer);
                    const float32 = new Float32Array(dataInt16.length);
                    for(let i=0; i<dataInt16.length; i++) float32[i] = dataInt16[i] / 32768.0;

                    const buffer = ctx.createBuffer(1, float32.length, 24000);
                    buffer.copyToChannel(float32, 0);

                    const node = ctx.createBufferSource();
                    node.buffer = buffer;
                    node.connect(ctx.destination);
                    node.start();
                }
            },
            onclose: onClose,
            onerror: (e) => { console.error(e); onClose(); }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
            }
        }
    });

    return {
        disconnect: () => {
            sessionPromise.then(s => s.close());
            inputAudioContext.close();
            outputAudioContext.close();
            stream.getTracks().forEach(t => t.stop());
        }
    };
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, X, Loader2, Image as ImageIcon, Video, Mic, Paperclip, Music, Search, MapPin, Zap, Brain, Wand2, XCircle } from 'lucide-react';
import { chatWithGemini, generateImage, generateVideo, connectLive, transcribeAudio, generateSpeech } from '../services/geminiService';
import { ChatMessage, ChatMode, AspectRatio, ImageSize } from '../types';

interface AIAssistantProps {
  currentCode: string;
  isOpen: boolean;
  onClose: () => void;
}

const AIAssistant: React.FC<AIAssistantProps> = ({ currentCode, isOpen, onClose }) => {
  // Modes: 'chat', 'image', 'video', 'live'
  const [activeTab, setActiveTab] = useState<'chat' | 'create' | 'live'>('chat');

  // Chat State
  const [messages, setMessages] = useState<ChatMessage[]>([{ id: '1', role: 'model', text: 'Hi! I am your Gemini Copilot.' }]);
  const [input, setInput] = useState('');
  const [chatMode, setChatMode] = useState<ChatMode>('standard');
  const [attachment, setAttachment] = useState<{base64: string, mimeType: string} | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // Create State
  const [createType, setCreateType] = useState<'image' | 'video'>('image');
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('1:1');
  const [imageSize, setImageSize] = useState<ImageSize>('1K');
  const [editImage, setEditImage] = useState<string | null>(null); // For image editing
  const [generatedMedia, setGeneratedMedia] = useState<{type: 'image'|'video', url: string} | null>(null);

  // Live State
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const liveSessionRef = useRef<any>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Auto-scroll chat
  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, activeTab]);

  // -- Chat Handlers --

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        setAttachment({ base64, mimeType: file.type });
        // If it's an image for editing in "Create" mode
        if (activeTab === 'create' && createType === 'image') {
            setEditImage(base64);
        }
    };
    reader.readAsDataURL(file);
  };

  const handleSendMessage = async () => {
    if ((!input.trim() && !attachment) || isProcessing) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      image: attachment?.mimeType.startsWith('image') ? attachment.base64 : undefined
    };
    setMessages(p => [...p, userMsg]);
    setInput('');
    setAttachment(null);
    setIsProcessing(true);

    try {
      // Check for audio attachment -> Transcribe
      if (attachment?.mimeType.startsWith('audio')) {
         const transcript = await transcribeAudio(attachment.base64);
         setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: `Transcription: ${transcript}` }]);
      } else {
         // Normal Chat / Analysis
         const response = await chatWithGemini(userMsg.text, chatMode, attachment ? [attachment] : [], currentCode);
         setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: response }]);
      }
    } catch (e: any) {
       setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: "Error: " + e.message, isError: true }]);
    } finally {
       setIsProcessing(false);
    }
  };

  // -- Create Handlers --

  const handleCreate = async () => {
      if (!prompt.trim()) return;
      setIsProcessing(true);
      setGeneratedMedia(null);
      try {
          if (createType === 'image') {
              const b64 = await generateImage(prompt, { aspectRatio, imageSize, sourceImage: editImage || undefined });
              setGeneratedMedia({ type: 'image', url: `data:image/png;base64,${b64}` });
          } else {
              const url = await generateVideo(prompt, { aspectRatio });
              setGeneratedMedia({ type: 'video', url });
          }
      } catch (e: any) {
          setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: "Generation Error: " + e.message, isError: true }]);
          setActiveTab('chat');
      } finally {
          setIsProcessing(false);
      }
  };

  // -- Live Handlers --

  const toggleLive = async () => {
      if (isLiveConnected) {
          liveSessionRef.current?.disconnect();
          setIsLiveConnected(false);
      } else {
          try {
              liveSessionRef.current = await connectLive(
                  (audioData) => { /* Visualizer hook could go here */ },
                  () => setIsLiveConnected(false)
              );
              setIsLiveConnected(true);
          } catch (e) {
              console.error(e);
              alert("Failed to connect to Live API. Ensure mic permissions.");
          }
      }
  };

  if (!isOpen) return null;

  return (
    <div className="w-96 h-full bg-[#1e1e1e] border-l border-gray-700 flex flex-col shadow-2xl absolute right-0 top-0 z-30 font-sans text-gray-300">

      {/* Header */}
      <div className="h-12 border-b border-gray-700 flex items-center justify-between px-4 bg-[#252526]">
        <div className="flex items-center gap-2 font-semibold text-white">
            <Sparkles className="text-blue-500" size={18} />
            <span>Gemini OS</span>
        </div>
        <button onClick={onClose}><X size={18} /></button>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-gray-700 bg-[#252526]">
          {['chat', 'create', 'live'].map((t) => (
              <button 
                key={t}
                onClick={() => setActiveTab(t as any)}
                className={`flex-1 py-3 text-sm font-medium capitalize transition-colors ${activeTab === t ? 'text-blue-500 border-b-2 border-blue-500' : 'text-gray-500 hover:text-gray-300'}`}
              >
                  {t}
              </button>
          ))}
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-hidden relative flex flex-col bg-[#1e1e1e]">

          {/* --- CHAT TAB --- */}
          {activeTab === 'chat' && (
              <>
                 {/* Chat Messages */}
                 <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
                    {messages.map(m => (
                        <div key={m.id} className={`flex gap-3 ${m.role === 'user' ? 'flex-row-reverse' : ''}`}>
                            <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${m.role === 'user' ? 'bg-gray-700' : 'bg-blue-900/30 text-blue-400'}`}>
                                {m.role === 'user' ? <User size={14} /> : <Bot size={14} />}
                            </div>
                            <div className={`p-3 rounded-lg max-w-[85%] text-sm ${m.role === 'user' ? 'bg-blue-600 text-white' : 'bg-gray-800'}`}>
                                {m.image && <img src={`data:image/png;base64,${m.image}`} alt="attachment" className="w-full rounded mb-2" />}
                                <div className="whitespace-pre-wrap">{m.text}</div>
                            </div>
                        </div>
                    ))}
                    {isProcessing && <div className="p-4 flex gap-2 text-gray-500 text-sm items-center"><Loader2 size={14} className="animate-spin" /> Thinking...</div>}
                 </div>

                 {/* Settings / Mode Toolbar */}
                 <div className="px-4 py-2 border-t border-gray-700 bg-[#252526] flex gap-2 overflow-x-auto no-scrollbar">
                    {[
                        { id: 'standard', icon: Bot, label: 'Std' },
                        { id: 'thinking', icon: Brain, label: 'Think' },
                        { id: 'search', icon: Search, label: 'Web' },
                        { id: 'maps', icon: MapPin, label: 'Maps' },
                        { id: 'fast', icon: Zap, label: 'Fast' }
                    ].map(mode => (
                        <button 
                            key={mode.id}
                            onClick={() => setChatMode(mode.id as ChatMode)}
                            className={`flex items-center gap-1 px-3 py-1.5 rounded-full text-xs whitespace-nowrap border transition-colors ${
                                chatMode === mode.id 
                                ? 'bg-blue-600 border-blue-600 text-white' 
                                : 'bg-transparent border-gray-600 text-gray-400 hover:border-gray-500'
                            }`}
                        >
                            <mode.icon size={12} />
                            {mode.label}
                        </button>
                    ))}
                 </div>

                 {/* Input Area */}
                 <div className="p-4 border-t border-gray-700 bg-[#252526]">
                    {attachment && (
                        <div className="mb-2 flex items-center gap-2 bg-gray-800 p-2 rounded text-xs">
                            <Paperclip size={12} />
                            <span className="truncate flex-1">Attachment added</span>
                            <button onClick={() => setAttachment(null)}><XCircle size={14} /></button>
                        </div>
                    )}
                    <div className="flex gap-2">
                        <button onClick={() => fileInputRef.current?.click()} className="p-2 text-gray-400 hover:text-white bg-gray-700 rounded-lg">
                            <Paperclip size={18} />
                        </button>
                        <input 
                           type="file" 
                           ref={fileInputRef} 
                           className="hidden" 
                           onChange={handleFileSelect} 
                           accept="image/*,audio/*,video/*"
                        />
                        <input
                            value={input}
                            onChange={e => setInput(e.target.value)}
                            onKeyDown={e => e.key === 'Enter' && !e.shiftKey && handleSendMessage()}
                            placeholder="Type a message..."
                            className="flex-1 bg-gray-900 border border-gray-700 rounded-lg px-3 text-sm text-white focus:outline-none focus:border-blue-500"
                        />
                        <button 
                           onClick={handleSendMessage} 
                           disabled={isProcessing}
                           className="p-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50"
                        >
                           <Send size={18} />
                        </button>
                    </div>
                 </div>
              </>
          )}

          {/* --- CREATE TAB --- */}
          {activeTab === 'create' && (
              <div className="p-4 flex flex-col h-full overflow-y-auto">
                 <div className="flex bg-gray-800 p-1 rounded-lg mb-4">
                     <button 
                        onClick={() => { setCreateType('image'); setGeneratedMedia(null); }} 
                        className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-md text-sm transition-colors ${createType === 'image' ? 'bg-gray-600 text-white' : 'text-gray-400'}`}
                     >
                         <ImageIcon size={14} /> Image
                     </button>
                     <button 
                        onClick={() => { setCreateType('video'); setGeneratedMedia(null); }}
                        className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-md text-sm transition-colors ${createType === 'video' ? 'bg-gray-600 text-white' : 'text-gray-400'}`}
                     >
                         <Video size={14} /> Video
                     </button>
                 </div>

                 <textarea
                    value={prompt}
                    onChange={e => setPrompt(e.target.value)}
                    placeholder={`Describe the ${createType} you want...`}
                    className="w-full bg-gray-900 border border-gray-700 rounded-lg p-3 text-sm text-white h-24 resize-none mb-4 focus:border-blue-500 outline-none"
                 />

                 {/* Options */}
                 <div className="grid grid-cols-2 gap-3 mb-4">
                     <div>
                         <label className="block text-xs text-gray-500 mb-1">Aspect Ratio</label>
                         <select 
                            value={aspectRatio} 
                            onChange={e => setAspectRatio(e.target.value as any)}
                            className="w-full bg-gray-800 border border-gray-700 rounded px-2 py-1.5 text-xs text-white"
                         >
                             {['1:1','16:9','9:16','4:3','3:4'].map(r => <option key={r} value={r}>{r}</option>)}
                         </select>
                     </div>
                     {createType === 'image' && (
                         <div>
                             <label className="block text-xs text-gray-500 mb-1">Size</label>
                             <select 
                                value={imageSize}
                                onChange={e => setImageSize(e.target.value as any)}
                                className="w-full bg-gray-800 border border-gray-700 rounded px-2 py-1.5 text-xs text-white"
                             >
                                 <option value="1K">1K</option>
                                 <option value="2K">2K</option>
                                 <option value="4K">4K</option>
                             </select>
                         </div>
                     )}
                 </div>

                 {createType === 'image' && (
                     <div className="mb-4">
                         <label className="block text-xs text-gray-500 mb-1">Edit Reference (Optional)</label>
                         <div 
                             onClick={() => fileInputRef.current?.click()}
                             className="border border-dashed border-gray-700 rounded-lg p-3 text-center cursor-pointer hover:bg-gray-800 transition-colors"
                         >
                             {editImage ? (
                                 <img src={`data:image/png;base64,${editImage}`} className="h-20 mx-auto rounded object-contain" />
                             ) : (
                                 <div className="text-gray-500 text-xs flex flex-col items-center gap-1">
                                     <ImageIcon size={16} />
                                     <span>Click to upload source</span>
                                 </div>
                             )}
                         </div>
                     </div>
                 )}

                 <button
                    onClick={handleCreate}
                    disabled={isProcessing || !prompt}
                    className="w-full py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg flex items-center justify-center gap-2 disabled:opacity-50"
                 >
                     {isProcessing ? <Loader2 size={16} className="animate-spin" /> : <Wand2 size={16} />}
                     Generate {createType === 'image' ? (editImage ? 'Edit' : 'Image') : 'Video'}
                 </button>

                 {generatedMedia && (
                     <div className="mt-6 border-t border-gray-700 pt-4">
                         <div className="text-xs text-green-400 mb-2 font-mono">Result Generated:</div>
                         {generatedMedia.type === 'image' ? (
                             <img src={generatedMedia.url} className="w-full rounded-lg border border-gray-700" />
                         ) : (
                             <video src={generatedMedia.url} controls className="w-full rounded-lg border border-gray-700" />
                         )}
                         <a href={generatedMedia.url} download className="block text-center mt-2 text-xs text-blue-400 hover:underline">Download</a>
                     </div>
                 )}
              </div>
          )}

          {/* --- LIVE TAB --- */}
          {activeTab === 'live' && (
              <div className="flex flex-col items-center justify-center h-full p-6 text-center">
                  <div className={`w-32 h-32 rounded-full flex items-center justify-center mb-6 transition-all duration-500 ${isLiveConnected ? 'bg-red-500/20 shadow-[0_0_50px_rgba(239,68,68,0.3)]' : 'bg-gray-800'}`}>
                      <Mic size={48} className={isLiveConnected ? 'text-red-500 animate-pulse' : 'text-gray-500'} />
                  </div>

                  <h3 className="text-lg font-medium text-white mb-2">
                      {isLiveConnected ? 'Live Session Active' : 'Start Voice Chat'}
                  </h3>
                  <p className="text-sm text-gray-500 mb-8 max-w-[200px]">
                      {isLiveConnected 
                          ? 'Gemini is listening. Speak naturally.' 
                          : 'Connect to have a real-time voice conversation with Gemini 2.5.'}
                  </p>

                  <button
                      onClick={toggleLive}
                      className={`px-8 py-3 rounded-full font-medium transition-colors ${
                          isLiveConnected 
                          ? 'bg-red-600 hover:bg-red-700 text-white' 
                          : 'bg-white text-black hover:bg-gray-200'
                      }`}
                  >
                      {isLiveConnected ? 'End Session' : 'Connect Live'}
                  </button>
              </div>
          )}
      </div>

      {/* Hidden File Input for reuse */}
      <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileSelect} accept="image/*,audio/*" />
    </div>
  );
};

