const getFileIcon = (fileName: string) => {
  if (fileName.endsWith('.html')) return <FileCode size={14} className="text-orange-400" />;
  if (fileName.endsWith('.css')) return <FileType size={14} className="text-blue-400" />;
  if (fileName.endsWith('.js') || fileName.endsWith('.ts') || fileName.endsWith('.tsx')) return <FileCode size={14} className="text-yellow-400" />;
  if (fileName.endsWith('.json')) return <FileJson size={14} className="text-green-400" />;
  return <File size={14} className="text-gray-400" />;
};

const FileExplorer: React.FC<FileExplorerProps> = ({ files, activeFileName, onSelect, onCreate, onDelete, onRename }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [newFileName, setNewFileName] = useState('');
  const [editingName, setEditingName] = useState<string | null>(null);
  const [editNameValue, setEditNameValue] = useState('');

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newFileName && !files.some(f => f.name === newFileName)) {
      onCreate(newFileName);
      setNewFileName('');
      setIsCreating(false);
    }
  };

  const handleRenameSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editNameValue && editingName && editNameValue !== editingName) {
        onRename(editingName, editNameValue);
    }
    setEditingName(null);
  };

  const startRename = (name: string) => {
      setEditingName(name);
      setEditNameValue(name);
  };

  return (
    <div className="w-56 bg-browser-toolbar border-r border-gray-700 flex flex-col h-full select-none">
      <div className="h-9 px-3 flex items-center justify-between border-b border-gray-700 bg-[#252526]">
        <div className="flex items-center gap-2 text-xs font-semibold text-gray-400">
          <FolderOpen size={14} />
          <span>EXPLORER</span>
        </div>
        <button 
          onClick={() => setIsCreating(true)} 
          className="text-gray-400 hover:text-white p-1"
          title="New File"
        >
          <FilePlus size={14} />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto py-2">
        {isCreating && (
          <form onSubmit={handleCreateSubmit} className="px-2 mb-2">
            <div className="flex items-center gap-1 bg-gray-800 border border-blue-500 px-2 py-1 rounded">
               <File size={12} className="text-gray-400" />
               <input
                 autoFocus
                 type="text"
                 value={newFileName}
                 onChange={(e) => setNewFileName(e.target.value)}
                 onBlur={() => setIsCreating(false)}
                 placeholder="filename.ext"
                 className="w-full bg-transparent text-xs text-white outline-none"
               />
            </div>
          </form>
        )}

        {files.map((file) => (
          <div
            key={file.name}
            onClick={() => onSelect(file.name)}
            className={`group flex items-center justify-between px-3 py-1.5 cursor-pointer text-sm transition-colors ${
              file.name === activeFileName
                ? 'bg-browser-tab text-white'
                : 'text-gray-400 hover:text-gray-200 hover:bg-white/5'
            }`}
          >
            {editingName === file.name ? (
                <form onSubmit={handleRenameSubmit} onClick={e => e.stopPropagation()} className="flex-1">
                    <input
                        autoFocus
                        type="text"
                        value={editNameValue}
                        onChange={(e) => setEditNameValue(e.target.value)}
                        onBlur={handleRenameSubmit}
                        className="w-full bg-gray-800 text-white text-xs px-1 py-0.5 rounded outline-none border border-blue-500"
                    />
                </form>
            ) : (
                <>
                    <div className="flex items-center gap-2 truncate">
                    {getFileIcon(file.name)}
                    <span className="truncate">{file.name}</span>
                    </div>
                    <div className="hidden group-hover:flex items-center gap-1">
                        <button 
                            onClick={(e) => { e.stopPropagation(); startRename(file.name); }}
                            className="p-1 hover:text-blue-400"
                            title="Rename"
                        >
                            <Edit2 size={10} />
                        </button>
                        <button 
                            onClick={(e) => {
                                e.stopPropagation();
                                onDelete(file.name);
                            }}
                            className="p-1 hover:text-red-400"
                            title="Delete"
                        >
                            <Trash2 size={10} />
                        </button>
                    </div>
                </>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default FileExplorer;

