                    <div className="flex gap-2 items-end">
                        <button 
                            onClick={() => fileInputRef.current?.click()} 
                            className="p-2.5 text-gray-400 hover:text-white bg-[#2a2a2a] border border-gray-700 rounded-xl hover:bg-gray-700 transition-colors"
                            title="Attach Image/Audio"
                        >
                            <Paperclip size={18} />
                        </button>
                        <div className="flex-1 relative">
                            <textarea
                                value={input}
                                onChange={e => setInput(e.target.value)}
                                onKeyDown={e => {
                                    if(e.key === 'Enter' && !e.shiftKey) {
                                        e.preventDefault();
                                        handleSendMessage();
                                    }
                                }}
                                placeholder="Message Gemini..."
                                className="w-full bg-[#2a2a2a] border border-gray-700 rounded-xl px-4 py-2.5 text-sm text-white focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500/50 resize-none custom-scrollbar"
                                style={{ minHeight: '42px', maxHeight: '120px' }}
