                           className="p-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-lg shadow-blue-900/20"
                        >
                           {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
                        </button>
                    </div>
                    <div className="text-[10px] text-gray-600 text-center mt-2">
                        Gemini can make mistakes. Check important info.
                    </div>
                 </div>
              </>
          )}

          {/* --- CREATE TAB --- */}
          {activeTab === 'create' && (
              <div className="p-4 flex flex-col h-full overflow-y-auto custom-scrollbar">
                 <div className="bg-[#2a2a2a] p-1 rounded-xl mb-6 grid grid-cols-2 gap-1 border border-gray-700">
                     <button 
                        onClick={() => { setCreateType('image'); setGeneratedMedia(null); }} 
                        className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-medium transition-all ${createType === 'image' ? 'bg-gray-700 text-white shadow-sm' : 'text-gray-400 hover:text-gray-200'}`}
                     >
                         <ImageIcon size={14} /> Image
                     </button>
                     <button 
                        onClick={() => { setCreateType('video'); setGeneratedMedia(null); }}
                        className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-medium transition-all ${createType === 'video' ? 'bg-gray-700 text-white shadow-sm' : 'text-gray-400 hover:text-gray-200'}`}
                     >
                         <Video size={14} /> Video
                     </button>
                 </div>

                 <div className="space-y-4">
                     <div>
                        <label className="block text-xs font-semibold text-gray-500 mb-2 uppercase tracking-wider">Prompt</label>
                        <textarea
                            value={prompt}
                            onChange={e => setPrompt(e.target.value)}
                            placeholder={`Describe the ${createType} in detail...`}
                            className="w-full bg-[#2a2a2a] border border-gray-700 rounded-xl p-3 text-sm text-white h-32 resize-none focus:border-blue-500 outline-none transition-colors"
