import React, { useState, useMemo } from 'react';
import { FileCode, FileJson, FileType, File, FolderOpen, Folder, FolderPlus, FilePlus, Edit2, Trash2, ChevronRight, ChevronDown } from 'lucide-react';
import { VirtualFile } from '../types';

interface FileExplorerProps {
  files: VirtualFile[];
  activeFileName: string;
  onSelect: (fileName: string) => void;
  onCreate: (fileName: string) => void;
  onCreateFolder: (folderName: string) => void;
  onDelete: (fileName: string) => void;
  onRename: (oldName: string, newName: string) => void;
}

const getFileIcon = (fileName: string) => {
  if (fileName.endsWith('.html')) return <FileCode size={14} className="text-orange-400" />;
  if (fileName.endsWith('.css')) return <FileType size={14} className="text-blue-400" />;
  if (fileName.endsWith('.js') || fileName.endsWith('.ts') || fileName.endsWith('.tsx')) return <FileCode size={14} className="text-yellow-400" />;
  if (fileName.endsWith('.json')) return <FileJson size={14} className="text-green-400" />;
  return <File size={14} className="text-gray-400" />;
};

// Tree Building Logic
interface TreeNode {
  id: string; // full path
  name: string; // segment name
  type: 'file' | 'directory';
  children: Record<string, TreeNode>;
  isOpen: boolean;
}

const buildTree = (files: VirtualFile[]) => {
  const root: Record<string, TreeNode> = {};

  // Sort files so folders come first, then alphabetical
  const sorted = [...files].sort((a, b) => {
      const typeA = a.type || 'file';
      const typeB = b.type || 'file';
      if (typeA !== typeB) return typeA === 'directory' ? -1 : 1;
      return a.name.localeCompare(b.name);
  });

  sorted.forEach(file => {
    const parts = file.name.split('/');
    let currentLevel = root;

    parts.forEach((part, index) => {
      const path = parts.slice(0, index + 1).join('/');
      const isFile = index === parts.length - 1 && file.type !== 'directory';

      if (!currentLevel[part]) {
        currentLevel[part] = {
          id: path,
          name: part,
          type: isFile ? 'file' : 'directory',
          children: {},
          isOpen: true // default open for demo
        };
      }
      currentLevel = currentLevel[part].children;
    });
  });

  return root;
};

const FileTreeItem: React.FC<{
  node: TreeNode;
  level: number;
  activeFileName: string;
  onSelect: (path: string) => void;
  onDelete: (path: string) => void;
  onRename: (oldPath: string, newPath: string) => void;
  selectedPath: string | null;
  setSelectedPath: (path: string | null) => void;
}> = ({ node, level, activeFileName, onSelect, onDelete, onRename, selectedPath, setSelectedPath }) => {
  const [isOpen, setIsOpen] = useState(node.isOpen);
  const [isRenaming, setIsRenaming] = useState(false);
  const [renameValue, setRenameValue] = useState(node.name);

  const handleRenameSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (renameValue !== node.name) {
       // Construct new path
       const parentPath = node.id.substring(0, node.id.lastIndexOf('/'));
       const newPath = parentPath ? `${parentPath}/${renameValue}` : renameValue;
       onRename(node.id, newPath);
    }
    setIsRenaming(false);
  };

  const hasChildren = Object.keys(node.children).length > 0;
  const isSelected = selectedPath === node.id;
  const isActive = activeFileName === node.id;

  return (
    <div className="select-none">
      <div 
        className={`flex items-center gap-1 py-1 px-2 cursor-pointer transition-colors ${
            isActive ? 'bg-browser-tab text-white' : 
            isSelected ? 'bg-white/10 text-gray-200' : 'text-gray-400 hover:text-gray-200 hover:bg-white/5'
        }`}
        style={{ paddingLeft: `${level * 12 + 8}px` }}
        onClick={(e) => {
            e.stopPropagation();
            setSelectedPath(node.id);
            if (node.type === 'directory') {
                setIsOpen(!isOpen);
            } else {
                onSelect(node.id);
            }
        }}
      >
        <span className="opacity-70 flex-shrink-0 w-4">
            {node.type === 'directory' && (
                isOpen ? <ChevronDown size={12} /> : <ChevronRight size={12} />
            )}
        </span>

        {isRenaming ? (
            <form onSubmit={handleRenameSubmit} onClick={e => e.stopPropagation()} className="flex-1 min-w-0">
                <input
                    autoFocus
                    value={renameValue}
                    onChange={e => setRenameValue(e.target.value)}
                    onBlur={handleRenameSubmit}
                    className="w-full bg-gray-800 text-white text-xs px-1 py-0.5 rounded border border-blue-500 outline-none"
                />
            </form>
        ) : (
            <div className="flex-1 flex items-center justify-between min-w-0 group">
                <div className="flex items-center gap-2 truncate">
                    {node.type === 'directory' ? (
                        isOpen ? <FolderOpen size={14} className="text-blue-300" /> : <Folder size={14} className="text-blue-300" />
                    ) : (
                        getFileIcon(node.name)
                    )}
                    <span className="truncate text-xs">{node.name}</span>
                </div>
                <div className="hidden group-hover:flex items-center gap-1 bg-[#252526] shadow-sm ml-2">
                     <button onClick={(e) => { e.stopPropagation(); setIsRenaming(true); }} className="p-0.5 hover:text-blue-400">
                         <Edit2 size={10} />
                     </button>
                     <button onClick={(e) => { e.stopPropagation(); onDelete(node.id); }} className="p-0.5 hover:text-red-400">
                         <Trash2 size={10} />
                     </button>
                </div>
            </div>
        )}
      </div>

      {node.type === 'directory' && isOpen && (
          <div>
              {Object.values(node.children)
                .sort((a, b) => {
                    if (a.type !== b.type) return a.type === 'directory' ? -1 : 1;
                    return a.name.localeCompare(b.name);
                })
                .map(child => (
                  <FileTreeItem 
                    key={child.id} 
                    node={child} 
                    level={level + 1} 
                    activeFileName={activeFileName}
                    onSelect={onSelect}
                    onDelete={onDelete}
                    onRename={onRename}
                    selectedPath={selectedPath}
                    setSelectedPath={setSelectedPath}
                  />
              ))}
          </div>
      )}
    </div>
  );
};

const FileExplorer: React.FC<FileExplorerProps> = ({ files, activeFileName, onSelect, onCreate, onCreateFolder, onDelete, onRename }) => {
  const [isCreating, setIsCreating] = useState<'file' | 'folder' | null>(null);
  const [newName, setNewName] = useState('');
  const [selectedPath, setSelectedPath] = useState<string | null>(null);

  const fileTree = useMemo(() => buildTree(files), [files]);

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName) {
        setIsCreating(null);
        return;
    }

    // Determine path based on selection
    // If selectedPath is a file, use its parent directory. If directory, use it.
    let parentPath = '';
    if (selectedPath) {
        const selectedFile = files.find(f => f.name === selectedPath);
        if (selectedFile?.type === 'directory') {
            parentPath = selectedPath;
        } else {
            const parts = selectedPath.split('/');
            parts.pop();
            parentPath = parts.join('/');
        }
    }

    const fullPath = parentPath ? `${parentPath}/${newName}` : newName;

    if (isCreating === 'file') {
        onCreate(fullPath);
    } else {
        onCreateFolder(fullPath);
    }

    setNewName('');
    setIsCreating(null);
  };

  return (
    <div className="w-60 bg-browser-toolbar border-r border-gray-700 flex flex-col h-full select-none" onClick={() => setSelectedPath(null)}>
      <div className="h-9 px-3 flex items-center justify-between border-b border-gray-700 bg-[#252526]">
        <div className="flex items-center gap-2 text-xs font-semibold text-gray-400">
          <FolderOpen size={14} />
          <span>EXPLORER</span>
        </div>
        <div className="flex items-center gap-1">
            <button 
                onClick={(e) => { e.stopPropagation(); setIsCreating('file'); }} 
                className="text-gray-400 hover:text-white p-1 hover:bg-white/10 rounded"
                title="New File"
            >
                <FilePlus size={14} />
            </button>
            <button 
                onClick={(e) => { e.stopPropagation(); setIsCreating('folder'); }} 
                className="text-gray-400 hover:text-white p-1 hover:bg-white/10 rounded"
                title="New Folder"
            >
                <FolderPlus size={14} />
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto py-2 custom-scrollbar">
        {isCreating && (
          <div className="px-2 mb-2">
            <form onSubmit={handleCreateSubmit} className="flex items-center gap-1 bg-gray-800 border border-blue-500 px-2 py-1 rounded">
               {isCreating === 'folder' ? <Folder size={12} className="text-gray-400" /> : <File size={12} className="text-gray-400" />}
               <input
                 autoFocus
                 type="text"
                 value={newName}
                 onChange={(e) => setNewName(e.target.value)}
                 onBlur={() => { if(!newName) setIsCreating(null); }}
                 placeholder={isCreating === 'folder' ? "folder_name" : "filename.ext"}
                 className="w-full bg-transparent text-xs text-white outline-none"
                 onClick={e => e.stopPropagation()}
               />
            </form>
          </div>
        )}

        {Object.values(fileTree).map(node => (
            <FileTreeItem 
                key={node.id} 
                node={node} 
                level={0}
                activeFileName={activeFileName}
                onSelect={onSelect}
                onDelete={onDelete}
                onRename={onRename}
                selectedPath={selectedPath}
                setSelectedPath={setSelectedPath}
            />
        ))}
      </div>
    </div>
  );
};

export default FileExplorer;

import React, { useState, useMemo } from 'react';
import { GitCommit, VirtualFile } from '../types';
import { GitCommitHorizontal, Check, Clock, RotateCcw, Play } from 'lucide-react';

interface SourceControlProps {
  files: VirtualFile[];
  commits: GitCommit[];
  onCommit: (message: string) => void;
  onCheckout: (commitId: string) => void;
}

const SourceControl: React.FC<SourceControlProps> = ({ files, commits, onCommit, onCheckout }) => {
  const [message, setMessage] = useState('');

  // Calculate differences between current files and HEAD (latest commit)
  const changes = useMemo(() => {
    const head = commits[0];
    const changesList: { name: string; type: 'M' | 'A' | 'D' }[] = [];

    // Filter out directories from diff
    const contentFiles = files.filter(f => f.type !== 'directory');
    const headContentFiles = head ? head.files.filter(f => f.type !== 'directory') : [];

    // If no commits, everything is Added
    if (!head) {
      return contentFiles.map(f => ({ name: f.name, type: 'A' as const }));
    }

    // Check Modified and Added
    contentFiles.forEach(f => {
      const prev = headContentFiles.find(pf => pf.name === f.name);
      if (!prev) {
        changesList.push({ name: f.name, type: 'A' });
      } else if (prev.content !== f.content) {
        changesList.push({ name: f.name, type: 'M' });
      }
    });

    // Check Deleted
    headContentFiles.forEach(pf => {
      if (!contentFiles.find(f => f.name === pf.name)) {
        changesList.push({ name: pf.name, type: 'D' });
      }
    });

    return changesList;
  }, [files, commits]);

  const handleCommit = () => {
    if (!message.trim()) return;
    onCommit(message);
    setMessage('');
  };

  return (
    <div className="w-64 bg-browser-toolbar border-r border-gray-700 flex flex-col h-full select-none">
      <div className="h-9 px-3 flex items-center justify-between border-b border-gray-700 bg-[#252526]">
        <div className="flex items-center gap-2 text-xs font-semibold text-gray-400">
          <GitCommitHorizontal size={14} />
          <span>SOURCE CONTROL</span>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-3">
        {/* Commit Input */}
        <div className="mb-6">
          <textarea
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            placeholder="Commit message"
            className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-xs text-white mb-2 focus:border-blue-500 outline-none resize-none h-20"
          />
          <button
            onClick={handleCommit}
            disabled={changes.length === 0 || !message.trim()}
            className="w-full bg-blue-600 hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed text-white text-xs py-1.5 rounded flex items-center justify-center gap-2"
          >
            <Check size={12} />
            Commit
          </button>
        </div>

        {/* Changes List */}
        <div className="mb-6">
          <div className="flex items-center justify-between text-xs font-bold text-gray-500 mb-2 uppercase tracking-wider">
            <span>Changes ({changes.length})</span>
          </div>
          <div className="space-y-1">
            {changes.length === 0 && <div className="text-gray-600 text-xs italic">No changes detected</div>}
            {changes.map((change) => (
              <div key={change.name} className="flex items-center justify-between group hover:bg-white/5 p-1 rounded cursor-default">
                <div className="flex items-center gap-2 text-xs text-gray-300 truncate">
                  <span className={`font-mono font-bold w-3 ${
                    change.type === 'M' ? 'text-yellow-500' : 
                    change.type === 'A' ? 'text-green-500' : 'text-red-500'
                  }`}>{change.type}</span>
                  <span className="truncate">{change.name}</span>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Commit History */}
        <div>
          <div className="flex items-center justify-between text-xs font-bold text-gray-500 mb-2 uppercase tracking-wider">
            <span>Commits ({commits.length})</span>
          </div>
          <div className="space-y-3 relative">
            {commits.map((commit, i) => (
              <div key={commit.id} className="relative pl-4 border-l-2 border-gray-700 pb-2 last:pb-0 group">
                 <div className="absolute -left-[5px] top-0 w-2 h-2 rounded-full bg-gray-500 group-hover:bg-blue-500 transition-colors"></div>
                 <div className="flex items-start justify-between">
                     <div>
                         <div className="text-xs text-white font-medium truncate w-32" title={commit.message}>{commit.message}</div>
                         <div className="text-[10px] text-gray-500 flex items-center gap-1">
                             <Clock size={10} />
                             {commit.timestamp}
                         </div>
                     </div>
                     {i !== 0 && (
                        <button 
                            onClick={() => { if(confirm('Revert to this commit? All current changes will be lost.')) onCheckout(commit.id); }}
                            className="p-1 text-gray-500 hover:text-white opacity-0 group-hover:opacity-100 transition-opacity"
                            title="Checkout (Revert)"
                        >
                            <RotateCcw size={12} />
                        </button>
                     )}
                     {i === 0 && (
                         <span className="text-[10px] bg-blue-900/50 text-blue-400 px-1 rounded border border-blue-900">HEAD</span>
                     )}
                 </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default SourceControl;

import React, { useState, useMemo } from 'react';
