        </span>

        {isRenaming ? (
            <form onSubmit={handleRenameSubmit} onClick={e => e.stopPropagation()} className="flex-1 min-w-0">
                <input
                    autoFocus
                    value={renameValue}
                    onChange={e => setRenameValue(e.target.value)}
                    onBlur={handleRenameSubmit}
                    className="w-full bg-gray-800 text-white text-xs px-1 py-0.5 rounded border border-blue-500 outline-none"
                />
            </form>
        ) : (
            <div className="flex-1 flex items-center justify-between min-w-0 group">
                <div className="flex items-center gap-2 truncate">
                    {node.type === 'directory' ? (
                        isOpen ? <FolderOpen size={14} className="text-blue-300" /> : <Folder size={14} className="text-blue-300" />
                    ) : (
                        getFileIcon(node.name)
                    )}
                    <span className="truncate text-xs">{node.name}</span>
                </div>
                <div className="hidden group-hover:flex items-center gap-1 bg-[#252526] shadow-sm ml-2">
                     <button onClick={(e) => { e.stopPropagation(); setIsRenaming(true); }} className="p-0.5 hover:text-blue-400">
                         <Edit2 size={10} />
                     </button>
                     <button onClick={(e) => { e.stopPropagation(); onDelete(node.id); }} className="p-0.5 hover:text-red-400">
                         <Trash2 size={10} />
                     </button>
                </div>
            </div>
        )}
      </div>

      {node.type === 'directory' && isOpen && (
          <div>
              {Object.values(node.children)
                .sort((a: TreeNode, b: TreeNode) => {
                    if (a.type !== b.type) return a.type === 'directory' ? -1 : 1;
                    return a.name.localeCompare(b.name);
                })
                .map((child: TreeNode) => (
                  <FileTreeItem 
                    key={child.id} 
                    node={child} 
                    level={level + 1} 
                    activeFileName={activeFileName}
                    onSelect={onSelect}
                    onDelete={onDelete}
                    onRename={onRename}
                    selectedPath={selectedPath}
                    setSelectedPath={setSelectedPath}
                  />
              ))}
          </div>
      )}
    </div>
  );
};

const FileExplorer: React.FC<FileExplorerProps> = ({ files, activeFileName, onSelect, onCreate, onCreateFolder, onDelete, onRename }) => {
  const [isCreating, setIsCreating] = useState<'file' | 'folder' | null>(null);
  const [newName, setNewName] = useState('');
  const [selectedPath, setSelectedPath] = useState<string | null>(null);

  const fileTree = useMemo(() => buildTree(files), [files]);

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName) {
        setIsCreating(null);
        return;
    }

    // Determine path based on selection
    // If selectedPath is a file, use its parent directory. If directory, use it.
    let parentPath = '';
    if (selectedPath) {
        const selectedFile = files.find(f => f.name === selectedPath);
        if (selectedFile?.type === 'directory') {
            parentPath = selectedPath;
        } else {
            const parts = selectedPath.split('/');
            parts.pop();
            parentPath = parts.join('/');
        }
    }

    const fullPath = parentPath ? `${parentPath}/${newName}` : newName;

    if (isCreating === 'file') {
        onCreate(fullPath);
    } else {
        onCreateFolder(fullPath);
    }

    setNewName('');
    setIsCreating(null);
  };

  return (
    <div className="w-60 bg-browser-toolbar border-r border-gray-700 flex flex-col h-full select-none" onClick={() => setSelectedPath(null)}>
      <div className="h-9 px-3 flex items-center justify-between border-b border-gray-700 bg-[#252526]">
        <div className="flex items-center gap-2 text-xs font-semibold text-gray-400">
          <FolderOpen size={14} />
          <span>EXPLORER</span>
        </div>
        <div className="flex items-center gap-1">
            <button 
                onClick={(e) => { e.stopPropagation(); setIsCreating('file'); }} 
                className="text-gray-400 hover:text-white p-1 hover:bg-white/10 rounded"
                title="New File"
            >
                <FilePlus size={14} />
            </button>
            <button 
                onClick={(e) => { e.stopPropagation(); setIsCreating('folder'); }} 
                className="text-gray-400 hover:text-white p-1 hover:bg-white/10 rounded"
                title="New Folder"
            >
                <FolderPlus size={14} />
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto py-2 custom-scrollbar">
        {isCreating && (
          <div className="px-2 mb-2">
            <form onSubmit={handleCreateSubmit} className="flex items-center gap-1 bg-gray-800 border border-blue-500 px-2 py-1 rounded">
               {isCreating === 'folder' ? <Folder size={12} className="text-gray-400" /> : <File size={12} className="text-gray-400" />}
               <input
                 autoFocus
                 type="text"
                 value={newName}
                 onChange={(e) => setNewName(e.target.value)}
                 onBlur={() => { if(!newName) setIsCreating(null); }}
                 placeholder={isCreating === 'folder' ? "folder_name" : "filename.ext"}
                 className="w-full bg-transparent text-xs text-white outline-none"
                 onClick={e => e.stopPropagation()}
               />
            </form>
          </div>
        )}

        {Object.values(fileTree).map((node: TreeNode) => (
            <FileTreeItem 
                key={node.id} 
                node={node} 
                level={0}
                activeFileName={activeFileName}
                onSelect={onSelect}
                onDelete={onDelete}
                onRename={onRename}
                selectedPath={selectedPath}
                setSelectedPath={setSelectedPath}
            />
        ))}
      </div>
    </div>
  );
};

export default FileExplorer;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Code2, SplitSquareHorizontal, Maximize2, Sparkles, Layout } from 'lucide-react';
import { LogEntry, LayoutMode, VirtualFile, GitCommit, SidebarView } from './types';
import Console from './components/Console';
import AddressBar from './components/AddressBar';
import AIAssistant from './components/AIAssistant';
import FileExplorer from './components/FileExplorer';
import SourceControl from './components/SourceControl';
import ActivityBar from './components/ActivityBar';

// Initial Empty Project
const INITIAL_FILES: VirtualFile[] = [
  {
    name: 'index.html',
    language: 'html',
    type: 'file',
    content: `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>New Project</title>
</head>
<body>

</body>
</html>`
  }
];

export default function App() {
  // Load initial state from localStorage if available
  const [files, setFiles] = useState<VirtualFile[]>(() => {
    try {
      const saved = localStorage.getItem('devbrowser_files');
      return saved ? JSON.parse(saved) : INITIAL_FILES;
    } catch (e) {
      console.error("Failed to load files from storage", e);
      return INITIAL_FILES;
    }
  });

  const [activeFileName, setActiveFileName] = useState(() => {
    return localStorage.getItem('devbrowser_activeFile') || 'index.html';
  });

  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [iframeKey, setIframeKey] = useState(0); 
  const [layoutMode, setLayoutMode] = useState<LayoutMode>(LayoutMode.SPLIT);
  const [isConsoleOpen, setIsConsoleOpen] = useState(true);
  const [isAIOpen, setIsAIOpen] = useState(false);

  // Navigation & Git State
  const [activeSidebar, setActiveSidebar] = useState<SidebarView>('explorer');
  const [commits, setCommits] = useState<GitCommit[]>([]);

  // Save to localStorage whenever files change
  useEffect(() => {
    localStorage.setItem('devbrowser_files', JSON.stringify(files));
  }, [files]);

  // Save active file selection
  useEffect(() => {
    localStorage.setItem('devbrowser_activeFile', activeFileName);
  }, [activeFileName]);

  // Init Git
  useEffect(() => {
    if (commits.length === 0) {
      setCommits([{
        id: 'init',
        message: 'Initial Commit',
        timestamp: new Date().toLocaleTimeString(),
        files: JSON.parse(JSON.stringify(INITIAL_FILES))
      }]);
    }
  }, []);

  const activeFile = files.find(f => f.name === activeFileName) || files[0];

  // Update file content
  const updateFileContent = (newContent: string) => {
    setFiles(prev => prev.map(f => f.name === activeFileName ? { ...f, content: newContent } : f));
  };

  // Git Operations
  const handleGitCommit = (message: string) => {
    const newCommit: GitCommit = {
      id: Date.now().toString(),
      message,
      timestamp: new Date().toLocaleTimeString(),
      files: JSON.parse(JSON.stringify(files)) // Deep copy
    };
    setCommits(prev => [newCommit, ...prev]); // Prepend to show latest first
  };

  const handleGitCheckout = (commitId: string) => {
    const commit = commits.find(c => c.id === commitId);
    if (commit) {
      setFiles(JSON.parse(JSON.stringify(commit.files)));
      // If active file is gone, reset to first
      if (!commit.files.find(f => f.name === activeFileName)) {
        setActiveFileName(commit.files[0]?.name || '');
      }
    }
  };

  // Calculate uncommitted changes count for badge
  const uncommittedChangesCount = useMemo(() => {
    const head = commits[0];
    if (!head) return files.filter(f => f.type !== 'directory').length;
    let count = 0;
    // Modified & Added (ignore directories)
    files.filter(f => f.type !== 'directory').forEach(f => {
      const prev = head.files.find(pf => pf.name === f.name);
      if (!prev || prev.content !== f.content) count++;
    });
    // Deleted (ignore directories)
    head.files.filter(f => f.type !== 'directory').forEach(pf => {
      if (!files.find(f => f.name === pf.name)) count++;
    });
    return count;
  }, [files, commits]);

  // File Operations
  const handleCreateFile = (name: string) => {
    if (files.some(f => f.name === name)) return;
    const ext = name.split('.').pop();
    let lang: VirtualFile['language'] = 'text';
    if (ext === 'html') lang = 'html';
    else if (ext === 'css') lang = 'css';
    else if (ext === 'js') lang = 'javascript';
    else if (ext === 'json') lang = 'json';

    setFiles(prev => [...prev, { name, content: '', language: lang, type: 'file' }]);
    setActiveFileName(name);
  };

  const handleCreateFolder = (name: string) => {
    if (files.some(f => f.name === name)) return;
    setFiles(prev => [...prev, { name, content: '', language: 'text', type: 'directory' }]);
  };

  const handleDeleteFile = (name: string) => {
    // Delete file and any children if it's a directory
    const newFiles = files.filter(f => f.name !== name && !f.name.startsWith(name + '/'));
    setFiles(newFiles);
    if (activeFileName === name || activeFileName.startsWith(name + '/')) {
        // Fallback to first available file
        const firstFile = newFiles.find(f => f.type === 'file');
        if (firstFile) setActiveFileName(firstFile.name);
        else setActiveFileName('');
    }
  };

  const handleRenameFile = (oldName: string, newName: string) => {
      if (files.some(f => f.name === newName)) {
          alert("Path already exists");
          return;
      }
      setFiles(prev => prev.map(f => {
          if (f.name === oldName) return { ...f, name: newName };
          if (f.name.startsWith(oldName + '/')) {
              return { ...f, name: f.name.replace(oldName + '/', newName + '/') };
          }
          return f;
      }));

      if (activeFileName === oldName) setActiveFileName(newName);
      else if (activeFileName.startsWith(oldName + '/')) {
          setActiveFileName(activeFileName.replace(oldName + '/', newName + '/'));
      }
  };

  // Handle messages from iframe
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'console') {
        const newLog: LogEntry = {
          id: Date.now().toString() + Math.random(),
          timestamp: new Date().toLocaleTimeString(),
          level: event.data.level,
          message: event.data.message.map((m: any) => 
            typeof m === 'object' ? JSON.stringify(m) : String(m)
          ).join(' ')
        };
        setLogs(prev => [...prev, newLog]);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const runCode = useCallback(() => {
    setLogs([]); 
    setIframeKey(prev => prev + 1);
  }, []);

  const clearLogs = () => setLogs([]);

  // Console Command Handler
  const handleConsoleCommand = (cmd: string) => {
    const args = cmd.trim().split(/\s+/);
    const command = args[0];
    const params = args.slice(1);

    // Log the user's command
    setLogs(prev => [...prev, {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString(),
      level: 'command',
      message: `> ${cmd}`
    }]);

    let output = '';
    let level: LogEntry['level'] = 'info';

    switch(command) {
        case 'help':
            output = 'Available commands: ls, cat <file>, touch <file>, mkdir <folder>, rm <path>, echo <text>, clear, pwd';
            break;
        case 'ls':
            output = files.map(f => `${f.name}${f.type === 'directory' ? '/' : ''}`).join('  ');
            break;
        case 'pwd':
            output = '/';
            break;
        case 'cat':
            if (!params[0]) {
                output = 'Usage: cat <filename>';
                level = 'error';
            } else {
                const f = files.find(file => file.name === params[0] && file.type !== 'directory');
                if (f) output = f.content;
                else {
                    output = `File not found: ${params[0]}`;
                    level = 'error';
                }
            }
            break;
        case 'touch':
            if (!params[0]) {
                output = 'Usage: touch <filename>';
                level = 'error';
            } else if (files.some(f => f.name === params[0])) {
                output = `File already exists: ${params[0]}`;
                level = 'warn';
            } else {
                handleCreateFile(params[0]);
                output = `Created ${params[0]}`;
                level = 'success';
            }
            break;
        case 'mkdir':
            if (!params[0]) {
                output = 'Usage: mkdir <foldername>';
                level = 'error';
            } else if (files.some(f => f.name === params[0])) {
                output = `Directory already exists: ${params[0]}`;
                level = 'warn';
            } else {
                handleCreateFolder(params[0]);
                output = `Created directory ${params[0]}`;
                level = 'success';
            }
            break;
        case 'rm':
            if (!params[0]) {
                output = 'Usage: rm <path>';
                level = 'error';
            } else if (!files.some(f => f.name === params[0])) {
                output = `Path not found: ${params[0]}`;
                level = 'error';
            } else {
                handleDeleteFile(params[0]);
                output = `Removed ${params[0]}`;
                level = 'success';
            }
            break;
        case 'echo':
            output = params.join(' ');
            break;
        case 'clear':
            setLogs([]);
            return;
        default:
            output = `Command not found: ${command}`;
            level = 'error';
    }

    if (output) {
        setLogs(prev => [...prev, {
            id: Date.now().toString() + 'r',
            timestamp: new Date().toLocaleTimeString(),
            level,
            message: output
        }]);
    }
  };

  // Bundler Logic: Inject CSS/JS into HTML
  const getSrcDoc = () => {
    const entryPoint = files.find(f => f.name === 'index.html');
    if (!entryPoint) return "<html><body><h1>No index.html found</h1></body></html>";

    let html = entryPoint.content;

    // Simple bundler handles basic paths by matching exact names in VirtualFS
    html = html.replace(/<link\s+rel="stylesheet"\s+href="(.+?)"\s*\/?>/g, (match, href) => {
      const cssFile = files.find(f => f.name === href); // href matches 'styles/main.css'
      return cssFile ? `<style>${cssFile.content}</style>` : match;
    });

    html = html.replace(/<script\s+src="(.+?)"><\/script>/g, (match, src) => {
      const jsFile = files.find(f => f.name === src); // src matches 'scripts/app.js'
      return jsFile ? `<script>${jsFile.content}</script>` : match;
    });

    const consoleHijack = `
      <script>
        const originalLog = console.log;
        const originalWarn = console.warn;
        const originalError = console.error;
        const originalInfo = console.info;

        function sendToParent(level, args) {
          try {
            window.parent.postMessage({
              type: 'console',
              level: level,
              message: Array.from(args)
            }, '*');
          } catch(e) {}
        }

        console.log = function(...args) { originalLog.apply(console, args); sendToParent('log', args); };
        console.warn = function(...args) { originalWarn.apply(console, args); sendToParent('warn', args); };
        console.error = function(...args) { originalError.apply(console, args); sendToParent('error', args); };
        console.info = function(...args) { originalInfo.apply(console, args); sendToParent('info', args); };

        window.onerror = function(msg, url, line) {
           sendToParent('error', [msg + " (Line " + line + ")"]);
        }
      </script>
    `;

    if (html.includes('</body>')) {
      return html.replace('</body>', `${consoleHijack}</body>`);
    }
    return html + consoleHijack;
  };

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Bar */}
      <div className="flex flex-col">
        {/* Tab Bar / Header */}
        <div className="flex items-center h-10 px-2 bg-browser-bg border-b border-browser-toolbar select-none justify-between">
           <div className="flex items-center gap-2">
              <div className="flex gap-1.5 px-3">
                 <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
              </div>
              <span className="text-xs font-semibold text-gray-500 ml-2">DevBrowser OS</span>
           </div>

           <div className="flex items-center gap-2">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className="p-1.5 hover:bg-white/10 rounded text-gray-400 hover:text-white transition"
                 title="Toggle Split View"
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={16} /> : <SplitSquareHorizontal size={16} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1.5 rounded transition-colors ${isAIOpen ? 'text-browser-accent bg-blue-500/10' : 'text-gray-400 hover:text-white hover:bg-white/10'}`}
                 title="Toggle AI Assistant"
              >
                <Sparkles size={16} />
              </button>
           </div>
        </div>

        {/* Address Bar */}
        <AddressBar url={`localhost:3000/${activeFileName}`} onRefresh={runCode} />
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Activity Bar (Leftmost) */}
        <ActivityBar 
            activeView={activeSidebar} 
            onViewChange={setActiveSidebar} 
            changesCount={uncommittedChangesCount}
        />

        {/* Sidebar Content (Dynamic) */}
        {activeSidebar === 'explorer' && (
            <FileExplorer 
              files={files} 
              activeFileName={activeFileName} 
              onSelect={setActiveFileName} 
              onCreate={handleCreateFile}
              onCreateFolder={handleCreateFolder}
              onDelete={(name) => { if(confirm(`Delete ${name}?`)) handleDeleteFile(name); }}
              onRename={handleRenameFile}
            />
        )}
        {activeSidebar === 'git' && (
            <SourceControl 
                files={files} 
                commits={commits} 
                onCommit={handleGitCommit}
                onCheckout={handleGitCheckout}
            />
        )}

        {/* Editor Pane */}
        <div className={`flex flex-col border-r border-gray-800 transition-all duration-300 ${
            layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-0 overflow-hidden'
        }`}>
          {/* Editor Header */}
          <div className="h-9 bg-[#1e1e1e] border-b border-gray-800 flex items-center px-4 text-xs">
             <Code2 size={14} className="text-blue-500 mr-2" />
             <span className="text-gray-300">{activeFileName}</span>
             <span className="ml-auto text-gray-600">{activeFile?.content.length || 0} chars</span>
          </div>

          <textarea
            className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed"
            value={activeFile?.content || ''}
            onChange={(e) => updateFileContent(e.target.value)}
            spellCheck={false}
          />
        </div>

        {/* Preview Pane */}
        <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${
             layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'
        }`}>
          <iframe
            key={iframeKey}
            title="Preview"
            srcDoc={getSrcDoc()}
            className="w-full h-full border-none"
            sandbox="allow-scripts allow-modals allow-forms allow-same-origin"
          />
        </div>

        {/* AI Sidebar Overlay */}
        <AIAssistant 
          currentCode={activeFile?.content || ''} 
          isOpen={isAIOpen} 
          onClose={() => setIsAIOpen(false)} 
        />
      </div>

      {/* Console (Fixed at Bottom) */}
      <Console 
        logs={logs} 
        onClear={clearLogs} 
        isOpen={isConsoleOpen} 
        toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} 
        onCommand={handleConsoleCommand}
      />
    </div>
  );
}

export interface Tab {
  id: string;
  title: string;
  type: 'editor' | 'preview' | 'ai';
  content: string;
  active: boolean;
}

export interface LogEntry {
  id: string;
  timestamp: string;
  level: 'info' | 'warn' | 'error' | 'log' | 'command' | 'success';
  message: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  image?: string; // base64
  video?: string; // url
  audio?: string; // base64
  isError?: boolean;
}

export enum LayoutMode {
  SPLIT = 'SPLIT',
  FULL = 'FULL'
}

export type ChatMode = 'standard' | 'thinking' | 'search' | 'maps' | 'fast';

export type AspectRatio = "1:1" | "2:3" | "3:2" | "3:4" | "4:3" | "9:16" | "16:9" | "21:9";
export type ImageSize = "1K" | "2K" | "4K";
export type VideoResolution = "720p" | "1080p";

export interface VirtualFile {
  name: string; // Full path
  content: string;
  language: 'html' | 'css' | 'javascript' | 'json' | 'typescript' | 'markdown' | 'text';
  type?: 'file' | 'directory';
}

export interface GitCommit {
  id: string;
  message: string;
  timestamp: string;
  files: VirtualFile[]; // Snapshot of files at this commit
}

export type SidebarView = 'explorer' | 'git' | 'deploy';

import React from 'react';
import { Files, GitGraph, Rocket } from 'lucide-react';
import { SidebarView } from '../types';

interface ActivityBarProps {
  activeView: SidebarView;
  onViewChange: (view: SidebarView) => void;
  changesCount?: number;
}

const ActivityBar: React.FC<ActivityBarProps> = ({ activeView, onViewChange, changesCount = 0 }) => {
  return (
    <div className="w-12 bg-[#333333] border-r border-gray-900 flex flex-col items-center py-4 gap-4 z-20">
      <button
        onClick={() => onViewChange('explorer')}
        className={`p-2 rounded-lg transition-colors relative ${
          activeView === 'explorer' ? 'text-white bg-white/10' : 'text-gray-500 hover:text-gray-300'
        }`}
        title="Explorer"
      >
        <Files size={24} strokeWidth={1.5} />
      </button>

      <button
        onClick={() => onViewChange('git')}
        className={`p-2 rounded-lg transition-colors relative ${
          activeView === 'git' ? 'text-white bg-white/10' : 'text-gray-500 hover:text-gray-300'
        }`}
        title="Source Control"
      >
        <GitGraph size={24} strokeWidth={1.5} />
        {changesCount > 0 && (
          <div className="absolute -top-1 -right-1 w-4 h-4 bg-blue-600 text-[10px] text-white flex items-center justify-center rounded-full font-bold">
            {changesCount}
          </div>
        )}
      </button>

      <button
        onClick={() => onViewChange('deploy')}
        className={`p-2 rounded-lg transition-colors relative ${
          activeView === 'deploy' ? 'text-white bg-white/10' : 'text-gray-500 hover:text-gray-300'
        }`}
        title="Deploy"
      >
        <Rocket size={24} strokeWidth={1.5} />
      </button>
    </div>
  );
};

