export default function App() {
  // Load initial state from localStorage if available
  const [files, setFiles] = useState<VirtualFile[]>(() => {
    try {
      const saved = localStorage.getItem('devbrowser_files');
      return saved ? JSON.parse(saved) : INITIAL_FILES;
    } catch (e) {
      console.error("Failed to load files from storage", e);
      return INITIAL_FILES;
    }
  });

  const [activeFileName, setActiveFileName] = useState(() => {
    return localStorage.getItem('devbrowser_activeFile') || 'index.html';
  });

  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [iframeKey, setIframeKey] = useState(0); 
  const [layoutMode, setLayoutMode] = useState<LayoutMode>(LayoutMode.SPLIT);
  const [isConsoleOpen, setIsConsoleOpen] = useState(true);
  const [isAIOpen, setIsAIOpen] = useState(false);

  // Navigation & Git State
  const [activeSidebar, setActiveSidebar] = useState<SidebarView>('explorer');
  const [commits, setCommits] = useState<GitCommit[]>([]);

  // Save to localStorage whenever files change
  useEffect(() => {
    localStorage.setItem('devbrowser_files', JSON.stringify(files));
  }, [files]);

  // Save active file selection
  useEffect(() => {
    localStorage.setItem('devbrowser_activeFile', activeFileName);
  }, [activeFileName]);

  // Init Git
  useEffect(() => {
    if (commits.length === 0) {
      setCommits([{
        id: 'init',
        message: 'Initial Commit',
        timestamp: new Date().toLocaleTimeString(),
        files: JSON.parse(JSON.stringify(INITIAL_FILES))
      }]);
    }
  }, []);

  const activeFile = files.find(f => f.name === activeFileName) || files[0];

  // Update file content
  const updateFileContent = (newContent: string) => {
    setFiles(prev => prev.map(f => f.name === activeFileName ? { ...f, content: newContent } : f));
  };

  // Format Code Logic
  const handleFormat = async () => {
    if (!activeFile) return;

    try {
      let parser: string | undefined;
      let plugins: any[] = [];

      switch (activeFile.language) {
        case 'javascript':
        case 'typescript':
        case 'json':
          parser = activeFile.language === 'json' ? 'json' : 'babel';
          plugins = [parserBabel, parserEstree];
          break;
        case 'html':
          parser = 'html';
          plugins = [parserHtml, parserBabel, parserPostcss, parserEstree];
          break;
        case 'css':
          parser = 'css';
          plugins = [parserPostcss];
          break;
        case 'markdown':
          parser = 'markdown';
          plugins = [parserMarkdown, parserBabel, parserEstree]; 
          break;
      }

      if (parser) {
        const formatted = await format(activeFile.content, {
          parser,
          plugins,
          printWidth: 80,
          tabWidth: 2,
          semi: true,
          singleQuote: false,
        });
        updateFileContent(formatted);
        setLogs(prev => [...prev, {
            id: Date.now().toString(),
            timestamp: new Date().toLocaleTimeString(),
            level: 'success',
            message: `Formatted ${activeFile.name}`
        }]);
      }
    } catch (e: any) {
        setLogs(prev => [...prev, {
            id: Date.now().toString(),
            timestamp: new Date().toLocaleTimeString(),
            level: 'error',
            message: `Format error: ${e.message}`
        }]);
    }
  };

  // Git Operations
  const handleGitCommit = (message: string) => {
    const newCommit: GitCommit = {
      id: Date.now().toString(),
      message,
      timestamp: new Date().toLocaleTimeString(),
      files: JSON.parse(JSON.stringify(files)) // Deep copy
    };
    setCommits(prev => [newCommit, ...prev]); // Prepend to show latest first
  };

  const handleGitCheckout = (commitId: string) => {
    const commit = commits.find(c => c.id === commitId);
    if (commit) {
      setFiles(JSON.parse(JSON.stringify(commit.files)));
      // If active file is gone, reset to first
      if (!commit.files.find(f => f.name === activeFileName)) {
        setActiveFileName(commit.files[0]?.name || '');
      }
    }
  };

  // Calculate uncommitted changes count for badge
  const uncommittedChangesCount = useMemo(() => {
    const head = commits[0];
    if (!head) return files.filter(f => f.type !== 'directory').length;
    let count = 0;
    // Modified & Added (ignore directories)
    files.filter(f => f.type !== 'directory').forEach(f => {
      const prev = head.files.find(pf => pf.name === f.name);
      if (!prev || prev.content !== f.content) count++;
    });
    // Deleted (ignore directories)
    head.files.filter(f => f.type !== 'directory').forEach(pf => {
      if (!files.find(f => f.name === pf.name)) count++;
    });
    return count;
  }, [files, commits]);

  // File Operations
  const handleCreateFile = (name: string) => {
    if (files.some(f => f.name === name)) return;
    const ext = name.split('.').pop();
    let lang: VirtualFile['language'] = 'text';
    if (ext === 'html') lang = 'html';
    else if (ext === 'css') lang = 'css';
    else if (ext === 'js') lang = 'javascript';
    else if (ext === 'json') lang = 'json';

    setFiles(prev => [...prev, { name, content: '', language: lang, type: 'file' }]);
    setActiveFileName(name);
  };

  const handleCreateFolder = (name: string) => {
    if (files.some(f => f.name === name)) return;
    setFiles(prev => [...prev, { name, content: '', language: 'text', type: 'directory' }]);
  };

  const handleDeleteFile = (name: string) => {
    // Delete file and any children if it's a directory
    const newFiles = files.filter(f => f.name !== name && !f.name.startsWith(name + '/'));
    setFiles(newFiles);
    if (activeFileName === name || activeFileName.startsWith(name + '/')) {
        // Fallback to first available file
        const firstFile = newFiles.find(f => f.type === 'file');
        if (firstFile) setActiveFileName(firstFile.name);
        else setActiveFileName('');
    }
  };

  const handleRenameFile = (oldName: string, newName: string) => {
      if (files.some(f => f.name === newName)) {
          alert("Path already exists");
          return;
      }
      setFiles(prev => prev.map(f => {
          if (f.name === oldName) return { ...f, name: newName };
          if (f.name.startsWith(oldName + '/')) {
              return { ...f, name: f.name.replace(oldName + '/', newName + '/') };
          }
          return f;
      }));

      if (activeFileName === oldName) setActiveFileName(newName);
      else if (activeFileName.startsWith(oldName + '/')) {
          setActiveFileName(activeFileName.replace(oldName + '/', newName + '/'));
      }
  };

  // Handle messages from iframe
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'console') {
        const newLog: LogEntry = {
          id: Date.now().toString() + Math.random(),
          timestamp: new Date().toLocaleTimeString(),
          level: event.data.level,
          message: event.data.message.map((m: any) => 
            typeof m === 'object' ? JSON.stringify(m) : String(m)
          ).join(' ')
        };
        setLogs(prev => [...prev, newLog]);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const runCode = useCallback(() => {
    setLogs([]); 
    setIframeKey(prev => prev + 1);
  }, []);

  const clearLogs = () => setLogs([]);

  // Console Command Handler
  const handleConsoleCommand = (cmd: string) => {
    const args = cmd.trim().split(/\s+/);
    const command = args[0];
    const params = args.slice(1);

    // Log the user's command
    setLogs(prev => [...prev, {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString(),
      level: 'command',
      message: `> ${cmd}`
    }]);

    let output = '';
    let level: LogEntry['level'] = 'info';

    switch(command) {
        case 'help':
            output = 'Available commands: ls, cat <file>, touch <file>, mkdir <folder>, rm <path>, echo <text>, clear, pwd';
            break;
        case 'ls':
            output = files.map(f => `${f.name}${f.type === 'directory' ? '/' : ''}`).join('  ');
            break;
        case 'pwd':
            output = '/';
            break;
        case 'cat':
            if (!params[0]) {
                output = 'Usage: cat <filename>';
                level = 'error';
            } else {
                const f = files.find(file => file.name === params[0] && file.type !== 'directory');
                if (f) output = f.content;
                else {
                    output = `File not found: ${params[0]}`;
                    level = 'error';
                }
            }
            break;
        case 'touch':
            if (!params[0]) {
                output = 'Usage: touch <filename>';
                level = 'error';
            } else if (files.some(f => f.name === params[0])) {
                output = `File already exists: ${params[0]}`;
                level = 'warn';
            } else {
                handleCreateFile(params[0]);
                output = `Created ${params[0]}`;
                level = 'success';
            }
            break;
        case 'mkdir':
            if (!params[0]) {
                output = 'Usage: mkdir <foldername>';
                level = 'error';
            } else if (files.some(f => f.name === params[0])) {
                output = `Directory already exists: ${params[0]}`;
                level = 'warn';
            } else {
                handleCreateFolder(params[0]);
                output = `Created directory ${params[0]}`;
                level = 'success';
            }
            break;
        case 'rm':
            if (!params[0]) {
                output = 'Usage: rm <path>';
                level = 'error';
            } else if (!files.some(f => f.name === params[0])) {
                output = `Path not found: ${params[0]}`;
                level = 'error';
            } else {
                handleDeleteFile(params[0]);
                output = `Removed ${params[0]}`;
                level = 'success';
            }
            break;
        case 'echo':
            output = params.join(' ');
            break;
        case 'clear':
            setLogs([]);
            return;
        default:
            output = `Command not found: ${command}`;
            level = 'error';
    }

    if (output) {
        setLogs(prev => [...prev, {
            id: Date.now().toString() + 'r',
            timestamp: new Date().toLocaleTimeString(),
            level,
            message: output
        }]);
    }
  };

  // Bundler Logic: Inject CSS/JS into HTML
  const getSrcDoc = () => {
    const entryPoint = files.find(f => f.name === 'index.html');
    if (!entryPoint) return "<html><body><h1>No index.html found</h1></body></html>";

    let html = entryPoint.content;

    // Simple bundler handles basic paths by matching exact names in VirtualFS
    html = html.replace(/<link\s+rel="stylesheet"\s+href="(.+?)"\s*\/?>/g, (match, href) => {
      const cssFile = files.find(f => f.name === href); // href matches 'styles/main.css'
      return cssFile ? `<style>${cssFile.content}</style>` : match;
    });

    html = html.replace(/<script\s+src="(.+?)"><\/script>/g, (match, src) => {
      const jsFile = files.find(f => f.name === src); // src matches 'scripts/app.js'
      return jsFile ? `<script>${jsFile.content}</script>` : match;
    });

    const consoleHijack = `
      <script>
        const originalLog = console.log;
        const originalWarn = console.warn;
        const originalError = console.error;
        const originalInfo = console.info;

        function sendToParent(level, args) {
          try {
            window.parent.postMessage({
              type: 'console',
              level: level,
              message: Array.from(args)
            }, '*');
          } catch(e) {}
        }

        console.log = function(...args) { originalLog.apply(console, args); sendToParent('log', args); };
        console.warn = function(...args) { originalWarn.apply(console, args); sendToParent('warn', args); };
        console.error = function(...args) { originalError.apply(console, args); sendToParent('error', args); };
        console.info = function(...args) { originalInfo.apply(console, args); sendToParent('info', args); };

        window.onerror = function(msg, url, line) {
           sendToParent('error', [msg + " (Line " + line + ")"]);
        }
      </script>
    `;

    if (html.includes('</body>')) {
      return html.replace('</body>', `${consoleHijack}</body>`);
    }
    return html + consoleHijack;
  };

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Bar */}
      <div className="flex flex-col">
        {/* Tab Bar / Header */}
        <div className="flex items-center h-10 px-2 bg-browser-bg border-b border-browser-toolbar select-none justify-between">
           <div className="flex items-center gap-2">
              <div className="flex gap-1.5 px-3">
                 <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
              </div>
              <span className="text-xs font-semibold text-gray-500 ml-2">DevBrowser OS</span>
           </div>

           <div className="flex items-center gap-2">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className="p-1.5 hover:bg-white/10 rounded text-gray-400 hover:text-white transition"
                 title="Toggle Split View"
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={16} /> : <SplitSquareHorizontal size={16} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1.5 rounded transition-colors ${isAIOpen ? 'text-browser-accent bg-blue-500/10' : 'text-gray-400 hover:text-white hover:bg-white/10'}`}
                 title="Toggle AI Assistant"
              >
                <Sparkles size={16} />
              </button>
           </div>
        </div>

        {/* Address Bar */}
        <AddressBar url={`localhost:3000/${activeFileName}`} onRefresh={runCode} />
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Activity Bar (Leftmost) */}
        <ActivityBar 
            activeView={activeSidebar} 
            onViewChange={setActiveSidebar} 
            changesCount={uncommittedChangesCount}
        />

        {/* Sidebar Content (Dynamic) */}
        {activeSidebar === 'explorer' && (
            <FileExplorer 
              files={files} 
              activeFileName={activeFileName} 
              onSelect={setActiveFileName} 
              onCreate={handleCreateFile}
              onCreateFolder={handleCreateFolder}
              onDelete={(name) => { if(confirm(`Delete ${name}?`)) handleDeleteFile(name); }}
              onRename={handleRenameFile}
            />
        )}
        {activeSidebar === 'git' && (
            <SourceControl 
                files={files} 
                commits={commits} 
                onCommit={handleGitCommit}
                onCheckout={handleGitCheckout}
            />
        )}
        {activeSidebar === 'deploy' && (
            <Deployment files={files} />
        )}

        {/* Editor Pane */}
        <div className={`flex flex-col border-r border-gray-800 transition-all duration-300 ${
            layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-0 overflow-hidden'
        }`}>
          {/* Editor Header */}
          <div className="h-9 bg-[#1e1e1e] border-b border-gray-800 flex items-center px-4 text-xs">
             <Code2 size={14} className="text-blue-500 mr-2" />
             <span className="text-gray-300">{activeFileName}</span>

             <div className="ml-auto flex items-center gap-4">
                 <button 
                    onClick={handleFormat} 
                    className="flex items-center gap-1.5 text-gray-500 hover:text-white transition-colors"
                    title="Format Code"
                 >
                     <AlignLeft size={14} />
                     <span className="hidden sm:inline">Format</span>
                 </button>
                 <span className="text-gray-600">{activeFile?.content.length || 0} chars</span>
             </div>
          </div>

          <textarea
            className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed"
            value={activeFile?.content || ''}
            onChange={(e) => updateFileContent(e.target.value)}
            spellCheck={false}
          />
        </div>

        {/* Preview Pane */}
        <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${
             layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'
        }`}>
          <iframe
            key={iframeKey}
            title="Preview"
            srcDoc={getSrcDoc()}
            className="w-full h-full border-none"
            sandbox="allow-scripts allow-modals allow-forms allow-same-origin"
          />
        </div>

        {/* AI Sidebar Overlay */}
        <AIAssistant 
          currentCode={activeFile?.content || ''} 
          isOpen={isAIOpen} 
          onClose={() => setIsAIOpen(false)} 
        />
      </div>

      {/* Console (Fixed at Bottom) */}
      <Console 
        logs={logs} 
        onClear={clearLogs} 
        isOpen={isConsoleOpen} 
        toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} 
        onCommand={handleConsoleCommand}
      />
    </div>
  );
}

export interface Tab {
  id: string;
  title: string;
  type: 'editor' | 'preview' | 'ai';
  content: string;
  active: boolean;
}

export interface LogEntry {
  id: string;
  timestamp: string;
  level: 'info' | 'warn' | 'error' | 'log' | 'command' | 'success';
  message: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  image?: string; // base64
  video?: string; // url
  audio?: string; // base64
  isError?: boolean;
}

export enum LayoutMode {
  SPLIT = 'SPLIT',
  FULL = 'FULL'
}

export type ChatMode = 'standard' | 'thinking' | 'search' | 'maps' | 'fast';

export type AspectRatio = "1:1" | "2:3" | "3:2" | "3:4" | "4:3" | "9:16" | "16:9" | "21:9";
export type ImageSize = "1K" | "2K" | "4K";
export type VideoResolution = "720p" | "1080p";

export interface VirtualFile {
  name: string; // Full path
  content: string;
  language: 'html' | 'css' | 'javascript' | 'json' | 'typescript' | 'markdown' | 'text';
  type?: 'file' | 'directory';
}

export interface GitCommit {
  id: string;
  message: string;
  timestamp: string;
  files: VirtualFile[]; // Snapshot of files at this commit
}

export type SidebarView = 'explorer' | 'search' | 'git' | 'deploy';

import React from 'react';
import { Files, GitGraph, Rocket, Search } from 'lucide-react';
import { SidebarView } from '../types';

interface ActivityBarProps {
  activeView: SidebarView;
  onViewChange: (view: SidebarView) => void;
  changesCount?: number;
}

const ActivityBar: React.FC<ActivityBarProps> = ({ activeView, onViewChange, changesCount = 0 }) => {
  return (
    <div className="w-12 bg-[#333333] border-r border-gray-900 flex flex-col items-center py-4 gap-4 z-20">
      <button
        onClick={() => onViewChange('explorer')}
        className={`p-2 rounded-lg transition-colors relative ${
          activeView === 'explorer' ? 'text-white bg-white/10' : 'text-gray-500 hover:text-gray-300'
        }`}
        title="Explorer"
      >
        <Files size={24} strokeWidth={1.5} />
      </button>

      <button
        onClick={() => onViewChange('search')}
        className={`p-2 rounded-lg transition-colors relative ${
          activeView === 'search' ? 'text-white bg-white/10' : 'text-gray-500 hover:text-gray-300'
        }`}
        title="Search"
      >
        <Search size={24} strokeWidth={1.5} />
      </button>

      <button
        onClick={() => onViewChange('git')}
        className={`p-2 rounded-lg transition-colors relative ${
          activeView === 'git' ? 'text-white bg-white/10' : 'text-gray-500 hover:text-gray-300'
        }`}
        title="Source Control"
      >
        <GitGraph size={24} strokeWidth={1.5} />
        {changesCount > 0 && (
          <div className="absolute -top-1 -right-1 w-4 h-4 bg-blue-600 text-[10px] text-white flex items-center justify-center rounded-full font-bold">
            {changesCount}
          </div>
        )}
      </button>

      <button
        onClick={() => onViewChange('deploy')}
        className={`p-2 rounded-lg transition-colors relative ${
          activeView === 'deploy' ? 'text-white bg-white/10' : 'text-gray-500 hover:text-gray-300'
        }`}
        title="Deploy"
      >
        <Rocket size={24} strokeWidth={1.5} />
      </button>
    </div>
  );
};

export default ActivityBar;

import React, { useState, useMemo } from 'react';
import { Search as SearchIcon, File, ChevronRight, ChevronDown, ListFilter } from 'lucide-react';
import { VirtualFile } from '../types';

interface SearchProps {
  files: VirtualFile[];
  onSelect: (fileName: string) => void;
}

interface SearchResult {
  file: VirtualFile;
  matches: { line: number; text: string }[];
}

const Search: React.FC<SearchProps> = ({ files, onSelect }) => {
  const [query, setQuery] = useState('');
  const [expandedFiles, setExpandedFiles] = useState<Record<string, boolean>>({});

  const toggleExpand = (fileName: string) => {
    setExpandedFiles(prev => ({ ...prev, [fileName]: !prev[fileName] }));
  };

  const results: SearchResult[] = useMemo(() => {
    if (!query.trim()) return [];

    const term = query.toLowerCase();
    const searchResults: SearchResult[] = [];

    files.forEach(file => {
      if (file.type === 'directory') return;

      const matches: { line: number; text: string }[] = [];

      // Check filename
      if (file.name.toLowerCase().includes(term)) {
          // If filename matches, we might just show the file, but let's also look for content
      }

      // Check content
      const lines = file.content.split('\n');
      lines.forEach((line, idx) => {
        if (line.toLowerCase().includes(term)) {
          matches.push({
            line: idx + 1,
            text: line.trim()
          });
        }
      });

      if (matches.length > 0 || file.name.toLowerCase().includes(term)) {
        searchResults.push({ file, matches });
      }
    });

    return searchResults;
  }, [files, query]);

  // Auto-expand results when searching
  useMemo(() => {
      if(query) {
          const newExpanded: Record<string, boolean> = {};
          results.forEach(r => newExpanded[r.file.name] = true);
          setExpandedFiles(newExpanded);
      }
  }, [results.length]); // Only re-expand if result count changes significantly (simple heuristic) or on first search

  return (
    <div className="w-64 bg-browser-toolbar border-r border-gray-700 flex flex-col h-full select-none text-gray-300">
      <div className="h-9 px-3 flex items-center justify-between border-b border-gray-700 bg-[#252526]">
        <div className="flex items-center gap-2 text-xs font-semibold text-gray-400">
          <SearchIcon size={14} />
          <span>SEARCH</span>
        </div>
      </div>

      <div className="p-3">
        <div className="relative mb-4">
            <input 
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className="w-full bg-[#3c3c3c] border border-gray-700 text-white text-xs rounded px-2 py-1.5 pl-8 focus:border-blue-500 outline-none"
                placeholder="Search"
                autoFocus
            />
            <div className="absolute left-2 top-1.5 text-gray-400">
                <SearchIcon size={14} />
            </div>
        </div>

        {query && (
            <div className="text-xs text-gray-500 mb-2 uppercase tracking-wider font-bold">
                {results.length} files found
            </div>
        )}

        <div className="space-y-1 overflow-y-auto custom-scrollbar" style={{maxHeight: 'calc(100vh - 120px)'}}>
            {results.map(result => (
                <div key={result.file.name} className="flex flex-col">
                    <div 
                        className="flex items-center gap-1 hover:bg-white/5 p-1 rounded cursor-pointer group"
                        onClick={() => toggleExpand(result.file.name)}
                    >
                        <span className="text-gray-500">
                            {expandedFiles[result.file.name] ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                        </span>
                        <File size={14} className="text-gray-400" />
                        <span className="text-xs text-gray-300 font-medium truncate flex-1">{result.file.name}</span>
                        <span className="text-[10px] bg-gray-700 text-gray-300 px-1.5 rounded-full">
                            {result.matches.length}
                        </span>
                    </div>

                    {expandedFiles[result.file.name] && (
                        <div className="ml-6 space-y-0.5 mt-0.5">
                            {result.matches.map((match, i) => (
                                <div 
                                    key={i} 
                                    className="text-xs text-gray-400 hover:text-white hover:bg-blue-500/20 px-1 py-0.5 rounded cursor-pointer font-mono truncate flex gap-2"
                                    onClick={() => onSelect(result.file.name)}
                                >
                                    <span className="text-gray-600 w-6 text-right flex-shrink-0">{match.line}:</span>
                                    <span className="truncate">{match.text}</span>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            ))}
            {query && results.length === 0 && (
                <div className="text-xs text-gray-500 text-center mt-4">No results found.</div>
            )}
        </div>
      </div>
    </div>
  );
};

export default Search;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Code2, SplitSquareHorizontal, Maximize2, Sparkles, Layout, AlignLeft } from 'lucide-react';
import { LogEntry, LayoutMode, VirtualFile, GitCommit, SidebarView } from './types';
import Console from './components/Console';
import AddressBar from './components/AddressBar';
import AIAssistant from './components/AIAssistant';
import FileExplorer from './components/FileExplorer';
import SourceControl from './components/SourceControl';
import Deployment from './components/Deployment';
import ActivityBar from './components/ActivityBar';
import Search from './components/Search';

// Prettier Imports
import { format } from "prettier/standalone";
import parserBabel from "prettier/plugins/babel";
import parserEstree from "prettier/plugins/estree";
import parserHtml from "prettier/plugins/html";
import parserPostcss from "prettier/plugins/postcss";
import parserMarkdown from "prettier/plugins/markdown";

// Initial Empty Project
const INITIAL_FILES: VirtualFile[] = [
  {
    name: 'index.html',
    language: 'html',
    type: 'file',
    content: `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>New Project</title>
</head>
<body>

</body>
</html>`
  }
];

export default function App() {
  // Load initial state from localStorage if available
  const [files, setFiles] = useState<VirtualFile[]>(() => {
    try {
      const saved = localStorage.getItem('devbrowser_files');
      return saved ? JSON.parse(saved) : INITIAL_FILES;
    } catch (e) {
      console.error("Failed to load files from storage", e);
      return INITIAL_FILES;
    }
  });

  const [activeFileName, setActiveFileName] = useState(() => {
    return localStorage.getItem('devbrowser_activeFile') || 'index.html';
  });

  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [iframeKey, setIframeKey] = useState(0); 
  const [layoutMode, setLayoutMode] = useState<LayoutMode>(LayoutMode.SPLIT);
  const [isConsoleOpen, setIsConsoleOpen] = useState(true);
  const [isAIOpen, setIsAIOpen] = useState(false);

  // Navigation & Git State
  const [activeSidebar, setActiveSidebar] = useState<SidebarView>('explorer');
  const [commits, setCommits] = useState<GitCommit[]>([]);

  // Save to localStorage whenever files change
  useEffect(() => {
    localStorage.setItem('devbrowser_files', JSON.stringify(files));
  }, [files]);

  // Save active file selection
  useEffect(() => {
    localStorage.setItem('devbrowser_activeFile', activeFileName);
  }, [activeFileName]);

  // Init Git
  useEffect(() => {
    if (commits.length === 0) {
      setCommits([{
        id: 'init',
        message: 'Initial Commit',
        timestamp: new Date().toLocaleTimeString(),
        files: JSON.parse(JSON.stringify(INITIAL_FILES))
      }]);
    }
  }, []);

  const activeFile = files.find(f => f.name === activeFileName) || files[0];

  // Update file content
  const updateFileContent = (newContent: string) => {
    setFiles(prev => prev.map(f => f.name === activeFileName ? { ...f, content: newContent } : f));
  };

  // Format Code Logic
  const handleFormat = async () => {
    if (!activeFile) return;

    try {
      let parser: string | undefined;
      let plugins: any[] = [];

      switch (activeFile.language) {
        case 'javascript':
        case 'typescript':
        case 'json':
          parser = activeFile.language === 'json' ? 'json' : 'babel';
          plugins = [parserBabel, parserEstree];
          break;
        case 'html':
          parser = 'html';
          plugins = [parserHtml, parserBabel, parserPostcss, parserEstree];
          break;
        case 'css':
          parser = 'css';
          plugins = [parserPostcss];
          break;
        case 'markdown':
          parser = 'markdown';
          plugins = [parserMarkdown, parserBabel, parserEstree]; 
          break;
      }

      if (parser) {
        const formatted = await format(activeFile.content, {
          parser,
          plugins,
          printWidth: 80,
          tabWidth: 2,
          semi: true,
          singleQuote: false,
        });
        updateFileContent(formatted);
        setLogs(prev => [...prev, {
            id: Date.now().toString(),
            timestamp: new Date().toLocaleTimeString(),
            level: 'success',
            message: `Formatted ${activeFile.name}`
        }]);
      }
    } catch (e: any) {
        setLogs(prev => [...prev, {
            id: Date.now().toString(),
            timestamp: new Date().toLocaleTimeString(),
            level: 'error',
            message: `Format error: ${e.message}`
        }]);
    }
  };

  // Git Operations
  const handleGitCommit = (message: string) => {
    const newCommit: GitCommit = {
      id: Date.now().toString(),
      message,
      timestamp: new Date().toLocaleTimeString(),
      files: JSON.parse(JSON.stringify(files)) // Deep copy
    };
    setCommits(prev => [newCommit, ...prev]); // Prepend to show latest first
  };

  const handleGitCheckout = (commitId: string) => {
    const commit = commits.find(c => c.id === commitId);
    if (commit) {
      setFiles(JSON.parse(JSON.stringify(commit.files)));
      // If active file is gone, reset to first
      if (!commit.files.find(f => f.name === activeFileName)) {
        setActiveFileName(commit.files[0]?.name || '');
      }
    }
  };

  // Calculate uncommitted changes count for badge
  const uncommittedChangesCount = useMemo(() => {
    const head = commits[0];
    if (!head) return files.filter(f => f.type !== 'directory').length;
    let count = 0;
    // Modified & Added (ignore directories)
    files.filter(f => f.type !== 'directory').forEach(f => {
      const prev = head.files.find(pf => pf.name === f.name);
      if (!prev || prev.content !== f.content) count++;
    });
    // Deleted (ignore directories)
    head.files.filter(f => f.type !== 'directory').forEach(pf => {
      if (!files.find(f => f.name === pf.name)) count++;
    });
    return count;
  }, [files, commits]);

  // File Operations
  const handleCreateFile = (name: string) => {
    if (files.some(f => f.name === name)) return;
    const ext = name.split('.').pop();
    let lang: VirtualFile['language'] = 'text';
    if (ext === 'html') lang = 'html';
    else if (ext === 'css') lang = 'css';
    else if (ext === 'js') lang = 'javascript';
    else if (ext === 'json') lang = 'json';

    setFiles(prev => [...prev, { name, content: '', language: lang, type: 'file' }]);
    setActiveFileName(name);
  };

  const handleCreateFolder = (name: string) => {
    if (files.some(f => f.name === name)) return;
    setFiles(prev => [...prev, { name, content: '', language: 'text', type: 'directory' }]);
  };

  const handleDeleteFile = (name: string) => {
    // Delete file and any children if it's a directory
    const newFiles = files.filter(f => f.name !== name && !f.name.startsWith(name + '/'));
    setFiles(newFiles);
    if (activeFileName === name || activeFileName.startsWith(name + '/')) {
        // Fallback to first available file
        const firstFile = newFiles.find(f => f.type === 'file');
        if (firstFile) setActiveFileName(firstFile.name);
        else setActiveFileName('');
    }
  };

  const handleRenameFile = (oldName: string, newName: string) => {
      if (files.some(f => f.name === newName)) {
          alert("Path already exists");
          return;
      }
      setFiles(prev => prev.map(f => {
          if (f.name === oldName) return { ...f, name: newName };
          if (f.name.startsWith(oldName + '/')) {
              return { ...f, name: f.name.replace(oldName + '/', newName + '/') };
          }
          return f;
      }));

      if (activeFileName === oldName) setActiveFileName(newName);
      else if (activeFileName.startsWith(oldName + '/')) {
          setActiveFileName(activeFileName.replace(oldName + '/', newName + '/'));
      }
  };

  // Handle messages from iframe
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'console') {
        const newLog: LogEntry = {
          id: Date.now().toString() + Math.random(),
          timestamp: new Date().toLocaleTimeString(),
          level: event.data.level,
          message: event.data.message.map((m: any) => 
            typeof m === 'object' ? JSON.stringify(m) : String(m)
          ).join(' ')
        };
        setLogs(prev => [...prev, newLog]);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const runCode = useCallback(() => {
    setLogs([]); 
    setIframeKey(prev => prev + 1);
  }, []);

  const clearLogs = () => setLogs([]);

  // Console Command Handler
  const handleConsoleCommand = (cmd: string) => {
    const args = cmd.trim().split(/\s+/);
    const command = args[0];
    const params = args.slice(1);

    // Log the user's command
    setLogs(prev => [...prev, {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString(),
      level: 'command',
      message: `> ${cmd}`
    }]);

    let output = '';
    let level: LogEntry['level'] = 'info';

    switch(command) {
        case 'help':
            output = 'Available commands: ls, cat <file>, touch <file>, mkdir <folder>, rm <path>, echo <text>, clear, pwd';
            break;
        case 'ls':
            output = files.map(f => `${f.name}${f.type === 'directory' ? '/' : ''}`).join('  ');
            break;
        case 'pwd':
            output = '/';
            break;
        case 'cat':
            if (!params[0]) {
                output = 'Usage: cat <filename>';
                level = 'error';
            } else {
                const f = files.find(file => file.name === params[0] && file.type !== 'directory');
                if (f) output = f.content;
                else {
                    output = `File not found: ${params[0]}`;
                    level = 'error';
                }
            }
            break;
        case 'touch':
            if (!params[0]) {
                output = 'Usage: touch <filename>';
                level = 'error';
            } else if (files.some(f => f.name === params[0])) {
                output = `File already exists: ${params[0]}`;
                level = 'warn';
            } else {
                handleCreateFile(params[0]);
                output = `Created ${params[0]}`;
                level = 'success';
            }
            break;
        case 'mkdir':
            if (!params[0]) {
                output = 'Usage: mkdir <foldername>';
                level = 'error';
            } else if (files.some(f => f.name === params[0])) {
                output = `Directory already exists: ${params[0]}`;
                level = 'warn';
            } else {
                handleCreateFolder(params[0]);
                output = `Created directory ${params[0]}`;
                level = 'success';
            }
            break;
        case 'rm':
            if (!params[0]) {
                output = 'Usage: rm <path>';
                level = 'error';
            } else if (!files.some(f => f.name === params[0])) {
                output = `Path not found: ${params[0]}`;
                level = 'error';
            } else {
                handleDeleteFile(params[0]);
                output = `Removed ${params[0]}`;
                level = 'success';
            }
            break;
        case 'echo':
            output = params.join(' ');
            break;
        case 'clear':
            setLogs([]);
            return;
        default:
            output = `Command not found: ${command}`;
            level = 'error';
    }

    if (output) {
        setLogs(prev => [...prev, {
            id: Date.now().toString() + 'r',
            timestamp: new Date().toLocaleTimeString(),
            level,
            message: output
        }]);
    }
  };

  // Bundler Logic: Inject CSS/JS into HTML
  const getSrcDoc = () => {
    const entryPoint = files.find(f => f.name === 'index.html');
    if (!entryPoint) return "<html><body><h1>No index.html found</h1></body></html>";

    let html = entryPoint.content;

    // Simple bundler handles basic paths by matching exact names in VirtualFS
    html = html.replace(/<link\s+rel="stylesheet"\s+href="(.+?)"\s*\/?>/g, (match, href) => {
      const cssFile = files.find(f => f.name === href); // href matches 'styles/main.css'
      return cssFile ? `<style>${cssFile.content}</style>` : match;
    });

    html = html.replace(/<script\s+src="(.+?)"><\/script>/g, (match, src) => {
      const jsFile = files.find(f => f.name === src); // src matches 'scripts/app.js'
      return jsFile ? `<script>${jsFile.content}</script>` : match;
    });

    const consoleHijack = `
      <script>
        const originalLog = console.log;
        const originalWarn = console.warn;
        const originalError = console.error;
        const originalInfo = console.info;

        function sendToParent(level, args) {
          try {
            window.parent.postMessage({
              type: 'console',
              level: level,
              message: Array.from(args)
            }, '*');
          } catch(e) {}
        }

        console.log = function(...args) { originalLog.apply(console, args); sendToParent('log', args); };
        console.warn = function(...args) { originalWarn.apply(console, args); sendToParent('warn', args); };
        console.error = function(...args) { originalError.apply(console, args); sendToParent('error', args); };
        console.info = function(...args) { originalInfo.apply(console, args); sendToParent('info', args); };

        window.onerror = function(msg, url, line) {
           sendToParent('error', [msg + " (Line " + line + ")"]);
        }
      </script>
    `;

    if (html.includes('</body>')) {
      return html.replace('</body>', `${consoleHijack}</body>`);
    }
    return html + consoleHijack;
  };

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Bar */}
      <div className="flex flex-col">
        {/* Tab Bar / Header */}
        <div className="flex items-center h-10 px-2 bg-browser-bg border-b border-browser-toolbar select-none justify-between">
           <div className="flex items-center gap-2">
              <div className="flex gap-1.5 px-3">
                 <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
              </div>
              <span className="text-xs font-semibold text-gray-500 ml-2">DevBrowser OS</span>
           </div>

           <div className="flex items-center gap-2">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className="p-1.5 hover:bg-white/10 rounded text-gray-400 hover:text-white transition"
                 title="Toggle Split View"
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={16} /> : <SplitSquareHorizontal size={16} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1.5 rounded transition-colors ${isAIOpen ? 'text-browser-accent bg-blue-500/10' : 'text-gray-400 hover:text-white hover:bg-white/10'}`}
                 title="Toggle AI Assistant"
              >
                <Sparkles size={16} />
              </button>
           </div>
        </div>

        {/* Address Bar */}
        <AddressBar url={`localhost:3000/${activeFileName}`} onRefresh={runCode} />
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Activity Bar (Leftmost) */}
        <ActivityBar 
            activeView={activeSidebar} 
            onViewChange={setActiveSidebar} 
            changesCount={uncommittedChangesCount}
        />

        {/* Sidebar Content (Dynamic) */}
        {activeSidebar === 'explorer' && (
            <FileExplorer 
              files={files} 
              activeFileName={activeFileName} 
              onSelect={setActiveFileName} 
              onCreate={handleCreateFile}
              onCreateFolder={handleCreateFolder}
              onDelete={(name) => { if(confirm(`Delete ${name}?`)) handleDeleteFile(name); }}
              onRename={handleRenameFile}
            />
        )}
        {activeSidebar === 'search' && (
            <Search 
              files={files} 
              onSelect={setActiveFileName} 
            />
        )}
        {activeSidebar === 'git' && (
            <SourceControl 
                files={files} 
                commits={commits} 
                onCommit={handleGitCommit}
                onCheckout={handleGitCheckout}
            />
        )}
        {activeSidebar === 'deploy' && (
            <Deployment files={files} />
        )}

        {/* Editor Pane */}
        <div className={`flex flex-col border-r border-gray-800 transition-all duration-300 ${
            layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-0 overflow-hidden'
        }`}>
          {/* Editor Header */}
          <div className="h-9 bg-[#1e1e1e] border-b border-gray-800 flex items-center px-4 text-xs">
             <Code2 size={14} className="text-blue-500 mr-2" />
             <span className="text-gray-300">{activeFileName}</span>

             <div className="ml-auto flex items-center gap-4">
                 <button 
                    onClick={handleFormat} 
                    className="flex items-center gap-1.5 text-gray-500 hover:text-white transition-colors"
                    title="Format Code"
                 >
                     <AlignLeft size={14} />
                     <span className="hidden sm:inline">Format</span>
                 </button>
                 <span className="text-gray-600">{activeFile?.content.length || 0} chars</span>
             </div>
          </div>

          <textarea
            className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed"
            value={activeFile?.content || ''}
            onChange={(e) => updateFileContent(e.target.value)}
            spellCheck={false}
          />
        </div>

        {/* Preview Pane */}
        <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${
             layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'
        }`}>
          <iframe
            key={iframeKey}
            title="Preview"
            srcDoc={getSrcDoc()}
            className="w-full h-full border-none"
            sandbox="allow-scripts allow-modals allow-forms allow-same-origin"
          />
        </div>

        {/* AI Sidebar Overlay */}
        <AIAssistant 
          currentCode={activeFile?.content || ''} 
          isOpen={isAIOpen} 
          onClose={() => setIsAIOpen(false)} 
        />
      </div>

      {/* Console (Fixed at Bottom) */}
      <Console 
        logs={logs} 
        onClear={clearLogs} 
        isOpen={isConsoleOpen} 
        toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} 
        onCommand={handleConsoleCommand}
      />
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, X, Loader2, Image as ImageIcon, Video, Mic, Paperclip, Trash2, Copy, Terminal, Zap, Search, MapPin, Brain } from 'lucide-react';
import { chatWithGemini, generateImage, generateVideo, connectLive, transcribeAudio } from '../services/geminiService';
import { ChatMessage, ChatMode, AspectRatio, ImageSize } from '../types';

interface AIAssistantProps {
  currentCode: string;
  isOpen: boolean;
  onClose: () => void;
}

// Simple formatter for code blocks
const MessageContent: React.FC<{ text: string }> = ({ text }) => {
  const parts = text.split(/(```[\s\S]*?```)/g);
  return (
    <div className="text-sm leading-relaxed space-y-2">
      {parts.map((part, i) => {
        if (part.startsWith('```') && part.endsWith('```')) {
          // Extract language if present
          const match = part.match(/^```(\w*)\n/);
          const lang = match ? match[1] : '';
          const content = part.replace(/^```\w*\n?/, '').replace(/```$/, '');
          return (
            <div key={i} className="my-2 bg-[#1e1e1e] border border-gray-700 rounded-md overflow-hidden shadow-sm group">
               <div className="bg-[#252526] px-3 py-1.5 text-xs text-gray-400 flex justify-between items-center border-b border-gray-700">
                  <span className="font-mono uppercase text-[10px]">{lang || 'CODE'}</span>
                  <button 
                    onClick={() => navigator.clipboard.writeText(content)}
                    className="flex items-center gap-1 hover:text-white transition-colors"
                    title="Copy code"
                  >
                    <Copy size={10} />
                    <span>Copy</span>
                  </button>
               </div>
               <pre className="p-3 overflow-x-auto text-xs font-mono text-blue-300 custom-scrollbar">
                 {content}
               </pre>
            </div>
          );
        }
        // Basic bold parsing (**text**)
        const textParts = part.split(/(\*\*.*?\*\*)/g);
        return (
            <span key={i}>
                {textParts.map((t, j) => {
                    if (t.startsWith('**') && t.endsWith('**')) {
                        return <strong key={j} className="text-blue-200 font-semibold">{t.slice(2, -2)}</strong>;
                    }
                    return t;
                })}
            </span>
        );
      })}
    </div>
  );
};

const AIAssistant: React.FC<AIAssistantProps> = ({ currentCode, isOpen, onClose }) => {
  const [activeTab, setActiveTab] = useState<'chat' | 'create' | 'live'>('chat');

  // Chat State
  const [messages, setMessages] = useState<ChatMessage[]>([{ id: '1', role: 'model', text: 'Hi! I am your Gemini Copilot. How can I help with your code today?' }]);
  const [input, setInput] = useState('');
  const [chatMode, setChatMode] = useState<ChatMode>('standard');
  const [attachment, setAttachment] = useState<{base64: string, mimeType: string} | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // Create State
  const [createType, setCreateType] = useState<'image' | 'video'>('image');
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('1:1');
  const [imageSize, setImageSize] = useState<ImageSize>('1K');
  const [editImage, setEditImage] = useState<string | null>(null);
  const [generatedMedia, setGeneratedMedia] = useState<{type: 'image'|'video', url: string} | null>(null);

  // Live State
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const liveSessionRef = useRef<any>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, activeTab]);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
        textareaRef.current.style.height = 'auto';
        textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }, [input]);

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        setAttachment({ base64, mimeType: file.type });
        if (activeTab === 'create' && createType === 'image') {
            setEditImage(base64);
        }
        // Reset input
        if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsDataURL(file);
  };

  const handleSendMessage = async () => {
    if ((!input.trim() && !attachment) || isProcessing) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      image: attachment?.mimeType.startsWith('image') ? attachment.base64 : undefined
    };
    setMessages(p => [...p, userMsg]);
    setInput('');
    setAttachment(null);
    setIsProcessing(true);

    try {
      if (attachment?.mimeType.startsWith('audio')) {
         const transcript = await transcribeAudio(attachment.base64);
         setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: `Transcription: ${transcript}` }]);
      } else {
         const response = await chatWithGemini(userMsg.text, chatMode, attachment ? [attachment] : [], currentCode);
         setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: response }]);
      }
    } catch (e: any) {
       setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: "Error: " + e.message, isError: true }]);
    } finally {
       setIsProcessing(false);
