import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Code2, SplitSquareHorizontal, Maximize2, Sparkles, Layout, AlignLeft } from 'lucide-react';
import { LogEntry, LayoutMode, VirtualFile, GitCommit, SidebarView } from './types';
import Console from './components/Console';
import AddressBar from './components/AddressBar';
import AIAssistant from './components/AIAssistant';
import FileExplorer from './components/FileExplorer';
import SourceControl from './components/SourceControl';
import Deployment from './components/Deployment';
import ActivityBar from './components/ActivityBar';
import Search from './components/Search';

// Prettier Imports
import { format } from "prettier/standalone";
import parserBabel from "prettier/plugins/babel";
import parserEstree from "prettier/plugins/estree";
import parserHtml from "prettier/plugins/html";
import parserPostcss from "prettier/plugins/postcss";
import parserMarkdown from "prettier/plugins/markdown";

// Initial Empty Project
const INITIAL_FILES: VirtualFile[] = [
  {
    name: 'index.html',
    language: 'html',
    type: 'file',
    content: `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>New Project</title>
</head>
<body>
  <div class="container">
    <h1>Hello, World!</h1>
    <p>Start editing to see magic happen.</p>
  </div>
  <style>
    body { font-family: system-ui, sans-serif; padding: 2rem; background: #f0f0f0; }
    .container { background: white; padding: 2rem; border-radius: 8px; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
  </style>
</body>
</html>`
  }
];

export default function App() {
  // Load initial state from localStorage if available
  const [files, setFiles] = useState<VirtualFile[]>(() => {
    try {
      const saved = localStorage.getItem('devbrowser_files');
      return saved ? JSON.parse(saved) : INITIAL_FILES;
    } catch (e) {
      console.error("Failed to load files from storage", e);
      return INITIAL_FILES;
    }
  });

  const [activeFileName, setActiveFileName] = useState(() => {
    return localStorage.getItem('devbrowser_activeFile') || 'index.html';
  });

  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [iframeKey, setIframeKey] = useState(0); 
  const [layoutMode, setLayoutMode] = useState<LayoutMode>(LayoutMode.SPLIT);
  const [isConsoleOpen, setIsConsoleOpen] = useState(true);
  const [isAIOpen, setIsAIOpen] = useState(false);

  // Navigation & Git State
  const [activeSidebar, setActiveSidebar] = useState<SidebarView>('explorer');
  const [commits, setCommits] = useState<GitCommit[]>([]);

  // Save to localStorage whenever files change
  useEffect(() => {
    localStorage.setItem('devbrowser_files', JSON.stringify(files));
  }, [files]);

  // Save active file selection
  useEffect(() => {
    localStorage.setItem('devbrowser_activeFile', activeFileName);
  }, [activeFileName]);

  // Init Git
  useEffect(() => {
    if (commits.length === 0) {
      setCommits([{
        id: 'init',
        message: 'Initial Commit',
        timestamp: new Date().toLocaleTimeString(),
        files: JSON.parse(JSON.stringify(INITIAL_FILES))
      }]);
    }
  }, []);

  const activeFile = files.find(f => f.name === activeFileName) || files[0];

  // Determine which file is being previewed (Active HTML or fallback to index.html)
  const previewFile = useMemo(() => {
      if (activeFile?.language === 'html') return activeFile;
      return files.find(f => f.name === 'index.html');
  }, [activeFile, files]);

  // Update file content
  const updateFileContent = (newContent: string) => {
    setFiles(prev => prev.map(f => f.name === activeFileName ? { ...f, content: newContent } : f));
  };

  // Format Code Logic
  const handleFormat = async () => {
    if (!activeFile) return;

    try {
      let parser: string | undefined;
      let plugins: any[] = [];

      switch (activeFile.language) {
        case 'javascript':
        case 'typescript':
        case 'json':
          parser = activeFile.language === 'json' ? 'json' : 'babel';
          plugins = [parserBabel, parserEstree];
          break;
        case 'html':
          parser = 'html';
          plugins = [parserHtml, parserBabel, parserPostcss, parserEstree];
          break;
        case 'css':
          parser = 'css';
          plugins = [parserPostcss];
          break;
        case 'markdown':
          parser = 'markdown';
          plugins = [parserMarkdown, parserBabel, parserEstree]; 
          break;
      }

      if (parser) {
        const formatted = await format(activeFile.content, {
          parser,
          plugins,
          printWidth: 80,
          tabWidth: 2,
          semi: true,
          singleQuote: false,
        });
        updateFileContent(formatted);
        setLogs(prev => [...prev, {
            id: Date.now().toString(),
            timestamp: new Date().toLocaleTimeString(),
            level: 'success',
            message: `Formatted ${activeFile.name}`
        }]);
      }
    } catch (e: any) {
        setLogs(prev => [...prev, {
            id: Date.now().toString(),
            timestamp: new Date().toLocaleTimeString(),
            level: 'error',
            message: `Format error: ${e.message}`
        }]);
    }
  };

  // Git Operations
  const handleGitCommit = (message: string) => {
    const newCommit: GitCommit = {
      id: Date.now().toString(),
      message,
      timestamp: new Date().toLocaleTimeString(),
      files: JSON.parse(JSON.stringify(files)) // Deep copy
    };
    setCommits(prev => [newCommit, ...prev]); // Prepend to show latest first
  };

  const handleGitCheckout = (commitId: string) => {
    const commit = commits.find(c => c.id === commitId);
    if (commit) {
      setFiles(JSON.parse(JSON.stringify(commit.files)));
      // If active file is gone, reset to first
      if (!commit.files.find(f => f.name === activeFileName)) {
        setActiveFileName(commit.files[0]?.name || '');
      }
    }
  };

  // Calculate uncommitted changes count for badge
  const uncommittedChangesCount = useMemo(() => {
    const head = commits[0];
    if (!head) return files.filter(f => f.type !== 'directory').length;
    let count = 0;
    // Modified & Added (ignore directories)
    files.filter(f => f.type !== 'directory').forEach(f => {
      const prev = head.files.find(pf => pf.name === f.name);
      if (!prev || prev.content !== f.content) count++;
    });
    // Deleted (ignore directories)
    head.files.filter(f => f.type !== 'directory').forEach(pf => {
      if (!files.find(f => f.name === pf.name)) count++;
    });
    return count;
  }, [files, commits]);

  // File Operations
  const handleCreateFile = (name: string) => {
    if (files.some(f => f.name === name)) return;
    const ext = name.split('.').pop();
    let lang: VirtualFile['language'] = 'text';
    if (ext === 'html') lang = 'html';
    else if (ext === 'css') lang = 'css';
    else if (ext === 'js') lang = 'javascript';
    else if (ext === 'json') lang = 'json';

    setFiles(prev => [...prev, { name, content: '', language: lang, type: 'file' }]);
    setActiveFileName(name);
  };

  const handleCreateFolder = (name: string) => {
    if (files.some(f => f.name === name)) return;
    setFiles(prev => [...prev, { name, content: '', language: 'text', type: 'directory' }]);
  };

  const handleDeleteFile = (name: string) => {
    // Delete file and any children if it's a directory
    const newFiles = files.filter(f => f.name !== name && !f.name.startsWith(name + '/'));
    setFiles(newFiles);
    if (activeFileName === name || activeFileName.startsWith(name + '/')) {
        // Fallback to first available file
        const firstFile = newFiles.find(f => f.type === 'file');
        if (firstFile) setActiveFileName(firstFile.name);
        else setActiveFileName('');
    }
  };

  const handleRenameFile = (oldName: string, newName: string) => {
      if (files.some(f => f.name === newName)) {
          alert("Path already exists");
          return;
      }
      setFiles(prev => prev.map(f => {
          if (f.name === oldName) return { ...f, name: newName };
          if (f.name.startsWith(oldName + '/')) {
              return { ...f, name: f.name.replace(oldName + '/', newName + '/') };
          }
          return f;
      }));

      if (activeFileName === oldName) setActiveFileName(newName);
      else if (activeFileName.startsWith(oldName + '/')) {
          setActiveFileName(activeFileName.replace(oldName + '/', newName + '/'));
      }
  };

  // Handle messages from iframe
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'console') {
        const newLog: LogEntry = {
          id: Date.now().toString() + Math.random(),
          timestamp: new Date().toLocaleTimeString(),
          level: event.data.level,
          message: event.data.message.map((m: any) => 
            typeof m === 'object' ? JSON.stringify(m) : String(m)
          ).join(' ')
        };
        setLogs(prev => [...prev, newLog]);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const runCode = useCallback(() => {
    setLogs([]); 
    setIframeKey(prev => prev + 1);
  }, []);

  const clearLogs = () => setLogs([]);

  // Console Command Handler
  const handleConsoleCommand = (cmd: string) => {
    const args = cmd.trim().split(/\s+/);
    const command = args[0];
    const params = args.slice(1);

    // Log the user's command
    setLogs(prev => [...prev, {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString(),
      level: 'command',
      message: `> ${cmd}`
    }]);

    let output = '';
    let level: LogEntry['level'] = 'info';

    switch(command) {
        case 'help':
            output = 'Available commands: ls, cat <file>, touch <file>, mkdir <folder>, rm <path>, echo <text>, clear, pwd';
            break;
        case 'ls':
            output = files.map(f => `${f.name}${f.type === 'directory' ? '/' : ''}`).join('  ');
            break;
        case 'pwd':
            output = '/';
            break;
        case 'cat':
            if (!params[0]) {
                output = 'Usage: cat <filename>';
                level = 'error';
            } else {
                const f = files.find(file => file.name === params[0] && file.type !== 'directory');
                if (f) output = f.content;
                else {
                    output = `File not found: ${params[0]}`;
                    level = 'error';
                }
            }
            break;
        case 'touch':
            if (!params[0]) {
                output = 'Usage: touch <filename>';
                level = 'error';
            } else if (files.some(f => f.name === params[0])) {
                output = `File already exists: ${params[0]}`;
                level = 'warn';
            } else {
                handleCreateFile(params[0]);
                output = `Created ${params[0]}`;
                level = 'success';
            }
            break;
        case 'mkdir':
            if (!params[0]) {
                output = 'Usage: mkdir <foldername>';
                level = 'error';
            } else if (files.some(f => f.name === params[0])) {
                output = `Directory already exists: ${params[0]}`;
                level = 'warn';
            } else {
                handleCreateFolder(params[0]);
                output = `Created directory ${params[0]}`;
                level = 'success';
            }
            break;
        case 'rm':
            if (!params[0]) {
                output = 'Usage: rm <path>';
                level = 'error';
            } else if (!files.some(f => f.name === params[0])) {
                output = `Path not found: ${params[0]}`;
                level = 'error';
            } else {
                handleDeleteFile(params[0]);
                output = `Removed ${params[0]}`;
                level = 'success';
            }
            break;
        case 'echo':
            output = params.join(' ');
            break;
        case 'clear':
            setLogs([]);
            return;
        default:
            output = `Command not found: ${command}`;
            level = 'error';
    }

    if (output) {
        setLogs(prev => [...prev, {
            id: Date.now().toString() + 'r',
            timestamp: new Date().toLocaleTimeString(),
            level,
            message: output
        }]);
    }
  };

  // Bundler Logic: Inject CSS/JS into HTML with path resolution
  const getSrcDoc = () => {
    if (!previewFile) return "<html><body style='font-family: sans-serif; padding: 2rem; color: #888; background: #fafafa;'><h1>No HTML file found</h1><p>Create an <code>index.html</code> file to see a preview.</p></body></html>";

    let html = previewFile.content;
    const basePath = previewFile.name; // e.g. "pages/about.html"

    // Helper to resolve paths like "../style.css" relative to "pages/about.html"
    const resolvePath = (relPath: string) => {
        if (relPath.startsWith('http') || relPath.startsWith('//')) return null; // External
        if (relPath.startsWith('/')) return relPath.slice(1); // Absolute

        const stack = basePath.split('/');
        stack.pop(); // Remove filename, leave dir

        const parts = relPath.split('/');
        for (const part of parts) {
            if (part === '.') continue;
            if (part === '..') {
                if (stack.length > 0) stack.pop();
            } else {
                stack.push(part);
            }
        }
        return stack.join('/');
    };

    // Replace <link rel="stylesheet"> with inline styles
    html = html.replace(/<link\s+[^>]*rel="stylesheet"[^>]*>/g, (match) => {
      const hrefMatch = match.match(/href="([^"]+)"/);
      if (!hrefMatch) return match;

      const href = hrefMatch[1];
      const resolvedPath = resolvePath(href);
      if (!resolvedPath) return match; // Leave external links alone

      const cssFile = files.find(f => f.name === resolvedPath);
      return cssFile ? `<style>/* ${resolvedPath} */\n${cssFile.content}</style>` : match;
    });

    // Replace <script src="..."> with inline scripts
    html = html.replace(/<script\s+[^>]*src="([^"]+)"[^>]*><\/script>/g, (match, src) => {
      const resolvedPath = resolvePath(src);
      if (!resolvedPath) return match;

      const jsFile = files.find(f => f.name === resolvedPath);
      return jsFile ? `<script>/* ${resolvedPath} */\n${jsFile.content}</script>` : match;
    });

    const consoleHijack = `
      <script>
        const originalLog = console.log;
        const originalWarn = console.warn;
        const originalError = console.error;
        const originalInfo = console.info;

        function sendToParent(level, args) {
          try {
            window.parent.postMessage({
              type: 'console',
              level: level,
              message: Array.from(args)
            }, '*');
          } catch(e) {}
        }

        console.log = function(...args) { originalLog.apply(console, args); sendToParent('log', args); };
        console.warn = function(...args) { originalWarn.apply(console, args); sendToParent('warn', args); };
        console.error = function(...args) { originalError.apply(console, args); sendToParent('error', args); };
        console.info = function(...args) { originalInfo.apply(console, args); sendToParent('info', args); };

        window.onerror = function(msg, url, line) {
           sendToParent('error', [msg + " (Line " + line + ")"]);
        }
      </script>
    `;

    if (html.includes('</body>')) {
      return html.replace('</body>', `${consoleHijack}</body>`);
    }
    return html + consoleHijack;
  };

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Bar */}
      <div className="flex flex-col">
        {/* Tab Bar / Header */}
        <div className="flex items-center h-10 px-2 bg-browser-bg border-b border-browser-toolbar select-none justify-between">
           <div className="flex items-center gap-2">
              <div className="flex gap-1.5 px-3">
                 <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
              </div>
              <span className="text-xs font-semibold text-gray-500 ml-2">DevBrowser OS</span>
           </div>

           <div className="flex items-center gap-2">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className="p-1.5 hover:bg-white/10 rounded text-gray-400 hover:text-white transition"
                 title="Toggle Split View"
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={16} /> : <SplitSquareHorizontal size={16} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1.5 rounded transition-colors ${isAIOpen ? 'text-browser-accent bg-blue-500/10' : 'text-gray-400 hover:text-white hover:bg-white/10'}`}
                 title="Toggle AI Assistant"
              >
                <Sparkles size={16} />
              </button>
           </div>
        </div>

        {/* Address Bar */}
        <AddressBar url={`localhost:3000/${previewFile ? previewFile.name : 'index.html'}`} onRefresh={runCode} />
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Activity Bar (Leftmost) */}
        <ActivityBar 
            activeView={activeSidebar} 
            onViewChange={setActiveSidebar} 
            changesCount={uncommittedChangesCount}
        />

        {/* Sidebar Content (Dynamic) */}
        {activeSidebar === 'explorer' && (
            <FileExplorer 
              files={files} 
              activeFileName={activeFileName} 
              onSelect={setActiveFileName} 
              onCreate={handleCreateFile}
              onCreateFolder={handleCreateFolder}
              onDelete={(name) => { if(confirm(`Delete ${name}?`)) handleDeleteFile(name); }}
              onRename={handleRenameFile}
            />
        )}
        {activeSidebar === 'search' && (
            <Search 
              files={files} 
              onSelect={setActiveFileName} 
            />
        )}
        {activeSidebar === 'git' && (
            <SourceControl 
                files={files} 
                commits={commits} 
                onCommit={handleGitCommit}
                onCheckout={handleGitCheckout}
            />
        )}
        {activeSidebar === 'deploy' && (
            <Deployment files={files} />
        )}

        {/* Editor Pane */}
        <div className={`flex flex-col border-r border-gray-800 transition-all duration-300 ${
            layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-0 overflow-hidden'
        }`}>
          {/* Editor Header */}
          <div className="h-9 bg-[#1e1e1e] border-b border-gray-800 flex items-center px-4 text-xs">
             <Code2 size={14} className="text-blue-500 mr-2" />
             <span className="text-gray-300">{activeFileName}</span>

             <div className="ml-auto flex items-center gap-4">
                 <button 
                    onClick={handleFormat} 
                    className="flex items-center gap-1.5 text-gray-500 hover:text-white transition-colors"
                    title="Format Code"
                 >
                     <AlignLeft size={14} />
                     <span className="hidden sm:inline">Format</span>
                 </button>
                 <span className="text-gray-600">{activeFile?.content.length || 0} chars</span>
             </div>
          </div>

          <textarea
            className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed"
            value={activeFile?.content || ''}
            onChange={(e) => updateFileContent(e.target.value)}
            spellCheck={false}
          />
        </div>

        {/* Preview Pane */}
        <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${
             layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'
        }`}>
          <iframe
            key={iframeKey}
            title="Preview"
            srcDoc={getSrcDoc()}
            className="w-full h-full border-none"
            sandbox="allow-scripts allow-modals allow-forms allow-same-origin"
          />
        </div>

        {/* AI Sidebar Overlay */}
        <AIAssistant 
          currentCode={activeFile?.content || ''} 
          isOpen={isAIOpen} 
          onClose={() => setIsAIOpen(false)} 
        />
      </div>

      {/* Console (Fixed at Bottom) */}
      <Console 
        logs={logs} 
        onClear={clearLogs} 
        isOpen={isConsoleOpen} 
        toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} 
        onCommand={handleConsoleCommand}
      />
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, X, Loader2, Image as ImageIcon, Video, Mic, Paperclip, Trash2, Copy, Terminal, Zap, Search, MapPin, Brain } from 'lucide-react';
import { chatWithGemini, generateImage, generateVideo, connectLive, transcribeAudio } from '../services/geminiService';
import { ChatMessage, ChatMode, AspectRatio, ImageSize } from '../types';

interface AIAssistantProps {
  currentCode: string;
  isOpen: boolean;
  onClose: () => void;
}

// Simple formatter for code blocks
const MessageContent: React.FC<{ text: string }> = ({ text }) => {
  const parts = text.split(/(```[\s\S]*?```)/g);
  return (
    <div className="text-sm leading-relaxed space-y-2">
      {parts.map((part, i) => {
        if (part.startsWith('```') && part.endsWith('```')) {
          // Extract language if present
          const match = part.match(/^```(\w*)\n/);
          const lang = match ? match[1] : '';
          const content = part.replace(/^```\w*\n?/, '').replace(/```$/, '');
          return (
            <div key={i} className="my-2 bg-[#1e1e1e] border border-gray-700 rounded-md overflow-hidden shadow-sm group">
               <div className="bg-[#252526] px-3 py-1.5 text-xs text-gray-400 flex justify-between items-center border-b border-gray-700">
                  <span className="font-mono uppercase text-[10px]">{lang || 'CODE'}</span>
                  <button 
                    onClick={() => navigator.clipboard.writeText(content)}
                    className="flex items-center gap-1 hover:text-white transition-colors"
                    title="Copy code"
                  >
                    <Copy size={10} />
                    <span>Copy</span>
                  </button>
               </div>
               <pre className="p-3 overflow-x-auto text-xs font-mono text-blue-300 custom-scrollbar">
                 {content}
               </pre>
            </div>
          );
        }
        // Basic bold parsing (**text**)
        const textParts = part.split(/(\*\*.*?\*\*)/g);
        return (
            <span key={i}>
                {textParts.map((t, j) => {
                    if (t.startsWith('**') && t.endsWith('**')) {
                        return <strong key={j} className="text-blue-200 font-semibold">{t.slice(2, -2)}</strong>;
                    }
                    return t;
                })}
            </span>
        );
      })}
    </div>
  );
};

const AIAssistant: React.FC<AIAssistantProps> = ({ currentCode, isOpen, onClose }) => {
  const [activeTab, setActiveTab] = useState<'chat' | 'create' | 'live'>('chat');

  // Chat State
  const [messages, setMessages] = useState<ChatMessage[]>([{ id: '1', role: 'model', text: 'Hi! I am your Gemini Copilot. How can I help with your code today?' }]);
  const [input, setInput] = useState('');
  const [chatMode, setChatMode] = useState<ChatMode>('standard');
  const [attachment, setAttachment] = useState<{base64: string, mimeType: string} | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);

  // Create State
  const [createType, setCreateType] = useState<'image' | 'video'>('image');
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('1:1');
  const [imageSize, setImageSize] = useState<ImageSize>('1K');
  const [editImage, setEditImage] = useState<string | null>(null);
  const [generatedMedia, setGeneratedMedia] = useState<{type: 'image'|'video', url: string} | null>(null);

  // Live State
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const liveSessionRef = useRef<any>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, activeTab]);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
        textareaRef.current.style.height = 'auto';
        textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }, [input]);

  const processFile = (file: File) => {
      if (!file) return;

      const reader = new FileReader();
      reader.onload = () => {
          const base64 = (reader.result as string).split(',')[1];
          if (activeTab === 'create' && createType === 'image') {
              setEditImage(base64);
          } else {
              setAttachment({ base64, mimeType: file.type });
          }
          if (fileInputRef.current) fileInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) processFile(file);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file && (file.type.startsWith('image/') || file.type.startsWith('audio/'))) {
        processFile(file);
    }
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    const items = e.clipboardData.items;
    for (const item of items) {
        if (item.type.indexOf('image') !== -1) {
            e.preventDefault();
            const file = item.getAsFile();
            if (file) processFile(file);
            return;
        }
    }
  };

  const handleSendMessage = async () => {
    if ((!input.trim() && !attachment) || isProcessing) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      image: attachment?.mimeType.startsWith('image') ? attachment.base64 : undefined
    };
    setMessages(p => [...p, userMsg]);
    setInput('');
    setAttachment(null);
    setIsProcessing(true);

    try {
      if (attachment?.mimeType.startsWith('audio')) {
         const transcript = await transcribeAudio(attachment.base64);
         setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: `Transcription: ${transcript}` }]);
      } else {
         const response = await chatWithGemini(userMsg.text, chatMode, attachment ? [attachment] : [], currentCode);
         setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: response }]);
      }
    } catch (e: any) {
       setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: "Error: " + e.message, isError: true }]);
    } finally {
       setIsProcessing(false);
    }
  };

  const handleCreate = async () => {
      if (!prompt.trim()) return;
      setIsProcessing(true);
      setGeneratedMedia(null);
      try {
          if (createType === 'image') {
              const b64 = await generateImage(prompt, { aspectRatio, imageSize, sourceImage: editImage || undefined });
              setGeneratedMedia({ type: 'image', url: `data:image/png;base64,${b64}` });
          } else {
              const url = await generateVideo(prompt, { aspectRatio });
              setGeneratedMedia({ type: 'video', url });
          }
      } catch (e: any) {
          setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: "Generation Error: " + e.message, isError: true }]);
          setActiveTab('chat');
      } finally {
          setIsProcessing(false);
      }
  };

  const toggleLive = async () => {
      if (isLiveConnected) {
          liveSessionRef.current?.disconnect();
          setIsLiveConnected(false);
      } else {
          try {
              liveSessionRef.current = await connectLive(
                  (audioData) => { /* Audio handling handled in service */ },
                  () => setIsLiveConnected(false)
              );
              setIsLiveConnected(true);
          } catch (e) {
              console.error(e);
              alert("Failed to connect. Ensure permissions are granted.");
          }
      }
  };

  if (!isOpen) return null;

  return (
    <div className="w-96 h-full bg-[#1e1e1e] border-l border-gray-700 flex flex-col shadow-2xl absolute right-0 top-0 z-30 font-sans text-gray-300 transition-transform duration-300 ease-in-out">

      {/* Header */}
      <div className="h-12 border-b border-gray-700 flex items-center justify-between px-4 bg-[#252526] select-none">
        <div className="flex items-center gap-2 font-semibold text-gray-100">
            <Sparkles className="text-blue-500" size={16} />
            <span className="tracking-tight">Gemini OS</span>
        </div>
        <button onClick={onClose} className="hover:text-white transition-colors"><X size={18} /></button>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-gray-700 bg-[#252526] p-1 gap-1">
          {['chat', 'create', 'live'].map((t) => (
              <button 
                key={t}
                onClick={() => setActiveTab(t as any)}
                className={`flex-1 py-1.5 text-xs font-medium rounded capitalize transition-all ${
                    activeTab === t 
                    ? 'bg-blue-600 text-white shadow-sm' 
                    : 'text-gray-400 hover:text-gray-200 hover:bg-white/5'
                }`}
              >
                  {t}
              </button>
          ))}
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-hidden relative flex flex-col bg-[#1e1e1e]">

          {/* --- CHAT TAB --- */}
          {activeTab === 'chat' && (
              <>
                 {/* Chat Messages */}
                 <div className="flex-1 overflow-y-auto p-4 space-y-5 custom-scrollbar" ref={scrollRef}>
                    {messages.map((m, idx) => (
                        <div key={m.id} className={`flex gap-3 ${m.role === 'user' ? 'flex-row-reverse' : ''} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                            <div className={`w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0 shadow-sm ${m.role === 'user' ? 'bg-blue-600 text-white' : 'bg-gradient-to-br from-blue-500/20 to-purple-500/20 text-blue-400 border border-white/5'}`}>
                                {m.role === 'user' ? <User size={16} /> : <Bot size={16} />}
                            </div>
                            <div className={`flex flex-col max-w-[85%] ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                                <div className={`px-4 py-3 rounded-2xl text-sm shadow-sm ${
                                    m.role === 'user' 
                                    ? 'bg-blue-600 text-white rounded-tr-sm' 
                                    : 'bg-[#2a2a2a] border border-gray-700 rounded-tl-sm'
                                }`}>
                                    {m.image && (
                                        <div className="mb-2 rounded-lg overflow-hidden border border-white/10">
                                            <img src={`data:image/png;base64,${m.image}`} alt="attachment" className="max-w-full" />
                                        </div>
                                    )}
                                    <MessageContent text={m.text} />
                                </div>
                                {m.isError && <span className="text-xs text-red-400 mt-1">Failed to send</span>}
                            </div>
                        </div>
                    ))}
                    {isProcessing && (
                        <div className="flex gap-3 animate-pulse">
                             <div className="w-8 h-8 rounded-lg bg-gray-800 flex items-center justify-center">
                                 <Bot size={16} className="text-gray-500" />
                             </div>
                             <div className="bg-[#2a2a2a] px-4 py-3 rounded-2xl rounded-tl-sm border border-gray-700">
                                 <div className="flex gap-1">
                                     <div className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></div>
                                     <div className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{animationDelay: '150ms'}}></div>
                                     <div className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{animationDelay: '300ms'}}></div>
                                 </div>
                             </div>
                        </div>
                    )}
                 </div>

                 {/* Settings / Mode Toolbar */}
                 <div className="px-3 py-2 border-t border-gray-700 bg-[#252526]">
                    <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                        {[
                            { id: 'standard', icon: Bot, label: 'Chat' },
                            { id: 'thinking', icon: Brain, label: 'Think' },
                            { id: 'search', icon: Search, label: 'Web' },
                            { id: 'maps', icon: MapPin, label: 'Maps' },
                            { id: 'fast', icon: Zap, label: 'Fast' }
                        ].map(mode => (
                            <button 
                                key={mode.id}
                                onClick={() => setChatMode(mode.id as ChatMode)}
                                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium whitespace-nowrap border transition-all ${
                                    chatMode === mode.id 
                                    ? 'bg-blue-600 border-blue-500 text-white shadow-sm' 
                                    : 'bg-gray-800 border-gray-700 text-gray-400 hover:border-gray-600 hover:text-gray-300'
                                }`}
                            >
                                <mode.icon size={12} />
                                {mode.label}
                            </button>
                        ))}
                    </div>
                 </div>

                 {/* Input Area */}
                 <div 
                    className="p-3 border-t border-gray-700 bg-[#1e1e1e] relative"
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                 >
                    {isDragging && (
                        <div className="absolute inset-0 bg-blue-500/10 z-20 flex items-center justify-center backdrop-blur-[1px] border-2 border-dashed border-blue-500/50 m-2 rounded-xl pointer-events-none">
                            <div className="bg-[#1e1e1e] text-blue-400 px-4 py-2 rounded-full shadow-xl flex items-center gap-2 font-medium text-sm border border-blue-500/20">
                                <Paperclip size={16} />
                                Drop to attach
                            </div>
                        </div>
                    )}

                    {attachment && (
                        <div className="mb-2 flex items-center gap-2 bg-gray-800 border border-gray-700 p-2 rounded-md text-xs animate-in slide-in-from-bottom-2">
                            <Paperclip size={12} className="text-blue-400" />
                            <span className="truncate flex-1 font-mono">{attachment.mimeType}</span>
                            <button onClick={() => setAttachment(null)} className="hover:text-red-400"><X size={14} /></button>
                        </div>
                    )}
                    <div className="flex gap-2 items-end">
                        <button 
                            onClick={() => fileInputRef.current?.click()} 
                            className="p-2.5 text-gray-400 hover:text-white bg-[#2a2a2a] border border-gray-700 rounded-xl hover:bg-gray-700 transition-colors mb-[1px]"
                            title="Attach Image/Audio"
                        >
                            <Paperclip size={18} />
                        </button>
                        <div className="flex-1 relative">
                            <textarea
                                ref={textareaRef}
                                value={input}
                                onChange={e => setInput(e.target.value)}
                                onKeyDown={e => {
                                    if(e.key === 'Enter' && !e.shiftKey) {
                                        e.preventDefault();
                                        handleSendMessage();
                                    }
                                }}
                                onPaste={handlePaste}
                                placeholder="Message Gemini..."
                                className="w-full bg-[#2a2a2a] border border-gray-700 rounded-xl px-4 py-3 text-sm text-white focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500/50 resize-none custom-scrollbar leading-relaxed"
                                style={{ minHeight: '46px', maxHeight: '150px' }}
                                rows={1}
                            />
                        </div>
                        <button 
                           onClick={handleSendMessage} 
                           disabled={isProcessing || (!input.trim() && !attachment)}
                           className="p-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-lg shadow-blue-900/20 mb-[1px]"
                        >
                           {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
                        </button>
                    </div>
                    <div className="text-[10px] text-gray-600 text-center mt-2">
                        Gemini can make mistakes. Check important info.
                    </div>
                 </div>
              </>
          )}

          {/* --- CREATE TAB --- */}
          {activeTab === 'create' && (
              <div className="p-4 flex flex-col h-full overflow-y-auto custom-scrollbar">
                 <div className="bg-[#2a2a2a] p-1 rounded-xl mb-6 grid grid-cols-2 gap-1 border border-gray-700">
                     <button 
                        onClick={() => { setCreateType('image'); setGeneratedMedia(null); }} 
                        className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-medium transition-all ${createType === 'image' ? 'bg-gray-700 text-white shadow-sm' : 'text-gray-400 hover:text-gray-200'}`}
                     >
                         <ImageIcon size={14} /> Image
                     </button>
                     <button 
                        onClick={() => { setCreateType('video'); setGeneratedMedia(null); }}
                        className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-medium transition-all ${createType === 'video' ? 'bg-gray-700 text-white shadow-sm' : 'text-gray-400 hover:text-gray-200'}`}
                     >
                         <Video size={14} /> Video
                     </button>
                 </div>

                 <div className="space-y-4">
                     <div>
                        <label className="block text-xs font-semibold text-gray-500 mb-2 uppercase tracking-wider">Prompt</label>
                        <textarea
                            value={prompt}
                            onChange={e => setPrompt(e.target.value)}
                            placeholder={`Describe the ${createType} in detail...`}
                            className="w-full bg-[#2a2a2a] border border-gray-700 rounded-xl p-3 text-sm text-white h-32 resize-none focus:border-blue-500 outline-none transition-colors"
                        />
                     </div>

                     <div className="grid grid-cols-2 gap-4">
                         <div>
                             <label className="block text-xs font-semibold text-gray-500 mb-2 uppercase tracking-wider">Aspect Ratio</label>
                             <select 
                                value={aspectRatio} 
                                onChange={e => setAspectRatio(e.target.value as any)}
                                className="w-full bg-[#2a2a2a] border border-gray-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-blue-500"
                             >
                                 {['1:1','16:9','9:16','4:3','3:4'].map(r => <option key={r} value={r}>{r}</option>)}
                             </select>
                         </div>
                         {createType === 'image' && (
                             <div>
                                 <label className="block text-xs font-semibold text-gray-500 mb-2 uppercase tracking-wider">Resolution</label>
                                 <select 
                                    value={imageSize}
                                    onChange={e => setImageSize(e.target.value as any)}
                                    className="w-full bg-[#2a2a2a] border border-gray-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-blue-500"
                                 >
                                     <option value="1K">1K (Standard)</option>
                                     <option value="2K">2K (HD)</option>
                                     <option value="4K">4K (Ultra)</option>
                                 </select>
                             </div>
                         )}
                     </div>

                     {createType === 'image' && (
                         <div>
                             <label className="block text-xs font-semibold text-gray-500 mb-2 uppercase tracking-wider">
                                Reference Image <span className="text-gray-600 font-normal">(Optional)</span>
                             </label>
                             <div 
                                 onClick={() => fileInputRef.current?.click()}
                                 className={`border border-dashed border-gray-700 rounded-xl p-4 text-center cursor-pointer transition-colors ${editImage ? 'bg-[#2a2a2a]' : 'hover:bg-[#2a2a2a] hover:border-gray-600'}`}
                             >
                                 {editImage ? (
                                     <div className="relative group">
                                         <img src={`data:image/png;base64,${editImage}`} className="h-32 mx-auto rounded-lg object-contain" />
                                         <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center rounded-lg transition-opacity">
                                             <span className="text-xs text-white">Click to change</span>
                                         </div>
                                     </div>
                                 ) : (
                                     <div className="text-gray-500 text-xs flex flex-col items-center gap-2 py-2">
                                         <ImageIcon size={24} className="opacity-50" />
                                         <span>Upload to edit</span>
                                     </div>
                                 )}
                             </div>
                         </div>
                     )}

                     <button
                        onClick={handleCreate}
                        disabled={isProcessing || !prompt}
                        className="w-full py-3 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white rounded-xl flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed font-medium shadow-lg shadow-blue-900/20 transition-all active:scale-[0.98]"
                     >
                         {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
                         Generate {createType === 'image' ? (editImage ? 'Edit' : 'Image') : 'Video'}
                     </button>
                 </div>

                 {generatedMedia && (
                     <div className="mt-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                         <div className="flex items-center justify-between mb-2">
                             <div className="text-xs font-bold text-green-400 uppercase tracking-wider flex items-center gap-1">
                                 <Zap size={12} /> Success
                             </div>
                             <a href={generatedMedia.url} download className="text-xs text-blue-400 hover:text-blue-300 hover:underline">Download</a>
                         </div>
                         <div className="rounded-xl overflow-hidden border border-gray-700 shadow-2xl bg-black">
                            {generatedMedia.type === 'image' ? (
                                <img src={generatedMedia.url} className="w-full" />
                            ) : (
                                <video src={generatedMedia.url} controls autoPlay loop className="w-full" />
                            )}
                         </div>
                     </div>
                 )}
              </div>
          )}

          {/* --- LIVE TAB --- */}
          {activeTab === 'live' && (
              <div className="flex flex-col items-center justify-center h-full p-6 text-center relative overflow-hidden">
                  <div className="absolute inset-0 bg-gradient-to-b from-blue-500/5 to-transparent pointer-events-none" />

                  <div className={`relative z-10 w-40 h-40 rounded-full flex items-center justify-center mb-8 transition-all duration-700 ${isLiveConnected ? 'bg-red-500/10 shadow-[0_0_60px_rgba(239,68,68,0.2)] scale-110' : 'bg-[#2a2a2a] border border-gray-700'}`}>
                      {isLiveConnected && (
                          <span className="absolute inset-0 rounded-full border border-red-500/30 animate-ping opacity-50"></span>
                      )}
                      <Mic size={56} className={`transition-colors duration-300 ${isLiveConnected ? 'text-red-500' : 'text-gray-500'}`} />
                  </div>

                  <h3 className="text-xl font-semibold text-white mb-2 relative z-10">
                      {isLiveConnected ? 'Live Session Active' : 'Voice Chat'}
                  </h3>
                  <p className="text-sm text-gray-400 mb-10 max-w-[240px] leading-relaxed relative z-10">
                      {isLiveConnected 
                          ? 'Listening...' 
                          : 'Experience real-time, low-latency conversation with Gemini 2.5.'}
                  </p>

                  <button
                      onClick={toggleLive}
                      className={`relative z-10 px-8 py-3.5 rounded-full font-medium transition-all transform active:scale-95 shadow-lg ${
                          isLiveConnected 
                          ? 'bg-red-600 hover:bg-red-500 text-white shadow-red-900/30' 
                          : 'bg-white text-black hover:bg-gray-100 shadow-white/10'
                      }`}
                  >
                      {isLiveConnected ? 'End Session' : 'Start Conversation'}
                  </button>
              </div>
          )}
      </div>

      {/* Hidden File Input for reuse */}
      <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileSelect} accept="image/*,audio/*" />
    </div>
  );
};

export default AIAssistant;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, X, Loader2, Image as ImageIcon, Video, Mic, Paperclip, Trash2, Copy, Terminal, Zap, Search, MapPin, Brain, Layers } from 'lucide-react';
import { chatWithGemini, generateImage, generateVideo, connectLive, transcribeAudio } from '../services/geminiService';
import { ChatMessage, ChatMode, AspectRatio, ImageSize } from '../types';

interface AIAssistantProps {
  currentCode: string;
  isOpen: boolean;
  onClose: () => void;
}

// Simple formatter for code blocks
const MessageContent: React.FC<{ text: string }> = ({ text }) => {
  const parts = text.split(/(```[\s\S]*?```)/g);
  return (
    <div className="text-sm leading-relaxed space-y-2">
      {parts.map((part, i) => {
        if (part.startsWith('```') && part.endsWith('```')) {
          // Extract language if present
          const match = part.match(/^```(\w*)\n/);
          const lang = match ? match[1] : '';
          const content = part.replace(/^```\w*\n?/, '').replace(/```$/, '');
          return (
            <div key={i} className="my-2 bg-[#1e1e1e] border border-gray-700 rounded-md overflow-hidden shadow-sm group">
               <div className="bg-[#252526] px-3 py-1.5 text-xs text-gray-400 flex justify-between items-center border-b border-gray-700">
                  <span className="font-mono uppercase text-[10px]">{lang || 'CODE'}</span>
                  <button 
                    onClick={() => navigator.clipboard.writeText(content)}
                    className="flex items-center gap-1 hover:text-white transition-colors"
                    title="Copy code"
                  >
                    <Copy size={10} />
                    <span>Copy</span>
                  </button>
               </div>
               <pre className="p-3 overflow-x-auto text-xs font-mono text-blue-300 custom-scrollbar">
                 {content}
               </pre>
            </div>
          );
        }
        // Basic bold parsing (**text**)
        const textParts = part.split(/(\*\*.*?\*\*)/g);
        return (
            <span key={i}>
                {textParts.map((t, j) => {
                    if (t.startsWith('**') && t.endsWith('**')) {
                        return <strong key={j} className="text-blue-200 font-semibold">{t.slice(2, -2)}</strong>;
                    }
                    return t;
                })}
            </span>
        );
      })}
    </div>
  );
};

const AIAssistant: React.FC<AIAssistantProps> = ({ currentCode, isOpen, onClose }) => {
  const [activeTab, setActiveTab] = useState<'chat' | 'create' | 'live'>('chat');

  // Chat State
  const [messages, setMessages] = useState<ChatMessage[]>([{ id: '1', role: 'model', text: 'Hi! I am your Gemini Copilot. How can I help with your code today?' }]);
  const [input, setInput] = useState('');
  const [chatMode, setChatMode] = useState<ChatMode>('standard');
  const [attachment, setAttachment] = useState<{base64: string, mimeType: string} | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);

  // Create State
  const [createType, setCreateType] = useState<'image' | 'video' | 'animation'>('image');
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('1:1');
  const [imageSize, setImageSize] = useState<ImageSize>('1K');
  const [editImage, setEditImage] = useState<string | null>(null);
  const [generatedMedia, setGeneratedMedia] = useState<{type: 'image'|'video', url: string} | null>(null);
  const [generatedAnimation, setGeneratedAnimation] = useState<string | null>(null);

  // Live State
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const liveSessionRef = useRef<any>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, activeTab]);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
        textareaRef.current.style.height = 'auto';
        textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }, [input]);

  const processFile = (file: File) => {
      if (!file) return;

      const reader = new FileReader();
      reader.onload = () => {
          const base64 = (reader.result as string).split(',')[1];
          if (activeTab === 'create' && createType === 'image') {
              setEditImage(base64);
          } else {
              setAttachment({ base64, mimeType: file.type });
          }
          if (fileInputRef.current) fileInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) processFile(file);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file && (file.type.startsWith('image/') || file.type.startsWith('audio/'))) {
        processFile(file);
    }
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    const items = e.clipboardData.items;
    for (const item of items) {
        if (item.type.indexOf('image') !== -1) {
            e.preventDefault();
            const file = item.getAsFile();
            if (file) processFile(file);
            return;
        }
    }
  };

  const handleSendMessage = async () => {
    if ((!input.trim() && !attachment) || isProcessing) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      image: attachment?.mimeType.startsWith('image') ? attachment.base64 : undefined
    };
    setMessages(p => [...p, userMsg]);
    setInput('');
    setAttachment(null);
    setIsProcessing(true);

    try {
      if (attachment?.mimeType.startsWith('audio')) {
         const transcript = await transcribeAudio(attachment.base64);
         setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: `Transcription: ${transcript}` }]);
      } else {
         const response = await chatWithGemini(userMsg.text, chatMode, attachment ? [attachment] : [], currentCode);
         setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: response }]);
      }
    } catch (e: any) {
       setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: "Error: " + e.message, isError: true }]);
    } finally {
       setIsProcessing(false);
    }
  };

  const handleCreate = async () => {
      if (!prompt.trim()) return;
      setIsProcessing(true);
      setGeneratedMedia(null);
      setGeneratedAnimation(null);

      try {
          if (createType === 'image') {
              const b64 = await generateImage(prompt, { aspectRatio, imageSize, sourceImage: editImage || undefined });
              setGeneratedMedia({ type: 'image', url: `data:image/png;base64,${b64}` });
          } else if (createType === 'video') {
              const url = await generateVideo(prompt, { aspectRatio });
              setGeneratedMedia({ type: 'video', url });
          } else if (createType === 'animation') {
              // Use chat service for code generation
              const animationPrompt = `Generate a modern CSS animation (keyframes and class) for: ${prompt}. Return ONLY the valid CSS code. Do not include markdown ticks.`;
              const cssCode = await chatWithGemini(animationPrompt, 'standard');
              // Strip markdown if AI adds it despite instructions
              const cleanCode = cssCode.replace(/```css|```/g, '').trim();
              setGeneratedAnimation(cleanCode);
          }
      } catch (e: any) {
          setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: "Generation Error: " + e.message, isError: true }]);
          setActiveTab('chat');
      } finally {
          setIsProcessing(false);
      }
  };

  const toggleLive = async () => {
      if (isLiveConnected) {
          liveSessionRef.current?.disconnect();
          setIsLiveConnected(false);
      } else {
          try {
              liveSessionRef.current = await connectLive(
                  (audioData) => { /* Audio handling handled in service */ },
                  () => setIsLiveConnected(false)
              );
              setIsLiveConnected(true);
          } catch (e) {
              console.error(e);
              alert("Failed to connect. Ensure permissions are granted.");
          }
      }
  };

  if (!isOpen) return null;

  return (
    <div className="w-96 h-full bg-[#1e1e1e] border-l border-gray-700 flex flex-col shadow-2xl absolute right-0 top-0 z-30 font-sans text-gray-300 transition-transform duration-300 ease-in-out">

      {/* Header */}
      <div className="h-12 border-b border-gray-700 flex items-center justify-between px-4 bg-[#252526] select-none">
        <div className="flex items-center gap-2 font-semibold text-gray-100">
            <Sparkles className="text-blue-500" size={16} />
            <span className="tracking-tight">Gemini OS</span>
        </div>
        <button onClick={onClose} className="hover:text-white transition-colors"><X size={18} /></button>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-gray-700 bg-[#252526] p-1 gap-1">
          {['chat', 'create', 'live'].map((t) => (
              <button 
                key={t}
                onClick={() => setActiveTab(t as any)}
                className={`flex-1 py-1.5 text-xs font-medium rounded capitalize transition-all ${
                    activeTab === t 
                    ? 'bg-blue-600 text-white shadow-sm' 
                    : 'text-gray-400 hover:text-gray-200 hover:bg-white/5'
                }`}
              >
                  {t}
              </button>
          ))}
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-hidden relative flex flex-col bg-[#1e1e1e]">

          {/* --- CHAT TAB --- */}
          {activeTab === 'chat' && (
              <>
                 {/* Chat Messages */}
                 <div className="flex-1 overflow-y-auto p-4 space-y-5 custom-scrollbar" ref={scrollRef}>
                    {messages.map((m, idx) => (
                        <div key={m.id} className={`flex gap-3 ${m.role === 'user' ? 'flex-row-reverse' : ''} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                            <div className={`w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0 shadow-sm ${m.role === 'user' ? 'bg-blue-600 text-white' : 'bg-gradient-to-br from-blue-500/20 to-purple-500/20 text-blue-400 border border-white/5'}`}>
                                {m.role === 'user' ? <User size={16} /> : <Bot size={16} />}
                            </div>
                            <div className={`flex flex-col max-w-[85%] ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                                <div className={`px-4 py-3 rounded-2xl text-sm shadow-sm ${
                                    m.role === 'user' 
                                    ? 'bg-blue-600 text-white rounded-tr-sm' 
                                    : 'bg-[#2a2a2a] border border-gray-700 rounded-tl-sm'
                                }`}>
                                    {m.image && (
                                        <div className="mb-2 rounded-lg overflow-hidden border border-white/10">
                                            <img src={`data:image/png;base64,${m.image}`} alt="attachment" className="max-w-full" />
                                        </div>
                                    )}
                                    <MessageContent text={m.text} />
                                </div>
                                {m.isError && <span className="text-xs text-red-400 mt-1">Failed to send</span>}
                            </div>
                        </div>
                    ))}
                    {isProcessing && (
                        <div className="flex gap-3 animate-pulse">
                             <div className="w-8 h-8 rounded-lg bg-gray-800 flex items-center justify-center">
                                 <Bot size={16} className="text-gray-500" />
                             </div>
                             <div className="bg-[#2a2a2a] px-4 py-3 rounded-2xl rounded-tl-sm border border-gray-700">
                                 <div className="flex gap-1">
                                     <div className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></div>
                                     <div className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{animationDelay: '150ms'}}></div>
                                     <div className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{animationDelay: '300ms'}}></div>
                                 </div>
                             </div>
                        </div>
                    )}
                 </div>

                 {/* Settings / Mode Toolbar */}
                 <div className="px-3 py-2 border-t border-gray-700 bg-[#252526]">
                    <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                        {[
                            { id: 'standard', icon: Bot, label: 'Chat' },
                            { id: 'thinking', icon: Brain, label: 'Think' },
                            { id: 'search', icon: Search, label: 'Web' },
                            { id: 'maps', icon: MapPin, label: 'Maps' },
                            { id: 'fast', icon: Zap, label: 'Fast' }
                        ].map(mode => (
                            <button 
                                key={mode.id}
                                onClick={() => setChatMode(mode.id as ChatMode)}
                                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium whitespace-nowrap border transition-all ${
                                    chatMode === mode.id 
                                    ? 'bg-blue-600 border-blue-500 text-white shadow-sm' 
                                    : 'bg-gray-800 border-gray-700 text-gray-400 hover:border-gray-600 hover:text-gray-300'
                                }`}
                            >
                                <mode.icon size={12} />
                                {mode.label}
                            </button>
                        ))}
                    </div>
                 </div>

                 {/* Input Area */}
                 <div 
                    className="p-3 border-t border-gray-700 bg-[#1e1e1e] relative"
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                 >
                    {isDragging && (
                        <div className="absolute inset-0 bg-blue-500/10 z-20 flex items-center justify-center backdrop-blur-[1px] border-2 border-dashed border-blue-500/50 m-2 rounded-xl pointer-events-none">
                            <div className="bg-[#1e1e1e] text-blue-400 px-4 py-2 rounded-full shadow-xl flex items-center gap-2 font-medium text-sm border border-blue-500/20">
                                <Paperclip size={16} />
                                Drop to attach
                            </div>
                        </div>
                    )}

                    {attachment && (
                        <div className="mb-2 flex items-center gap-2 bg-gray-800 border border-gray-700 p-2 rounded-md text-xs animate-in slide-in-from-bottom-2">
                            <Paperclip size={12} className="text-blue-400" />
                            <span className="truncate flex-1 font-mono">{attachment.mimeType}</span>
                            <button onClick={() => setAttachment(null)} className="hover:text-red-400"><X size={14} /></button>
                        </div>
                    )}
                    <div className="flex gap-2 items-end">
                        <button 
                            onClick={() => fileInputRef.current?.click()} 
                            className="p-2.5 text-gray-400 hover:text-white bg-[#2a2a2a] border border-gray-700 rounded-xl hover:bg-gray-700 transition-colors mb-[1px]"
                            title="Attach Image/Audio"
                        >
                            <Paperclip size={18} />
                        </button>
                        <div className="flex-1 relative">
                            <textarea
                                ref={textareaRef}
                                value={input}
                                onChange={e => setInput(e.target.value)}
                                onKeyDown={e => {
                                    if(e.key === 'Enter' && !e.shiftKey) {
                                        e.preventDefault();
                                        handleSendMessage();
                                    }
                                }}
                                onPaste={handlePaste}
                                placeholder="Message Gemini..."
                                className="w-full bg-[#2a2a2a] border border-gray-700 rounded-xl px-4 py-3 text-sm text-white focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500/50 resize-none custom-scrollbar leading-relaxed"
                                style={{ minHeight: '46px', maxHeight: '150px' }}
                                rows={1}
                            />
                        </div>
                        <button 
                           onClick={handleSendMessage} 
                           disabled={isProcessing || (!input.trim() && !attachment)}
                           className="p-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-lg shadow-blue-900/20 mb-[1px]"
                        >
                           {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
                        </button>
                    </div>
                    <div className="text-[10px] text-gray-600 text-center mt-2">
                        Gemini can make mistakes. Check important info.
                    </div>
                 </div>
              </>
          )}

          {/* --- CREATE TAB --- */}
          {activeTab === 'create' && (
              <div className="p-4 flex flex-col h-full overflow-y-auto custom-scrollbar">
                 <div className="bg-[#2a2a2a] p-1 rounded-xl mb-6 grid grid-cols-3 gap-1 border border-gray-700">
                     <button 
                        onClick={() => { setCreateType('image'); setGeneratedMedia(null); setGeneratedAnimation(null); }} 
                        className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-medium transition-all ${createType === 'image' ? 'bg-gray-700 text-white shadow-sm' : 'text-gray-400 hover:text-gray-200'}`}
                     >
                         <ImageIcon size={14} /> Image
                     </button>
                     <button 
                        onClick={() => { setCreateType('video'); setGeneratedMedia(null); setGeneratedAnimation(null); }}
                        className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-medium transition-all ${createType === 'video' ? 'bg-gray-700 text-white shadow-sm' : 'text-gray-400 hover:text-gray-200'}`}
                     >
                         <Video size={14} /> Video
                     </button>
                     <button 
                        onClick={() => { setCreateType('animation'); setGeneratedMedia(null); setGeneratedAnimation(null); }}
                        className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-medium transition-all ${createType === 'animation' ? 'bg-gray-700 text-white shadow-sm' : 'text-gray-400 hover:text-gray-200'}`}
