export default AIAssistant;

import { GoogleGenAI, Modality, Type, FunctionDeclaration, LiveServerMessage } from "@google/genai";

// -- Helpers --

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key is missing");
  return new GoogleGenAI({ apiKey });
};

const getPaidClient = async () => {
  // @ts-ignore
  if (window.aistudio && window.aistudio.hasSelectedApiKey && window.aistudio.openSelectKey) {
     // @ts-ignore
     const hasKey = await window.aistudio.hasSelectedApiKey();
     if (!hasKey) {
         // @ts-ignore
         await window.aistudio.openSelectKey();
     }
  }
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// -- Chat & Text Features --

export const chatWithGemini = async (
  prompt: string, 
  mode: 'standard' | 'thinking' | 'search' | 'maps' | 'fast',
  attachments: { base64: string, mimeType: string }[] = [],
  contextCode?: string
) => {
  const ai = getClient();
  let model = 'gemini-3-pro-preview';
  const config: any = {
    systemInstruction: contextCode 
      ? `You are an expert developer assistant. Current code context:\n\`\`\`\n${contextCode}\n\`\`\`` 
      : 'You are a helpful AI assistant.',
  };

  if (mode === 'fast') {
    model = 'gemini-2.5-flash-lite-latest';
  } else if (mode === 'thinking') {
    model = 'gemini-3-pro-preview';
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else if (mode === 'search') {
    model = 'gemini-3-flash-preview';
    config.tools = [{ googleSearch: {} }];
  } else if (mode === 'maps') {
    model = 'gemini-2.5-flash'; // Maps only on 2.5 Flash
    config.tools = [{ googleMaps: {} }];
    // Try to get location
    try {
      const pos: any = await new Promise((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(resolve, reject, { timeout: 5000 });
      });
      config.toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: pos.coords.latitude,
            longitude: pos.coords.longitude
          }
        }
      };
    } catch (e) {
      console.warn("Could not get location for Maps grounding");
    }
  }

  // Handle attachments (Image/Video Analysis, Audio Transcription)
  // Logic: Analysis uses Pro, Transcription uses Flash. 
  // If attachments exist, override model if necessary for best results, 
  // unless user specifically requested a mode.
  let parts: any[] = [];

  if (attachments.length > 0) {
    // If audio is present, prefer Flash for transcription
    if (attachments.some(a => a.mimeType.startsWith('audio/'))) {
      if (mode === 'standard') model = 'gemini-3-flash-preview';
    }

    parts = attachments.map(a => ({
      inlineData: {
        data: a.base64,
        mimeType: a.mimeType
      }
    }));
  }

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model,
    contents: { parts },
    config
  });

  // Extract grounding metadata if present
  let text = response.text || "";
  const grounding = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (grounding) {
    const links = grounding
      .map((c: any) => c.web?.uri ? `[${c.web.title}](${c.web.uri})` : c.maps?.uri ? `[${c.maps.title}](${c.maps.uri})` : '')
      .filter(Boolean)
      .join('\n');
    if (links) text += `\n\nSources:\n${links}`;
  }

  return text;
};

// -- Audio Features --

export const transcribeAudio = async (audioBase64: string) => {
  const ai = getClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'audio/wav', data: audioBase64 } },
        { text: "Transcribe this audio." }
      ]
    }
  });
  return response.text;
};

export const generateSpeech = async (text: string) => {
  const ai = getClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-preview-tts',
    contents: { parts: [{ text }] },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
      },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
};

// -- Image Features --

export const generateImage = async (
  prompt: string, 
  options: { 
    aspectRatio?: string, 
    imageSize?: string,
    sourceImage?: string // Base64 for editing
  }
) => {
  // If editing (source image present), use 2.5 Flash Image
  if (options.sourceImage) {
    const ai = getClient();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/png', data: options.sourceImage } },
          { text: prompt }
        ]
      },
      config: {
         imageConfig: {
             aspectRatio: options.aspectRatio as any || "1:1"
         }
      }
    });
    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return part.inlineData.data;
    }
    throw new Error("No image generated");
  } else {
    // Generation use 3 Pro Image (requires paid key)
    const ai = await getPaidClient();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: options.aspectRatio as any || "1:1",
          imageSize: options.imageSize as any || "1K"
        }
      }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return part.inlineData.data;
    }
    throw new Error("No image generated");
  }
};

// -- Video Features --

export const generateVideo = async (
  prompt: string,
  options: { aspectRatio: string }
) => {
  const ai = await getPaidClient();
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt,
    config: {
      numberOfVideos: 1,
      aspectRatio: options.aspectRatio as any,
      resolution: '720p'
    }
  });

  // Polling
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({ operation });
  }

  const uri = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!uri) throw new Error("Video generation failed");

  // Fetch with API key
  const response = await fetch(`${uri}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

// -- Live API --

export const connectLive = async (
    onAudioData: (base64: string) => void,
    onCodeUpdate: (code: string) => void,
    onClose: () => void
) => {
    const ai = getClient();
    // Audio Context Setup
    const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    // Setup Input Stream
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const source = inputAudioContext.createMediaStreamSource(stream);
    const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);

    // Define Tools
    const updateCodeTool: FunctionDeclaration = {
        name: 'update_code',
        description: 'Overwrite the current file content with new code. Use this when the user asks to write, change, or fix code.',
        parameters: {
            type: Type.OBJECT,
            properties: {
                code: { type: Type.STRING, description: 'The complete code content to write.' }
            },
            required: ['code']
        }
    };

    // Connect to Live API
    const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
            onopen: () => {
                scriptProcessor.onaudioprocess = (e) => {
                    const inputData = e.inputBuffer.getChannelData(0);
                    // Convert Float32 to PCM Int16
                    const l = inputData.length;
                    const int16 = new Int16Array(l);
                    for (let i = 0; i < l; i++) int16[i] = inputData[i] * 32768;
                    const bytes = new Uint8Array(int16.buffer);
                    let binary = '';
                    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
                    const base64Data = btoa(binary);

                    sessionPromise.then(session => {
                        session.sendRealtimeInput({
                            media: {
                                mimeType: 'audio/pcm;rate=16000',
                                data: base64Data
                            }
                        });
                    });
                };
                source.connect(scriptProcessor);
                scriptProcessor.connect(inputAudioContext.destination);
            },
            onmessage: (msg: LiveServerMessage) => {
                // Handle Audio Output
                const data = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (data) {
                    onAudioData(data);
                    // Play audio
                    const binaryString = atob(data);
                    const len = binaryString.length;
                    const bytes = new Uint8Array(len);
                    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);

                    // Simple decode and play
                    const ctx = outputAudioContext;
                    const dataInt16 = new Int16Array(bytes.buffer);
                    const float32 = new Float32Array(dataInt16.length);
                    for(let i=0; i<dataInt16.length; i++) float32[i] = dataInt16[i] / 32768.0;

                    const buffer = ctx.createBuffer(1, float32.length, 24000);
                    buffer.copyToChannel(float32, 0);

                    const node = ctx.createBufferSource();
                    node.buffer = buffer;
                    node.connect(ctx.destination);
                    node.start();
                }

                // Handle Tool Calls
                if (msg.toolCall) {
                    msg.toolCall.functionCalls.forEach(fc => {
                        if (fc.name === 'update_code') {
                            const args = fc.args as any;
                            if (args.code) {
                                onCodeUpdate(args.code);
                            }
                            // Respond to tool call
                            sessionPromise.then(session => session.sendToolResponse({
                                functionResponses: [{
                                    id: fc.id,
                                    name: fc.name,
                                    response: { result: 'Code updated successfully' }
                                }]
                            }));
                        }
                    });
                }
            },
            onclose: onClose,
            onerror: (e) => { console.error(e); onClose(); }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
            },
            systemInstruction: "You are an expert coding assistant. You can hear the user and update their code in real-time. When asked to write code, use the update_code tool.",
            tools: [{ functionDeclarations: [updateCodeTool] }]
        }
    });

    return {
        disconnect: () => {
            sessionPromise.then(s => s.close());
            inputAudioContext.close();
            outputAudioContext.close();
            stream.getTracks().forEach(t => t.stop());
        }
    };
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, X, Loader2, Image as ImageIcon, Video, Mic, Paperclip, Trash2, Copy, Terminal, Zap, Search, MapPin, Brain, Layers } from 'lucide-react';
import { chatWithGemini, generateImage, generateVideo, connectLive, transcribeAudio } from '../services/geminiService';
import { ChatMessage, ChatMode, AspectRatio, ImageSize } from '../types';

interface AIAssistantProps {
  currentCode: string;
  isOpen: boolean;
  onClose: () => void;
  onUpdateCode: (code: string) => void;
}

// Simple formatter for code blocks
const MessageContent: React.FC<{ text: string }> = ({ text }) => {
  const parts = text.split(/(```[\s\S]*?```)/g);
  return (
    <div className="text-sm leading-relaxed space-y-2">
      {parts.map((part, i) => {
        if (part.startsWith('```') && part.endsWith('```')) {
          // Extract language if present
          const match = part.match(/^```(\w*)\n/);
          const lang = match ? match[1] : '';
          const content = part.replace(/^```\w*\n?/, '').replace(/```$/, '');
          return (
            <div key={i} className="my-2 bg-[#1e1e1e] border border-gray-700 rounded-md overflow-hidden shadow-sm group">
               <div className="bg-[#252526] px-3 py-1.5 text-xs text-gray-400 flex justify-between items-center border-b border-gray-700">
                  <span className="font-mono uppercase text-[10px]">{lang || 'CODE'}</span>
                  <button 
                    onClick={() => navigator.clipboard.writeText(content)}
                    className="flex items-center gap-1 hover:text-white transition-colors"
                    title="Copy code"
                  >
                    <Copy size={10} />
                    <span>Copy</span>
                  </button>
               </div>
               <pre className="p-3 overflow-x-auto text-xs font-mono text-blue-300 custom-scrollbar">
                 {content}
               </pre>
            </div>
          );
        }
        // Basic bold parsing (**text**)
        const textParts = part.split(/(\*\*.*?\*\*)/g);
        return (
            <span key={i}>
                {textParts.map((t, j) => {
                    if (t.startsWith('**') && t.endsWith('**')) {
                        return <strong key={j} className="text-blue-200 font-semibold">{t.slice(2, -2)}</strong>;
                    }
                    return t;
                })}
            </span>
        );
      })}
    </div>
  );
};

const AIAssistant: React.FC<AIAssistantProps> = ({ currentCode, isOpen, onClose, onUpdateCode }) => {
  const [activeTab, setActiveTab] = useState<'chat' | 'create' | 'live'>('chat');

  // Chat State
  const [messages, setMessages] = useState<ChatMessage[]>([{ id: '1', role: 'model', text: 'Hi! I am your Gemini Copilot. How can I help with your code today?' }]);
  const [input, setInput] = useState('');
  const [chatMode, setChatMode] = useState<ChatMode>('standard');
  const [attachment, setAttachment] = useState<{base64: string, mimeType: string} | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);

  // Create State
  const [createType, setCreateType] = useState<'image' | 'video' | 'animation'>('image');
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('1:1');
  const [imageSize, setImageSize] = useState<ImageSize>('1K');
  const [editImage, setEditImage] = useState<string | null>(null);
  const [generatedMedia, setGeneratedMedia] = useState<{type: 'image'|'video', url: string} | null>(null);
  const [generatedAnimation, setGeneratedAnimation] = useState<string | null>(null);

  // Animation Controls State
  const [animDuration, setAnimDuration] = useState(1.5);
  const [animEasing, setAnimEasing] = useState('ease-in-out');
  const [animIteration, setAnimIteration] = useState('infinite');

  // Live State
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const liveSessionRef = useRef<any>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, activeTab]);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
        textareaRef.current.style.height = 'auto';
        textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }, [input]);

  const processFile = (file: File) => {
      if (!file) return;

      const reader = new FileReader();
      reader.onload = () => {
          const base64 = (reader.result as string).split(',')[1];
          if (activeTab === 'create' && createType === 'image') {
              setEditImage(base64);
          } else {
              setAttachment({ base64, mimeType: file.type });
          }
          if (fileInputRef.current) fileInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) processFile(file);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file && (file.type.startsWith('image/') || file.type.startsWith('audio/'))) {
        processFile(file);
    }
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    const items = e.clipboardData.items;
    for (const item of items) {
        if (item.type.indexOf('image') !== -1) {
            e.preventDefault();
            const file = item.getAsFile();
            if (file) processFile(file);
            return;
        }
    }
  };

  const handleSendMessage = async () => {
    if ((!input.trim() && !attachment) || isProcessing) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      image: attachment?.mimeType.startsWith('image') ? attachment.base64 : undefined
    };
    setMessages(p => [...p, userMsg]);
    setInput('');
    setAttachment(null);
    setIsProcessing(true);

    try {
      if (attachment?.mimeType.startsWith('audio')) {
         const transcript = await transcribeAudio(attachment.base64);
         setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: `Transcription: ${transcript}` }]);
      } else {
         const response = await chatWithGemini(userMsg.text, chatMode, attachment ? [attachment] : [], currentCode);
         setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: response }]);
      }
    } catch (e: any) {
       setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: "Error: " + e.message, isError: true }]);
    } finally {
       setIsProcessing(false);
    }
  };

  const handleCreate = async () => {
      if (!prompt.trim()) return;
      setIsProcessing(true);
      setGeneratedMedia(null);
      setGeneratedAnimation(null);

      try {
          if (createType === 'image') {
              const b64 = await generateImage(prompt, { aspectRatio, imageSize, sourceImage: editImage || undefined });
              setGeneratedMedia({ type: 'image', url: `data:image/png;base64,${b64}` });
          } else if (createType === 'video') {
              const url = await generateVideo(prompt, { aspectRatio });
              setGeneratedMedia({ type: 'video', url });
          } else if (createType === 'animation') {
              // Use chat service for code generation
              const animationPrompt = `Generate a modern CSS animation (keyframes and class) for: ${prompt}. 

              Strict configuration:
              - duration: ${animDuration}s
              - timing-function: ${animEasing}
              - iteration-count: ${animIteration}

              Return ONLY the valid CSS code. Do not include markdown ticks.`;
              const cssCode = await chatWithGemini(animationPrompt, 'standard');
              // Strip markdown if AI adds it despite instructions
              const cleanCode = cssCode.replace(/```css|```/g, '').trim();
              setGeneratedAnimation(cleanCode);
          }
      } catch (e: any) {
          setMessages(p => [...p, { id: Date.now().toString(), role: 'model', text: "Generation Error: " + e.message, isError: true }]);
          setActiveTab('chat');
      } finally {
          setIsProcessing(false);
      }
  };

  const toggleLive = async () => {
      if (isLiveConnected) {
          liveSessionRef.current?.disconnect();
          setIsLiveConnected(false);
      } else {
          try {
              liveSessionRef.current = await connectLive(
                  (audioData) => { /* Audio handling handled in service */ },
                  (code) => onUpdateCode(code),
                  () => setIsLiveConnected(false)
              );
              setIsLiveConnected(true);
          } catch (e) {
              console.error(e);
              alert("Failed to connect. Ensure permissions are granted.");
          }
      }
  };

  if (!isOpen) return null;

  return (
    <div className="w-96 h-full bg-[#1e1e1e] border-l border-gray-700 flex flex-col shadow-2xl absolute right-0 top-0 z-30 font-sans text-gray-300 transition-transform duration-300 ease-in-out">

      {/* Header */}
      <div className="h-12 border-b border-gray-700 flex items-center justify-between px-4 bg-[#252526] select-none">
        <div className="flex items-center gap-2 font-semibold text-gray-100">
            <Sparkles className="text-blue-500" size={16} />
            <span className="tracking-tight">Gemini OS</span>
        </div>
        <button onClick={onClose} className="hover:text-white transition-colors"><X size={18} /></button>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-gray-700 bg-[#252526] p-1 gap-1">
          {['chat', 'create', 'live'].map((t) => (
              <button 
                key={t}
                onClick={() => setActiveTab(t as any)}
                className={`flex-1 py-1.5 text-xs font-medium rounded capitalize transition-all ${
                    activeTab === t 
                    ? 'bg-blue-600 text-white shadow-sm' 
                    : 'text-gray-400 hover:text-gray-200 hover:bg-white/5'
                }`}
              >
                  {t}
              </button>
          ))}
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-hidden relative flex flex-col bg-[#1e1e1e]">

          {/* --- CHAT TAB --- */}
          {activeTab === 'chat' && (
              <>
                 {/* Chat Messages */}
                 <div className="flex-1 overflow-y-auto p-4 space-y-5 custom-scrollbar" ref={scrollRef}>
                    {messages.map((m, idx) => (
                        <div key={m.id} className={`flex gap-3 ${m.role === 'user' ? 'flex-row-reverse' : ''} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                            <div className={`w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0 shadow-sm ${m.role === 'user' ? 'bg-blue-600 text-white' : 'bg-gradient-to-br from-blue-500/20 to-purple-500/20 text-blue-400 border border-white/5'}`}>
                                {m.role === 'user' ? <User size={16} /> : <Bot size={16} />}
                            </div>
                            <div className={`flex flex-col max-w-[85%] ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                                <div className={`px-4 py-3 rounded-2xl text-sm shadow-sm ${
                                    m.role === 'user' 
                                    ? 'bg-blue-600 text-white rounded-tr-sm' 
                                    : 'bg-[#2a2a2a] border border-gray-700 rounded-tl-sm'
                                }`}>
                                    {m.image && (
                                        <div className="mb-2 rounded-lg overflow-hidden border border-white/10">
                                            <img src={`data:image/png;base64,${m.image}`} alt="attachment" className="max-w-full" />
                                        </div>
                                    )}
                                    <MessageContent text={m.text} />
                                </div>
                                {m.isError && <span className="text-xs text-red-400 mt-1">Failed to send</span>}
                            </div>
                        </div>
                    ))}
                    {isProcessing && (
                        <div className="flex gap-3 animate-pulse">
                             <div className="w-8 h-8 rounded-lg bg-gray-800 flex items-center justify-center">
                                 <Bot size={16} className="text-gray-500" />
                             </div>
                             <div className="bg-[#2a2a2a] px-4 py-3 rounded-2xl rounded-tl-sm border border-gray-700">
                                 <div className="flex gap-1">
                                     <div className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></div>
                                     <div className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{animationDelay: '150ms'}}></div>
                                     <div className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{animationDelay: '300ms'}}></div>
                                 </div>
                             </div>
                        </div>
                    )}
                 </div>

                 {/* Settings / Mode Toolbar */}
                 <div className="px-3 py-2 border-t border-gray-700 bg-[#252526]">
                    <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                        {[
                            { id: 'standard', icon: Bot, label: 'Chat' },
                            { id: 'thinking', icon: Brain, label: 'Think' },
                            { id: 'search', icon: Search, label: 'Web' },
                            { id: 'maps', icon: MapPin, label: 'Maps' },
                            { id: 'fast', icon: Zap, label: 'Fast' }
                        ].map(mode => (
                            <button 
                                key={mode.id}
                                onClick={() => setChatMode(mode.id as ChatMode)}
                                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium whitespace-nowrap border transition-all ${
                                    chatMode === mode.id 
                                    ? 'bg-blue-600 border-blue-500 text-white shadow-sm' 
                                    : 'bg-gray-800 border-gray-700 text-gray-400 hover:border-gray-600 hover:text-gray-300'
                                }`}
                            >
                                <mode.icon size={12} />
                                {mode.label}
                            </button>
                        ))}
                    </div>
                 </div>

                 {/* Input Area */}
                 <div 
                    className="p-3 border-t border-gray-700 bg-[#1e1e1e] relative"
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                 >
                    {isDragging && (
                        <div className="absolute inset-0 bg-blue-500/10 z-20 flex items-center justify-center backdrop-blur-[1px] border-2 border-dashed border-blue-500/50 m-2 rounded-xl pointer-events-none">
                            <div className="bg-[#1e1e1e] text-blue-400 px-4 py-2 rounded-full shadow-xl flex items-center gap-2 font-medium text-sm border border-blue-500/20">
                                <Paperclip size={16} />
                                Drop to attach
                            </div>
                        </div>
                    )}

                    {attachment && (
                        <div className="mb-2 flex items-center gap-2 bg-gray-800 border border-gray-700 p-2 rounded-md text-xs animate-in slide-in-from-bottom-2">
                            <Paperclip size={12} className="text-blue-400" />
                            <span className="truncate flex-1 font-mono">{attachment.mimeType}</span>
                            <button onClick={() => setAttachment(null)} className="hover:text-red-400"><X size={14} /></button>
                        </div>
                    )}
                    <div className="flex gap-2 items-end">
                        <button 
                            onClick={() => fileInputRef.current?.click()} 
                            className="p-2.5 text-gray-400 hover:text-white bg-[#2a2a2a] border border-gray-700 rounded-xl hover:bg-gray-700 transition-colors mb-[1px]"
