import React, { useState, useEffect } from 'react';
import { Rocket, Globe, CheckCircle, Loader2, ExternalLink, AlertCircle } from 'lucide-react';
import { VirtualFile } from '../types';

interface DeploymentProps {
  files: VirtualFile[];
}

const Deployment: React.FC<DeploymentProps> = ({ files }) => {
  const [domain, setDomain] = useState('');
  const [status, setStatus] = useState<'idle' | 'building' | 'deployed' | 'error'>('idle');
  const [logs, setLogs] = useState<string[]>([]);
  const [deployedUrl, setDeployedUrl] = useState<string | null>(null);
  const [blobUrl, setBlobUrl] = useState<string | null>(null);

  const handleDeploy = async () => {
    if (!domain.trim()) return;

    setStatus('building');
    setLogs(['Initializing build environment...']);
    setDeployedUrl(null);

    // Simulate build steps
    await new Promise(r => setTimeout(r, 800));
    setLogs(p => [...p, 'Bundling assets...']);

    // Bundle Logic
    try {
        const entryPoint = files.find(f => f.name === 'index.html');
        if (!entryPoint) throw new Error("Missing index.html");

        let html = entryPoint.content;

        // Inline CSS - Robust Regex for any attribute order
        html = html.replace(/<link[^>]+>/g, (match) => {
          if (!match.includes('rel="stylesheet"')) return match;
          const hrefMatch = match.match(/href="([^"]+)"/);
          if (!hrefMatch) return match;

          const href = hrefMatch[1];
          const cssFile = files.find(f => f.name === href);
          return cssFile ? `<style>/* Inlined ${href} */\n${cssFile.content}</style>` : match;
        });

        // Inline JS
        html = html.replace(/<script[^>]+src="([^"]+)"[^>]*><\/script>/g, (match, src) => {
          const jsFile = files.find(f => f.name === src);
          return jsFile ? `<script>/* Inlined ${src} */\n${jsFile.content}</script>` : match;
        });

        const blob = new Blob([html], { type: 'text/html' });
        const url = URL.createObjectURL(blob);
        setBlobUrl(url);

        await new Promise(r => setTimeout(r, 800));
        setLogs(p => [...p, 'Optimizing build...']);

        await new Promise(r => setTimeout(r, 800));
        setLogs(p => [...p, 'Uploading to CDN...']);

        await new Promise(r => setTimeout(r, 600));
        setStatus('deployed');
        setDeployedUrl(`https://${domain}.devbrowser.app`);
        setLogs(p => [...p, 'Deployment successful!']);

    } catch (e: any) {
        setStatus('error');
        setLogs(p => [...p, `Build failed: ${e.message}`]);
    }
  };

  return (
    <div className="w-64 bg-browser-toolbar border-r border-gray-700 flex flex-col h-full select-none text-gray-300">
      <div className="h-9 px-3 flex items-center justify-between border-b border-gray-700 bg-[#252526]">
        <div className="flex items-center gap-2 text-xs font-semibold text-gray-400">
          <Rocket size={14} />
          <span>DEPLOYMENT</span>
        </div>
      </div>

      <div className="p-4 flex-1 overflow-y-auto">
         <div className="mb-6">
            <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-3">Project Domain</h3>
            <div className="flex items-center bg-gray-900 border border-gray-700 rounded-md overflow-hidden focus-within:border-blue-500 transition-colors">
                <div className="pl-3 pr-2 text-gray-500">
                    <Globe size={14} />
                </div>
                <input 
                    type="text"
                    value={domain}
                    onChange={(e) => setDomain(e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, ''))}
                    placeholder="project-name"
                    className="flex-1 bg-transparent border-none outline-none text-xs text-white py-2"
                    disabled={status === 'building'}
                />
                <div className="pr-3 text-[10px] text-gray-500 select-none bg-gray-800 h-full flex items-center px-2 border-l border-gray-700">
                    .dev
                </div>
            </div>
            <p className="text-[10px] text-gray-500 mt-2">
                Only lowercase letters, numbers, and dashes.
            </p>
         </div>

         {status === 'deployed' ? (
             <div className="bg-green-500/10 border border-green-500/20 rounded-lg p-3 mb-6 animate-in fade-in zoom-in duration-300">
                 <div className="flex items-center gap-2 text-green-400 font-bold text-xs mb-2">
                     <CheckCircle size={14} />
                     <span>Live on Production</span>
                 </div>
                 <div className="text-xs text-gray-300 break-all font-mono mb-3 bg-black/20 p-1.5 rounded">
                     {deployedUrl}
                 </div>
                 <a 
                    href={blobUrl || '#'} 
                    target="_blank" 
                    rel="noreferrer"
                    className="flex items-center justify-center gap-2 w-full bg-green-600 hover:bg-green-500 text-white text-xs font-medium py-1.5 rounded transition-colors"
                 >
                     <ExternalLink size={12} />
                     Visit Site
                 </a>
                 <button 
                    onClick={() => setStatus('idle')}
                    className="w-full text-[10px] text-gray-500 hover:text-gray-300 mt-2 underline"
                 >
                    Deploy new version
                 </button>
             </div>
         ) : (
             <button
                onClick={handleDeploy}
                disabled={status === 'building' || !domain}
                className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed text-white text-xs font-medium py-2 rounded flex items-center justify-center gap-2 transition-all"
             >
                 {status === 'building' ? <Loader2 size={14} className="animate-spin" /> : <Rocket size={14} />}
                 {status === 'building' ? 'Deploying...' : 'Publish Project'}
             </button>
         )}

         {/* Logs / Status */}
         {(status === 'building' || status === 'error' || logs.length > 0) && (
             <div className="mt-6">
                 <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Build Logs</h3>
                 <div className="bg-black/40 rounded-lg p-3 font-mono text-[10px] space-y-1.5 h-40 overflow-y-auto custom-scrollbar border border-white/5">
                     {logs.map((log, i) => (
                         <div key={i} className={`flex items-start gap-2 ${log.includes('failed') ? 'text-red-400' : log.includes('successful') ? 'text-green-400' : 'text-gray-400'}`}>
                             <span className="opacity-50 select-none">{'>'}</span>
                             <span>{log}</span>
                         </div>
                     ))}
                     {status === 'building' && (
                         <div className="flex items-center gap-2 text-blue-400 animate-pulse">
                             <span className="opacity-50">{'>'}</span>
                             <span>Working...</span>
                         </div>
                     )}
                 </div>
             </div>
         )}

         {status === 'error' && (
             <div className="mt-4 flex items-center gap-2 text-red-400 text-xs bg-red-900/10 p-2 rounded border border-red-500/20">
                 <AlertCircle size={14} />
                 <span>Deployment Failed</span>
             </div>
         )}
      </div>
    </div>
  );
};

export default Deployment;

import React, { useState, useMemo } from 'react';
import { Search as SearchIcon, File, ChevronRight, ChevronDown, ListFilter, ExternalLink } from 'lucide-react';
import { VirtualFile } from '../types';

interface SearchProps {
  files: VirtualFile[];
  onSelect: (fileName: string) => void;
}

interface SearchResult {
  file: VirtualFile;
  matches: { line: number; text: string }[];
}

const Search: React.FC<SearchProps> = ({ files, onSelect }) => {
  const [query, setQuery] = useState('');
  const [expandedFiles, setExpandedFiles] = useState<Record<string, boolean>>({});

  const toggleExpand = (fileName: string) => {
    setExpandedFiles(prev => ({ ...prev, [fileName]: !prev[fileName] }));
  };

  const results: SearchResult[] = useMemo(() => {
    if (!query.trim()) return [];

    const term = query.toLowerCase();
    const searchResults: SearchResult[] = [];

    files.forEach(file => {
      if (file.type === 'directory') return;

      const matches: { line: number; text: string }[] = [];

      // Check content
      const lines = file.content.split('\n');
      lines.forEach((line, idx) => {
        if (line.toLowerCase().includes(term)) {
          matches.push({
            line: idx + 1,
            text: line.trim()
          });
        }
      });

      // Include if content matched OR filename matched
      if (matches.length > 0 || file.name.toLowerCase().includes(term)) {
        searchResults.push({ file, matches });
      }
    });

    return searchResults;
  }, [files, query]);

  // Auto-expand results with content matches when searching
  useMemo(() => {
      if(query) {
          const newExpanded: Record<string, boolean> = {};
          results.forEach(r => {
             if (r.matches.length > 0) newExpanded[r.file.name] = true;
          });
          setExpandedFiles(newExpanded);
      }
  }, [results.length, query]); 

  return (
    <div className="w-64 bg-browser-toolbar border-r border-gray-700 flex flex-col h-full select-none text-gray-300">
      <div className="h-9 px-3 flex items-center justify-between border-b border-gray-700 bg-[#252526]">
        <div className="flex items-center gap-2 text-xs font-semibold text-gray-400">
          <SearchIcon size={14} />
          <span>SEARCH</span>
        </div>
      </div>

      <div className="p-3">
        <div className="relative mb-4">
            <input 
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className="w-full bg-[#3c3c3c] border border-gray-700 text-white text-xs rounded px-2 py-1.5 pl-8 focus:border-blue-500 outline-none"
                placeholder="Search"
                autoFocus
            />
            <div className="absolute left-2 top-1.5 text-gray-400">
                <SearchIcon size={14} />
            </div>
        </div>

        {query && (
            <div className="text-xs text-gray-500 mb-2 uppercase tracking-wider font-bold">
                {results.length} files found
            </div>
        )}

        <div className="space-y-1 overflow-y-auto custom-scrollbar" style={{maxHeight: 'calc(100vh - 120px)'}}>
            {results.map(result => {
                const hasContentMatches = result.matches.length > 0;

                return (
                    <div key={result.file.name} className="flex flex-col">
                        <div 
                            className="flex items-center gap-1 hover:bg-white/5 p-1 rounded cursor-pointer group"
                            onClick={() => {
                                if (hasContentMatches) {
                                    toggleExpand(result.file.name);
                                } else {
                                    onSelect(result.file.name);
                                }
                            }}
                        >
                            <span className={`text-gray-500 ${!hasContentMatches && 'opacity-0'}`}>
                                {expandedFiles[result.file.name] ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                            </span>
                            <File size={14} className="text-gray-400" />
                            <span className="text-xs text-gray-300 font-medium truncate flex-1" title={result.file.name}>
                                {result.file.name}
                            </span>
                            {hasContentMatches ? (
                                <span className="text-[10px] bg-gray-700 text-gray-300 px-1.5 rounded-full">
                                    {result.matches.length}
                                </span>
                            ) : (
                                <span className="text-[10px] text-blue-400 opacity-0 group-hover:opacity-100 flex items-center gap-0.5">
                                    Open <ExternalLink size={10} />
                                </span>
                            )}
                        </div>

                        {hasContentMatches && expandedFiles[result.file.name] && (
                            <div className="ml-6 space-y-0.5 mt-0.5">
                                {result.matches.map((match, i) => (
                                    <div 
                                        key={i} 
                                        className="text-xs text-gray-400 hover:text-white hover:bg-blue-500/20 px-1 py-0.5 rounded cursor-pointer font-mono truncate flex gap-2"
                                        onClick={() => onSelect(result.file.name)}
                                        title={match.text}
                                    >
                                        <span className="text-gray-600 w-6 text-right flex-shrink-0">{match.line}:</span>
                                        <span className="truncate">{match.text}</span>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                );
            })}
            {query && results.length === 0 && (
                <div className="text-xs text-gray-500 text-center mt-4">No results found.</div>
            )}
        </div>
      </div>
    </div>
  );
};

export default Search;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Code2, SplitSquareHorizontal, Maximize2, Sparkles, Layout, AlignLeft } from 'lucide-react';
import { LogEntry, LayoutMode, VirtualFile, GitCommit, SidebarView } from './types';
import Console from './components/Console';
import AddressBar from './components/AddressBar';
import AIAssistant from './components/AIAssistant';
import FileExplorer from './components/FileExplorer';
import SourceControl from './components/SourceControl';
import Deployment from './components/Deployment';
import ActivityBar from './components/ActivityBar';
import Search from './components/Search';

// Prettier Imports
import { format } from "prettier/standalone";
import parserBabel from "prettier/plugins/babel";
import parserEstree from "prettier/plugins/estree";
import parserHtml from "prettier/plugins/html";
import parserPostcss from "prettier/plugins/postcss";
import parserMarkdown from "prettier/plugins/markdown";

// Initial Empty Project
const INITIAL_FILES: VirtualFile[] = [
  {
    name: 'index.html',
    language: 'html',
    type: 'file',
    content: `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>New Project</title>
</head>
<body>
  <div class="container">
    <h1>Hello, World!</h1>
    <p>Start editing to see magic happen.</p>
  </div>
  <style>
    body { font-family: system-ui, sans-serif; padding: 2rem; background: #f0f0f0; }
    .container { background: white; padding: 2rem; border-radius: 8px; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
  </style>
</body>
</html>`
  }
];

export default function App() {
  // Load initial state from localStorage if available
  const [files, setFiles] = useState<VirtualFile[]>(() => {
    try {
      const saved = localStorage.getItem('devbrowser_files');
      return saved ? JSON.parse(saved) : INITIAL_FILES;
    } catch (e) {
      console.error("Failed to load files from storage", e);
      return INITIAL_FILES;
    }
  });

  const [activeFileName, setActiveFileName] = useState(() => {
    return localStorage.getItem('devbrowser_activeFile') || 'index.html';
  });

  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [iframeKey, setIframeKey] = useState(0); 
  const [layoutMode, setLayoutMode] = useState<LayoutMode>(LayoutMode.SPLIT);
  const [isConsoleOpen, setIsConsoleOpen] = useState(true);
  const [isAIOpen, setIsAIOpen] = useState(false);

  // Navigation & Git State
  const [activeSidebar, setActiveSidebar] = useState<SidebarView>('explorer');
  const [commits, setCommits] = useState<GitCommit[]>([]);

  // Save to localStorage whenever files change
  useEffect(() => {
    localStorage.setItem('devbrowser_files', JSON.stringify(files));
  }, [files]);

  // Save active file selection
  useEffect(() => {
    localStorage.setItem('devbrowser_activeFile', activeFileName);
  }, [activeFileName]);

  // Init Git
  useEffect(() => {
    if (commits.length === 0) {
      setCommits([{
        id: 'init',
        message: 'Initial Commit',
        timestamp: new Date().toLocaleTimeString(),
        files: JSON.parse(JSON.stringify(INITIAL_FILES))
      }]);
    }
  }, []);

  const activeFile = files.find(f => f.name === activeFileName) || files[0];

  // Determine which file is being previewed (Active HTML or fallback to index.html)
  const previewFile = useMemo(() => {
      if (activeFile?.language === 'html') return activeFile;
      return files.find(f => f.name === 'index.html');
  }, [activeFile, files]);

  // Update file content
  const updateFileContent = (newContent: string) => {
    setFiles(prev => prev.map(f => f.name === activeFileName ? { ...f, content: newContent } : f));
  };

  // Format Code Logic
  const handleFormat = async () => {
    if (!activeFile) return;

    try {
      let parser: string | undefined;
      let plugins: any[] = [];

      switch (activeFile.language) {
        case 'javascript':
        case 'typescript':
        case 'json':
          parser = activeFile.language === 'json' ? 'json' : 'babel';
          plugins = [parserBabel, parserEstree];
          break;
        case 'html':
          parser = 'html';
          plugins = [parserHtml, parserBabel, parserPostcss, parserEstree];
          break;
        case 'css':
          parser = 'css';
          plugins = [parserPostcss];
          break;
        case 'markdown':
          parser = 'markdown';
          plugins = [parserMarkdown, parserBabel, parserEstree]; 
          break;
      }

      if (parser) {
        const formatted = await format(activeFile.content, {
          parser,
          plugins,
          printWidth: 80,
          tabWidth: 2,
          semi: true,
          singleQuote: false,
        });
        updateFileContent(formatted);
        setLogs(prev => [...prev, {
            id: Date.now().toString(),
            timestamp: new Date().toLocaleTimeString(),
            level: 'success',
            message: `Formatted ${activeFile.name}`
        }]);
      }
    } catch (e: any) {
        setLogs(prev => [...prev, {
            id: Date.now().toString(),
            timestamp: new Date().toLocaleTimeString(),
            level: 'error',
            message: `Format error: ${e.message}`
        }]);
    }
  };

  // Git Operations
  const handleGitCommit = (message: string) => {
    const newCommit: GitCommit = {
      id: Date.now().toString(),
      message,
      timestamp: new Date().toLocaleTimeString(),
      files: JSON.parse(JSON.stringify(files)) // Deep copy
    };
    setCommits(prev => [newCommit, ...prev]); // Prepend to show latest first
  };

  const handleGitCheckout = (commitId: string) => {
    const commit = commits.find(c => c.id === commitId);
    if (commit) {
      setFiles(JSON.parse(JSON.stringify(commit.files)));
      // If active file is gone, reset to first
      if (!commit.files.find(f => f.name === activeFileName)) {
        setActiveFileName(commit.files[0]?.name || '');
      }
    }
  };

  // Calculate uncommitted changes count for badge
  const uncommittedChangesCount = useMemo(() => {
    const head = commits[0];
    if (!head) return files.filter(f => f.type !== 'directory').length;
    let count = 0;
    // Modified & Added (ignore directories)
    files.filter(f => f.type !== 'directory').forEach(f => {
      const prev = head.files.find(pf => pf.name === f.name);
      if (!prev || prev.content !== f.content) count++;
    });
    // Deleted (ignore directories)
    head.files.filter(f => f.type !== 'directory').forEach(pf => {
      if (!files.find(f => f.name === pf.name)) count++;
    });
    return count;
  }, [files, commits]);

  // File Operations
  const handleCreateFile = (name: string) => {
    if (files.some(f => f.name === name)) return;
    const ext = name.split('.').pop();
    let lang: VirtualFile['language'] = 'text';
    if (ext === 'html') lang = 'html';
    else if (ext === 'css') lang = 'css';
    else if (ext === 'js') lang = 'javascript';
    else if (ext === 'json') lang = 'json';

    setFiles(prev => [...prev, { name, content: '', language: lang, type: 'file' }]);
    setActiveFileName(name);
  };

  const handleCreateFolder = (name: string) => {
    if (files.some(f => f.name === name)) return;
    setFiles(prev => [...prev, { name, content: '', language: 'text', type: 'directory' }]);
  };

  const handleDeleteFile = (name: string) => {
    // Delete file and any children if it's a directory
    const newFiles = files.filter(f => f.name !== name && !f.name.startsWith(name + '/'));
    setFiles(newFiles);
    if (activeFileName === name || activeFileName.startsWith(name + '/')) {
        // Fallback to first available file
        const firstFile = newFiles.find(f => f.type === 'file');
        if (firstFile) setActiveFileName(firstFile.name);
        else setActiveFileName('');
    }
  };

  const handleRenameFile = (oldName: string, newName: string) => {
      if (files.some(f => f.name === newName)) {
          alert("Path already exists");
          return;
      }
      setFiles(prev => prev.map(f => {
          if (f.name === oldName) return { ...f, name: newName };
          if (f.name.startsWith(oldName + '/')) {
              return { ...f, name: f.name.replace(oldName + '/', newName + '/') };
          }
          return f;
      }));

      if (activeFileName === oldName) setActiveFileName(newName);
      else if (activeFileName.startsWith(oldName + '/')) {
          setActiveFileName(activeFileName.replace(oldName + '/', newName + '/'));
      }
  };

  // Handle messages from iframe
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'console') {
        const newLog: LogEntry = {
          id: Date.now().toString() + Math.random(),
          timestamp: new Date().toLocaleTimeString(),
          level: event.data.level,
          message: event.data.message.map((m: any) => 
            typeof m === 'object' ? JSON.stringify(m) : String(m)
          ).join(' ')
        };
        setLogs(prev => [...prev, newLog]);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const runCode = useCallback(() => {
    setLogs([]); 
    setIframeKey(prev => prev + 1);
  }, []);

  const clearLogs = () => setLogs([]);

  // Console Command Handler
  const handleConsoleCommand = (cmd: string) => {
    const args = cmd.trim().split(/\s+/);
    const command = args[0];
    const params = args.slice(1);

    // Log the user's command
    setLogs(prev => [...prev, {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString(),
      level: 'command',
      message: `> ${cmd}`
    }]);

    let output = '';
    let level: LogEntry['level'] = 'info';

    switch(command) {
        case 'help':
            output = 'Available commands: ls, cat <file>, touch <file>, mkdir <folder>, rm <path>, echo <text>, clear, pwd';
            break;
        case 'ls':
            output = files.map(f => `${f.name}${f.type === 'directory' ? '/' : ''}`).join('  ');
            break;
        case 'pwd':
            output = '/';
            break;
        case 'cat':
            if (!params[0]) {
                output = 'Usage: cat <filename>';
                level = 'error';
            } else {
                const f = files.find(file => file.name === params[0] && file.type !== 'directory');
                if (f) output = f.content;
                else {
                    output = `File not found: ${params[0]}`;
                    level = 'error';
                }
            }
            break;
        case 'touch':
            if (!params[0]) {
                output = 'Usage: touch <filename>';
                level = 'error';
            } else if (files.some(f => f.name === params[0])) {
                output = `File already exists: ${params[0]}`;
                level = 'warn';
            } else {
                handleCreateFile(params[0]);
                output = `Created ${params[0]}`;
                level = 'success';
            }
            break;
        case 'mkdir':
            if (!params[0]) {
                output = 'Usage: mkdir <foldername>';
                level = 'error';
            } else if (files.some(f => f.name === params[0])) {
                output = `Directory already exists: ${params[0]}`;
                level = 'warn';
            } else {
                handleCreateFolder(params[0]);
                output = `Created directory ${params[0]}`;
                level = 'success';
            }
            break;
        case 'rm':
            if (!params[0]) {
                output = 'Usage: rm <path>';
                level = 'error';
            } else if (!files.some(f => f.name === params[0])) {
                output = `Path not found: ${params[0]}`;
                level = 'error';
            } else {
                handleDeleteFile(params[0]);
                output = `Removed ${params[0]}`;
                level = 'success';
            }
            break;
        case 'echo':
            output = params.join(' ');
            break;
        case 'clear':
            setLogs([]);
            return;
        default:
            output = `Command not found: ${command}`;
            level = 'error';
    }

    if (output) {
        setLogs(prev => [...prev, {
            id: Date.now().toString() + 'r',
            timestamp: new Date().toLocaleTimeString(),
            level,
            message: output
        }]);
    }
  };

  // Bundler Logic: Inject CSS/JS into HTML with path resolution
  const getSrcDoc = () => {
    if (!previewFile) return "<html><body style='font-family: sans-serif; padding: 2rem; color: #888; background: #fafafa;'><h1>No HTML file found</h1><p>Create an <code>index.html</code> file to see a preview.</p></body></html>";

    let html = previewFile.content;
    const basePath = previewFile.name; // e.g. "pages/about.html"

    // Helper to resolve paths like "../style.css" relative to "pages/about.html"
    const resolvePath = (relPath: string) => {
        if (relPath.startsWith('http') || relPath.startsWith('//')) return null; // External
        if (relPath.startsWith('/')) return relPath.slice(1); // Absolute

        const stack = basePath.split('/');
        stack.pop(); // Remove filename, leave dir

        const parts = relPath.split('/');
        for (const part of parts) {
            if (part === '.') continue;
            if (part === '..') {
                if (stack.length > 0) stack.pop();
            } else {
                stack.push(part);
            }
        }
        return stack.join('/');
    };

    // Replace <link rel="stylesheet"> with inline styles
    html = html.replace(/<link\s+[^>]*rel="stylesheet"[^>]*>/g, (match) => {
      const hrefMatch = match.match(/href="([^"]+)"/);
      if (!hrefMatch) return match;

      const href = hrefMatch[1];
      const resolvedPath = resolvePath(href);
      if (!resolvedPath) return match; // Leave external links alone

      const cssFile = files.find(f => f.name === resolvedPath);
      return cssFile ? `<style>/* ${resolvedPath} */\n${cssFile.content}</style>` : match;
    });

    // Replace <script src="..."> with inline scripts
    html = html.replace(/<script\s+[^>]*src="([^"]+)"[^>]*><\/script>/g, (match, src) => {
      const resolvedPath = resolvePath(src);
      if (!resolvedPath) return match;

      const jsFile = files.find(f => f.name === resolvedPath);
      return jsFile ? `<script>/* ${resolvedPath} */\n${jsFile.content}</script>` : match;
    });

    const consoleHijack = `
      <script>
        const originalLog = console.log;
        const originalWarn = console.warn;
        const originalError = console.error;
        const originalInfo = console.info;

        function sendToParent(level, args) {
          try {
            window.parent.postMessage({
              type: 'console',
              level: level,
              message: Array.from(args).map(a => {
                  if (a instanceof Error) return a.toString();
                  return a;
              })
            }, '*');
          } catch(e) {}
        }

        console.log = function(...args) { originalLog.apply(console, args); sendToParent('log', args); };
        console.warn = function(...args) { originalWarn.apply(console, args); sendToParent('warn', args); };
        console.error = function(...args) { originalError.apply(console, args); sendToParent('error', args); };
        console.info = function(...args) { originalInfo.apply(console, args); sendToParent('info', args); };

        window.onerror = function(msg, url, line) {
           sendToParent('error', [msg + " (Line " + line + ")"]);
        }
      </script>
    `;

    if (html.includes('</body>')) {
      return html.replace('</body>', `${consoleHijack}</body>`);
    }
    return html + consoleHijack;
  };

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Bar */}
      <div className="flex flex-col">
        {/* Tab Bar / Header */}
        <div className="flex items-center h-10 px-2 bg-browser-bg border-b border-browser-toolbar select-none justify-between">
           <div className="flex items-center gap-2">
              <div className="flex gap-1.5 px-3">
                 <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
              </div>
              <span className="text-xs font-semibold text-gray-500 ml-2">Deploy Studio</span>
           </div>

           <div className="flex items-center gap-2">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className="p-1.5 hover:bg-white/10 rounded text-gray-400 hover:text-white transition"
                 title="Toggle Split View"
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={16} /> : <SplitSquareHorizontal size={16} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1.5 rounded transition-colors ${isAIOpen ? 'text-browser-accent bg-blue-500/10' : 'text-gray-400 hover:text-white hover:bg-white/10'}`}
                 title="Toggle AI Assistant"
              >
                <Sparkles size={16} />
              </button>
           </div>
        </div>

        {/* Address Bar */}
        <AddressBar url={`localhost:3000/${previewFile ? previewFile.name : 'index.html'}`} onRefresh={runCode} />
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Activity Bar (Leftmost) */}
        <ActivityBar 
            activeView={activeSidebar} 
            onViewChange={setActiveSidebar} 
            changesCount={uncommittedChangesCount}
        />

        {/* Sidebar Content (Dynamic) */}
        {activeSidebar === 'explorer' && (
            <FileExplorer 
              files={files} 
              activeFileName={activeFileName} 
              onSelect={setActiveFileName} 
              onCreate={handleCreateFile}
              onCreateFolder={handleCreateFolder}
              onDelete={(name) => { if(confirm(`Delete ${name}?`)) handleDeleteFile(name); }}
              onRename={handleRenameFile}
            />
        )}
        {activeSidebar === 'search' && (
            <Search 
              files={files} 
              onSelect={setActiveFileName} 
            />
        )}
        {activeSidebar === 'git' && (
            <SourceControl 
                files={files} 
                commits={commits} 
                onCommit={handleGitCommit}
                onCheckout={handleGitCheckout}
            />
        )}
        {activeSidebar === 'deploy' && (
            <Deployment files={files} />
        )}

        {/* Editor Pane */}
        <div className={`flex flex-col border-r border-gray-800 transition-all duration-300 ${
            layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-0 overflow-hidden'
        }`}>
          {/* Editor Header */}
          <div className="h-9 bg-[#1e1e1e] border-b border-gray-800 flex items-center px-4 text-xs">
             <Code2 size={14} className="text-blue-500 mr-2" />
             <span className="text-gray-300">{activeFileName}</span>

             <div className="ml-auto flex items-center gap-4">
                 <button 
                    onClick={handleFormat} 
                    className="flex items-center gap-1.5 text-gray-500 hover:text-white transition-colors"
                    title="Format Code"
                 >
                     <AlignLeft size={14} />
                     <span className="hidden sm:inline">Format</span>
                 </button>
                 <span className="text-gray-600">{activeFile?.content.length || 0} chars</span>
             </div>
          </div>

          <textarea
            className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed"
            value={activeFile?.content || ''}
            onChange={(e) => updateFileContent(e.target.value)}
            spellCheck={false}
          />
        </div>

        {/* Preview Pane */}
        <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${
             layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'
        }`}>
          <iframe
            key={iframeKey}
            title="Preview"
            srcDoc={getSrcDoc()}
            className="w-full h-full border-none"
            sandbox="allow-scripts allow-modals allow-forms allow-same-origin"
          />
        </div>

        {/* AI Sidebar Overlay */}
        <AIAssistant 
          currentCode={activeFile?.content || ''} 
          isOpen={isAIOpen} 
          onClose={() => setIsAIOpen(false)} 
          onUpdateCode={(code) => updateFileContent(code)}
        />
      </div>

      {/* Console (Fixed at Bottom) */}
      <Console 
        logs={logs} 
        onClear={clearLogs} 
        isOpen={isConsoleOpen} 
        toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} 
        onCommand={handleConsoleCommand}
      />
    </div>
  );
}

import { GoogleGenAI, Modality, Type, FunctionDeclaration, LiveServerMessage } from "@google/genai";

// -- Helpers --

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key is missing");
  return new GoogleGenAI({ apiKey });
};

const getPaidClient = async () => {
  // @ts-ignore
  if (window.aistudio && window.aistudio.hasSelectedApiKey && window.aistudio.openSelectKey) {
     // @ts-ignore
     const hasKey = await window.aistudio.hasSelectedApiKey();
     if (!hasKey) {
         // @ts-ignore
         await window.aistudio.openSelectKey();
     }
  }
  // Create new instance to pick up the injected key
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// -- Chat & Text Features --

export const chatWithGemini = async (
  prompt: string, 
  mode: 'standard' | 'thinking' | 'search' | 'maps' | 'fast',
  attachments: { base64: string, mimeType: string }[] = [],
  contextCode?: string
) => {
  const ai = getClient();
  let model = 'gemini-3-flash-preview'; // Default for standard chat
  const config: any = {
    systemInstruction: contextCode 
      ? `You are an expert developer assistant. Current code context:\n\`\`\`\n${contextCode}\n\`\`\`` 
      : 'You are a helpful AI assistant.',
  };

  if (mode === 'fast') {
    model = 'gemini-2.5-flash-lite-latest';
  } else if (mode === 'thinking') {
    model = 'gemini-3-pro-preview';
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else if (mode === 'search') {
    model = 'gemini-3-pro-preview'; // Pro is better for search integration
    config.tools = [{ googleSearch: {} }];
  } else if (mode === 'maps') {
    model = 'gemini-2.5-flash'; // Maps currently supported on 2.5 Flash
    config.tools = [{ googleMaps: {} }];
    // Try to get location
    try {
      const pos: any = await new Promise((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(resolve, reject, { timeout: 5000 });
      });
      config.toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: pos.coords.latitude,
            longitude: pos.coords.longitude
          }
        }
      };
    } catch (e) {
      console.warn("Could not get location for Maps grounding");
    }
  }

  // Handle attachments
  let parts: any[] = [];

  if (attachments.length > 0) {
    // If audio is present, use Flash (multimodal efficiency)
    if (attachments.some(a => a.mimeType.startsWith('audio/'))) {
      model = 'gemini-2.5-flash-native-audio-preview-12-2025';
    } else if (attachments.some(a => a.mimeType.startsWith('image/')) && mode === 'standard') {
        // Use Pro for better image reasoning if in standard mode
        model = 'gemini-3-pro-preview';
    }

    parts = attachments.map(a => ({
      inlineData: {
        data: a.base64,
        mimeType: a.mimeType
      }
    }));
  }

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model,
    contents: { parts },
    config
  });

  // Extract grounding metadata if present
  let text = response.text || "";
  const grounding = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (grounding) {
    const links = grounding
      .map((c: any) => c.web?.uri ? `[${c.web.title}](${c.web.uri})` : c.maps?.uri ? `[${c.maps.title}](${c.maps.uri})` : '')
      .filter(Boolean)
      .join('\n');
    if (links) text += `\n\nSources:\n${links}`;
  }

  return text;
};

// -- Audio Features --

export const transcribeAudio = async (audioBase64: string) => {
  const ai = getClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    contents: {
      parts: [
        { inlineData: { mimeType: 'audio/wav', data: audioBase64 } },
        { text: "Transcribe this audio." }
      ]
    }
