export default function App() {
  // Load initial state from localStorage if available
  const [files, setFiles] = useState<VirtualFile[]>(() => {
    try {
      const saved = localStorage.getItem('devbrowser_files');
      return saved ? JSON.parse(saved) : INITIAL_FILES;
    } catch (e) {
      console.error("Failed to load files from storage", e);
      return INITIAL_FILES;
    }
  });

  const [activeFileName, setActiveFileName] = useState(() => {
    return localStorage.getItem('devbrowser_activeFile') || 'index.html';
  });

  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [layoutMode, setLayoutMode] = useState<LayoutMode>(LayoutMode.SPLIT);
  const [isConsoleOpen, setIsConsoleOpen] = useState(true);
  const [isAIOpen, setIsAIOpen] = useState(false);

  // Navigation & Git State
  const [activeSidebar, setActiveSidebar] = useState<SidebarView>('explorer');
  const [commits, setCommits] = useState<GitCommit[]>([]);

  // -- TAB STATE --
  const [tabs, setTabs] = useState<Tab[]>([
      { id: '1', title: 'Local Preview', type: 'preview', url: 'localhost:3000/index.html', loading: false }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('1');

  // Save to localStorage whenever files change
  useEffect(() => {
    localStorage.setItem('devbrowser_files', JSON.stringify(files));
  }, [files]);

  // Save active file selection
  useEffect(() => {
    localStorage.setItem('devbrowser_activeFile', activeFileName);
  }, [activeFileName]);

  // Init Git
  useEffect(() => {
    if (commits.length === 0) {
      setCommits([{
        id: 'init',
        message: 'Initial Commit',
        timestamp: new Date().toLocaleTimeString(),
        files: JSON.parse(JSON.stringify(INITIAL_FILES))
      }]);
    }
  }, []);

  const activeFile = files.find(f => f.name === activeFileName) || files[0];
  const activeTab = tabs.find(t => t.id === activeTabId) || tabs[0];

  // Determine which file is being previewed (Active HTML or fallback to index.html)
  const previewFile = useMemo(() => {
      if (activeFile?.language === 'html') return activeFile;
      return files.find(f => f.name === 'index.html');
  }, [activeFile, files]);

  // Update file content
  const updateFileContent = (newContent: string) => {
    setFiles(prev => prev.map(f => f.name === activeFileName ? { ...f, content: newContent } : f));
  };

  // Format Code Logic
  const handleFormat = async () => {
    if (!activeFile) return;
    try {
      let parser: string | undefined;
      let plugins: any[] = [];
      switch (activeFile.language) {
        case 'javascript': case 'typescript': case 'json':
          parser = activeFile.language === 'json' ? 'json' : 'babel';
          plugins = [parserBabel, parserEstree];
          break;
        case 'html':
          parser = 'html'; plugins = [parserHtml, parserBabel, parserPostcss, parserEstree];
          break;
        case 'css':
          parser = 'css'; plugins = [parserPostcss];
          break;
        case 'markdown':
          parser = 'markdown'; plugins = [parserMarkdown, parserBabel, parserEstree]; 
          break;
      }
      if (parser) {
        const formatted = await format(activeFile.content, { parser, plugins, printWidth: 80, tabWidth: 2, semi: true, singleQuote: false });
        updateFileContent(formatted);
        setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'success', message: `Formatted ${activeFile.name}` }]);
      }
    } catch (e: any) {
        setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'error', message: `Format error: ${e.message}` }]);
    }
  };

  // Git Operations
  const handleGitCommit = (message: string) => {
    const newCommit: GitCommit = { id: Date.now().toString(), message, timestamp: new Date().toLocaleTimeString(), files: JSON.parse(JSON.stringify(files)) };
    setCommits(prev => [newCommit, ...prev]);
  };

  const handleGitCheckout = (commitId: string) => {
    const commit = commits.find(c => c.id === commitId);
    if (commit) {
      setFiles(JSON.parse(JSON.stringify(commit.files)));
      if (!commit.files.find(f => f.name === activeFileName)) {
        setActiveFileName(commit.files[0]?.name || '');
      }
    }
  };

  // Calculate uncommitted changes
  const uncommittedChangesCount = useMemo(() => {
    const head = commits[0];
    if (!head) return files.filter(f => f.type !== 'directory').length;
    let count = 0;
    files.filter(f => f.type !== 'directory').forEach(f => {
      const prev = head.files.find(pf => pf.name === f.name);
      if (!prev || prev.content !== f.content) count++;
    });
    head.files.filter(f => f.type !== 'directory').forEach(pf => {
      if (!files.find(f => f.name === pf.name)) count++;
    });
    return count;
  }, [files, commits]);

  // File Operations
  const handleCreateFile = (name: string) => {
    if (files.some(f => f.name === name)) return;
    const ext = name.split('.').pop();
    let lang: VirtualFile['language'] = 'text';
    if (ext === 'html') lang = 'html'; else if (ext === 'css') lang = 'css'; else if (ext === 'js') lang = 'javascript'; else if (ext === 'json') lang = 'json';
    setFiles(prev => [...prev, { name, content: '', language: lang, type: 'file' }]);
    setActiveFileName(name);
  };

  const handleCreateFolder = (name: string) => {
    if (files.some(f => f.name === name)) return;
    setFiles(prev => [...prev, { name, content: '', language: 'text', type: 'directory' }]);
  };

  const handleDeleteFile = (name: string) => {
    const newFiles = files.filter(f => f.name !== name && !f.name.startsWith(name + '/'));
    setFiles(newFiles);
    if (activeFileName === name || activeFileName.startsWith(name + '/')) {
        const firstFile = newFiles.find(f => f.type === 'file');
        setActiveFileName(firstFile ? firstFile.name : '');
    }
  };

  const handleRenameFile = (oldName: string, newName: string) => {
      if (files.some(f => f.name === newName)) { alert("Path already exists"); return; }
      setFiles(prev => prev.map(f => {
          if (f.name === oldName) return { ...f, name: newName };
          if (f.name.startsWith(oldName + '/')) return { ...f, name: f.name.replace(oldName + '/', newName + '/') };
          return f;
      }));
      if (activeFileName === oldName) setActiveFileName(newName);
      else if (activeFileName.startsWith(oldName + '/')) setActiveFileName(activeFileName.replace(oldName + '/', newName + '/'));
  };

  // Tab Operations
  const handleNewTab = () => {
      const newId = Date.now().toString();
      setTabs(prev => [...prev, { id: newId, title: 'New Tab', type: 'browser', url: '', loading: false }]);
      setActiveTabId(newId);
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      const newTabs = tabs.filter(t => t.id !== id);
      if (newTabs.length === 0) {
           // Always keep one tab
           setTabs([{ id: Date.now().toString(), title: 'New Tab', type: 'browser', url: '', loading: false }]);
      } else {
           setTabs(newTabs);
           if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
      }
  };

  const handleNavigate = async (inputUrl: string) => {
     let url = inputUrl.trim();

     // 1. Localhost Case
     if (!url || url.includes('localhost')) {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, type: 'preview', url: `localhost:3000/${previewFile?.name || ''}`, title: 'Local Preview', loading: false } : t));
         return;
     }

     // 2. Search/Web Case
     setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, type: 'browser', url: url, title: url, loading: true } : t));

     try {
         const results = await searchWeb(url);
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, content: results, title: url } : t));
     } catch (e) {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, content: [], title: 'Error' } : t));
     }
  };

  // Handle messages from iframe (console)
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'console') {
        const newLog: LogEntry = {
          id: Date.now().toString() + Math.random(),
          timestamp: new Date().toLocaleTimeString(),
          level: event.data.level,
          message: event.data.message.map((m: any) => typeof m === 'object' ? JSON.stringify(m) : String(m)).join(' ')
        };
        setLogs(prev => [...prev, newLog]);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const clearLogs = () => setLogs([]);

  // Console Command Handler
  const handleConsoleCommand = (cmd: string) => { /* Same as before */ };

  // Bundler Logic: Inject CSS/JS into HTML with path resolution
  const getSrcDoc = () => {
    if (!previewFile) return "";
    let html = previewFile.content;
    const basePath = previewFile.name;
    const resolvePath = (relPath: string) => {
        if (relPath.startsWith('http') || relPath.startsWith('//')) return null;
        if (relPath.startsWith('/')) return relPath.slice(1);
        const stack = basePath.split('/'); stack.pop();
        const parts = relPath.split('/');
        for (const part of parts) { if (part === '.') continue; if (part === '..') { if (stack.length > 0) stack.pop(); } else { stack.push(part); } }
        return stack.join('/');
    };
    html = html.replace(/<link\s+[^>]*rel="stylesheet"[^>]*>/g, (match) => {
      const hrefMatch = match.match(/href="([^"]+)"/); if (!hrefMatch) return match;
      const resolvedPath = resolvePath(hrefMatch[1]); if (!resolvedPath) return match;
      const cssFile = files.find(f => f.name === resolvedPath); return cssFile ? `<style>/* ${resolvedPath} */\n${cssFile.content}</style>` : match;
    });
    html = html.replace(/<script\s+[^>]*src="([^"]+)"[^>]*><\/script>/g, (match, src) => {
      const resolvedPath = resolvePath(src); if (!resolvedPath) return match;
      const jsFile = files.find(f => f.name === resolvedPath); return jsFile ? `<script>/* ${resolvedPath} */\n${jsFile.content}</script>` : match;
    });
    const consoleHijack = `<script>
        const originalLog = console.log; const originalWarn = console.warn; const originalError = console.error; const originalInfo = console.info;
        function sendToParent(level, args) { try { window.parent.postMessage({ type: 'console', level: level, message: Array.from(args).map(a => { if (a instanceof Error) return a.toString(); return a; }) }, '*'); } catch(e) {} }
        console.log = function(...args) { originalLog.apply(console, args); sendToParent('log', args); };
        console.warn = function(...args) { originalWarn.apply(console, args); sendToParent('warn', args); };
        console.error = function(...args) { originalError.apply(console, args); sendToParent('error', args); };
        console.info = function(...args) { originalInfo.apply(console, args); sendToParent('info', args); };
        window.onerror = function(msg, url, line) { sendToParent('error', [msg + " (Line " + line + ")"]); }
      </script>`;
    if (html.includes('</body>')) { return html.replace('</body>', `${consoleHijack}</body>`); }
    return html + consoleHijack;
  };

  const srcDoc = useMemo(() => getSrcDoc(), [files, previewFile]);

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Bar / Tab Strip */}
      <div className="flex items-end h-10 px-2 bg-browser-bg border-b border-browser-toolbar select-none gap-2 pt-2">
           {/* Controls */}
           <div className="flex items-center gap-2 mb-2 mr-2">
              <div className="flex gap-1.5 px-2">
                 <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
              </div>
           </div>

           {/* Tab Strip */}
           <div className="flex-1 flex overflow-x-auto no-scrollbar items-end h-full">
               {tabs.map(tab => (
                   <div 
                      key={tab.id}
                      onClick={() => setActiveTabId(tab.id)}
                      className={`
                        group relative flex items-center gap-2 px-3 py-1.5 min-w-[120px] max-w-[200px] text-xs rounded-t-lg cursor-default border-r border-gray-800/50 transition-colors
                        ${activeTabId === tab.id ? 'bg-[#3c3c3c] text-white' : 'bg-transparent text-gray-500 hover:bg-[#2d2d2d]'}
                      `}
                   >
                       {tab.type === 'preview' ? <Lock size={10} className="text-green-500" /> : <Globe size={10} className="text-blue-400" />}
                       <span className="truncate flex-1">{tab.title || 'New Tab'}</span>
                       <button 
                         onClick={(e) => handleCloseTab(tab.id, e)}
                         className={`p-0.5 rounded-full hover:bg-white/20 opacity-0 group-hover:opacity-100 ${tabs.length === 1 ? 'hidden' : ''}`}
                       >
                           <X size={10} />
                       </button>
                   </div>
               ))}
               <button onClick={handleNewTab} className="p-1.5 ml-1 text-gray-500 hover:text-white hover:bg-white/10 rounded mb-1">
                   <Plus size={14} />
               </button>
           </div>

           {/* Window Controls */}
           <div className="flex items-center gap-2 mb-1.5">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className="p-1.5 hover:bg-white/10 rounded text-gray-400 hover:text-white transition"
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={16} /> : <SplitSquareHorizontal size={16} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1.5 rounded transition-colors ${isAIOpen ? 'text-browser-accent bg-blue-500/10' : 'text-gray-400 hover:text-white hover:bg-white/10'}`}
              >
                <Sparkles size={16} />
              </button>
           </div>
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Activity Bar */}
        <ActivityBar activeView={activeSidebar} onViewChange={setActiveSidebar} changesCount={uncommittedChangesCount} />

        {/* Sidebar Content */}
        {activeSidebar === 'explorer' && (
            <FileExplorer 
              files={files} activeFileName={activeFileName} onSelect={setActiveFileName} 
              onCreate={handleCreateFile} onCreateFolder={handleCreateFolder} 
              onDelete={(name) => { if(confirm(`Delete ${name}?`)) handleDeleteFile(name); }} onRename={handleRenameFile}
            />
        )}
        {activeSidebar === 'search' && <Search files={files} onSelect={setActiveFileName} />}
        {activeSidebar === 'git' && <SourceControl files={files} commits={commits} onCommit={handleGitCommit} onCheckout={handleGitCheckout} />}
        {activeSidebar === 'deploy' && <Deployment files={files} />}

        {/* Editor Pane (Left) */}
        <div className={`flex flex-col border-r border-gray-800 transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-0 overflow-hidden'}`}>
          <div className="h-9 bg-[#1e1e1e] border-b border-gray-800 flex items-center px-4 text-xs">
             <Code2 size={14} className="text-blue-500 mr-2" />
             <span className="text-gray-300">{activeFileName}</span>
             <div className="ml-auto flex items-center gap-4">
                 <button onClick={handleFormat} className="flex items-center gap-1.5 text-gray-500 hover:text-white"><AlignLeft size={14} /><span className="hidden sm:inline">Format</span></button>
             </div>
          </div>
          <textarea
            className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed"
            value={activeFile?.content || ''}
            onChange={(e) => updateFileContent(e.target.value)}
            spellCheck={false}
          />
        </div>

        {/* Browser Pane (Right) - Tab Content */}
        <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'}`}>
          <AddressBar 
              url={activeTab.url} 
              onNavigate={handleNavigate} 
              onRefresh={() => setIframeKey(k => k + 1)} 
              isLoading={activeTab.loading}
          />
          <div className="flex-1 relative overflow-hidden bg-[#1e1e1e]">
              <BrowserTab key={activeTab.id} tab={activeTab} srcDoc={srcDoc} />
          </div>
        </div>

        {/* AI Sidebar */}
        <AIAssistant currentCode={activeFile?.content || ''} isOpen={isAIOpen} onClose={() => setIsAIOpen(false)} onUpdateCode={updateFileContent} />
      </div>

      <Console logs={logs} onClear={clearLogs} isOpen={isConsoleOpen} toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} onCommand={handleConsoleCommand} />
    </div>
  );
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Code2, SplitSquareHorizontal, Maximize2, Sparkles, Layout, AlignLeft, Plus, X, Globe, Lock } from 'lucide-react';
import { LogEntry, LayoutMode, VirtualFile, GitCommit, SidebarView, Tab } from './types';
import Console from './components/Console';
import AddressBar from './components/AddressBar';
import AIAssistant from './components/AIAssistant';
import FileExplorer from './components/FileExplorer';
import SourceControl from './components/SourceControl';
import Deployment from './components/Deployment';
import ActivityBar from './components/ActivityBar';
import Search from './components/Search';
import BrowserTab from './components/BrowserTab';
import { searchWeb } from './services/geminiService';

// Prettier Imports
import { format } from "prettier/standalone";
import parserBabel from "prettier/plugins/babel";
import parserEstree from "prettier/plugins/estree";
import parserHtml from "prettier/plugins/html";
import parserPostcss from "prettier/plugins/postcss";
import parserMarkdown from "prettier/plugins/markdown";

// Initial Empty Project
const INITIAL_FILES: VirtualFile[] = [
  {
    name: 'index.html',
    language: 'html',
    type: 'file',
    content: `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>New Project</title>
</head>
<body>
  <div class="container">
    <h1>Hello, World!</h1>
    <p>Start editing to see magic happen.</p>
  </div>
  <style>
    body { font-family: system-ui, sans-serif; padding: 2rem; background: #f0f0f0; }
    .container { background: white; padding: 2rem; border-radius: 8px; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
  </style>
</body>
</html>`
  }
];

export default function App() {
  // Load initial state from localStorage if available
  const [files, setFiles] = useState<VirtualFile[]>(() => {
    try {
      const saved = localStorage.getItem('devbrowser_files');
      return saved ? JSON.parse(saved) : INITIAL_FILES;
    } catch (e) {
      console.error("Failed to load files from storage", e);
      return INITIAL_FILES;
    }
  });

  const [activeFileName, setActiveFileName] = useState(() => {
    return localStorage.getItem('devbrowser_activeFile') || 'index.html';
  });

  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [layoutMode, setLayoutMode] = useState<LayoutMode>(LayoutMode.SPLIT);
  const [isConsoleOpen, setIsConsoleOpen] = useState(true);
  const [isAIOpen, setIsAIOpen] = useState(false);

  // Navigation & Git State
  const [activeSidebar, setActiveSidebar] = useState<SidebarView>('explorer');
  const [commits, setCommits] = useState<GitCommit[]>([]);

  // -- TAB STATE --
  const [tabs, setTabs] = useState<Tab[]>([
      { id: '1', title: 'Local Preview', type: 'preview', url: 'localhost:3000/index.html', loading: false }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('1');
  const [iframeKey, setIframeKey] = useState(0);

  // Save to localStorage whenever files change
  useEffect(() => {
    localStorage.setItem('devbrowser_files', JSON.stringify(files));
  }, [files]);

  // Save active file selection
  useEffect(() => {
    localStorage.setItem('devbrowser_activeFile', activeFileName);
  }, [activeFileName]);

  // Init Git
  useEffect(() => {
    if (commits.length === 0) {
      setCommits([{
        id: 'init',
        message: 'Initial Commit',
        timestamp: new Date().toLocaleTimeString(),
        files: JSON.parse(JSON.stringify(INITIAL_FILES))
      }]);
    }
  }, []);

  const activeFile = files.find(f => f.name === activeFileName) || files[0];
  const activeTab = tabs.find(t => t.id === activeTabId) || tabs[0];

  // Determine which file is being previewed (Active HTML or fallback to index.html)
  const previewFile = useMemo(() => {
      if (activeFile?.language === 'html') return activeFile;
      return files.find(f => f.name === 'index.html');
  }, [activeFile, files]);

  // Update file content
  const updateFileContent = (newContent: string) => {
    setFiles(prev => prev.map(f => f.name === activeFileName ? { ...f, content: newContent } : f));
  };

  // Format Code Logic
  const handleFormat = async () => {
    if (!activeFile) return;
    try {
      let parser: string | undefined;
      let plugins: any[] = [];
      switch (activeFile.language) {
        case 'javascript': case 'typescript': case 'json':
          parser = activeFile.language === 'json' ? 'json' : 'babel';
          plugins = [parserBabel, parserEstree];
          break;
        case 'html':
          parser = 'html'; plugins = [parserHtml, parserBabel, parserPostcss, parserEstree];
          break;
        case 'css':
          parser = 'css'; plugins = [parserPostcss];
          break;
        case 'markdown':
          parser = 'markdown'; plugins = [parserMarkdown, parserBabel, parserEstree]; 
          break;
      }
      if (parser) {
        const formatted = await format(activeFile.content, { parser, plugins, printWidth: 80, tabWidth: 2, semi: true, singleQuote: false });
        updateFileContent(formatted);
        setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'success', message: `Formatted ${activeFile.name}` }]);
      }
    } catch (e: any) {
        setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'error', message: `Format error: ${e.message}` }]);
    }
  };

  // Git Operations
  const handleGitCommit = (message: string) => {
    const newCommit: GitCommit = { id: Date.now().toString(), message, timestamp: new Date().toLocaleTimeString(), files: JSON.parse(JSON.stringify(files)) };
    setCommits(prev => [newCommit, ...prev]);
  };

  const handleGitCheckout = (commitId: string) => {
    const commit = commits.find(c => c.id === commitId);
    if (commit) {
      setFiles(JSON.parse(JSON.stringify(commit.files)));
      if (!commit.files.find(f => f.name === activeFileName)) {
        setActiveFileName(commit.files[0]?.name || '');
      }
    }
  };

  // Calculate uncommitted changes
  const uncommittedChangesCount = useMemo(() => {
    const head = commits[0];
    if (!head) return files.filter(f => f.type !== 'directory').length;
    let count = 0;
    files.filter(f => f.type !== 'directory').forEach(f => {
      const prev = head.files.find(pf => pf.name === f.name);
      if (!prev || prev.content !== f.content) count++;
    });
    head.files.filter(f => f.type !== 'directory').forEach(pf => {
      if (!files.find(f => f.name === pf.name)) count++;
    });
    return count;
  }, [files, commits]);

  // File Operations
  const handleCreateFile = (name: string) => {
    if (files.some(f => f.name === name)) return;
    const ext = name.split('.').pop();
    let lang: VirtualFile['language'] = 'text';
    if (ext === 'html') lang = 'html'; else if (ext === 'css') lang = 'css'; else if (ext === 'js') lang = 'javascript'; else if (ext === 'json') lang = 'json';
    setFiles(prev => [...prev, { name, content: '', language: lang, type: 'file' }]);
    setActiveFileName(name);
  };

  const handleCreateFolder = (name: string) => {
    if (files.some(f => f.name === name)) return;
    setFiles(prev => [...prev, { name, content: '', language: 'text', type: 'directory' }]);
  };

  const handleDeleteFile = (name: string) => {
    const newFiles = files.filter(f => f.name !== name && !f.name.startsWith(name + '/'));
    setFiles(newFiles);
    if (activeFileName === name || activeFileName.startsWith(name + '/')) {
        const firstFile = newFiles.find(f => f.type === 'file');
        setActiveFileName(firstFile ? firstFile.name : '');
    }
  };

  const handleRenameFile = (oldName: string, newName: string) => {
      if (files.some(f => f.name === newName)) { alert("Path already exists"); return; }
      setFiles(prev => prev.map(f => {
          if (f.name === oldName) return { ...f, name: newName };
          if (f.name.startsWith(oldName + '/')) return { ...f, name: f.name.replace(oldName + '/', newName + '/') };
          return f;
      }));
      if (activeFileName === oldName) setActiveFileName(newName);
      else if (activeFileName.startsWith(oldName + '/')) setActiveFileName(activeFileName.replace(oldName + '/', newName + '/'));
  };

  // Tab Operations
  const handleNewTab = () => {
      const newId = Date.now().toString();
      setTabs(prev => [...prev, { id: newId, title: 'New Tab', type: 'browser', url: '', loading: false }]);
      setActiveTabId(newId);
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      const newTabs = tabs.filter(t => t.id !== id);
      if (newTabs.length === 0) {
           // Always keep one tab
           setTabs([{ id: Date.now().toString(), title: 'New Tab', type: 'browser', url: '', loading: false }]);
      } else {
           setTabs(newTabs);
           if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
      }
  };

  const handleNavigate = async (inputUrl: string) => {
     let url = inputUrl.trim();

     // 1. Localhost Case
     if (!url || url.includes('localhost')) {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, type: 'preview', url: `localhost:3000/${previewFile?.name || ''}`, title: 'Local Preview', loading: false } : t));
         return;
     }

     // 2. Search/Web Case
     setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, type: 'browser', url: url, title: url, loading: true } : t));

     try {
         const results = await searchWeb(url);
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, content: results, title: url } : t));
     } catch (e) {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, content: [], title: 'Error' } : t));
     }
  };

  // Handle messages from iframe (console)
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'console') {
        const newLog: LogEntry = {
          id: Date.now().toString() + Math.random(),
          timestamp: new Date().toLocaleTimeString(),
          level: event.data.level,
          message: event.data.message.map((m: any) => typeof m === 'object' ? JSON.stringify(m) : String(m)).join(' ')
        };
        setLogs(prev => [...prev, newLog]);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const clearLogs = () => setLogs([]);

  // Console Command Handler
  const handleConsoleCommand = (cmd: string) => { /* Same as before */ };

  // Bundler Logic: Inject CSS/JS into HTML with path resolution
  const getSrcDoc = () => {
    if (!previewFile) return "";
    let html = previewFile.content;
    const basePath = previewFile.name;
    const resolvePath = (relPath: string) => {
        if (relPath.startsWith('http') || relPath.startsWith('//')) return null;
        if (relPath.startsWith('/')) return relPath.slice(1);
        const stack = basePath.split('/'); stack.pop();
        const parts = relPath.split('/');
        for (const part of parts) { if (part === '.') continue; if (part === '..') { if (stack.length > 0) stack.pop(); } else { stack.push(part); } }
        return stack.join('/');
    };
    html = html.replace(/<link\s+[^>]*rel="stylesheet"[^>]*>/g, (match) => {
      const hrefMatch = match.match(/href="([^"]+)"/); if (!hrefMatch) return match;
      const resolvedPath = resolvePath(hrefMatch[1]); if (!resolvedPath) return match;
      const cssFile = files.find(f => f.name === resolvedPath); return cssFile ? `<style>/* ${resolvedPath} */\n${cssFile.content}</style>` : match;
    });
    html = html.replace(/<script\s+[^>]*src="([^"]+)"[^>]*><\/script>/g, (match, src) => {
      const resolvedPath = resolvePath(src); if (!resolvedPath) return match;
      const jsFile = files.find(f => f.name === resolvedPath); return jsFile ? `<script>/* ${resolvedPath} */\n${jsFile.content}</script>` : match;
    });
    const consoleHijack = `<script>
        const originalLog = console.log; const originalWarn = console.warn; const originalError = console.error; const originalInfo = console.info;
        function sendToParent(level, args) { try { window.parent.postMessage({ type: 'console', level: level, message: Array.from(args).map(a => { if (a instanceof Error) return a.toString(); return a; }) }, '*'); } catch(e) {} }
        console.log = function(...args) { originalLog.apply(console, args); sendToParent('log', args); };
        console.warn = function(...args) { originalWarn.apply(console, args); sendToParent('warn', args); };
        console.error = function(...args) { originalError.apply(console, args); sendToParent('error', args); };
        console.info = function(...args) { originalInfo.apply(console, args); sendToParent('info', args); };
        window.onerror = function(msg, url, line) { sendToParent('error', [msg + " (Line " + line + ")"]); }
      </script>`;
    if (html.includes('</body>')) { return html.replace('</body>', `${consoleHijack}</body>`); }
    return html + consoleHijack;
  };

  const srcDoc = useMemo(() => getSrcDoc(), [files, previewFile]);

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Bar / Tab Strip */}
      <div className="flex items-end h-10 px-2 bg-browser-bg border-b border-browser-toolbar select-none gap-2 pt-2">
           {/* Controls */}
           <div className="flex items-center gap-2 mb-2 mr-2">
              <div className="flex gap-1.5 px-2">
                 <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
              </div>
           </div>

           {/* Tab Strip */}
           <div className="flex-1 flex overflow-x-auto no-scrollbar items-end h-full">
               {tabs.map(tab => (
                   <div 
                      key={tab.id}
                      onClick={() => setActiveTabId(tab.id)}
                      className={`
                        group relative flex items-center gap-2 px-3 py-1.5 min-w-[120px] max-w-[200px] text-xs rounded-t-lg cursor-default border-r border-gray-800/50 transition-colors
                        ${activeTabId === tab.id ? 'bg-[#3c3c3c] text-white' : 'bg-transparent text-gray-500 hover:bg-[#2d2d2d]'}
                      `}
                   >
                       {tab.type === 'preview' ? <Lock size={10} className="text-green-500" /> : <Globe size={10} className="text-blue-400" />}
                       <span className="truncate flex-1">{tab.title || 'New Tab'}</span>
                       <button 
                         onClick={(e) => handleCloseTab(tab.id, e)}
                         className={`p-0.5 rounded-full hover:bg-white/20 opacity-0 group-hover:opacity-100 ${tabs.length === 1 ? 'hidden' : ''}`}
                       >
                           <X size={10} />
                       </button>
                   </div>
               ))}
               <button onClick={handleNewTab} className="p-1.5 ml-1 text-gray-500 hover:text-white hover:bg-white/10 rounded mb-1">
                   <Plus size={14} />
               </button>
           </div>

           {/* Window Controls */}
           <div className="flex items-center gap-2 mb-1.5">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className="p-1.5 hover:bg-white/10 rounded text-gray-400 hover:text-white transition"
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={16} /> : <SplitSquareHorizontal size={16} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1.5 rounded transition-colors ${isAIOpen ? 'text-browser-accent bg-blue-500/10' : 'text-gray-400 hover:text-white hover:bg-white/10'}`}
              >
                <Sparkles size={16} />
              </button>
           </div>
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Activity Bar */}
        <ActivityBar activeView={activeSidebar} onViewChange={setActiveSidebar} changesCount={uncommittedChangesCount} />

        {/* Sidebar Content */}
        {activeSidebar === 'explorer' && (
            <FileExplorer 
              files={files} activeFileName={activeFileName} onSelect={setActiveFileName} 
              onCreate={handleCreateFile} onCreateFolder={handleCreateFolder} 
              onDelete={(name) => { if(confirm(`Delete ${name}?`)) handleDeleteFile(name); }} onRename={handleRenameFile}
            />
        )}
        {activeSidebar === 'search' && <Search files={files} onSelect={setActiveFileName} />}
        {activeSidebar === 'git' && <SourceControl files={files} commits={commits} onCommit={handleGitCommit} onCheckout={handleGitCheckout} />}
        {activeSidebar === 'deploy' && <Deployment files={files} />}

        {/* Editor Pane (Left) */}
        <div className={`flex flex-col border-r border-gray-800 transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-0 overflow-hidden'}`}>
          <div className="h-9 bg-[#1e1e1e] border-b border-gray-800 flex items-center px-4 text-xs">
             <Code2 size={14} className="text-blue-500 mr-2" />
             <span className="text-gray-300">{activeFileName}</span>
             <div className="ml-auto flex items-center gap-4">
                 <button onClick={handleFormat} className="flex items-center gap-1.5 text-gray-500 hover:text-white"><AlignLeft size={14} /><span className="hidden sm:inline">Format</span></button>
             </div>
          </div>
          <textarea
            className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed"
            value={activeFile?.content || ''}
            onChange={(e) => updateFileContent(e.target.value)}
            spellCheck={false}
          />
        </div>

        {/* Browser Pane (Right) - Tab Content */}
        <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'}`}>
          <AddressBar 
              url={activeTab.url} 
              onNavigate={handleNavigate} 
              onRefresh={() => setIframeKey(k => k + 1)} 
              isLoading={activeTab.loading}
          />
          <div className="flex-1 relative overflow-hidden bg-[#1e1e1e]">
              <BrowserTab key={`${activeTab.id}-${iframeKey}`} tab={activeTab} srcDoc={srcDoc} />
          </div>
        </div>

        {/* AI Sidebar */}
        <AIAssistant currentCode={activeFile?.content || ''} isOpen={isAIOpen} onClose={() => setIsAIOpen(false)} onUpdateCode={updateFileContent} />
      </div>

      <Console logs={logs} onClear={clearLogs} isOpen={isConsoleOpen} toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} onCommand={handleConsoleCommand} />
    </div>
  );
}

import { GoogleGenAI, Modality, Type, FunctionDeclaration, LiveServerMessage } from "@google/genai";
import { SearchResult } from "../types";

// -- Helpers --

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key is missing");
  return new GoogleGenAI({ apiKey });
};

const getPaidClient = async () => {
  // @ts-ignore
  if (window.aistudio && window.aistudio.hasSelectedApiKey && window.aistudio.openSelectKey) {
     // @ts-ignore
     const hasKey = await window.aistudio.hasSelectedApiKey();
     if (!hasKey) {
         // @ts-ignore
         await window.aistudio.openSelectKey();
     }
  }
  // Create new instance to pick up the injected key
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// -- Chat & Text Features --

export const chatWithGemini = async (
  prompt: string, 
  mode: 'standard' | 'thinking' | 'search' | 'maps' | 'fast',
  attachments: { base64: string, mimeType: string }[] = [],
  contextCode?: string
) => {
  const ai = getClient();
  let model = 'gemini-3-flash-preview'; // Default for standard chat
  const config: any = {
    systemInstruction: contextCode 
      ? `You are an expert developer assistant. Current code context:\n\`\`\`\n${contextCode}\n\`\`\`` 
      : 'You are a helpful AI assistant.',
  };

  if (mode === 'fast') {
    model = 'gemini-2.5-flash-lite-latest';
  } else if (mode === 'thinking') {
    model = 'gemini-3-pro-preview';
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else if (mode === 'search') {
    model = 'gemini-3-pro-preview'; // Pro is better for search integration
    config.tools = [{ googleSearch: {} }];
  } else if (mode === 'maps') {
    model = 'gemini-2.5-flash'; // Maps currently supported on 2.5 Flash
    config.tools = [{ googleMaps: {} }];
    // Try to get location
    try {
      const pos: any = await new Promise((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(resolve, reject, { timeout: 5000 });
      });
      config.toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: pos.coords.latitude,
            longitude: pos.coords.longitude
          }
        }
      };
    } catch (e) {
      console.warn("Could not get location for Maps grounding");
    }
  }

  // Handle attachments
  let parts: any[] = [];

  if (attachments.length > 0) {
    // If audio is present, use Flash (multimodal efficiency)
    if (attachments.some(a => a.mimeType.startsWith('audio/'))) {
      model = 'gemini-2.5-flash-native-audio-preview-12-2025';
    } else if (attachments.some(a => a.mimeType.startsWith('image/')) && mode === 'standard') {
        // Use Pro for better image reasoning if in standard mode
        model = 'gemini-3-pro-preview';
    }

    parts = attachments.map(a => ({
      inlineData: {
        data: a.base64,
        mimeType: a.mimeType
      }
    }));
  }

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model,
    contents: { parts },
    config
  });

  // Extract grounding metadata if present
  let text = response.text || "";
  const grounding = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (grounding) {
    const links = grounding
      .map((c: any) => c.web?.uri ? `[${c.web.title}](${c.web.uri})` : c.maps?.uri ? `[${c.maps.title}](${c.maps.uri})` : '')
      .filter(Boolean)
      .join('\n');
    if (links) text += `\n\nSources:\n${links}`;
  }

  return text;
};

// -- Search Feature (For Browser Tabs) --

export const searchWeb = async (query: string): Promise<SearchResult[]> => {
  const ai = getClient();
  // Improved prompt to get more results and strictly formatted JSON
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: [{ text: `Search the web for: "${query}". Return a JSON array of at least 8 relevant search results. For each result include 'title', 'url', and a helpful 'snippet'.` }] },
    config: {
      tools: [{ googleSearch: {} }],
      responseSchema: {
         type: Type.ARRAY,
         items: {
             type: Type.OBJECT,
             properties: {
                 title: { type: Type.STRING },
                 url: { type: Type.STRING },
                 snippet: { type: Type.STRING }
             }
         }
      }
    }
  });

  try {
      // Direct JSON parsing
      const json = JSON.parse(response.text || "[]");
      // Filter out empty results
      return json.filter((r: any) => r.title && r.url);
  } catch (e) {
      // Fallback: extract from grounding metadata if JSON parse fails
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const results = chunks
        .filter((c: any) => c.web)
        .map((c: any) => ({
            title: c.web.title,
            url: c.web.uri,
            snippet: "Result from Google Search"
        }));
      return results;
  }
};

// -- Audio Features --

export const transcribeAudio = async (audioBase64: string) => {
  const ai = getClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    contents: {
      parts: [
        { inlineData: { mimeType: 'audio/wav', data: audioBase64 } },
        { text: "Transcribe this audio." }
      ]
    }
  });
  return response.text;
};

// -- Image Features --

export const generateImage = async (
  prompt: string, 
  options: { 
    aspectRatio?: string, 
    imageSize?: string,
    sourceImage?: string // Base64 for editing
  }
) => {
  // If editing (source image present), use 2.5 Flash Image
  if (options.sourceImage) {
    const ai = getClient();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/png', data: options.sourceImage } },
          { text: prompt }
        ]
      },
      config: {
         imageConfig: {
             aspectRatio: options.aspectRatio as any || "1:1"
         }
      }
    });
    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return part.inlineData.data;
    }
    throw new Error("No image generated");
  } else {
    // Generation use 3 Pro Image (requires paid key logic)
    const ai = await getPaidClient();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: options.aspectRatio as any || "1:1",
          imageSize: options.imageSize as any || "1K"
        }
      }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return part.inlineData.data;
    }
    throw new Error("No image generated from API response");
  }
};

// -- Video Features --

export const generateVideo = async (
  prompt: string,
  options: { aspectRatio: string }
) => {
  const ai = await getPaidClient();
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt,
    config: {
      numberOfVideos: 1,
      aspectRatio: options.aspectRatio as any,
      resolution: '720p'
    }
  });

  // Polling with recommended delay
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000)); // 10s delay as per guidelines
    operation = await ai.operations.getVideosOperation({ operation });
  }

  const uri = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!uri) throw new Error("Video generation failed or still processing");

  // Fetch with API key appended
  const response = await fetch(`${uri}&key=${process.env.API_KEY}`);
  if (!response.ok) throw new Error("Failed to download video blob");

  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

// -- Live API --

export const connectLive = async (
    onAudioData: (base64: string) => void,
    onCodeUpdate: (code: string) => void,
    onClose: () => void
) => {
    const ai = getClient();
    // Audio Context Setup
    const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    // Setup Input Stream
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const source = inputAudioContext.createMediaStreamSource(stream);
    const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);

    // Define Tools
    const updateCodeTool: FunctionDeclaration = {
        name: 'update_code',
        description: 'Overwrite the current file content with new code. Use this when the user asks to write, change, or fix code.',
        parameters: {
            type: Type.OBJECT,
            properties: {
                code: { type: Type.STRING, description: 'The complete code content to write.' }
            },
            required: ['code']
        }
    };

    // Connect to Live API
    const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
            onopen: () => {
                scriptProcessor.onaudioprocess = (e) => {
                    const inputData = e.inputBuffer.getChannelData(0);
                    // Convert Float32 to PCM Int16
                    const l = inputData.length;
                    const int16 = new Int16Array(l);
                    for (let i = 0; i < l; i++) int16[i] = inputData[i] * 32768;
                    const bytes = new Uint8Array(int16.buffer);
                    let binary = '';
                    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
                    const base64Data = btoa(binary);

                    sessionPromise.then(session => {
                        session.sendRealtimeInput({
                            media: {
                                mimeType: 'audio/pcm;rate=16000',
                                data: base64Data
                            }
                        });
                    });
                };
                source.connect(scriptProcessor);
                scriptProcessor.connect(inputAudioContext.destination);
            },
            onmessage: (msg: LiveServerMessage) => {
                // Handle Audio Output
                const data = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (data) {
                    onAudioData(data);
                    // Play audio
                    const binaryString = atob(data);
                    const len = binaryString.length;
                    const bytes = new Uint8Array(len);
                    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);

                    // Simple decode and play
                    const ctx = outputAudioContext;
                    const dataInt16 = new Int16Array(bytes.buffer);
                    const float32 = new Float32Array(dataInt16.length);
                    for(let i=0; i<dataInt16.length; i++) float32[i] = dataInt16[i] / 32768.0;

                    const buffer = ctx.createBuffer(1, float32.length, 24000);
                    buffer.copyToChannel(float32, 0);

                    const node = ctx.createBufferSource();
                    node.buffer = buffer;
                    node.connect(ctx.destination);
                    node.start();
                }

                // Handle Tool Calls
                if (msg.toolCall) {
                    msg.toolCall.functionCalls.forEach(fc => {
                        if (fc.name === 'update_code') {
                            const args = fc.args as any;
                            if (args.code) {
                                onCodeUpdate(args.code);
                            }
                            // Respond to tool call
                            sessionPromise.then(session => session.sendToolResponse({
                                functionResponses: [{
                                    id: fc.id,
                                    name: fc.name,
                                    response: { result: 'Code updated successfully' }
                                }]
                            }));
                        }
                    });
                }
            },
            onclose: onClose,
            onerror: (e) => { console.error(e); onClose(); }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
            },
            systemInstruction: "You are an expert coding assistant. You can hear the user and update their code in real-time. When asked to write code, use the update_code tool.",
            tools: [{ functionDeclarations: [updateCodeTool] }]
        }
    });

    return {
        disconnect: () => {
            sessionPromise.then(s => s.close());
            inputAudioContext.close();
            outputAudioContext.close();
            stream.getTracks().forEach(t => t.stop());
        }
    };
};

import React from 'react';
import { SearchResult, Tab } from '../types';
import { Loader2, Search, ExternalLink, Globe, AlertCircle, ShieldAlert, X } from 'lucide-react';

interface BrowserTabProps {
  tab: Tab;
  srcDoc: string; // For preview mode
  onNavigate: (url: string) => void;
}

const BrowserTab: React.FC<BrowserTabProps> = ({ tab, srcDoc, onNavigate }) => {

  // -- Mode 1: Local Preview (iframe) --
  if (tab.type === 'preview') {
    return (
      <iframe
        title={tab.title}
        srcDoc={srcDoc}
        className="w-full h-full border-none bg-white"
        sandbox="allow-scripts allow-modals allow-forms allow-same-origin"
      />
    );
  }

  // -- Mode 2: External Browser / Search --
  // If we have search results (array), show them.
  // If we have a URL but NO search results, try to render the site.

  const isBrowsingSite = tab.url && !tab.loading && (!tab.content || !Array.isArray(tab.content));

  if (isBrowsingSite) {
      return (
          <div className="w-full h-full flex flex-col bg-white">
              {/* Security Banner / External Link Fallback */}
              <div className="bg-yellow-50 text-yellow-800 px-4 py-2 text-xs flex items-center justify-between border-b border-yellow-200">
                  <div className="flex items-center gap-2">
                      <ShieldAlert size={14} />
                      <span>Some websites refuse to load inside this window (security headers).</span>
                  </div>
                  <a 
                    href={tab.url} 
                    target="_blank" 
                    rel="noreferrer"
                    className="flex items-center gap-1 font-bold hover:underline"
                  >
                      Open in New Tab <ExternalLink size={12} />
                  </a>
              </div>
              <iframe 
                src={tab.url}
                className="flex-1 w-full border-none"
                title="External Site"
                sandbox="allow-scripts allow-modals allow-forms allow-same-origin allow-popups"
              />
          </div>
      );
  }

  return (
    <div className="w-full h-full bg-[#1e1e1e] overflow-y-auto custom-scrollbar flex flex-col items-center">

       {/* Empty State / New Tab */}
       {!tab.url && !tab.loading && (
           <div className="mt-32 flex flex-col items-center opacity-50">
               <Globe size={64} className="text-gray-600 mb-4" />
               <h2 className="text-2xl font-bold text-gray-400">New Tab</h2>
               <p className="text-gray-500 mt-2">Search or enter a URL in the address bar</p>
           </div>
       )}

       {/* Loading State */}
       {tab.loading && (
           <div className="mt-40 flex flex-col items-center">
               <Loader2 size={48} className="text-blue-500 animate-spin mb-4" />
               <p className="text-gray-400 animate-pulse">Searching the web...</p>
           </div>
       )}

       {/* Search Results */}
       {!tab.loading && tab.content && Array.isArray(tab.content) && (
           <div className="w-full max-w-3xl px-6 py-8 space-y-8">
               <div className="border-b border-gray-700 pb-4 mb-6">
                   <h1 className="text-xl text-gray-200 font-medium flex items-center gap-2">
                       <Search size={20} className="text-blue-500" />
                       Results for <span className="text-white font-bold">"{tab.title}"</span>
                   </h1>
               </div>

               {tab.content.length === 0 ? (
                   <div className="text-gray-500 flex items-center gap-2 bg-gray-800/50 p-4 rounded-lg">
                       <AlertCircle size={18} /> No results found. Try a different query.
                   </div>
               ) : (
                   tab.content.map((result: SearchResult, idx: number) => {
                       // Format display URL
                       let displayUrl = result.url;
                       try { displayUrl = new URL(result.url).hostname; } catch(e){}

                       return (
                           <div key={idx} className="group mb-6">
                               <div className="flex items-center gap-2 text-xs text-gray-400 mb-1">
                                   <div className="w-6 h-6 rounded-full bg-gray-700 flex items-center justify-center text-[10px] font-bold text-gray-300">
                                       {displayUrl.charAt(0).toUpperCase()}
                                   </div>
                                   <span className="truncate max-w-[300px]">{displayUrl}</span>
                               </div>
                               <button 
                                    onClick={() => onNavigate(result.url)}
                                    className="text-blue-400 text-lg hover:underline font-medium block mb-1 text-left visited:text-purple-400 outline-none focus:underline"
                               >
                                   {result.title}
                               </button>
                               <p className="text-sm text-gray-400 leading-relaxed line-clamp-2 group-hover:text-gray-300 transition-colors">
                                   {result.snippet}
                               </p>
                           </div>
                       );
                   })
               )}

               <div className="pt-8 border-t border-gray-800 text-center text-xs text-gray-600">
                   Search results provided by Gemini Grounding
               </div>
           </div>
       )}
    </div>
  );
};

export default BrowserTab;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Code2, SplitSquareHorizontal, Maximize2, Sparkles, Layout, AlignLeft, Plus, X, Globe, Lock } from 'lucide-react';
import { LogEntry, LayoutMode, VirtualFile, GitCommit, SidebarView, Tab } from './types';
import Console from './components/Console';
import AddressBar from './components/AddressBar';
import AIAssistant from './components/AIAssistant';
import FileExplorer from './components/FileExplorer';
import SourceControl from './components/SourceControl';
import Deployment from './components/Deployment';
import ActivityBar from './components/ActivityBar';
import Search from './components/Search';
import BrowserTab from './components/BrowserTab';
import { searchWeb } from './services/geminiService';

// Prettier Imports
import { format } from "prettier/standalone";
import parserBabel from "prettier/plugins/babel";
import parserEstree from "prettier/plugins/estree";
import parserHtml from "prettier/plugins/html";
import parserPostcss from "prettier/plugins/postcss";
import parserMarkdown from "prettier/plugins/markdown";

// Initial Empty Project
const INITIAL_FILES: VirtualFile[] = [
  {
    name: 'index.html',
    language: 'html',
    type: 'file',
    content: `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>New Project</title>
</head>
<body>
  <div class="container">
    <h1>Hello, World!</h1>
    <p>Start editing to see magic happen.</p>
  </div>
  <style>
    body { font-family: system-ui, sans-serif; padding: 2rem; background: #f0f0f0; }
    .container { background: white; padding: 2rem; border-radius: 8px; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
  </style>
</body>
</html>`
  }
];

export default function App() {
  // Load initial state from localStorage if available
  const [files, setFiles] = useState<VirtualFile[]>(() => {
    try {
      const saved = localStorage.getItem('devbrowser_files');
      return saved ? JSON.parse(saved) : INITIAL_FILES;
    } catch (e) {
      console.error("Failed to load files from storage", e);
      return INITIAL_FILES;
    }
  });

  const [activeFileName, setActiveFileName] = useState(() => {
    return localStorage.getItem('devbrowser_activeFile') || 'index.html';
  });

  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [layoutMode, setLayoutMode] = useState<LayoutMode>(LayoutMode.SPLIT);
  const [isConsoleOpen, setIsConsoleOpen] = useState(true);
  const [isAIOpen, setIsAIOpen] = useState(false);

  // Navigation & Git State
  const [activeSidebar, setActiveSidebar] = useState<SidebarView>('explorer');
  const [commits, setCommits] = useState<GitCommit[]>([]);

  // -- TAB STATE --
  const [tabs, setTabs] = useState<Tab[]>([
      { id: '1', title: 'Local Preview', type: 'preview', url: 'localhost:3000/index.html', loading: false }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('1');
  const [iframeKey, setIframeKey] = useState(0);

  // Save to localStorage whenever files change
  useEffect(() => {
    localStorage.setItem('devbrowser_files', JSON.stringify(files));
  }, [files]);

  // Save active file selection
  useEffect(() => {
    localStorage.setItem('devbrowser_activeFile', activeFileName);
  }, [activeFileName]);

  // Init Git
  useEffect(() => {
    if (commits.length === 0) {
      setCommits([{
        id: 'init',
        message: 'Initial Commit',
        timestamp: new Date().toLocaleTimeString(),
        files: JSON.parse(JSON.stringify(INITIAL_FILES))
      }]);
    }
  }, []);

  const activeFile = files.find(f => f.name === activeFileName) || files[0];
  const activeTab = tabs.find(t => t.id === activeTabId) || tabs[0];

  // Determine which file is being previewed (Active HTML or fallback to index.html)
  const previewFile = useMemo(() => {
      if (activeFile?.language === 'html') return activeFile;
      return files.find(f => f.name === 'index.html');
  }, [activeFile, files]);

  // Update file content
  const updateFileContent = (newContent: string) => {
    setFiles(prev => prev.map(f => f.name === activeFileName ? { ...f, content: newContent } : f));
  };

  // Format Code Logic
  const handleFormat = async () => {
    if (!activeFile) return;
    try {
      let parser: string | undefined;
      let plugins: any[] = [];
      switch (activeFile.language) {
        case 'javascript': case 'typescript': case 'json':
          parser = activeFile.language === 'json' ? 'json' : 'babel';
          plugins = [parserBabel, parserEstree];
          break;
        case 'html':
          parser = 'html'; plugins = [parserHtml, parserBabel, parserPostcss, parserEstree];
          break;
        case 'css':
          parser = 'css'; plugins = [parserPostcss];
          break;
        case 'markdown':
          parser = 'markdown'; plugins = [parserMarkdown, parserBabel, parserEstree]; 
          break;
      }
      if (parser) {
        const formatted = await format(activeFile.content, { parser, plugins, printWidth: 80, tabWidth: 2, semi: true, singleQuote: false });
        updateFileContent(formatted);
        setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'success', message: `Formatted ${activeFile.name}` }]);
      }
    } catch (e: any) {
        setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'error', message: `Format error: ${e.message}` }]);
    }
  };

  // Git Operations
  const handleGitCommit = (message: string) => {
    const newCommit: GitCommit = { id: Date.now().toString(), message, timestamp: new Date().toLocaleTimeString(), files: JSON.parse(JSON.stringify(files)) };
    setCommits(prev => [newCommit, ...prev]);
  };

  const handleGitCheckout = (commitId: string) => {
    const commit = commits.find(c => c.id === commitId);
    if (commit) {
      setFiles(JSON.parse(JSON.stringify(commit.files)));
      if (!commit.files.find(f => f.name === activeFileName)) {
        setActiveFileName(commit.files[0]?.name || '');
      }
    }
  };

  // Calculate uncommitted changes
  const uncommittedChangesCount = useMemo(() => {
    const head = commits[0];
    if (!head) return files.filter(f => f.type !== 'directory').length;
    let count = 0;
    files.filter(f => f.type !== 'directory').forEach(f => {
      const prev = head.files.find(pf => pf.name === f.name);
      if (!prev || prev.content !== f.content) count++;
    });
    head.files.filter(f => f.type !== 'directory').forEach(pf => {
      if (!files.find(f => f.name === pf.name)) count++;
    });
    return count;
  }, [files, commits]);

  // File Operations
  const handleCreateFile = (name: string) => {
    if (files.some(f => f.name === name)) return;
    const ext = name.split('.').pop();
    let lang: VirtualFile['language'] = 'text';
    if (ext === 'html') lang = 'html'; else if (ext === 'css') lang = 'css'; else if (ext === 'js') lang = 'javascript'; else if (ext === 'json') lang = 'json';
    setFiles(prev => [...prev, { name, content: '', language: lang, type: 'file' }]);
    setActiveFileName(name);
  };

  const handleCreateFolder = (name: string) => {
    if (files.some(f => f.name === name)) return;
    setFiles(prev => [...prev, { name, content: '', language: 'text', type: 'directory' }]);
  };

  const handleDeleteFile = (name: string) => {
    const newFiles = files.filter(f => f.name !== name && !f.name.startsWith(name + '/'));
    setFiles(newFiles);
    if (activeFileName === name || activeFileName.startsWith(name + '/')) {
        const firstFile = newFiles.find(f => f.type === 'file');
        setActiveFileName(firstFile ? firstFile.name : '');
    }
  };

  const handleRenameFile = (oldName: string, newName: string) => {
      if (files.some(f => f.name === newName)) { alert("Path already exists"); return; }
      setFiles(prev => prev.map(f => {
          if (f.name === oldName) return { ...f, name: newName };
          if (f.name.startsWith(oldName + '/')) return { ...f, name: f.name.replace(oldName + '/', newName + '/') };
          return f;
      }));
      if (activeFileName === oldName) setActiveFileName(newName);
      else if (activeFileName.startsWith(oldName + '/')) setActiveFileName(activeFileName.replace(oldName + '/', newName + '/'));
  };

  // Tab Operations
  const handleNewTab = () => {
      const newId = Date.now().toString();
      setTabs(prev => [...prev, { id: newId, title: 'New Tab', type: 'browser', url: '', loading: false }]);
      setActiveTabId(newId);
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      const newTabs = tabs.filter(t => t.id !== id);
      if (newTabs.length === 0) {
           // Always keep one tab
           setTabs([{ id: Date.now().toString(), title: 'New Tab', type: 'browser', url: '', loading: false }]);
      } else {
           setTabs(newTabs);
           if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
      }
  };

  const handleNavigate = async (inputUrl: string) => {
     let url = inputUrl.trim();
     if (!url) return;

     // 1. Localhost Case
     if (url.includes('localhost')) {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, type: 'preview', url: `localhost:3000/${previewFile?.name || ''}`, title: 'Local Preview', loading: false } : t));
         return;
     }

     // 2. URL detection (Heuristic)
     const isUrl = url.includes('.') && !url.includes(' ') && !url.startsWith('?');

     if (isUrl) {
         // It is a URL, visit it
         if (!/^https?:\/\//i.test(url)) url = 'https://' + url;
         let hostname = url;
         try { hostname = new URL(url).hostname; } catch(e){}

         setTabs(prev => prev.map(t => t.id === activeTabId ? { 
            ...t, 
            type: 'browser', 
            url: url, 
            title: hostname, 
            loading: false, 
            content: null // null content = show iframe in BrowserTab
         } : t));
     } else {
         // 3. Search Query
         setTabs(prev => prev.map(t => t.id === activeTabId ? { 
            ...t, 
            type: 'browser', 
            url: url, // Keep query in address bar
            title: url, 
            loading: true, 
            content: [] 
         } : t));

         try {
             const results = await searchWeb(url);
             setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, content: results } : t));
         } catch (e) {
             setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, content: [], title: 'Error' } : t));
         }
     }
  };

  // Handle messages from iframe (console)
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'console') {
        const newLog: LogEntry = {
          id: Date.now().toString() + Math.random(),
          timestamp: new Date().toLocaleTimeString(),
          level: event.data.level,
          message: event.data.message.map((m: any) => typeof m === 'object' ? JSON.stringify(m) : String(m)).join(' ')
        };
        setLogs(prev => [...prev, newLog]);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const clearLogs = () => setLogs([]);

  // Console Command Handler
  const handleConsoleCommand = (cmd: string) => { /* Same as before */ };

  // Bundler Logic: Inject CSS/JS into HTML with path resolution
  const getSrcDoc = () => {
    if (!previewFile) return "";
    let html = previewFile.content;
    const basePath = previewFile.name;
    const resolvePath = (relPath: string) => {
        if (relPath.startsWith('http') || relPath.startsWith('//')) return null;
        if (relPath.startsWith('/')) return relPath.slice(1);
        const stack = basePath.split('/'); stack.pop();
        const parts = relPath.split('/');
        for (const part of parts) { if (part === '.') continue; if (part === '..') { if (stack.length > 0) stack.pop(); } else { stack.push(part); } }
        return stack.join('/');
    };
    html = html.replace(/<link\s+[^>]*rel="stylesheet"[^>]*>/g, (match) => {
      const hrefMatch = match.match(/href="([^"]+)"/); if (!hrefMatch) return match;
      const resolvedPath = resolvePath(hrefMatch[1]); if (!resolvedPath) return match;
      const cssFile = files.find(f => f.name === resolvedPath); return cssFile ? `<style>/* ${resolvedPath} */\n${cssFile.content}</style>` : match;
    });
    html = html.replace(/<script\s+[^>]*src="([^"]+)"[^>]*><\/script>/g, (match, src) => {
      const resolvedPath = resolvePath(src); if (!resolvedPath) return match;
      const jsFile = files.find(f => f.name === resolvedPath); return jsFile ? `<script>/* ${resolvedPath} */\n${jsFile.content}</script>` : match;
    });
    const consoleHijack = `<script>
        const originalLog = console.log; const originalWarn = console.warn; const originalError = console.error; const originalInfo = console.info;
        function sendToParent(level, args) { try { window.parent.postMessage({ type: 'console', level: level, message: Array.from(args).map(a => { if (a instanceof Error) return a.toString(); return a; }) }, '*'); } catch(e) {} }
        console.log = function(...args) { originalLog.apply(console, args); sendToParent('log', args); };
        console.warn = function(...args) { originalWarn.apply(console, args); sendToParent('warn', args); };
        console.error = function(...args) { originalError.apply(console, args); sendToParent('error', args); };
        console.info = function(...args) { originalInfo.apply(console, args); sendToParent('info', args); };
        window.onerror = function(msg, url, line) { sendToParent('error', [msg + " (Line " + line + ")"]); }
      </script>`;
    if (html.includes('</body>')) { return html.replace('</body>', `${consoleHijack}</body>`); }
    return html + consoleHijack;
  };

  const srcDoc = useMemo(() => getSrcDoc(), [files, previewFile]);

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Bar / Tab Strip */}
      <div className="flex items-end h-10 px-2 bg-browser-bg border-b border-browser-toolbar select-none gap-2 pt-2">
           {/* Controls */}
           <div className="flex items-center gap-2 mb-2 mr-2">
              <div className="flex gap-1.5 px-2">
                 <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
              </div>
           </div>

           {/* Tab Strip */}
           <div className="flex-1 flex overflow-x-auto no-scrollbar items-end h-full">
               {tabs.map(tab => (
                   <div 
                      key={tab.id}
                      onClick={() => setActiveTabId(tab.id)}
                      className={`
                        group relative flex items-center gap-2 px-3 py-1.5 min-w-[120px] max-w-[200px] text-xs rounded-t-lg cursor-default border-r border-gray-800/50 transition-colors
                        ${activeTabId === tab.id ? 'bg-[#3c3c3c] text-white' : 'bg-transparent text-gray-500 hover:bg-[#2d2d2d]'}
                      `}
                   >
                       {tab.type === 'preview' ? <Lock size={10} className="text-green-500" /> : <Globe size={10} className="text-blue-400" />}
                       <span className="truncate flex-1">{tab.title || 'New Tab'}</span>
                       <button 
                         onClick={(e) => handleCloseTab(tab.id, e)}
                         className={`p-0.5 rounded-full hover:bg-white/20 opacity-0 group-hover:opacity-100 ${tabs.length === 1 ? 'hidden' : ''}`}
                       >
                           <X size={10} />
                       </button>
                   </div>
               ))}
               <button onClick={handleNewTab} className="p-1.5 ml-1 text-gray-500 hover:text-white hover:bg-white/10 rounded mb-1">
                   <Plus size={14} />
               </button>
           </div>

           {/* Window Controls */}
           <div className="flex items-center gap-2 mb-1.5">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className="p-1.5 hover:bg-white/10 rounded text-gray-400 hover:text-white transition"
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={16} /> : <SplitSquareHorizontal size={16} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1.5 rounded transition-colors ${isAIOpen ? 'text-browser-accent bg-blue-500/10' : 'text-gray-400 hover:text-white hover:bg-white/10'}`}
              >
                <Sparkles size={16} />
              </button>
           </div>
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Activity Bar */}
        <ActivityBar activeView={activeSidebar} onViewChange={setActiveSidebar} changesCount={uncommittedChangesCount} />

        {/* Sidebar Content */}
        {activeSidebar === 'explorer' && (
            <FileExplorer 
              files={files} activeFileName={activeFileName} onSelect={setActiveFileName} 
              onCreate={handleCreateFile} onCreateFolder={handleCreateFolder} 
              onDelete={(name) => { if(confirm(`Delete ${name}?`)) handleDeleteFile(name); }} onRename={handleRenameFile}
            />
        )}
        {activeSidebar === 'search' && <Search files={files} onSelect={setActiveFileName} />}
        {activeSidebar === 'git' && <SourceControl files={files} commits={commits} onCommit={handleGitCommit} onCheckout={handleGitCheckout} />}
        {activeSidebar === 'deploy' && <Deployment files={files} />}

        {/* Editor Pane (Left) */}
        <div className={`flex flex-col border-r border-gray-800 transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-0 overflow-hidden'}`}>
          <div className="h-9 bg-[#1e1e1e] border-b border-gray-800 flex items-center px-4 text-xs">
             <Code2 size={14} className="text-blue-500 mr-2" />
             <span className="text-gray-300">{activeFileName}</span>
             <div className="ml-auto flex items-center gap-4">
                 <button onClick={handleFormat} className="flex items-center gap-1.5 text-gray-500 hover:text-white"><AlignLeft size={14} /><span className="hidden sm:inline">Format</span></button>
             </div>
          </div>
          <textarea
            className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed"
            value={activeFile?.content || ''}
            onChange={(e) => updateFileContent(e.target.value)}
            spellCheck={false}
          />
        </div>

        {/* Browser Pane (Right) - Tab Content */}
        <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'}`}>
          <AddressBar 
              url={activeTab.url} 
              onNavigate={handleNavigate} 
              onRefresh={() => setIframeKey(k => k + 1)} 
              isLoading={activeTab.loading}
          />
          <div className="flex-1 relative overflow-hidden bg-[#1e1e1e]">
              <BrowserTab key={`${activeTab.id}-${iframeKey}`} tab={activeTab} srcDoc={srcDoc} onNavigate={handleNavigate} />
          </div>
        </div>

        {/* AI Sidebar */}
        <AIAssistant currentCode={activeFile?.content || ''} isOpen={isAIOpen} onClose={() => setIsAIOpen(false)} onUpdateCode={updateFileContent} />
      </div>

      <Console logs={logs} onClear={clearLogs} isOpen={isConsoleOpen} toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} onCommand={handleConsoleCommand} />
    </div>
  );
}

import { GoogleGenAI, Modality, Type, FunctionDeclaration, LiveServerMessage } from "@google/genai";
import { SearchResult } from "../types";

// -- Helpers --

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key is missing");
  return new GoogleGenAI({ apiKey });
};

const getPaidClient = async () => {
  // @ts-ignore
  if (window.aistudio && window.aistudio.hasSelectedApiKey && window.aistudio.openSelectKey) {
     // @ts-ignore
     const hasKey = await window.aistudio.hasSelectedApiKey();
     if (!hasKey) {
         // @ts-ignore
         await window.aistudio.openSelectKey();
     }
  }
  // Create new instance to pick up the injected key
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// -- Chat & Text Features --

export const chatWithGemini = async (
  prompt: string, 
  mode: 'standard' | 'thinking' | 'search' | 'maps' | 'fast',
  attachments: { base64: string, mimeType: string }[] = [],
  contextCode?: string
) => {
  const ai = getClient();
  let model = 'gemini-3-flash-preview'; // Default for standard chat
  const config: any = {
    systemInstruction: contextCode 
      ? `You are an expert developer assistant. Current code context:\n\`\`\`\n${contextCode}\n\`\`\`` 
      : 'You are a helpful AI assistant.',
  };

  if (mode === 'fast') {
    model = 'gemini-2.5-flash-lite-latest';
  } else if (mode === 'thinking') {
    model = 'gemini-3-pro-preview';
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else if (mode === 'search') {
    model = 'gemini-3-pro-preview'; // Pro is better for search integration
    config.tools = [{ googleSearch: {} }];
  } else if (mode === 'maps') {
    model = 'gemini-2.5-flash'; // Maps currently supported on 2.5 Flash
    config.tools = [{ googleMaps: {} }];
    // Try to get location
    try {
      const pos: any = await new Promise((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(resolve, reject, { timeout: 5000 });
      });
      config.toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: pos.coords.latitude,
            longitude: pos.coords.longitude
          }
        }
      };
    } catch (e) {
      console.warn("Could not get location for Maps grounding");
    }
  }

  // Handle attachments
  let parts: any[] = [];

  if (attachments.length > 0) {
    // If audio is present, use Flash (multimodal efficiency)
    if (attachments.some(a => a.mimeType.startsWith('audio/'))) {
      model = 'gemini-2.5-flash-native-audio-preview-12-2025';
    } else if (attachments.some(a => a.mimeType.startsWith('image/')) && mode === 'standard') {
        // Use Pro for better image reasoning if in standard mode
        model = 'gemini-3-pro-preview';
    }

    parts = attachments.map(a => ({
      inlineData: {
        data: a.base64,
        mimeType: a.mimeType
      }
    }));
  }

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model,
    contents: { parts },
    config
  });

  // Extract grounding metadata if present
  let text = response.text || "";
  const grounding = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (grounding) {
    const links = grounding
      .map((c: any) => c.web?.uri ? `[${c.web.title}](${c.web.uri})` : c.maps?.uri ? `[${c.maps.title}](${c.maps.uri})` : '')
      .filter(Boolean)
      .join('\n');
    if (links) text += `\n\nSources:\n${links}`;
  }

  return text;
};

// -- Search Feature (For Browser Tabs) --

export const searchWeb = async (query: string): Promise<SearchResult[]> => {
  const ai = getClient();

  // Optimization: Use gemini-2.5-flash for extreme speed
  // Optimization: We don't ask for JSON schema processing which is slow.
  // We rely on the raw "groundingChunks" which come directly from Google Search engine.

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash', 
    contents: { parts: [{ text: `Find information about: "${query}"` }] },
    config: {
      tools: [{ googleSearch: {} }],
    }
  });

  // FAST PATH: Extract directly from Grounding Metadata (Real Google Results)
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const webResults = chunks
    .filter((c: any) => c.web)
    .map((c: any) => ({
        title: c.web.title,
        url: c.web.uri,
        snippet: "Google Search Result" // Flash grounding sometimes omits snippet in metadata to be fast, we use title
    }));

  if (webResults.length > 0) {
