// -- Live API --

export const connectLive = async (
    onAudioData: (base64: string) => void,
    onCodeUpdate: (code: string) => void,
    onClose: () => void
) => {
    const ai = getClient();
    // Audio Context Setup
    const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    // Setup Input Stream
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const source = inputAudioContext.createMediaStreamSource(stream);
    const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);

    // Define Tools
    const updateCodeTool: FunctionDeclaration = {
        name: 'update_code',
        description: 'Overwrite the current file content with new code. Use this when the user asks to write, change, or fix code.',
        parameters: {
            type: Type.OBJECT,
            properties: {
                code: { type: Type.STRING, description: 'The complete code content to write.' }
            },
            required: ['code']
        }
    };

    // Connect to Live API
    const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
            onopen: () => {
                scriptProcessor.onaudioprocess = (e) => {
                    const inputData = e.inputBuffer.getChannelData(0);
                    // Convert Float32 to PCM Int16
                    const l = inputData.length;
                    const int16 = new Int16Array(l);
                    for (let i = 0; i < l; i++) int16[i] = inputData[i] * 32768;
                    const bytes = new Uint8Array(int16.buffer);
                    let binary = '';
                    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
                    const base64Data = btoa(binary);

                    sessionPromise.then(session => {
                        session.sendRealtimeInput({
                            media: {
                                mimeType: 'audio/pcm;rate=16000',
                                data: base64Data
                            }
                        });
                    });
                };
                source.connect(scriptProcessor);
                scriptProcessor.connect(inputAudioContext.destination);
            },
            onmessage: (msg: LiveServerMessage) => {
                // Handle Audio Output
                const data = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (data) {
                    onAudioData(data);
                    // Play audio
                    const binaryString = atob(data);
                    const len = binaryString.length;
                    const bytes = new Uint8Array(len);
                    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);

                    // Simple decode and play
                    const ctx = outputAudioContext;
                    const dataInt16 = new Int16Array(bytes.buffer);
                    const float32 = new Float32Array(dataInt16.length);
                    for(let i=0; i<dataInt16.length; i++) float32[i] = dataInt16[i] / 32768.0;

                    const buffer = ctx.createBuffer(1, float32.length, 24000);
                    buffer.copyToChannel(float32, 0);

                    const node = ctx.createBufferSource();
                    node.buffer = buffer;
                    node.connect(ctx.destination);
                    node.start();
                }

                // Handle Tool Calls
                if (msg.toolCall) {
                    msg.toolCall.functionCalls.forEach(fc => {
                        if (fc.name === 'update_code') {
                            const args = fc.args as any;
                            if (args.code) {
                                onCodeUpdate(args.code);
                            }
                            // Respond to tool call
                            sessionPromise.then(session => session.sendToolResponse({
                                functionResponses: [{
                                    id: fc.id,
                                    name: fc.name,
                                    response: { result: 'Code updated successfully' }
                                }]
                            }));
                        }
                    });
                }
            },
            onclose: onClose,
            onerror: (e) => { console.error(e); onClose(); }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
            },
            systemInstruction: "You are an expert coding assistant. You can hear the user and update their code in real-time. When asked to write code, use the update_code tool.",
            tools: [{ functionDeclarations: [updateCodeTool] }]
        }
    });

    return {
        disconnect: () => {
            sessionPromise.then(s => s.close());
            inputAudioContext.close();
            outputAudioContext.close();
            stream.getTracks().forEach(t => t.stop());
        }
    };
};

import React from 'react';
import { SearchResult, Tab } from '../types';
import { Loader2, Search, ExternalLink, Globe, AlertCircle, ShieldAlert, X } from 'lucide-react';

interface BrowserTabProps {
  tab: Tab;
  srcDoc: string; // For preview mode
  onNavigate: (url: string) => void;
}

const BrowserTab: React.FC<BrowserTabProps> = ({ tab, srcDoc, onNavigate }) => {

  // -- Mode 1: Local Preview (iframe) --
  if (tab.type === 'preview') {
    return (
      <iframe
        title={tab.title}
        srcDoc={srcDoc}
        className="w-full h-full border-none bg-white"
        sandbox="allow-scripts allow-modals allow-forms allow-same-origin"
      />
    );
  }

  // -- Mode 2: External Browser / Search --

  const isBrowsingSite = tab.url && !tab.loading && (!tab.content || !Array.isArray(tab.content));

  if (isBrowsingSite) {
      return (
          <div className="w-full h-full flex flex-col bg-white">
              {/* Security Banner / External Link Fallback */}
              <div className="bg-yellow-50 text-yellow-800 px-4 py-2 text-xs flex items-center justify-between border-b border-yellow-200">
                  <div className="flex items-center gap-2">
                      <ShieldAlert size={14} />
                      <span>Some websites refuse to load inside this window (security headers).</span>
                  </div>
                  <a 
                    href={tab.url} 
                    target="_blank" 
                    rel="noreferrer"
                    className="flex items-center gap-1 font-bold hover:underline"
                  >
                      Open in New Tab <ExternalLink size={12} />
                  </a>
              </div>
              <iframe 
                src={tab.url}
                className="flex-1 w-full border-none"
                title="External Site"
                sandbox="allow-scripts allow-modals allow-forms allow-same-origin allow-popups"
              />
          </div>
      );
  }

  return (
    <div className="w-full h-full bg-[#1e1e1e] overflow-y-auto custom-scrollbar flex flex-col items-center">

       {/* Empty State / New Tab */}
       {!tab.url && !tab.loading && (
           <div className="mt-32 flex flex-col items-center opacity-50">
               <Globe size={64} className="text-gray-600 mb-4" />
               <h2 className="text-2xl font-bold text-gray-400">New Tab</h2>
               <p className="text-gray-500 mt-2">Search or enter a URL in the address bar</p>
           </div>
       )}

       {/* Loading State - Skeleton Loader */}
       {tab.loading && (
           <div className="w-full max-w-3xl px-6 py-8 space-y-8 animate-pulse">
               <div className="border-b border-gray-700 pb-4 mb-6">
                   <div className="h-6 w-48 bg-gray-800 rounded"></div>
               </div>
               {[1, 2, 3, 4].map((i) => (
                   <div key={i} className="space-y-2">
                       <div className="flex items-center gap-2">
                           <div className="w-6 h-6 rounded-full bg-gray-800"></div>
                           <div className="h-3 w-32 bg-gray-800 rounded"></div>
                       </div>
                       <div className="h-5 w-3/4 bg-gray-700 rounded"></div>
                       <div className="h-3 w-full bg-gray-800 rounded"></div>
                       <div className="h-3 w-2/3 bg-gray-800 rounded"></div>
                   </div>
               ))}
           </div>
       )}

       {/* Search Results */}
       {!tab.loading && tab.content && Array.isArray(tab.content) && (
           <div className="w-full max-w-3xl px-6 py-8 space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
               <div className="border-b border-gray-700 pb-4 mb-6">
                   <h1 className="text-xl text-gray-200 font-medium flex items-center gap-2">
                       <Search size={20} className="text-blue-500" />
                       Results for <span className="text-white font-bold">"{tab.title}"</span>
                   </h1>
               </div>

               {tab.content.length === 0 ? (
                   <div className="text-gray-500 flex items-center gap-2 bg-gray-800/50 p-4 rounded-lg">
                       <AlertCircle size={18} /> No results found. Try a different query.
                   </div>
               ) : (
                   tab.content.map((result: SearchResult, idx: number) => {
                       // Format display URL
                       let displayUrl = result.url;
                       try { displayUrl = new URL(result.url).hostname; } catch(e){}

                       return (
                           <div key={idx} className="group mb-6">
                               <div className="flex items-center gap-2 text-xs text-gray-400 mb-1">
                                   <div className="w-6 h-6 rounded-full bg-gray-700 flex items-center justify-center text-[10px] font-bold text-gray-300">
                                       {displayUrl.charAt(0).toUpperCase()}
                                   </div>
                                   <span className="truncate max-w-[300px]">{displayUrl}</span>
                               </div>
                               <button 
                                    onClick={() => onNavigate(result.url)}
                                    className="text-blue-400 text-lg hover:underline font-medium block mb-1 text-left visited:text-purple-400 outline-none focus:underline"
                               >
                                   {result.title}
                               </button>
                               <p className="text-sm text-gray-400 leading-relaxed line-clamp-2 group-hover:text-gray-300 transition-colors">
                                   {result.snippet}
                               </p>
                           </div>
                       );
                   })
               )}

               <div className="pt-8 border-t border-gray-800 text-center text-xs text-gray-600">
                   Search results provided by Gemini Grounding
               </div>
           </div>
       )}
    </div>
  );
};

