export default function App() {
  // Load initial state from localStorage if available
  const [files, setFiles] = useState<VirtualFile[]>(() => {
    try {
      const saved = localStorage.getItem('devbrowser_files');
      return saved ? JSON.parse(saved) : INITIAL_FILES;
    } catch (e) {
      console.error("Failed to load files from storage", e);
      return INITIAL_FILES;
    }
  });

  const [activeFileName, setActiveFileName] = useState(() => {
    return localStorage.getItem('devbrowser_activeFile') || 'index.html';
  });

  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [layoutMode, setLayoutMode] = useState<LayoutMode>(LayoutMode.SPLIT);
  const [isConsoleOpen, setIsConsoleOpen] = useState(true);
  const [isAIOpen, setIsAIOpen] = useState(false);

  // Navigation & Git State
  const [activeSidebar, setActiveSidebar] = useState<SidebarView>('explorer');
  const [commits, setCommits] = useState<GitCommit[]>([]);

  // -- TAB STATE --
  const [tabs, setTabs] = useState<Tab[]>([
      { id: '1', title: 'Local Preview', type: 'preview', url: 'localhost:3000/index.html', loading: false, viewMode: 'live' }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('1');
  const [iframeKey, setIframeKey] = useState(0);

  // Save to localStorage whenever files change
  useEffect(() => {
    localStorage.setItem('devbrowser_files', JSON.stringify(files));
  }, [files]);

  // Save active file selection
  useEffect(() => {
    localStorage.setItem('devbrowser_activeFile', activeFileName);
  }, [activeFileName]);

  // Init Git
  useEffect(() => {
    if (commits.length === 0) {
      setCommits([{
        id: 'init',
        message: 'Initial Commit',
        timestamp: new Date().toLocaleTimeString(),
        files: JSON.parse(JSON.stringify(INITIAL_FILES))
      }]);
    }
  }, []);

  const activeFile = files.find(f => f.name === activeFileName) || files[0];
  const activeTab = tabs.find(t => t.id === activeTabId) || tabs[0];

  // Determine which file is being previewed (Active HTML or fallback to index.html)
  const previewFile = useMemo(() => {
      if (activeFile?.language === 'html') return activeFile;
      return files.find(f => f.name === 'index.html');
  }, [activeFile, files]);

  // Update file content
  const updateFileContent = (newContent: string) => {
    setFiles(prev => prev.map(f => f.name === activeFileName ? { ...f, content: newContent } : f));
  };

  // Format Code Logic
  const handleFormat = async () => {
    if (!activeFile) return;
    try {
      let parser: string | undefined;
      let plugins: any[] = [];
      switch (activeFile.language) {
        case 'javascript': case 'typescript': case 'json':
          parser = activeFile.language === 'json' ? 'json' : 'babel';
          plugins = [parserBabel, parserEstree];
          break;
        case 'html':
          parser = 'html'; plugins = [parserHtml, parserBabel, parserPostcss, parserEstree];
          break;
        case 'css':
          parser = 'css'; plugins = [parserPostcss];
          break;
        case 'markdown':
          parser = 'markdown'; plugins = [parserMarkdown, parserBabel, parserEstree]; 
          break;
      }
      if (parser) {
        const formatted = await format(activeFile.content, { parser, plugins, printWidth: 80, tabWidth: 2, semi: true, singleQuote: false });
        updateFileContent(formatted);
        setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'success', message: `Formatted ${activeFile.name}` }]);
      }
    } catch (e: any) {
        setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'error', message: `Format error: ${e.message}` }]);
    }
  };

  // Git Operations
  const handleGitCommit = (message: string) => {
    const newCommit: GitCommit = { id: Date.now().toString(), message, timestamp: new Date().toLocaleTimeString(), files: JSON.parse(JSON.stringify(files)) };
    setCommits(prev => [newCommit, ...prev]);
  };

  const handleGitCheckout = (commitId: string) => {
    const commit = commits.find(c => c.id === commitId);
    if (commit) {
      setFiles(JSON.parse(JSON.stringify(commit.files)));
      if (!commit.files.find(f => f.name === activeFileName)) {
        setActiveFileName(commit.files[0]?.name || '');
      }
    }
  };

  // Calculate uncommitted changes
  const uncommittedChangesCount = useMemo(() => {
    const head = commits[0];
    if (!head) return files.filter(f => f.type !== 'directory').length;
    let count = 0;
    files.filter(f => f.type !== 'directory').forEach(f => {
      const prev = head.files.find(pf => pf.name === f.name);
      if (!prev || prev.content !== f.content) count++;
    });
    head.files.filter(f => f.type !== 'directory').forEach(pf => {
      if (!files.find(f => f.name === pf.name)) count++;
    });
    return count;
  }, [files, commits]);

  // File Operations
  const handleCreateFile = (name: string) => {
    if (files.some(f => f.name === name)) return;
    const ext = name.split('.').pop();
    let lang: VirtualFile['language'] = 'text';
    if (ext === 'html') lang = 'html'; else if (ext === 'css') lang = 'css'; else if (ext === 'js') lang = 'javascript'; else if (ext === 'json') lang = 'json';
    setFiles(prev => [...prev, { name, content: '', language: lang, type: 'file' }]);
    setActiveFileName(name);
  };

  const handleCreateFolder = (name: string) => {
    if (files.some(f => f.name === name)) return;
    setFiles(prev => [...prev, { name, content: '', language: 'text', type: 'directory' }]);
  };

  const handleDeleteFile = (name: string) => {
    const newFiles = files.filter(f => f.name !== name && !f.name.startsWith(name + '/'));
    setFiles(newFiles);
    if (activeFileName === name || activeFileName.startsWith(name + '/')) {
        const firstFile = newFiles.find(f => f.type === 'file');
        setActiveFileName(firstFile ? firstFile.name : '');
    }
  };

  const handleRenameFile = (oldName: string, newName: string) => {
      if (files.some(f => f.name === newName)) { alert("Path already exists"); return; }
      setFiles(prev => prev.map(f => {
          if (f.name === oldName) return { ...f, name: newName };
          if (f.name.startsWith(oldName + '/')) return { ...f, name: f.name.replace(oldName + '/', newName + '/') };
          return f;
      }));
      if (activeFileName === oldName) setActiveFileName(newName);
      else if (activeFileName.startsWith(oldName + '/')) setActiveFileName(activeFileName.replace(oldName + '/', newName + '/'));
  };

  // Tab Operations
  const handleNewTab = () => {
      const newId = Date.now().toString();
      setTabs(prev => [...prev, { id: newId, title: 'New Tab', type: 'browser', url: '', loading: false, viewMode: 'live' }]);
      setActiveTabId(newId);
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      const newTabs = tabs.filter(t => t.id !== id);
      if (newTabs.length === 0) {
           // Always keep one tab
           setTabs([{ id: Date.now().toString(), title: 'New Tab', type: 'browser', url: '', loading: false, viewMode: 'live' }]);
      } else {
           setTabs(newTabs);
           if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
      }
  };

  const handleNavigate = async (inputUrl: string) => {
     let url = inputUrl.trim();
     if (!url) return;

     // 1. Localhost Case
     if (url.includes('localhost')) {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, type: 'preview', url: `localhost:3000/${previewFile?.name || ''}`, title: 'Local Preview', loading: false } : t));
         return;
     }

     // 2. URL detection (Heuristic)
     const isUrl = url.includes('.') && !url.includes(' ') && !url.startsWith('?');

     if (isUrl) {
         // It is a URL, visit it
         if (!/^https?:\/\//i.test(url)) url = 'https://' + url;
         let hostname = url;
         try { hostname = new URL(url).hostname; } catch(e){}

         setTabs(prev => prev.map(t => t.id === activeTabId ? { 
            ...t, 
            type: 'browser', 
            viewMode: 'live',
            url: url, 
            title: hostname, 
            loading: false, 
            content: null // null content = show iframe in BrowserTab
         } : t));
     } else {
         // 3. Search Query
         setTabs(prev => prev.map(t => t.id === activeTabId ? { 
            ...t, 
            type: 'browser', 
            viewMode: 'live',
            url: url, // Keep query in address bar
            title: url, 
            loading: true, 
            content: [] 
         } : t));

         try {
             const results = await searchWeb(url);
             setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, content: results } : t));
         } catch (e) {
             setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, content: [], title: 'Error' } : t));
         }
     }
  };

  const handleSwitchToReader = async () => {
     const tab = activeTab;
     if (!tab.url) return;

     // Toggle Logic
     if (tab.viewMode === 'reader') {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, viewMode: 'live' } : t));
         return;
     }

     // Set mode to reader immediately to show UI state
     setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, viewMode: 'reader' } : t));

     // If we already have content, don't fetch again
     if (tab.readerContent) return;

     // Set loading state for reader (reuse loading flag or add specific one, reusing main loading for simplicity but keeping iframe intact might be better. Let's toggle loading.)
     setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: true } : t));

     try {
         const content = await readPageContent(tab.url);
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, readerContent: content } : t));
     } catch (e) {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, readerContent: "Failed to load content via AI Reader." } : t));
     }
  };

  // Handle messages from iframe (console)
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'console') {
        const newLog: LogEntry = {
          id: Date.now().toString() + Math.random(),
          timestamp: new Date().toLocaleTimeString(),
          level: event.data.level,
          message: event.data.message.map((m: any) => typeof m === 'object' ? JSON.stringify(m) : String(m)).join(' ')
        };
        setLogs(prev => [...prev, newLog]);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const clearLogs = () => setLogs([]);

  // Console Command Handler
  const handleConsoleCommand = (cmd: string) => { /* Same as before */ };

  // Bundler Logic: Inject CSS/JS into HTML with path resolution
  const getSrcDoc = () => {
    if (!previewFile) return "";
    let html = previewFile.content;
    const basePath = previewFile.name;
    const resolvePath = (relPath: string) => {
        if (relPath.startsWith('http') || relPath.startsWith('//')) return null;
        if (relPath.startsWith('/')) return relPath.slice(1);
        const stack = basePath.split('/'); stack.pop();
        const parts = relPath.split('/');
        for (const part of parts) { if (part === '.') continue; if (part === '..') { if (stack.length > 0) stack.pop(); } else { stack.push(part); } }
        return stack.join('/');
    };
    html = html.replace(/<link\s+[^>]*rel="stylesheet"[^>]*>/g, (match) => {
      const hrefMatch = match.match(/href="([^"]+)"/); if (!hrefMatch) return match;
      const resolvedPath = resolvePath(hrefMatch[1]); if (!resolvedPath) return match;
      const cssFile = files.find(f => f.name === resolvedPath); return cssFile ? `<style>/* ${resolvedPath} */\n${cssFile.content}</style>` : match;
    });
    html = html.replace(/<script\s+[^>]*src="([^"]+)"[^>]*><\/script>/g, (match, src) => {
      const resolvedPath = resolvePath(src); if (!resolvedPath) return match;
      const jsFile = files.find(f => f.name === resolvedPath); return jsFile ? `<script>/* ${resolvedPath} */\n${jsFile.content}</script>` : match;
    });
    const consoleHijack = `<script>
        const originalLog = console.log; const originalWarn = console.warn; const originalError = console.error; const originalInfo = console.info;
        function sendToParent(level, args) { try { window.parent.postMessage({ type: 'console', level: level, message: Array.from(args).map(a => { if (a instanceof Error) return a.toString(); return a; }) }, '*'); } catch(e) {} }
        console.log = function(...args) { originalLog.apply(console, args); sendToParent('log', args); };
        console.warn = function(...args) { originalWarn.apply(console, args); sendToParent('warn', args); };
        console.error = function(...args) { originalError.apply(console, args); sendToParent('error', args); };
        console.info = function(...args) { originalInfo.apply(console, args); sendToParent('info', args); };
        window.onerror = function(msg, url, line) { sendToParent('error', [msg + " (Line " + line + ")"]); }
      </script>`;
    if (html.includes('</body>')) { return html.replace('</body>', `${consoleHijack}</body>`); }
    return html + consoleHijack;
  };

  const srcDoc = useMemo(() => getSrcDoc(), [files, previewFile]);

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Bar / Tab Strip */}
      <div className="flex items-end h-10 px-2 bg-browser-bg border-b border-browser-toolbar select-none gap-2 pt-2">
           {/* Controls */}
           <div className="flex items-center gap-2 mb-2 mr-2">
              <div className="flex gap-1.5 px-2">
                 <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
              </div>
           </div>

           {/* Tab Strip */}
           <div className="flex-1 flex overflow-x-auto no-scrollbar items-end h-full">
               {tabs.map(tab => (
                   <div 
                      key={tab.id}
                      onClick={() => setActiveTabId(tab.id)}
                      className={`
                        group relative flex items-center gap-2 px-3 py-1.5 min-w-[120px] max-w-[200px] text-xs rounded-t-lg cursor-default border-r border-gray-800/50 transition-colors
                        ${activeTabId === tab.id ? 'bg-[#3c3c3c] text-white' : 'bg-transparent text-gray-500 hover:bg-[#2d2d2d]'}
                      `}
                   >
                       {tab.type === 'preview' ? <Lock size={10} className="text-green-500" /> : <Globe size={10} className="text-blue-400" />}
                       <span className="truncate flex-1">{tab.title || 'New Tab'}</span>
                       <button 
                         onClick={(e) => handleCloseTab(tab.id, e)}
                         className={`p-0.5 rounded-full hover:bg-white/20 opacity-0 group-hover:opacity-100 ${tabs.length === 1 ? 'hidden' : ''}`}
                       >
                           <X size={10} />
                       </button>
                   </div>
               ))}
               <button onClick={handleNewTab} className="p-1.5 ml-1 text-gray-500 hover:text-white hover:bg-white/10 rounded mb-1">
                   <Plus size={14} />
               </button>
           </div>

           {/* Window Controls */}
           <div className="flex items-center gap-2 mb-1.5">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className="p-1.5 hover:bg-white/10 rounded text-gray-400 hover:text-white transition"
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={16} /> : <SplitSquareHorizontal size={16} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1.5 rounded transition-colors ${isAIOpen ? 'text-browser-accent bg-blue-500/10' : 'text-gray-400 hover:text-white hover:bg-white/10'}`}
              >
                <Sparkles size={16} />
              </button>
           </div>
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Activity Bar */}
        <ActivityBar activeView={activeSidebar} onViewChange={setActiveSidebar} changesCount={uncommittedChangesCount} />

        {/* Sidebar Content */}
        {activeSidebar === 'explorer' && (
            <FileExplorer 
              files={files} activeFileName={activeFileName} onSelect={setActiveFileName} 
              onCreate={handleCreateFile} onCreateFolder={handleCreateFolder} 
              onDelete={(name) => { if(confirm(`Delete ${name}?`)) handleDeleteFile(name); }} onRename={handleRenameFile}
            />
        )}
        {activeSidebar === 'search' && <Search files={files} onSelect={setActiveFileName} />}
        {activeSidebar === 'git' && <SourceControl files={files} commits={commits} onCommit={handleGitCommit} onCheckout={handleGitCheckout} />}
        {activeSidebar === 'deploy' && <Deployment files={files} />}

        {/* Editor Pane (Left) */}
        <div className={`flex flex-col border-r border-gray-800 transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-0 overflow-hidden'}`}>
          <div className="h-9 bg-[#1e1e1e] border-b border-gray-800 flex items-center px-4 text-xs">
             <Code2 size={14} className="text-blue-500 mr-2" />
             <span className="text-gray-300">{activeFileName}</span>
             <div className="ml-auto flex items-center gap-4">
                 <button onClick={handleFormat} className="flex items-center gap-1.5 text-gray-500 hover:text-white"><AlignLeft size={14} /><span className="hidden sm:inline">Format</span></button>
             </div>
          </div>
          <textarea
            className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed"
            value={activeFile?.content || ''}
            onChange={(e) => updateFileContent(e.target.value)}
            spellCheck={false}
          />
        </div>

        {/* Browser Pane (Right) - Tab Content */}
        <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'}`}>
          <AddressBar 
              url={activeTab.url} 
              onNavigate={handleNavigate} 
              onRefresh={() => setIframeKey(k => k + 1)} 
              isLoading={activeTab.loading}
          />
          <div className="flex-1 relative overflow-hidden bg-[#1e1e1e]">
              <BrowserTab 
                 key={`${activeTab.id}-${iframeKey}`} 
                 tab={activeTab} 
                 srcDoc={srcDoc} 
                 onNavigate={handleNavigate}
                 onToggleReader={handleSwitchToReader}
              />
          </div>
        </div>

        {/* AI Sidebar */}
        <AIAssistant currentCode={activeFile?.content || ''} isOpen={isAIOpen} onClose={() => setIsAIOpen(false)} onUpdateCode={updateFileContent} />
      </div>

      <Console logs={logs} onClear={clearLogs} isOpen={isConsoleOpen} toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} onCommand={handleConsoleCommand} />
    </div>
  );
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Code2, SplitSquareHorizontal, Maximize2, Sparkles, Layout, AlignLeft, Plus, X, Globe, Lock } from 'lucide-react';
import { LogEntry, LayoutMode, VirtualFile, GitCommit, SidebarView, Tab } from './types';
import Console from './components/Console';
import AddressBar from './components/AddressBar';
import AIAssistant from './components/AIAssistant';
import FileExplorer from './components/FileExplorer';
import SourceControl from './components/SourceControl';
import Deployment from './components/Deployment';
import ActivityBar from './components/ActivityBar';
import Search from './components/Search';
import BrowserTab from './components/BrowserTab';
import { searchWeb, readPageContent } from './services/geminiService';

// Prettier Imports
import { format } from "prettier/standalone";
import parserBabel from "prettier/plugins/babel";
import parserEstree from "prettier/plugins/estree";
import parserHtml from "prettier/plugins/html";
import parserPostcss from "prettier/plugins/postcss";
import parserMarkdown from "prettier/plugins/markdown";

// Initial Empty Project
const INITIAL_FILES: VirtualFile[] = [
  {
    name: 'index.html',
    language: 'html',
    type: 'file',
    content: `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>New Project</title>
</head>
<body>
  <div class="container">
    <h1>Hello, World!</h1>
    <p>Start editing to see magic happen.</p>
  </div>
  <style>
    body { font-family: system-ui, sans-serif; padding: 2rem; background: #f0f0f0; }
    .container { background: white; padding: 2rem; border-radius: 8px; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
  </style>
</body>
</html>`
  }
];

export default function App() {
  // Load initial state from localStorage if available
  const [files, setFiles] = useState<VirtualFile[]>(() => {
    try {
      const saved = localStorage.getItem('devbrowser_files');
      return saved ? JSON.parse(saved) : INITIAL_FILES;
    } catch (e) {
      console.error("Failed to load files from storage", e);
      return INITIAL_FILES;
    }
  });

  const [activeFileName, setActiveFileName] = useState(() => {
    return localStorage.getItem('devbrowser_activeFile') || 'index.html';
  });

  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [layoutMode, setLayoutMode] = useState<LayoutMode>(LayoutMode.SPLIT);
  const [isConsoleOpen, setIsConsoleOpen] = useState(true);
  const [isAIOpen, setIsAIOpen] = useState(false);

  // Navigation & Git State
  const [activeSidebar, setActiveSidebar] = useState<SidebarView>('explorer');
  const [commits, setCommits] = useState<GitCommit[]>([]);

  // -- TAB STATE --
  const [tabs, setTabs] = useState<Tab[]>([
      { id: '1', title: 'Local Preview', type: 'preview', url: 'localhost:3000/index.html', loading: false, viewMode: 'live' }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('1');
  const [iframeKey, setIframeKey] = useState(0);

  // Save to localStorage whenever files change
  useEffect(() => {
    localStorage.setItem('devbrowser_files', JSON.stringify(files));
  }, [files]);

  // Save active file selection
  useEffect(() => {
    localStorage.setItem('devbrowser_activeFile', activeFileName);
  }, [activeFileName]);

  // Init Git
  useEffect(() => {
    if (commits.length === 0) {
      setCommits([{
        id: 'init',
        message: 'Initial Commit',
        timestamp: new Date().toLocaleTimeString(),
        files: JSON.parse(JSON.stringify(INITIAL_FILES))
      }]);
    }
  }, []);

  const activeFile = files.find(f => f.name === activeFileName) || files[0];
  const activeTab = tabs.find(t => t.id === activeTabId) || tabs[0];

  // Determine which file is being previewed (Active HTML or fallback to index.html)
  const previewFile = useMemo(() => {
      if (activeFile?.language === 'html') return activeFile;
      return files.find(f => f.name === 'index.html');
  }, [activeFile, files]);

  // Update file content
  const updateFileContent = (newContent: string) => {
    setFiles(prev => prev.map(f => f.name === activeFileName ? { ...f, content: newContent } : f));
  };

  // Format Code Logic
  const handleFormat = async () => {
    if (!activeFile) return;
    try {
      let parser: string | undefined;
      let plugins: any[] = [];
      switch (activeFile.language) {
        case 'javascript': case 'typescript': case 'json':
          parser = activeFile.language === 'json' ? 'json' : 'babel';
          plugins = [parserBabel, parserEstree];
          break;
        case 'html':
          parser = 'html'; plugins = [parserHtml, parserBabel, parserPostcss, parserEstree];
          break;
        case 'css':
          parser = 'css'; plugins = [parserPostcss];
          break;
        case 'markdown':
          parser = 'markdown'; plugins = [parserMarkdown, parserBabel, parserEstree]; 
          break;
      }
      if (parser) {
        const formatted = await format(activeFile.content, { parser, plugins, printWidth: 80, tabWidth: 2, semi: true, singleQuote: false });
        updateFileContent(formatted);
        setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'success', message: `Formatted ${activeFile.name}` }]);
      }
    } catch (e: any) {
        setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'error', message: `Format error: ${e.message}` }]);
    }
  };

  // Git Operations
  const handleGitCommit = (message: string) => {
    const newCommit: GitCommit = { id: Date.now().toString(), message, timestamp: new Date().toLocaleTimeString(), files: JSON.parse(JSON.stringify(files)) };
    setCommits(prev => [newCommit, ...prev]);
  };

  const handleGitCheckout = (commitId: string) => {
    const commit = commits.find(c => c.id === commitId);
    if (commit) {
      setFiles(JSON.parse(JSON.stringify(commit.files)));
      if (!commit.files.find(f => f.name === activeFileName)) {
        setActiveFileName(commit.files[0]?.name || '');
      }
    }
  };

  // Calculate uncommitted changes
  const uncommittedChangesCount = useMemo(() => {
    const head = commits[0];
    if (!head) return files.filter(f => f.type !== 'directory').length;
    let count = 0;
    files.filter(f => f.type !== 'directory').forEach(f => {
      const prev = head.files.find(pf => pf.name === f.name);
      if (!prev || prev.content !== f.content) count++;
    });
    head.files.filter(f => f.type !== 'directory').forEach(pf => {
      if (!files.find(f => f.name === pf.name)) count++;
    });
    return count;
  }, [files, commits]);

  // File Operations
  const handleCreateFile = (name: string) => {
    if (files.some(f => f.name === name)) return;
    const ext = name.split('.').pop();
    let lang: VirtualFile['language'] = 'text';
    if (ext === 'html') lang = 'html'; else if (ext === 'css') lang = 'css'; else if (ext === 'js') lang = 'javascript'; else if (ext === 'json') lang = 'json';
    setFiles(prev => [...prev, { name, content: '', language: lang, type: 'file' }]);
    setActiveFileName(name);
  };

  const handleCreateFolder = (name: string) => {
    if (files.some(f => f.name === name)) return;
    setFiles(prev => [...prev, { name, content: '', language: 'text', type: 'directory' }]);
  };

  const handleDeleteFile = (name: string) => {
    const newFiles = files.filter(f => f.name !== name && !f.name.startsWith(name + '/'));
    setFiles(newFiles);
    if (activeFileName === name || activeFileName.startsWith(name + '/')) {
        const firstFile = newFiles.find(f => f.type === 'file');
        setActiveFileName(firstFile ? firstFile.name : '');
    }
  };

  const handleRenameFile = (oldName: string, newName: string) => {
      if (files.some(f => f.name === newName)) { alert("Path already exists"); return; }
      setFiles(prev => prev.map(f => {
          if (f.name === oldName) return { ...f, name: newName };
          if (f.name.startsWith(oldName + '/')) return { ...f, name: f.name.replace(oldName + '/', newName + '/') };
          return f;
      }));
      if (activeFileName === oldName) setActiveFileName(newName);
      else if (activeFileName.startsWith(oldName + '/')) setActiveFileName(activeFileName.replace(oldName + '/', newName + '/'));
  };

  const handleImportProject = (importedFiles: VirtualFile[]) => {
      if (confirm('Importing will overwrite your current files. Continue?')) {
          setFiles(importedFiles);
          const firstFile = importedFiles.find(f => f.type === 'file');
          if (firstFile) setActiveFileName(firstFile.name);
          setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'success', message: `Project imported successfully (${importedFiles.length} files)` }]);
      }
  };

  // Tab Operations
  const handleNewTab = () => {
      const newId = Date.now().toString();
      setTabs(prev => [...prev, { id: newId, title: 'New Tab', type: 'browser', url: '', loading: false, viewMode: 'live' }]);
      setActiveTabId(newId);
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      const newTabs = tabs.filter(t => t.id !== id);
      if (newTabs.length === 0) {
           // Always keep one tab
           setTabs([{ id: Date.now().toString(), title: 'New Tab', type: 'browser', url: '', loading: false, viewMode: 'live' }]);
      } else {
           setTabs(newTabs);
           if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
      }
  };

  const handleNavigate = async (inputUrl: string) => {
     let url = inputUrl.trim();
     if (!url) return;

     // 1. Localhost Case
     if (url.includes('localhost')) {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, type: 'preview', url: `localhost:3000/${previewFile?.name || ''}`, title: 'Local Preview', loading: false } : t));
         return;
     }

     // 2. URL detection (Heuristic)
     const isUrl = url.includes('.') && !url.includes(' ') && !url.startsWith('?');

     if (isUrl) {
         // It is a URL, visit it
         if (!/^https?:\/\//i.test(url)) url = 'https://' + url;
         let hostname = url;
         try { hostname = new URL(url).hostname; } catch(e){}

         setTabs(prev => prev.map(t => t.id === activeTabId ? { 
            ...t, 
            type: 'browser', 
            viewMode: 'live',
            url: url, 
            title: hostname, 
            loading: false, 
            content: null // null content = show iframe in BrowserTab
         } : t));
     } else {
         // 3. Search Query
         setTabs(prev => prev.map(t => t.id === activeTabId ? { 
            ...t, 
            type: 'browser', 
            viewMode: 'live',
            url: url, // Keep query in address bar
            title: url, 
            loading: true, 
            content: [] 
         } : t));

         try {
             const results = await searchWeb(url);
             setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, content: results } : t));
         } catch (e) {
             setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, content: [], title: 'Error' } : t));
         }
     }
  };

  const handleSwitchToReader = async () => {
     const tab = activeTab;
     if (!tab.url) return;

     // Toggle Logic
     if (tab.viewMode === 'reader') {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, viewMode: 'live' } : t));
         return;
     }

     // Set mode to reader immediately to show UI state
     setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, viewMode: 'reader' } : t));

     // If we already have content, don't fetch again
     if (tab.readerContent) return;

     // Set loading state for reader (reuse loading flag or add specific one, reusing main loading for simplicity but keeping iframe intact might be better. Let's toggle loading.)
     setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: true } : t));

     try {
         const content = await readPageContent(tab.url);
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, readerContent: content } : t));
     } catch (e) {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, readerContent: "Failed to load content via AI Reader." } : t));
     }
  };

  // Handle messages from iframe (console)
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'console') {
        const newLog: LogEntry = {
          id: Date.now().toString() + Math.random(),
          timestamp: new Date().toLocaleTimeString(),
          level: event.data.level,
          message: event.data.message.map((m: any) => typeof m === 'object' ? JSON.stringify(m) : String(m)).join(' ')
        };
        setLogs(prev => [...prev, newLog]);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const clearLogs = () => setLogs([]);

  // Console Command Handler
  const handleConsoleCommand = (cmd: string) => { /* Same as before */ };

  // Bundler Logic: Inject CSS/JS into HTML with path resolution
  const getSrcDoc = () => {
    if (!previewFile) return "";
    let html = previewFile.content;
    const basePath = previewFile.name;
    const resolvePath = (relPath: string) => {
        if (relPath.startsWith('http') || relPath.startsWith('//')) return null;
        if (relPath.startsWith('/')) return relPath.slice(1);
        const stack = basePath.split('/'); stack.pop();
        const parts = relPath.split('/');
        for (const part of parts) { if (part === '.') continue; if (part === '..') { if (stack.length > 0) stack.pop(); } else { stack.push(part); } }
        return stack.join('/');
    };
    html = html.replace(/<link\s+[^>]*rel="stylesheet"[^>]*>/g, (match) => {
      const hrefMatch = match.match(/href="([^"]+)"/); if (!hrefMatch) return match;
      const resolvedPath = resolvePath(hrefMatch[1]); if (!resolvedPath) return match;
      const cssFile = files.find(f => f.name === resolvedPath); return cssFile ? `<style>/* ${resolvedPath} */\n${cssFile.content}</style>` : match;
    });
    html = html.replace(/<script\s+[^>]*src="([^"]+)"[^>]*><\/script>/g, (match, src) => {
      const resolvedPath = resolvePath(src); if (!resolvedPath) return match;
      const jsFile = files.find(f => f.name === resolvedPath); return jsFile ? `<script>/* ${resolvedPath} */\n${jsFile.content}</script>` : match;
    });
    const consoleHijack = `<script>
        const originalLog = console.log; const originalWarn = console.warn; const originalError = console.error; const originalInfo = console.info;
        function sendToParent(level, args) { try { window.parent.postMessage({ type: 'console', level: level, message: Array.from(args).map(a => { if (a instanceof Error) return a.toString(); return a; }) }, '*'); } catch(e) {} }
        console.log = function(...args) { originalLog.apply(console, args); sendToParent('log', args); };
        console.warn = function(...args) { originalWarn.apply(console, args); sendToParent('warn', args); };
        console.error = function(...args) { originalError.apply(console, args); sendToParent('error', args); };
        console.info = function(...args) { originalInfo.apply(console, args); sendToParent('info', args); };
        window.onerror = function(msg, url, line) { sendToParent('error', [msg + " (Line " + line + ")"]); }
      </script>`;
    if (html.includes('</body>')) { return html.replace('</body>', `${consoleHijack}</body>`); }
    return html + consoleHijack;
  };

  const srcDoc = useMemo(() => getSrcDoc(), [files, previewFile]);

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Bar / Tab Strip */}
      <div className="flex items-end h-10 px-2 bg-browser-bg border-b border-browser-toolbar select-none gap-2 pt-2">
           {/* Controls */}
           <div className="flex items-center gap-2 mb-2 mr-2">
              <div className="flex gap-1.5 px-2">
                 <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
              </div>
           </div>

           {/* Tab Strip */}
           <div className="flex-1 flex overflow-x-auto no-scrollbar items-end h-full">
               {tabs.map(tab => (
                   <div 
                      key={tab.id}
                      onClick={() => setActiveTabId(tab.id)}
                      className={`
                        group relative flex items-center gap-2 px-3 py-1.5 min-w-[120px] max-w-[200px] text-xs rounded-t-lg cursor-default border-r border-gray-800/50 transition-colors
                        ${activeTabId === tab.id ? 'bg-[#3c3c3c] text-white' : 'bg-transparent text-gray-500 hover:bg-[#2d2d2d]'}
                      `}
                   >
                       {tab.type === 'preview' ? <Lock size={10} className="text-green-500" /> : <Globe size={10} className="text-blue-400" />}
                       <span className="truncate flex-1">{tab.title || 'New Tab'}</span>
                       <button 
                         onClick={(e) => handleCloseTab(tab.id, e)}
                         className={`p-0.5 rounded-full hover:bg-white/20 opacity-0 group-hover:opacity-100 ${tabs.length === 1 ? 'hidden' : ''}`}
                       >
                           <X size={10} />
                       </button>
                   </div>
               ))}
               <button onClick={handleNewTab} className="p-1.5 ml-1 text-gray-500 hover:text-white hover:bg-white/10 rounded mb-1">
                   <Plus size={14} />
               </button>
           </div>

           {/* Window Controls */}
           <div className="flex items-center gap-2 mb-1.5">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className="p-1.5 hover:bg-white/10 rounded text-gray-400 hover:text-white transition"
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={16} /> : <SplitSquareHorizontal size={16} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1.5 rounded transition-colors ${isAIOpen ? 'text-browser-accent bg-blue-500/10' : 'text-gray-400 hover:text-white hover:bg-white/10'}`}
              >
                <Sparkles size={16} />
              </button>
           </div>
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Activity Bar */}
        <ActivityBar activeView={activeSidebar} onViewChange={setActiveSidebar} changesCount={uncommittedChangesCount} />

        {/* Sidebar Content */}
        {activeSidebar === 'explorer' && (
            <FileExplorer 
              files={files} activeFileName={activeFileName} onSelect={setActiveFileName} 
              onCreate={handleCreateFile} onCreateFolder={handleCreateFolder} 
              onDelete={(name) => { if(confirm(`Delete ${name}?`)) handleDeleteFile(name); }} onRename={handleRenameFile}
              onImport={handleImportProject}
            />
        )}
        {activeSidebar === 'search' && <Search files={files} onSelect={setActiveFileName} />}
        {activeSidebar === 'git' && <SourceControl files={files} commits={commits} onCommit={handleGitCommit} onCheckout={handleGitCheckout} />}
        {activeSidebar === 'deploy' && <Deployment files={files} />}

        {/* Editor Pane (Left) */}
        <div className={`flex flex-col border-r border-gray-800 transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-0 overflow-hidden'}`}>
          <div className="h-9 bg-[#1e1e1e] border-b border-gray-800 flex items-center px-4 text-xs">
             <Code2 size={14} className="text-blue-500 mr-2" />
             <span className="text-gray-300">{activeFileName}</span>
             <div className="ml-auto flex items-center gap-4">
                 <button onClick={handleFormat} className="flex items-center gap-1.5 text-gray-500 hover:text-white"><AlignLeft size={14} /><span className="hidden sm:inline">Format</span></button>
             </div>
          </div>
          <textarea
            className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed"
            value={activeFile?.content || ''}
            onChange={(e) => updateFileContent(e.target.value)}
            spellCheck={false}
          />
        </div>

        {/* Browser Pane (Right) - Tab Content */}
        <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'}`}>
          <AddressBar 
              url={activeTab.url} 
              onNavigate={handleNavigate} 
              onRefresh={() => setIframeKey(k => k + 1)} 
              isLoading={activeTab.loading}
          />
          <div className="flex-1 relative overflow-hidden bg-[#1e1e1e]">
              <BrowserTab 
                 key={`${activeTab.id}-${iframeKey}`} 
                 tab={activeTab} 
                 srcDoc={srcDoc} 
                 onNavigate={handleNavigate}
                 onToggleReader={handleSwitchToReader}
              />
          </div>
        </div>

        {/* AI Sidebar */}
        <AIAssistant currentCode={activeFile?.content || ''} isOpen={isAIOpen} onClose={() => setIsAIOpen(false)} onUpdateCode={updateFileContent} />
      </div>

      <Console logs={logs} onClear={clearLogs} isOpen={isConsoleOpen} toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} onCommand={handleConsoleCommand} />
    </div>
  );
}

import React, { useState, useMemo, useRef } from 'react';
import { FileCode, FileJson, FileType, File, FolderOpen, Folder, FolderPlus, FilePlus, Edit2, Trash2, ChevronRight, ChevronDown, Download, Upload } from 'lucide-react';
import { VirtualFile } from '../types';

interface FileExplorerProps {
  files: VirtualFile[];
  activeFileName: string;
  onSelect: (fileName: string) => void;
  onCreate: (fileName: string) => void;
  onCreateFolder: (folderName: string) => void;
  onDelete: (fileName: string) => void;
  onRename: (oldName: string, newName: string) => void;
  onImport?: (files: VirtualFile[]) => void;
}

const getFileIcon = (fileName: string) => {
  if (fileName.endsWith('.html')) return <FileCode size={14} className="text-orange-400" />;
  if (fileName.endsWith('.css')) return <FileType size={14} className="text-blue-400" />;
  if (fileName.endsWith('.js') || fileName.endsWith('.ts') || fileName.endsWith('.tsx')) return <FileCode size={14} className="text-yellow-400" />;
  if (fileName.endsWith('.json')) return <FileJson size={14} className="text-green-400" />;
  return <File size={14} className="text-gray-400" />;
};

// Tree Building Logic
interface TreeNode {
  id: string; // full path
  name: string; // segment name
  type: 'file' | 'directory';
  children: Record<string, TreeNode>;
  isOpen: boolean;
}

const buildTree = (files: VirtualFile[]) => {
  const root: Record<string, TreeNode> = {};

  // Sort files so folders come first, then alphabetical
  const sorted = [...files].sort((a, b) => {
      const typeA = a.type || 'file';
      const typeB = b.type || 'file';
      if (typeA !== typeB) return typeA === 'directory' ? -1 : 1;
      return a.name.localeCompare(b.name);
  });

  sorted.forEach(file => {
    const parts = file.name.split('/');
    let currentLevel = root;

    parts.forEach((part, index) => {
      const path = parts.slice(0, index + 1).join('/');
      const isFile = index === parts.length - 1 && file.type !== 'directory';

      if (!currentLevel[part]) {
        currentLevel[part] = {
          id: path,
          name: part,
          type: isFile ? 'file' : 'directory',
          children: {},
          isOpen: true // default open for demo
        };
      }
      currentLevel = currentLevel[part].children;
    });
  });

  return root;
};

const FileTreeItem: React.FC<{
  node: TreeNode;
  level: number;
  activeFileName: string;
  onSelect: (path: string) => void;
  onDelete: (path: string) => void;
  onRename: (oldPath: string, newPath: string) => void;
  selectedPath: string | null;
  setSelectedPath: (path: string | null) => void;
}> = ({ node, level, activeFileName, onSelect, onDelete, onRename, selectedPath, setSelectedPath }) => {
  const [isOpen, setIsOpen] = useState(node.isOpen);
  const [isRenaming, setIsRenaming] = useState(false);
  const [renameValue, setRenameValue] = useState(node.name);

  const handleRenameSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (renameValue !== node.name) {
       // Construct new path
       const parentPath = node.id.substring(0, node.id.lastIndexOf('/'));
       const newPath = parentPath ? `${parentPath}/${renameValue}` : renameValue;
       onRename(node.id, newPath);
    }
    setIsRenaming(false);
  };

  const hasChildren = Object.keys(node.children).length > 0;
  const isSelected = selectedPath === node.id;
  const isActive = activeFileName === node.id;

  return (
    <div className="select-none">
      <div 
        className={`flex items-center gap-1 py-1 px-2 cursor-pointer transition-colors ${
            isActive ? 'bg-browser-tab text-white' : 
            isSelected ? 'bg-white/10 text-gray-200' : 'text-gray-400 hover:text-gray-200 hover:bg-white/5'
        }`}
        style={{ paddingLeft: `${level * 12 + 8}px` }}
        onClick={(e) => {
            e.stopPropagation();
            setSelectedPath(node.id);
            if (node.type === 'directory') {
                setIsOpen(!isOpen);
            } else {
                onSelect(node.id);
            }
        }}
      >
        <span className="opacity-70 flex-shrink-0 w-4">
            {node.type === 'directory' && (
                isOpen ? <ChevronDown size={12} /> : <ChevronRight size={12} />
            )}
        </span>

        {isRenaming ? (
            <form onSubmit={handleRenameSubmit} onClick={e => e.stopPropagation()} className="flex-1 min-w-0">
                <input
                    autoFocus
                    value={renameValue}
                    onChange={e => setRenameValue(e.target.value)}
                    onBlur={handleRenameSubmit}
                    className="w-full bg-gray-800 text-white text-xs px-1 py-0.5 rounded border border-blue-500 outline-none"
                />
            </form>
        ) : (
            <div className="flex-1 flex items-center justify-between min-w-0 group">
                <div className="flex items-center gap-2 truncate">
                    {node.type === 'directory' ? (
                        isOpen ? <FolderOpen size={14} className="text-blue-300" /> : <Folder size={14} className="text-blue-300" />
                    ) : (
                        getFileIcon(node.name)
                    )}
                    <span className="truncate text-xs">{node.name}</span>
                </div>
                <div className="hidden group-hover:flex items-center gap-1 bg-[#252526] shadow-sm ml-2">
                     <button onClick={(e) => { e.stopPropagation(); setIsRenaming(true); }} className="p-0.5 hover:text-blue-400">
                         <Edit2 size={10} />
                     </button>
                     <button onClick={(e) => { e.stopPropagation(); onDelete(node.id); }} className="p-0.5 hover:text-red-400">
                         <Trash2 size={10} />
                     </button>
                </div>
            </div>
        )}
      </div>

      {node.type === 'directory' && isOpen && (
          <div>
              {Object.values(node.children)
                .sort((a: TreeNode, b: TreeNode) => {
                    if (a.type !== b.type) return a.type === 'directory' ? -1 : 1;
                    return a.name.localeCompare(b.name);
                })
                .map((child: TreeNode) => (
                  <FileTreeItem 
                    key={child.id} 
                    node={child} 
                    level={level + 1} 
                    activeFileName={activeFileName}
                    onSelect={onSelect}
                    onDelete={onDelete}
                    onRename={onRename}
                    selectedPath={selectedPath}
                    setSelectedPath={setSelectedPath}
                  />
              ))}
          </div>
      )}
    </div>
  );
};

const FileExplorer: React.FC<FileExplorerProps> = ({ files, activeFileName, onSelect, onCreate, onCreateFolder, onDelete, onRename, onImport }) => {
  const [isCreating, setIsCreating] = useState<'file' | 'folder' | null>(null);
  const [newName, setNewName] = useState('');
  const [selectedPath, setSelectedPath] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const fileTree = useMemo(() => buildTree(files), [files]);

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName) {
        setIsCreating(null);
        return;
    }

    // Determine path based on selection
    // If selectedPath is a file, use its parent directory. If directory, use it.
    let parentPath = '';
    if (selectedPath) {
        const selectedFile = files.find(f => f.name === selectedPath);
        if (selectedFile?.type === 'directory') {
            parentPath = selectedPath;
        } else {
            const parts = selectedPath.split('/');
            parts.pop();
            parentPath = parts.join('/');
        }
    }

    const fullPath = parentPath ? `${parentPath}/${newName}` : newName;

    if (isCreating === 'file') {
        onCreate(fullPath);
    } else {
        onCreateFolder(fullPath);
    }

    setNewName('');
    setIsCreating(null);
  };

  const handleDownload = () => {
    const data = JSON.stringify(files, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `project-backup-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file || !onImport) return;

      const reader = new FileReader();
      reader.onload = (ev) => {
          try {
              const content = JSON.parse(ev.target?.result as string);
              if (Array.isArray(content)) {
                  onImport(content);
              } else {
                  alert('Invalid project file format');
              }
          } catch(err) {
              alert('Failed to parse project file');
          }
          if (fileInputRef.current) fileInputRef.current.value = '';
      };
      reader.readAsText(file);
  };

  return (
    <div className="w-60 bg-browser-toolbar border-r border-gray-700 flex flex-col h-full select-none" onClick={() => setSelectedPath(null)}>
      <div className="h-9 px-3 flex items-center justify-between border-b border-gray-700 bg-[#252526]">
        <div className="flex items-center gap-2 text-xs font-semibold text-gray-400">
          <FolderOpen size={14} />
          <span>EXPLORER</span>
        </div>
        <div className="flex items-center gap-1">
             {/* Import/Export */}
            {onImport && (
                <>
                    <button 
                        onClick={(e) => { e.stopPropagation(); fileInputRef.current?.click(); }}
                        className="text-gray-400 hover:text-blue-400 p-1 hover:bg-white/10 rounded"
                        title="Import Project from Disk"
                    >
                        <Upload size={14} />
                    </button>
                    <button 
                        onClick={(e) => { e.stopPropagation(); handleDownload(); }}
                        className="text-gray-400 hover:text-green-400 p-1 hover:bg-white/10 rounded"
                        title="Export Project to Disk"
                    >
                        <Download size={14} />
                    </button>
                    <div className="w-px h-3 bg-gray-700 mx-1"></div>
                </>
            )}

            <button 
                onClick={(e) => { e.stopPropagation(); setIsCreating('file'); }} 
                className="text-gray-400 hover:text-white p-1 hover:bg-white/10 rounded"
                title="New File"
            >
                <FilePlus size={14} />
            </button>
            <button 
                onClick={(e) => { e.stopPropagation(); setIsCreating('folder'); }} 
                className="text-gray-400 hover:text-white p-1 hover:bg-white/10 rounded"
                title="New Folder"
            >
                <FolderPlus size={14} />
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto py-2 custom-scrollbar">
        {isCreating && (
          <div className="px-2 mb-2">
            <form onSubmit={handleCreateSubmit} className="flex items-center gap-1 bg-gray-800 border border-blue-500 px-2 py-1 rounded">
               {isCreating === 'folder' ? <Folder size={12} className="text-gray-400" /> : <File size={12} className="text-gray-400" />}
               <input
                 autoFocus
                 type="text"
                 value={newName}
                 onChange={(e) => setNewName(e.target.value)}
                 onBlur={() => { if(!newName) setIsCreating(null); }}
                 placeholder={isCreating === 'folder' ? "folder_name" : "filename.ext"}
                 className="w-full bg-transparent text-xs text-white outline-none"
                 onClick={e => e.stopPropagation()}
               />
            </form>
          </div>
        )}

        {Object.values(fileTree).map((node: TreeNode) => (
            <FileTreeItem 
                key={node.id} 
                node={node} 
                level={0}
                activeFileName={activeFileName}
                onSelect={onSelect}
                onDelete={onDelete}
                onRename={onRename}
                selectedPath={selectedPath}
                setSelectedPath={setSelectedPath}
            />
        ))}
      </div>

      {/* Hidden Upload Input */}
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleUpload} 
        className="hidden" 
        accept=".json"
      />
    </div>
  );
};

export default FileExplorer;

