import { User } from '../types';

const DB_KEY = 'devbrowser_users_db';

interface StoredUser {
  profile: User;
  passwordHash: string; // Simple base64 for this demo
}

interface UserDatabase {
  [username: string]: StoredUser;
}

// Helper to get the DB
const getDb = (): UserDatabase => {
  try {
    const data = localStorage.getItem(DB_KEY);
    return data ? JSON.parse(data) : {};
  } catch (e) {
    return {};
  }
};

// Helper to save the DB
const saveDb = (db: UserDatabase) => {
  localStorage.setItem(DB_KEY, JSON.stringify(db));
};

// Simple hash function (Base64) to avoid storing plain text
// In a real app, use bcrypt or argon2 on a server
const hashPassword = (pwd: string) => btoa(pwd);

export const authService = {
  login: (username: string, password: string): User => {
    const db = getDb();
    const userKey = username.trim();
    const targetUser = db[userKey];

    if (!targetUser) {
      throw new Error("Account not found. Please register.");
    }

    if (targetUser.passwordHash !== hashPassword(password)) {
      throw new Error("Invalid password.");
    }

    // Update last login
    targetUser.profile.lastLogin = new Date().toISOString();
    db[userKey] = targetUser;
    saveDb(db);

    return targetUser.profile;
  },

  register: (userProfile: User, password: string): User => {
    const db = getDb();
    const userKey = userProfile.username.trim();

    if (db[userKey]) {
      throw new Error("Username already taken.");
    }

    // Save new user
    db[userKey] = {
      profile: {
        ...userProfile,
        lastLogin: new Date().toISOString()
      },
      passwordHash: hashPassword(password)
    };

    saveDb(db);

    return db[userKey].profile;
  }
};

