import React, { useState, useEffect, useRef } from 'react';
import { Terminal as TerminalIcon } from 'lucide-react';
import { VirtualFile, User } from '../types';

interface TerminalProps {
  files: VirtualFile[];
  user: User;
  onUpdateFiles: (files: VirtualFile[]) => void;
  onSelectFile: (fileName: string) => void;
}

interface HistoryItem {
  id: string;
  type: 'input' | 'output' | 'error';
  content: string;
  cwd?: string;
}

const Terminal: React.FC<TerminalProps> = ({ files, user, onUpdateFiles, onSelectFile }) => {
  const [history, setHistory] = useState<HistoryItem[]>([
    { id: 'init', type: 'output', content: `DeployOS Kernel [v4.19.0-21-amd64]\nCopyright (c) 2024 Deploy Studio Inc.\n\nType 'help' for a list of commands.` }
  ]);
  const [cwd, setCwd] = useState<string>('~');
  const [input, setInput] = useState('');
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [history]);

  const resolvePath = (path: string): string => {
    if (path === '~' || path === '/') return '';
    if (path.startsWith('/')) return path.slice(1);
    if (path.startsWith('./')) return cwd ? `${cwd}/${path.slice(2)}` : path.slice(2);
    return cwd ? `${cwd}/${path}` : path;
  };

  const getFilesAt = (path: string) => {
    const prefix = path ? path + '/' : '';
    // Find direct children
    return files.filter(f => {
       if (path === '' && !f.name.includes('/')) return true;
       if (f.name.startsWith(prefix)) {
           const rest = f.name.slice(prefix.length);
           return !rest.includes('/');
       }
       return false;
    });
  };

  const executeCommand = (cmdStr: string) => {
    const args = cmdStr.trim().split(/\s+/);
    const cmd = args[0].toLowerCase();
    const newHistory: HistoryItem[] = [
      ...history, 
      { id: Date.now().toString(), type: 'input', content: cmdStr, cwd }
    ];

    try {
      switch (cmd) {
        case 'help':
          newHistory.push({
            id: Date.now() + '1',
            type: 'output',
            content: `Available commands:
  ls        List directory contents
  cd        Change directory
  cat       Concatenate and print files
  mkdir     Make directories
  touch     Change file timestamps (create empty file)
  rm        Remove files or directories
  echo      Display a line of text
  whoami    Print effective userid
  pwd       Print working directory
  clear     Clear the terminal screen
  date      Print system date and time`
          });
          break;

        case 'clear':
          setHistory([]);
          setInput('');
          return;

        case 'ls': {
           const targetPath = args[1] ? resolvePath(args[1]) : (cwd === '~' ? '' : cwd);
           const items = getFilesAt(targetPath);
           const output = items.map(f => {
               return f.type === 'directory' 
                 ? `\u001b[1;34m${f.name.split('/').pop()}/\u001b[0m` 
                 : f.name.split('/').pop();
           }).join('  ');
           newHistory.push({ id: Date.now() + '1', type: 'output', content: output || '(empty)' });
           break;
        }

        case 'pwd':
           newHistory.push({ id: Date.now() + '1', type: 'output', content: cwd === '~' ? '/home/' + user.username : '/home/' + user.username + '/' + cwd });
           break;

        case 'whoami':
           newHistory.push({ id: Date.now() + '1', type: 'output', content: user.username });
           break;

        case 'date':
           newHistory.push({ id: Date.now() + '1', type: 'output', content: new Date().toString() });
           break;

        case 'cd': {
           const target = args[1];
           if (!target || target === '~') {
               setCwd('~');
           } else if (target === '..') {
               if (cwd !== '~' && cwd !== '') {
                   const parts = cwd.split('/');
                   parts.pop();
                   setCwd(parts.length > 0 ? parts.join('/') : '~');
               } else {
                   setCwd('~');
               }
           } else {
               const newPath = resolvePath(target);
               // Verify exists
               const exists = files.some(f => f.name === newPath && f.type === 'directory') || getFilesAt(newPath).length > 0;
               // Simplified logic: Check if any file starts with this path to assume it's a valid folder structure
               const isValidDir = files.some(f => f.name.startsWith(newPath + '/'));

               if (isValidDir || newPath === '') {
                   setCwd(newPath);
               } else {
                   throw new Error(`cd: ${target}: No such file or directory`);
               }
           }
           break;
        }

        case 'cat': {
            const fileName = args[1];
            if (!fileName) throw new Error('cat: missing operand');
            const fullPath = resolvePath(fileName);
            const file = files.find(f => f.name === fullPath && f.type !== 'directory');
            if (file) {
                newHistory.push({ id: Date.now() + '1', type: 'output', content: file.content });
                onSelectFile(fullPath); // Open in editor too for convenience
            } else {
                throw new Error(`cat: ${fileName}: No such file`);
            }
            break;
        }

        case 'touch': {
            const fileName = args[1];
            if (!fileName) throw new Error('touch: missing operand');
            const fullPath = resolvePath(fileName);
            if (!files.some(f => f.name === fullPath)) {
                // Determine extension language
                const ext = fileName.split('.').pop();
                let lang: VirtualFile['language'] = 'text';
                if (ext === 'js') lang = 'javascript';
                if (ext === 'html') lang = 'html';
                if (ext === 'css') lang = 'css';

                onUpdateFiles([...files, { name: fullPath, content: '', language: lang, type: 'file' }]);
            }
            break;
        }

        case 'mkdir': {
            const dirName = args[1];
            if (!dirName) throw new Error('mkdir: missing operand');
            const fullPath = resolvePath(dirName);
             if (!files.some(f => f.name === fullPath)) {
                onUpdateFiles([...files, { name: fullPath, content: '', language: 'text', type: 'directory' }]);
            } else {
                throw new Error(`mkdir: cannot create directory '${dirName}': File exists`);
            }
            break;
        }

        case 'rm': {
            const target = args[1];
            if (!target) throw new Error('rm: missing operand');
            const fullPath = resolvePath(target);
            // Check if it exists
            const exists = files.some(f => f.name === fullPath || f.name.startsWith(fullPath + '/'));
            if (!exists) throw new Error(`rm: cannot remove '${target}': No such file or directory`);

            // Filter out
            const newFiles = files.filter(f => f.name !== fullPath && !f.name.startsWith(fullPath + '/'));
            onUpdateFiles(newFiles);
            break;
        }

        case 'echo':
            newHistory.push({ id: Date.now() + '1', type: 'output', content: args.slice(1).join(' ') });
            break;

        case '':
            break;

        default:
           throw new Error(`${cmd}: command not found`);
      }
    } catch (e: any) {
        newHistory.push({ id: Date.now() + '2', type: 'error', content: e.message });
    }

    setHistory(newHistory);
    setInput('');
  };

  return (
    <div className="flex-1 flex flex-col bg-[#0c0c0c] font-mono text-sm overflow-hidden h-full">
      <div className="h-9 bg-[#1a1a1a] flex items-center px-4 border-b border-gray-800 select-none">
          <TerminalIcon size={14} className="text-green-500 mr-2" />
          <span className="text-gray-300">DeployOS Terminal</span>
      </div>

      <div className="flex-1 overflow-y-auto p-4 custom-scrollbar" onClick={() => document.getElementById('term-input')?.focus()}>
         {history.map((item) => (
             <div key={item.id} className="mb-2">
                 {item.type === 'input' && (
                     <div className="flex items-center text-gray-300">
                         <span className="text-green-500 font-bold mr-2">{user.username}@{user.username}-devbox:{item.cwd === '~' ? '~' : '~/' + item.cwd}$</span>
                         <span>{item.content}</span>
                     </div>
                 )}
                 {item.type === 'output' && (
                     <div className="text-gray-400 whitespace-pre-wrap ml-1 leading-relaxed">
                         {/* Simple ANSI color parsing for directory blue */}
                         {item.content.split(/(\u001b\[1;34m.*?\u001b\[0m)/g).map((part, i) => {
                             if (part.startsWith('\u001b[1;34m')) {
                                 return <span key={i} className="text-blue-400 font-bold">{part.replace(/\u001b\[.*?m/g, '')}</span>
                             }
                             return part;
                         })}
                     </div>
                 )}
                 {item.type === 'error' && (
                     <div className="text-red-400 ml-1">{item.content}</div>
                 )}
             </div>
         ))}

         <div className="flex items-center text-gray-300">
             <span className="text-green-500 font-bold mr-2">{user.username}@{user.username}-devbox:{cwd === '~' ? '~' : '~/' + cwd}$</span>
             <input 
                id="term-input"
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => {
                    if (e.key === 'Enter') executeCommand(input);
                }}
                className="flex-1 bg-transparent border-none outline-none text-white placeholder-gray-600"
                autoComplete="off"
                autoFocus
             />
         </div>
         <div ref={bottomRef} />
      </div>
    </div>
  );
};

