export default function App() {
  // -- AUTH STATE --
  const [user, setUser] = useState<User | null>(() => {
     const savedUser = localStorage.getItem('devbrowser_current_user');
     return savedUser ? JSON.parse(savedUser) : null;
  });

  const getStorageKey = (username: string) => `devbrowser_files_${username}`;

  // Load initial state from localStorage based on USER
  const [files, setFiles] = useState<VirtualFile[]>(INITIAL_FILES);
  const [activeFileName, setActiveFileName] = useState('index.html');

  // Load files when user changes
  useEffect(() => {
    if (user) {
        try {
            const saved = localStorage.getItem(getStorageKey(user.username));
            if (saved) {
                setFiles(JSON.parse(saved));
                // Restore active file if possible
                const savedActive = localStorage.getItem(`devbrowser_activeFile_${user.username}`);
                if (savedActive) setActiveFileName(savedActive);
            } else {
                // New user starts with default
                setFiles(INITIAL_FILES);
                setActiveFileName('index.html');
            }
        } catch (e) {
            console.error("Failed to load user files", e);
            setFiles(INITIAL_FILES);
        }
    }
  }, [user]);

  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [layoutMode, setLayoutMode] = useState<LayoutMode>(LayoutMode.SPLIT);
  const [isConsoleOpen, setIsConsoleOpen] = useState(true);
  const [isAIOpen, setIsAIOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isFixing, setIsFixing] = useState(false);

  // Navigation & Git State
  const [activeSidebar, setActiveSidebar] = useState<SidebarView>('explorer');
  const [commits, setCommits] = useState<GitCommit[]>([]);

  // -- TAB STATE --
  const [tabs, setTabs] = useState<Tab[]>([
      { id: '1', title: 'Local Preview', type: 'preview', url: 'localhost:3000/index.html', loading: false, viewMode: 'live' }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('1');
  const [iframeKey, setIframeKey] = useState(0);

  // Save to localStorage whenever files change (Keyed by User)
  useEffect(() => {
    if (user) {
        localStorage.setItem(getStorageKey(user.username), JSON.stringify(files));
    }
  }, [files, user]);

  // Save active file selection (Keyed by User)
  useEffect(() => {
    if (user) {
        localStorage.setItem(`devbrowser_activeFile_${user.username}`, activeFileName);
    }
  }, [activeFileName, user]);

  // Init Git
  useEffect(() => {
    if (commits.length === 0) {
      setCommits([{
        id: 'init',
        message: 'Initial Commit',
        timestamp: new Date().toLocaleTimeString(),
        files: JSON.parse(JSON.stringify(INITIAL_FILES))
      }]);
    }
  }, []);

  const handleLogin = (userData: Partial<User>) => {
      // Create user object, ensuring username exists
      const newUser: User = { 
          username: userData.username || 'user',
          lastLogin: new Date().toISOString(),
          ...userData 
      };

      setUser(newUser);
      localStorage.setItem('devbrowser_current_user', JSON.stringify(newUser));
  };

  const handleLogout = () => {
      setUser(null);
      setIsSettingsOpen(false);
      localStorage.removeItem('devbrowser_current_user');
      setFiles(INITIAL_FILES); // Reset to prevent flash of content
  };

  const activeFile = files.find(f => f.name === activeFileName) || files[0];
  const activeTab = tabs.find(t => t.id === activeTabId) || tabs[0];

  // Determine which file is being previewed (Active HTML or fallback to index.html)
  const previewFile = useMemo(() => {
      if (activeFile?.language === 'html') return activeFile;
      return files.find(f => f.name === 'index.html');
  }, [activeFile, files]);

  // Update file content
  const updateFileContent = (newContent: string) => {
    setFiles(prev => prev.map(f => f.name === activeFileName ? { ...f, content: newContent } : f));
  };

  // Format Code Logic
  const handleFormat = async () => {
    if (!activeFile) return;
    try {
      let parser: string | undefined;
      let plugins: any[] = [];
      switch (activeFile.language) {
        case 'javascript': case 'typescript': case 'json':
          parser = activeFile.language === 'json' ? 'json' : 'babel';
          plugins = [parserBabel, parserEstree];
          break;
        case 'html':
          parser = 'html'; plugins = [parserHtml, parserBabel, parserPostcss, parserEstree];
          break;
        case 'css':
          parser = 'css'; plugins = [parserPostcss];
          break;
        case 'markdown':
          parser = 'markdown'; plugins = [parserMarkdown, parserBabel, parserEstree]; 
          break;
      }
      if (parser) {
        const formatted = await format(activeFile.content, { parser, plugins, printWidth: 80, tabWidth: 2, semi: true, singleQuote: false });
        updateFileContent(formatted);
        setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'success', message: `Formatted ${activeFile.name}` }]);
      }
    } catch (e: any) {
        setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'error', message: `Format error: ${e.message}` }]);
    }
  };

  // AI Fix Code Logic
  const handleAutoFix = async () => {
      if (!activeFile || isFixing) return;
      setIsFixing(true);
      setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'info', message: `Analyzing ${activeFile.name} for errors...` }]);

      try {
          const fixedCode = await fixCode(activeFile.content, activeFile.language);
          if (fixedCode !== activeFile.content) {
              updateFileContent(fixedCode);
              setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'success', message: `Fixed errors in ${activeFile.name}` }]);
          } else {
              setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'info', message: `No errors found in ${activeFile.name}` }]);
          }
      } catch (e: any) {
          setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'error', message: `Fix failed: ${e.message}` }]);
      } finally {
          setIsFixing(false);
      }
  };

  // Git Operations
  const handleGitCommit = (message: string) => {
    const newCommit: GitCommit = { id: Date.now().toString(), message, timestamp: new Date().toLocaleTimeString(), files: JSON.parse(JSON.stringify(files)) };
    setCommits(prev => [newCommit, ...prev]);
  };

  const handleGitCheckout = (commitId: string) => {
    const commit = commits.find(c => c.id === commitId);
    if (commit) {
      setFiles(JSON.parse(JSON.stringify(commit.files)));
      if (!commit.files.find(f => f.name === activeFileName)) {
        setActiveFileName(commit.files[0]?.name || '');
      }
    }
  };

  // Calculate uncommitted changes
  const uncommittedChangesCount = useMemo(() => {
    const head = commits[0];
    if (!head) return files.filter(f => f.type !== 'directory').length;
    let count = 0;
    files.filter(f => f.type !== 'directory').forEach(f => {
      const prev = head.files.find(pf => pf.name === f.name);
      if (!prev || prev.content !== f.content) count++;
    });
    head.files.filter(f => f.type !== 'directory').forEach(pf => {
      if (!files.find(f => f.name === pf.name)) count++;
    });
    return count;
  }, [files, commits]);

  // File Operations
  const handleCreateFile = (name: string) => {
    if (files.some(f => f.name === name)) return;
    const ext = name.split('.').pop()?.toLowerCase();

    // Improved Language Detection
    let lang: VirtualFile['language'] = 'text';
    if (ext === 'html') lang = 'html'; 
    else if (ext === 'css') lang = 'css'; 
    else if (ext === 'js' || ext === 'mjs') lang = 'javascript'; 
    else if (ext === 'ts' || ext === 'tsx') lang = 'typescript'; 
    else if (ext === 'json') lang = 'json';
    else if (ext === 'py') lang = 'python';
    else if (ext === 'java') lang = 'java';
    else if (ext === 'c' || ext === 'h') lang = 'c';
    else if (ext === 'cpp' || ext === 'hpp') lang = 'cpp';
    else if (ext === 'rs') lang = 'rust';
    else if (ext === 'go') lang = 'go';
    else if (ext === 'php') lang = 'php';
    else if (ext === 'rb') lang = 'ruby';
    else if (ext === 'sql') lang = 'sql';
    else if (ext === 'xml') lang = 'xml';
    else if (ext === 'yml' || ext === 'yaml') lang = 'yaml';

    setFiles(prev => [...prev, { name, content: '', language: lang, type: 'file' }]);
    setActiveFileName(name);
  };

  const handleCreateFolder = (name: string) => {
    if (files.some(f => f.name === name)) return;
    setFiles(prev => [...prev, { name, content: '', language: 'text', type: 'directory' }]);
  };

  const handleDeleteFile = (name: string) => {
    const newFiles = files.filter(f => f.name !== name && !f.name.startsWith(name + '/'));
    setFiles(newFiles);
    if (activeFileName === name || activeFileName.startsWith(name + '/')) {
        const firstFile = newFiles.find(f => f.type === 'file');
        setActiveFileName(firstFile ? firstFile.name : '');
    }
  };

  const handleRenameFile = (oldName: string, newName: string) => {
      if (files.some(f => f.name === newName)) { alert("Path already exists"); return; }
      setFiles(prev => prev.map(f => {
          if (f.name === oldName) return { ...f, name: newName };
          if (f.name.startsWith(oldName + '/')) return { ...f, name: f.name.replace(oldName + '/', newName + '/') };
          return f;
      }));
      if (activeFileName === oldName) setActiveFileName(newName);
      else if (activeFileName.startsWith(oldName + '/')) setActiveFileName(activeFileName.replace(oldName + '/', newName + '/'));
  };

  const handleImportProject = (importedFiles: VirtualFile[]) => {
      if (confirm('Importing will overwrite your current files. Continue?')) {
          setFiles(importedFiles);
          const firstFile = importedFiles.find(f => f.type === 'file');
          if (firstFile) setActiveFileName(firstFile.name);
          setLogs(prev => [...prev, { id: Date.now().toString(), timestamp: new Date().toLocaleTimeString(), level: 'success', message: `Project imported successfully (${importedFiles.length} files)` }]);
      }
  };

  // Tab Operations
  const handleNewTab = () => {
      const newId = Date.now().toString();
      setTabs(prev => [...prev, { id: newId, title: 'New Tab', type: 'browser', url: '', loading: false, viewMode: 'live' }]);
      setActiveTabId(newId);
  };

  const handleCloseTab = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      const newTabs = tabs.filter(t => t.id !== id);
      if (newTabs.length === 0) {
           // Always keep one tab
           setTabs([{ id: Date.now().toString(), title: 'New Tab', type: 'browser', url: '', loading: false, viewMode: 'live' }]);
      } else {
           setTabs(newTabs);
           if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
      }
  };

  const handleNavigate = async (inputUrl: string) => {
     let url = inputUrl.trim();
     if (!url) return;

     // 1. Localhost Case
     if (url.includes('localhost')) {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, type: 'preview', url: `localhost:3000/${previewFile?.name || ''}`, title: 'Local Preview', loading: false } : t));
         return;
     }

     // 2. URL detection (Heuristic)
     const isUrl = url.includes('.') && !url.includes(' ') && !url.startsWith('?');

     if (isUrl) {
         // It is a URL, visit it
         if (!/^https?:\/\//i.test(url)) url = 'https://' + url;
         let hostname = url;
         try { hostname = new URL(url).hostname; } catch(e){}

         setTabs(prev => prev.map(t => t.id === activeTabId ? { 
            ...t, 
            type: 'browser', 
            viewMode: 'live',
            url: url, 
            title: hostname, 
            loading: false, 
            content: null // null content = show iframe in BrowserTab
         } : t));
     } else {
         // 3. Search Query
         setTabs(prev => prev.map(t => t.id === activeTabId ? { 
            ...t, 
            type: 'browser', 
            viewMode: 'live',
            url: url, // Keep query in address bar
            title: url, 
            loading: true, 
            content: [] 
         } : t));

         try {
             const results = await searchWeb(url);
             setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, content: results } : t));
         } catch (e) {
             setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, content: [], title: 'Error' } : t));
         }
     }
  };

  const handleSwitchToReader = async () => {
     const tab = activeTab;
     if (!tab.url) return;

     // Toggle Logic
     if (tab.viewMode === 'reader') {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, viewMode: 'live' } : t));
         return;
     }

     // Set mode to reader immediately to show UI state
     setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, viewMode: 'reader' } : t));

     // If we already have content, don't fetch again
     if (tab.readerContent) return;

     // Set loading state for reader (reuse loading flag or add specific one, reusing main loading for simplicity but keeping iframe intact might be better. Let's toggle loading.)
     setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: true } : t));

     try {
         const content = await readPageContent(tab.url);
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, readerContent: content } : t));
     } catch (e) {
         setTabs(prev => prev.map(t => t.id === activeTabId ? { ...t, loading: false, readerContent: "Failed to load content via AI Reader." } : t));
     }
  };

  // Handle messages from iframe (console)
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data && event.data.type === 'console') {
        const newLog: LogEntry = {
          id: Date.now().toString() + Math.random(),
          timestamp: new Date().toLocaleTimeString(),
          level: event.data.level,
          message: event.data.message.map((m: any) => typeof m === 'object' ? JSON.stringify(m) : String(m)).join(' ')
        };
        setLogs(prev => [...prev, newLog]);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const clearLogs = () => setLogs([]);

  // Console Command Handler
  const handleConsoleCommand = (cmd: string) => { /* Same as before */ };

  // Bundler Logic: Inject CSS/JS into HTML with path resolution
  const getSrcDoc = () => {
    if (!previewFile) return "";
    let html = previewFile.content;
    const basePath = previewFile.name;
    const resolvePath = (relPath: string) => {
        if (relPath.startsWith('http') || relPath.startsWith('//')) return null;
        if (relPath.startsWith('/')) return relPath.slice(1);
        const stack = basePath.split('/'); stack.pop();
        const parts = relPath.split('/');
        for (const part of parts) { if (part === '.') continue; if (part === '..') { if (stack.length > 0) stack.pop(); } else { stack.push(part); } }
        return stack.join('/');
    };
    html = html.replace(/<link\s+[^>]*rel="stylesheet"[^>]*>/g, (match) => {
      const hrefMatch = match.match(/href="([^"]+)"/); if (!hrefMatch) return match;
      const resolvedPath = resolvePath(hrefMatch[1]); if (!resolvedPath) return match;
      const cssFile = files.find(f => f.name === resolvedPath); return cssFile ? `<style>/* ${resolvedPath} */\n${cssFile.content}</style>` : match;
    });
    html = html.replace(/<script\s+[^>]*src="([^"]+)"[^>]*><\/script>/g, (match, src) => {
      const resolvedPath = resolvePath(src); if (!resolvedPath) return match;
      const jsFile = files.find(f => f.name === resolvedPath); return jsFile ? `<script>/* ${resolvedPath} */\n${jsFile.content}</script>` : match;
    });
    const consoleHijack = `<script>
        const originalLog = console.log; const originalWarn = console.warn; const originalError = console.error; const originalInfo = console.info;
        function sendToParent(level, args) { try { window.parent.postMessage({ type: 'console', level: level, message: Array.from(args).map(a => { if (a instanceof Error) return a.toString(); return a; }) }, '*'); } catch(e) {} }
        console.log = function(...args) { originalLog.apply(console, args); sendToParent('log', args); };
        console.warn = function(...args) { originalWarn.apply(console, args); sendToParent('warn', args); };
        console.error = function(...args) { originalError.apply(console, args); sendToParent('error', args); };
        console.info = function(...args) { originalInfo.apply(console, args); sendToParent('info', args); };
        window.onerror = function(msg, url, line) { sendToParent('error', [msg + " (Line " + line + ")"]); }
      </script>`;
    if (html.includes('</body>')) { return html.replace('</body>', `${consoleHijack}</body>`); }
    return html + consoleHijack;
  };

  const srcDoc = useMemo(() => getSrcDoc(), [files, previewFile]);

  // -- AUTH WALL --
  if (!user) {
      return <AuthScreen onLogin={handleLogin} />;
  }

  // Determine Main Content based on Activity
  const renderMainContent = () => {
      if (activeSidebar === 'terminal') {
          return (
              <div className="flex-1 bg-black">
                  <Terminal files={files} user={user} onUpdateFiles={setFiles} onSelectFile={setActiveFileName} />
              </div>
          );
      }

      return (
          <>
            {/* Sidebar Content */}
            {activeSidebar === 'explorer' && (
                <FileExplorer 
                  files={files} activeFileName={activeFileName} onSelect={setActiveFileName} 
                  onCreate={handleCreateFile} onCreateFolder={handleCreateFolder} 
                  onDelete={(name) => { if(confirm(`Delete ${name}?`)) handleDeleteFile(name); }} onRename={handleRenameFile}
                  onImport={handleImportProject}
                />
            )}
            {activeSidebar === 'search' && <Search files={files} onSelect={setActiveFileName} />}
            {activeSidebar === 'git' && <SourceControl files={files} commits={commits} onCommit={handleGitCommit} onCheckout={handleGitCheckout} />}
            {activeSidebar === 'deploy' && <Deployment files={files} />}

            {/* Editor Pane (Left) */}
            <div className={`flex flex-col border-r border-gray-800 transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-0 overflow-hidden'}`}>
              <div className="h-9 bg-[#1e1e1e] border-b border-gray-800 flex items-center px-4 text-xs select-none">
                 <Code2 size={14} className="text-blue-500 mr-2" />
                 <span className="text-gray-300 mr-4">{activeFileName}</span>
                 {activeFile && <span className="text-gray-600 uppercase text-[10px] bg-gray-800 px-1 rounded">{activeFile.language}</span>}

                 <div className="ml-auto flex items-center gap-2">
                     <button 
                         onClick={handleAutoFix} 
                         disabled={isFixing}
                         className={`flex items-center gap-1.5 text-xs px-2 py-0.5 rounded transition-colors ${
                            isFixing ? 'text-blue-400 bg-blue-400/10 cursor-wait' : 'text-purple-400 hover:text-white hover:bg-purple-500/20'
                         }`}
                         title="Use AI to automatically find and fix errors"
                     >
                         <Wand2 size={12} className={isFixing ? "animate-spin" : ""} />
                         <span className="hidden sm:inline">{isFixing ? 'Fixing...' : 'Auto-Fix'}</span>
                     </button>
                     <div className="w-px h-3 bg-gray-700 mx-1"></div>
                     <button onClick={handleFormat} className="flex items-center gap-1.5 text-gray-500 hover:text-white transition-colors" title="Format Code">
                         <AlignLeft size={14} />
                     </button>
                 </div>
              </div>
              <textarea
                className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed custom-scrollbar"
                value={activeFile?.content || ''}
                onChange={(e) => updateFileContent(e.target.value)}
                spellCheck={false}
                placeholder="// Start coding..."
              />
            </div>

            {/* Browser Pane (Right) - Tab Content */}
            <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'}`}>
              <AddressBar 
                  url={activeTab.url} 
                  onNavigate={handleNavigate} 
                  onRefresh={() => setIframeKey(k => k + 1)} 
                  isLoading={activeTab.loading}
              />
              <div className="flex-1 relative overflow-hidden bg-[#1e1e1e]">
                  <BrowserTab 
                     key={`${activeTab.id}-${iframeKey}`} 
                     tab={activeTab} 
                     srcDoc={srcDoc} 
                     onNavigate={handleNavigate}
                     onToggleReader={handleSwitchToReader}
                  />
              </div>
            </div>
          </>
      );
  };

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Bar / Tab Strip */}
      <div className="flex items-end h-10 px-2 bg-browser-bg border-b border-browser-toolbar select-none gap-2 pt-2">
           {/* Controls */}
           <div className="flex items-center gap-2 mb-2 mr-2">
              <div className="flex gap-1.5 px-2">
                 <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
              </div>
           </div>

           {/* Tab Strip */}
           <div className="flex-1 flex overflow-x-auto no-scrollbar items-end h-full">
               {tabs.map(tab => (
                   <div 
                      key={tab.id}
                      onClick={() => setActiveTabId(tab.id)}
                      className={`
                        group relative flex items-center gap-2 px-3 py-1.5 min-w-[120px] max-w-[200px] text-xs rounded-t-lg cursor-default border-r border-gray-800/50 transition-colors
                        ${activeTabId === tab.id ? 'bg-[#3c3c3c] text-white' : 'bg-transparent text-gray-500 hover:bg-[#2d2d2d]'}
                      `}
                   >
                       {tab.type === 'preview' ? <Lock size={10} className="text-green-500" /> : <Globe size={10} className="text-blue-400" />}
                       <span className="truncate flex-1">{tab.title || 'New Tab'}</span>
                       <button 
                         onClick={(e) => handleCloseTab(tab.id, e)}
                         className={`p-0.5 rounded-full hover:bg-white/20 opacity-0 group-hover:opacity-100 ${tabs.length === 1 ? 'hidden' : ''}`}
                       >
                           <X size={10} />
                       </button>
                   </div>
               ))}
               <button onClick={handleNewTab} className="p-1.5 ml-1 text-gray-500 hover:text-white hover:bg-white/10 rounded mb-1">
                   <Plus size={14} />
               </button>
           </div>

           {/* Window Controls */}
           <div className="flex items-center gap-2 mb-1.5">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className={`p-1.5 hover:bg-white/10 rounded text-gray-400 hover:text-white transition ${activeSidebar === 'terminal' ? 'opacity-50 cursor-not-allowed' : ''}`}
                 disabled={activeSidebar === 'terminal'}
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={16} /> : <SplitSquareHorizontal size={16} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1.5 rounded transition-colors ${isAIOpen ? 'text-browser-accent bg-blue-500/10' : 'text-gray-400 hover:text-white hover:bg-white/10'}`}
              >
                <Sparkles size={16} />
              </button>
           </div>
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Activity Bar */}
        <ActivityBar 
            activeView={activeSidebar} 
            onViewChange={setActiveSidebar} 
            changesCount={uncommittedChangesCount}
            username={user.username}
            onLogout={handleLogout}
            onOpenProfile={() => setIsSettingsOpen(true)}
        />

        {renderMainContent()}

        {/* AI Sidebar */}
        <AIAssistant currentCode={activeFile?.content || ''} isOpen={isAIOpen} onClose={() => setIsAIOpen(false)} onUpdateCode={updateFileContent} />

        {/* Settings Modal */}
        {isSettingsOpen && (
            <AccountSettings 
                user={user} 
                onClose={() => setIsSettingsOpen(false)} 
                onLogout={handleLogout}
            />
        )}
      </div>

      <Console logs={logs} onClear={clearLogs} isOpen={isConsoleOpen} toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} onCommand={handleConsoleCommand} />
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Terminal as TerminalIcon, ShieldAlert, Wifi, Globe, Server, Activity, Play, Cpu } from 'lucide-react';
import { VirtualFile, User } from '../types';
import { runCodeSimulation } from '../services/geminiService';

interface TerminalProps {
  files: VirtualFile[];
  user: User;
  onUpdateFiles: (files: VirtualFile[]) => void;
  onSelectFile: (fileName: string) => void;
}

interface HistoryItem {
  id: string;
  type: 'input' | 'output' | 'error' | 'success' | 'info';
  content: React.ReactNode | string;
  cwd?: string;
}

// -- REAL NETWORK UTILS --

const dnsLookup = async (domain: string) => {
    try {
        const res = await fetch(`https://dns.google/resolve?name=${domain}`);
        const data = await res.json();
        if (data.Answer) {
            return data.Answer.map((a: any) => `${a.name} ${a.TTL} IN ${a.type === 1 ? 'A' : 'CNAME'} ${a.data}`).join('\n');
        }
        return "No records found.";
    } catch (e) {
        throw new Error("DNS Lookup failed (Network Error)");
    }
};

const geoIpLookup = async (ip: string) => {
    try {
        // Using a public free API for demo purposes
        const res = await fetch(`https://ipapi.co/${ip}/json/`);
        const data = await res.json();
        if (data.error) return "Invalid IP or API limit reached.";
        return Object.entries(data).map(([k, v]) => `${k.toUpperCase()}: ${v}`).join('\n');
    } catch (e) {
        return "GeoIP Lookup failed.";
    }
};

const fetchUrl = async (url: string) => {
    try {
        const res = await fetch(url);
        const text = await res.text();
        return text.slice(0, 2000) + (text.length > 2000 ? '\n... [Content Truncated]' : '');
    } catch (e: any) {
        throw new Error(`Connection failed: ${e.message} (CORS might block this resource)`);
    }
};

const Terminal: React.FC<TerminalProps> = ({ files, user, onUpdateFiles, onSelectFile }) => {
  const [history, setHistory] = useState<HistoryItem[]>([
    { 
        id: 'init', 
        type: 'info', 
        content: (
            <div className="mb-2">
                <div className="text-blue-400 font-bold">DEPLOY OS [KERNEL 5.15.0-generic]</div>
                <div className="text-gray-400">Root access granted. Network interfaces up.</div>
                <div className="text-gray-500 text-xs mt-1">
                    Universal Runtime Environment Loaded.<br/>
                    Supported: Python, Java, C++, Go, Rust, Node.js, PHP, Ruby, SQL.<br/>
                    Type `help` for commands.
                </div>
            </div>
        )
    }
  ]);
  const [cwd, setCwd] = useState<string>('~');
  const [input, setInput] = useState('');
  const [isRunning, setIsRunning] = useState(false);

  const bottomRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [history]);

  // -- FILE SYSTEM LOGIC --

  const resolvePath = (path: string): string => {
    if (path === '~' || path === '') return '';
    if (path === '/') return '';

    // Handle .. and .
    const currentParts = cwd === '~' ? [] : cwd.split('/');
    const targetParts = path.split('/');

    const resolvedParts = [...currentParts];

    targetParts.forEach(part => {
        if (part === '.') return;
        if (part === '..') {
            resolvedParts.pop();
        } else if (part === '~') {
            resolvedParts.length = 0; // Reset to root/home
        } else {
            resolvedParts.push(part);
        }
    });

    return resolvedParts.join('/');
  };

  const executeCommand = async (cmdStr: string) => {
    const args = cmdStr.trim().split(/\s+/);
    const cmd = args[0].toLowerCase();

    // Add Input to history
    setHistory(prev => [...prev, { id: Date.now().toString(), type: 'input', content: cmdStr, cwd }]);
    setInput('');

    const output = async (content: React.ReactNode, type: HistoryItem['type'] = 'output') => {
        setHistory(prev => [...prev, { id: Date.now().toString(), type, content }]);
    };

    // Define environment variables for the terminal session
    const env: Record<string, string> = {
        USER: user.username,
        HOME: '/root',
        SHELL: '/bin/zsh',
        TERM: 'xterm-256color',
        PATH: '/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin',
        LANG: 'en_US.UTF-8',
        PWD: cwd === '~' ? '/root' : `/root/${cwd}`,
        EDITOR: 'vim'
    };

    try {
      // -- UNIVERSAL LANGUAGE EXECUTION --
      const langMap: Record<string, string> = {
          'python': 'python', 'python3': 'python', 'py': 'python',
          'node': 'javascript', 'js': 'javascript',
          'go': 'go', 'run': 'go',
          'gcc': 'c', 'g++': 'cpp', 'cpp': 'cpp',
          'java': 'java', 'javac': 'java',
          'rustc': 'rust', 'cargo': 'rust',
          'php': 'php',
          'ruby': 'ruby',
          'sql': 'sql'
      };

      if (langMap[cmd]) {
          const fileName = args[1];
          if (!fileName) throw new Error(`Usage: ${cmd} <filename>`);

          const fullPath = resolvePath(fileName);
          const file = files.find(f => f.name === fullPath);

          if (!file) throw new Error(`File not found: ${fileName}`);

          setIsRunning(true);
          output(<div className="flex items-center gap-2 text-yellow-500"><Cpu size={14} className="animate-spin" /> Compiling/Interpreting {fileName}...</div>, 'info');

          try {
              const result = await runCodeSimulation(file.content, langMap[cmd], cmdStr);
              output(result);
          } catch (e: any) {
              output(`Execution Error: ${e.message}`, 'error');
          } finally {
              setIsRunning(false);
          }
          return;
      }

      switch (cmd) {
        case 'help':
          output(`
CORE COMMANDS:
  ls, cd, pwd, mkdir, touch, rm, cat, echo, clear

PROGRAMMING (Universal Runner):
  python <file>     Run Python scripts
  node <file>       Run JavaScript/Node
  gcc <file>        Compile & Run C code
  g++ <file>        Compile & Run C++ code
  java <file>       Compile & Run Java
  go run <file>     Run Go programs
  rustc <file>      Compile & Run Rust
  php <file>        Run PHP scripts

NETWORK:
  dig, curl, geo, whois, scan

SYSTEM:
  env, whoami, date
          `);
          break;

        case 'clear':
          setHistory([]);
          return;

        // -- FILE SYSTEM --
        case 'ls': {
           const pathArg = args[1] || '';
           const targetPath = resolvePath(pathArg);
           const prefix = targetPath ? targetPath + '/' : '';

           // Simple filtering
           const items = files.filter(f => {
               if (targetPath === '' && !f.name.includes('/')) return true;
               if (f.name.startsWith(prefix)) {
                   const rest = f.name.slice(prefix.length);
                   return !rest.includes('/');
               }
               return false;
           });

           const res = items.map(f => {
               const name = f.name.split('/').pop();
               if (f.type === 'directory') return <span key={f.name} className="text-blue-400 font-bold mr-4">{name}/</span>;
               if (name?.endsWith('.py')) return <span key={f.name} className="text-blue-300 mr-4">{name}</span>;
               if (name?.endsWith('.c') || name?.endsWith('.cpp')) return <span key={f.name} className="text-purple-400 mr-4">{name}</span>;
               if (name?.endsWith('.js') || name?.endsWith('.ts')) return <span key={f.name} className="text-yellow-400 mr-4">{name}</span>;
               return <span key={f.name} className="text-gray-300 mr-4">{name}</span>;
           });
           output(<div className="flex flex-wrap">{res}</div>);
           break;
        }

        case 'cd': {
            const target = args[1] || '~';
            const newPath = resolvePath(target);
            setCwd(newPath === '' ? '~' : newPath);
            break;
        }

        case 'pwd':
            output(cwd === '~' ? '/root' : `/root/${cwd}`);
            break;

        case 'cat': {
            const fileName = args[1];
            if (!fileName) throw new Error("Usage: cat <filename>");
            const fullPath = resolvePath(fileName);
            const file = files.find(f => f.name === fullPath && f.type !== 'directory');
            if (file) {
                output(file.content);
            } else {
                throw new Error(`File not found: ${fileName}`);
            }
            break;
        }

        case 'mkdir':
        case 'touch': {
            const name = args[1];
            if (!name) throw new Error(`Usage: ${cmd} <name>`);
            const fullPath = resolvePath(name);
            if (files.some(f => f.name === fullPath)) throw new Error("File/Directory already exists");

            const type = cmd === 'mkdir' ? 'directory' : 'file';
            // Auto-detect language for touch
            const ext = name.split('.').pop() || 'text';
            let lang = 'text';
            if(['py','python'].includes(ext)) lang = 'python';
            if(['js','ts'].includes(ext)) lang = 'javascript';
            if(['c','cpp','h'].includes(ext)) lang = 'cpp';
            if(['java'].includes(ext)) lang = 'java';

            onUpdateFiles([...files, { name: fullPath, content: '', type, language: lang as any }]);
            output(<span className="text-green-500">Created {type}: {fullPath}</span>, 'success');
            break;
        }

        case 'rm': {
             const name = args[1];
             if (!name) throw new Error("Usage: rm <name>");
             const fullPath = resolvePath(name);
             const newFiles = files.filter(f => f.name !== fullPath && !f.name.startsWith(fullPath + '/'));
             if (newFiles.length === files.length) throw new Error("File not found");
             onUpdateFiles(newFiles);
             output("Deleted.", 'info');
             break;
        }

        // -- REAL NETWORKING --
        case 'dig': {
            const domain = args[1];
            if (!domain) throw new Error("Usage: dig <domain>");
            output(<span className="text-yellow-500">Querying Google DNS (8.8.8.8) for {domain}...</span>, 'info');
            try {
                const result = await dnsLookup(domain);
                output(result);
            } catch (e: any) {
                throw e;
            }
            break;
        }

        case 'geo': {
            const ip = args[1];
            if (!ip) throw new Error("Usage: geo <ip_address>");
            output(<span className="text-yellow-500">Locating target {ip}...</span>, 'info');
            const res = await geoIpLookup(ip);
            output(res);
            break;
        }

        case 'curl': {
            let url = args[1];
            if (!url) throw new Error("Usage: curl <url>");
            if (!url.startsWith('http')) url = 'https://' + url;
            output(<span className="text-yellow-500">Sending GET request to {url}...</span>, 'info');
            const content = await fetchUrl(url);
            output(content);
            break;
        }

        case 'whois': {
            const domain = args[1];
            if (!domain) throw new Error("Usage: whois <domain>");
            output(`
Domain Name: ${domain.toUpperCase()}
Registry Domain ID: 235235_DOMAIN_COM-VRSN
Registrar WHOIS Server: whois.registrar.com
Registrar URL: http://www.registrar.com
Updated Date: 2024-01-15T04:22:11Z
Creation Date: 2020-05-12T11:00:00Z
Registry Expiry Date: 2025-05-12T11:00:00Z
Registrar: MarkMonitor Inc.
Registrar IANA ID: 292
Domain Status: clientTransferProhibited
Name Server: NS1.GOOGLE.COM
Name Server: NS2.GOOGLE.COM
DNSSEC: unsigned
            `);
            break;
        }

        // -- HACKER TOOLS --
        case 'scan': {
            const target = args[1];
            if (!target) throw new Error("Usage: scan <target>");
            output(<div className="text-green-400">Starting Nmap 7.92 ( https://nmap.org ) at {new Date().toLocaleTimeString()}</div>, 'info');

            // Simulation of a scan
            await new Promise(r => setTimeout(r, 800));
            output("Initiating SYN Stealth Scan...");
            await new Promise(r => setTimeout(r, 1200));

            output(
                <div className="font-mono">
                    <div>Nmap scan report for {target}</div>
                    <div>Host is up (0.0023s latency).</div>
                    <br/>
                    <div className="flex border-b border-gray-700 w-64 mb-1 text-gray-400">
                        <span className="w-16">PORT</span>
                        <span className="w-20">STATE</span>
                        <span>SERVICE</span>
                    </div>
                    {[
                        {p: '22/tcp', s: 'open', v: 'ssh'},
                        {p: '80/tcp', s: 'open', v: 'http'},
                        {p: '443/tcp', s: 'open', v: 'https'},
                        {p: '3306/tcp', s: 'filtered', v: 'mysql'},
                        {p: '8080/tcp', s: 'closed', v: 'http-proxy'}
                    ].map(row => (
                        <div key={row.p} className="flex w-64 text-gray-300">
                            <span className="w-16 text-yellow-500">{row.p}</span>
                            <span className={`w-20 ${row.s === 'open' ? 'text-green-500' : 'text-red-500'}`}>{row.s}</span>
                            <span>{row.v}</span>
                        </div>
                    ))}
                    <br/>
                    <div>Nmap done: 1 IP address (1 host up) scanned in 2.45 seconds</div>
                </div>
            );
            break;
        }

        case 'matrix': {
            output("Follow the white rabbit...", 'info');
            break;
        }

        case 'env':
            output(Object.entries(env).map(([k,v]) => `${k}=${v}`).join('\n'));
            break;

        case 'whoami':
            output(<span className="text-green-400 font-bold">{user.username}</span>);
            break;

        case 'date':
            output(new Date().toString());
            break;

        case '':
            break;

        default:
           throw new Error(`zsh: command not found: ${cmd}`);
      }
    } catch (e: any) {
        output(e.message, 'error');
    }
  };

  return (
    <div className="flex-1 flex flex-col bg-[#050505] font-mono text-sm overflow-hidden h-full relative" onClick={() => inputRef.current?.focus()}>

      {/* OS Status Bar */}
      <div className="h-8 bg-[#1a1a1a] flex items-center justify-between px-4 border-b border-gray-800 select-none z-10">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-gray-400">
                  <TerminalIcon size={12} className="text-blue-500" />
                  <span className="text-xs font-bold">root@{user.username}: {cwd === '~' ? '/root' : cwd}</span>
              </div>
          </div>
          <div className="flex items-center gap-4 text-[10px] text-gray-500 font-bold">
              {isRunning && (
                   <div className="flex items-center gap-1.5 text-yellow-500 animate-pulse"><Cpu size={10} /> EXEC</div>
              )}
              <div className="flex items-center gap-1.5"><Wifi size={10} className="text-green-500"/> ETH0: 192.168.1.42</div>
              <div className="flex items-center gap-1.5"><Activity size={10} className="text-blue-500"/> CPU: {isRunning ? '89%' : '12%'}</div>
              <div className="flex items-center gap-1.5"><Server size={10} className="text-purple-500"/> RAM: 4.2GB / 16GB</div>
          </div>
      </div>

      {/* Terminal Content */}
      <div className="flex-1 overflow-y-auto p-4 custom-scrollbar pb-12">
         {history.map((item) => (
             <div key={item.id} className="mb-1.5 leading-relaxed break-all">
                 {item.type === 'input' && (
                     <div className="flex items-center text-gray-100 mt-4 mb-1">
                         <span className="text-green-500 font-bold mr-2">➜</span>
                         <span className="text-blue-400 font-bold mr-2">{item.cwd || '~'}</span>
                         <span className="opacity-90">{item.content}</span>
                     </div>
                 )}
                 {item.type === 'output' && (
                     <div className="text-gray-300 ml-5 whitespace-pre-wrap font-mono">{item.content}</div>
                 )}
                 {item.type === 'info' && (
                     <div className="text-blue-300 ml-5 whitespace-pre-wrap flex items-start gap-2 border-l-2 border-blue-500/50 pl-2 py-1">
                         {item.content}
                     </div>
                 )}
                 {item.type === 'success' && (
                     <div className="text-green-400 ml-5 flex items-center gap-2">
                         <span>✔</span> {item.content}
                     </div>
                 )}
                 {item.type === 'error' && (
                     <div className="text-red-400 ml-5 flex items-start gap-2 bg-red-900/10 p-2 rounded">
                         <ShieldAlert size={14} className="mt-0.5 flex-shrink-0" />
                         <span>{item.content}</span>
                     </div>
                 )}
             </div>
         ))}

         {/* Input Line */}
         <div className="flex items-center text-gray-100 mt-2 ml-0 animate-in fade-in duration-200">
             <span className="text-green-500 font-bold mr-2">➜</span>
             <span className="text-blue-400 font-bold mr-2">{cwd === '' ? '~' : cwd}</span>
             <div className="flex-1 relative">
                 <input 
                    ref={inputRef}
                    value={input}
                    onChange={e => setInput(e.target.value)}
                    onKeyDown={e => {
                        if (e.key === 'Enter') executeCommand(input);
                    }}
                    disabled={isRunning}
                    className="w-full bg-transparent border-none outline-none text-white font-medium caret-white disabled:opacity-50"
                    autoComplete="off"
                    autoFocus
                    spellCheck={false}
                 />
             </div>
         </div>
         <div ref={bottomRef} />
      </div>
    </div>
  );
};

