            }

            if (!email.trim() || !firstName.trim() || !lastName.trim() || !birthDate) {
                throw new Error('All fields are required for registration');
            }

            const newUserProfile: UserType = {
                username,
                email,
                firstName,
                lastName,
                birthDate,
                lastLogin: new Date().toISOString()
            };

            const createdUser = authService.register(newUserProfile, password);
            onLogin(createdUser);

        } else {
            // LOGIN LOGIC - checks persistent storage
            const user = authService.login(username, password);
