}

const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);

  // Form State
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [email, setEmail] = useState('');
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [birthDate, setBirthDate] = useState('');

  // Captcha State
  const [captchaChallenge, setCaptchaChallenge] = useState({ q: '', a: 0 });
  const [captchaInput, setCaptchaInput] = useState('');

  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Generate a random math problem
  const generateCaptcha = () => {
    const n1 = Math.floor(Math.random() * 10) + 1;
    const n2 = Math.floor(Math.random() * 10) + 1;
    setCaptchaChallenge({ q: `What is ${n1} + ${n2}?`, a: n1 + n2 });
    setCaptchaInput('');
  };

  useEffect(() => {
    if (isRegistering) {
        generateCaptcha();
    }
  }, [isRegistering]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    // Artificial delay for UX
    await new Promise(r => setTimeout(r, 600));

    try {
        // Common Validation
        if (!username.trim() || !password.trim()) {
          throw new Error('Username and password are required');
        }

        if (username.length < 3) {
          throw new Error('Username must be at least 3 characters');
        }

        if (isRegistering) {
            // REGISTRATION LOGIC

            // 1. Anti-Robot Verification (Only for Register)
            if (parseInt(captchaInput) !== captchaChallenge.a) {
                 generateCaptcha(); // Reset on fail
                 throw new Error("Anti-Robot verification failed. Wrong answer.");
            }

            if (!email.trim() || !firstName.trim() || !lastName.trim() || !birthDate) {
                throw new Error('All fields are required for registration');
            }

            const newUserProfile: UserType = {
                username,
                email,
                firstName,
                lastName,
                birthDate,
                lastLogin: new Date().toISOString()
            };

            const createdUser = authService.register(newUserProfile, password);
            onLogin(createdUser);

        } else {
            // LOGIN LOGIC - checks persistent storage
            const user = authService.login(username, password);
            onLogin(user);
