import { chatWithGemini, generateImage, generateVideo, connectLive, transcribeAudio } from '../services/geminiService';
import { ChatMessage, ChatMode, AspectRatio, ImageSize } from '../types';
import Logo from './Logo';

// Prettier Imports for Auto-Formatting
import { format } from "prettier/standalone";
import parserBabel from "prettier/plugins/babel";
import parserEstree from "prettier/plugins/estree";
import parserHtml from "prettier/plugins/html";
import parserPostcss from "prettier/plugins/postcss";
import parserMarkdown from "prettier/plugins/markdown";

interface AIAssistantProps {
  currentCode: string;
  isOpen: boolean;
  onClose: () => void;
  onUpdateCode: (code: string) => void;
}

// Component to handle async code formatting
const CodeBlock: React.FC<{ code: string; lang: string }> = ({ code, lang }) => {
  const [formattedCode, setFormattedCode] = useState(code);

  useEffect(() => {
    let mounted = true;
    const formatCode = async () => {
      try {
        let parser = '';
        let plugins: any[] = [];
        const l = lang.toLowerCase();

        if (['js', 'javascript', 'ts', 'typescript', 'jsx', 'tsx', 'json'].includes(l)) {
          parser = l === 'json' ? 'json' : 'babel';
          plugins = [parserBabel, parserEstree];
        } else if (['html'].includes(l)) {
          parser = 'html';
          plugins = [parserHtml, parserBabel, parserPostcss, parserEstree];
        } else if (['css', 'scss', 'less'].includes(l)) {
          parser = 'css';
          plugins = [parserPostcss];
        } else if (['md', 'markdown'].includes(l)) {
          parser = 'markdown';
          plugins = [parserMarkdown, parserBabel, parserEstree];
        }

        if (parser) {
          const formatted = await format(code, {
            parser,
            plugins,
            printWidth: 80,
            tabWidth: 2,
            semi: true,
            singleQuote: false,
          });
          if (mounted) setFormattedCode(formatted.trim());
        }
      } catch (e) {
        // If formatting fails (e.g. invalid syntax), keep original code
      }
    };

    // Attempt formatting
    formatCode();

    return () => { mounted = false; };
  }, [code, lang]);

  return (
    <div className="my-2 bg-[#1e1e1e] border border-gray-700 rounded-md overflow-hidden shadow-sm group">
       <div className="bg-[#252526] px-3 py-1.5 text-xs text-gray-400 flex justify-between items-center border-b border-gray-700">
          <span className="font-mono uppercase text-[10px]">{lang || 'CODE'}</span>
          <button 
            onClick={() => navigator.clipboard.writeText(formattedCode)}
            className="flex items-center gap-1 hover:text-white transition-colors"
            title="Copy code"
          >
            <Copy size={10} />
            <span>Copy</span>
          </button>
       </div>
       <pre className="p-3 overflow-x-auto text-xs font-mono text-blue-300 custom-scrollbar">
         {formattedCode}
       </pre>
    </div>
  );
};

// Simple formatter for code blocks
const MessageContent: React.FC<{ text: string }> = ({ text }) => {
  const parts = text.split(/(```[\s\S]*?```)/g);
  return (
    <div className="text-sm leading-relaxed space-y-2">
      {parts.map((part, i) => {
        if (part.startsWith('```') && part.endsWith('```')) {
          // Extract language if present
          const match = part.match(/^```(\w*)\n/);
          const lang = match ? match[1] : '';
          const content = part.replace(/^```\w*\n?/, '').replace(/```$/, '');
          return <CodeBlock key={i} code={content} lang={lang} />;
        }
        // Basic bold parsing (**text**)
        const textParts = part.split(/(\*\*.*?\*\*)/g);
        return (
            <span key={i}>
                {textParts.map((t, j) => {
                    if (t.startsWith('**') && t.endsWith('**')) {
                        return <strong key={j} className="text-blue-200 font-semibold">{t.slice(2, -2)}</strong>;
                    }
                    return t;
                })}
            </span>
        );
      })}
    </div>
  );
};

const AIAssistant: React.FC<AIAssistantProps> = ({ currentCode, isOpen, onClose, onUpdateCode }) => {
