                  (audioData) => { /* Audio handling handled in service */ },
                  (code) => onUpdateCode(code),
                  () => setIsLiveConnected(false)
              );
              setIsLiveConnected(true);
          } catch (e) {
              console.error(e);
              alert("Failed to connect. Ensure permissions are granted.");
          }
      }
