                     </div>

                     {createType !== 'animation' && (
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-semibold text-gray-500 mb-2 uppercase tracking-wider">Aspect Ratio</label>
                                <select 
                                    value={aspectRatio} 
