import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { Code2, SplitSquareHorizontal, Maximize2, Sparkles, Layout, AlignLeft, Plus, X, Globe, Lock, Wand2, Undo2, Redo2 } from 'lucide-react';
