export default AuthScreen;

import { User } from '../types';

const DB_KEY = 'devbrowser_users_db';

interface StoredUser {
  profile: User;
  passwordHash: string; // Simple base64 for this demo
}

interface UserDatabase {
  [username: string]: StoredUser;
}

// Helper: Normalize username key to lowercase to avoid case-sensitivity issues
const normalizeKey = (username: string) => username.trim().toLowerCase();

// Helper: Get DB safely with corruption handling
const getDb = (): UserDatabase => {
  try {
    const data = localStorage.getItem(DB_KEY);
    if (!data) return {};
    return JSON.parse(data);
  } catch (e) {
    console.warn("User database corrupted or invalid format. Resetting.");
    return {};
  }
};

// Helper: Save DB safely
const saveDb = (db: UserDatabase) => {
  try {
    const serialized = JSON.stringify(db);
    localStorage.setItem(DB_KEY, serialized);
    console.log("Database saved successfully.", Object.keys(db));
  } catch (e) {
    console.error("Failed to save user database", e);
    alert("Storage Error: Could not save account data. Your browser storage might be full or disabled.");
  }
};

// Simple hash function (Base64) to avoid storing plain text
const hashPassword = (pwd: string) => btoa(pwd);

export const authService = {
  login: (username: string, password: string): User => {
    const db = getDb();
    const key = normalizeKey(username);
    const targetUser = db[key];

    // Check if user exists in persistent storage
    if (!targetUser) {
      console.error(`Login failed: User '${key}' not found in DB keys:`, Object.keys(db));
      throw new Error("Account not found. Please register first.");
    }

    // Verify password
    if (targetUser.passwordHash !== hashPassword(password)) {
      throw new Error("Incorrect password.");
    }

    // Update last login timestamp and save back to storage
    const updatedUser = {
        ...targetUser,
        profile: {
            ...targetUser.profile,
            // Ensure we keep the original username casing for display, but update login time
            lastLogin: new Date().toISOString()
        }
    };

    db[key] = updatedUser;
    saveDb(db);

    return updatedUser.profile;
  },

  register: (userProfile: User, password: string): User => {
    const db = getDb();
    const key = normalizeKey(userProfile.username);

    if (db[key]) {
      throw new Error("Username already taken. Please choose another.");
    }

    // Save new user to persistent storage
    db[key] = {
      profile: {
        ...userProfile,
        lastLogin: new Date().toISOString()
      },
      passwordHash: hashPassword(password)
    };

    console.log(`Registering new user: ${key}`);
    saveDb(db);

    // Verify save
    const verifyDb = getDb();
    if (!verifyDb[key]) {
        throw new Error("Critical Error: Database save failed. Please check browser privacy settings.");
    }

    return db[key].profile;
  },

  // Verify if a user exists (useful for UI checks)
  userExists: (username: string): boolean => {
      const db = getDb();
      const key = normalizeKey(username);
      return !!db[key];
  },

  // Retrieve user profile for session re-hydration
  getUser: (username: string): User | null => {
      const db = getDb();
      const key = normalizeKey(username);
      return db[key] ? db[key].profile : null;
  }
};

