                            isFixing ? 'text-blue-400 bg-blue-400/10 cursor-wait' : 'text-purple-400 hover:text-white hover:bg-purple-500/20'
                         }`}
                         title="Use AI to automatically find and fix errors"
                     >
                         <Wand2 size={12} className={isFixing ? "animate-spin" : ""} />
                         <span className="hidden sm:inline">{isFixing ? 'Fixing...' : 'Auto-Fix'}</span>
                     </button>
                     <div className="w-px h-3 bg-gray-700 mx-1"></div>
                     <button onClick={handleFormat} className="flex items-center gap-1.5 text-gray-500 hover:text-white transition-colors" title="Format Code">
                         <AlignLeft size={14} />
                     </button>
                 </div>
              </div>
              <textarea
                className="flex-1 w-full bg-[#1e1e1e] text-gray-300 font-mono text-sm p-4 outline-none resize-none leading-relaxed custom-scrollbar"
                value={activeFile?.content || ''}
                onChange={(e) => updateFileContent(e.target.value)}
                onKeyDown={(e) => {
                    if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
                        e.preventDefault();
                        if (e.shiftKey) {
                            handleRedo();
                        } else {
                            handleUndo();
                        }
                    } else if ((e.metaKey || e.ctrlKey) && e.key === 'y') {
                        e.preventDefault();
                        handleRedo();
                    }
                }}
                spellCheck={false}
                placeholder="// Start coding..."
              />
            </div>

            {/* Browser Pane (Right) - Tab Content */}
            <div className={`flex-1 flex flex-col bg-white relative transition-all duration-300 ${layoutMode === LayoutMode.SPLIT ? 'w-1/2' : 'w-full'}`}>
              <AddressBar 
                  url={activeTab.url} 
                  onNavigate={handleNavigate} 
                  onRefresh={() => setIframeKey(k => k + 1)} 
                  isLoading={activeTab.loading}
              />
              <div className="flex-1 relative overflow-hidden bg-[#1e1e1e]">
                  <BrowserTab 
                     key={`${activeTab.id}-${iframeKey}`} 
                     tab={activeTab} 
                     srcDoc={srcDoc} 
                     onNavigate={handleNavigate}
                     onToggleReader={handleSwitchToReader}
                  />
              </div>
            </div>
          </>
      );
  };

  return (
    <div className="flex flex-col h-screen w-screen bg-browser-bg text-gray-300">

      {/* Top Bar / Tab Strip */}
      <div className="flex items-end h-10 px-2 bg-browser-bg border-b border-browser-toolbar select-none gap-2 pt-2">
           {/* Controls */}
           <div className="flex items-center gap-2 mb-2 mr-2">
              <div className="flex gap-1.5 px-2">
                 <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
                 <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
              </div>
           </div>

           {/* Tab Strip */}
           <div className="flex-1 flex overflow-x-auto no-scrollbar items-end h-full">
               {tabs.map(tab => (
                   <div 
                      key={tab.id}
                      onClick={() => setActiveTabId(tab.id)}
                      className={`
                        group relative flex items-center gap-2 px-3 py-1.5 min-w-[120px] max-w-[200px] text-xs rounded-t-lg cursor-default border-r border-gray-800/50 transition-colors
                        ${activeTabId === tab.id ? 'bg-[#3c3c3c] text-white' : 'bg-transparent text-gray-500 hover:bg-[#2d2d2d]'}
                      `}
                   >
                       {tab.type === 'preview' ? <Lock size={10} className="text-green-500" /> : <Globe size={10} className="text-blue-400" />}
                       <span className="truncate flex-1">{tab.title || 'New Tab'}</span>
                       <button 
                         onClick={(e) => handleCloseTab(tab.id, e)}
                         className={`p-0.5 rounded-full hover:bg-white/20 opacity-0 group-hover:opacity-100 ${tabs.length === 1 ? 'hidden' : ''}`}
                       >
                           <X size={10} />
                       </button>
                   </div>
               ))}
               <button onClick={handleNewTab} className="p-1.5 ml-1 text-gray-500 hover:text-white hover:bg-white/10 rounded mb-1">
                   <Plus size={14} />
               </button>
           </div>

           {/* Window Controls */}
           <div className="flex items-center gap-2 mb-1.5">
              <button 
                 onClick={() => setLayoutMode(layoutMode === LayoutMode.SPLIT ? LayoutMode.FULL : LayoutMode.SPLIT)}
                 className={`p-1.5 hover:bg-white/10 rounded text-gray-400 hover:text-white transition ${activeSidebar === 'terminal' ? 'opacity-50 cursor-not-allowed' : ''}`}
                 disabled={activeSidebar === 'terminal'}
              >
                {layoutMode === LayoutMode.SPLIT ? <Maximize2 size={16} /> : <SplitSquareHorizontal size={16} />}
              </button>
              <button 
                 onClick={() => setIsAIOpen(!isAIOpen)}
                 className={`p-1.5 rounded transition-colors ${isAIOpen ? 'text-browser-accent bg-blue-500/10' : 'text-gray-400 hover:text-white hover:bg-white/10'}`}
              >
                <Sparkles size={16} />
              </button>
           </div>
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Activity Bar */}
        <ActivityBar 
            activeView={activeSidebar} 
            onViewChange={setActiveSidebar} 
            changesCount={uncommittedChangesCount}
            username={user.username}
            onLogout={handleLogout}
            onOpenProfile={() => setIsSettingsOpen(true)}
        />

        {renderMainContent()}

        {/* AI Sidebar */}
        <AIAssistant user={user} currentCode={activeFile?.content || ''} isOpen={isAIOpen} onClose={() => setIsAIOpen(false)} onUpdateCode={updateFileContent} />

        {/* Settings Modal */}
        {isSettingsOpen && (
            <AccountSettings 
                user={user} 
                onClose={() => setIsSettingsOpen(false)} 
                onLogout={handleLogout}
            />
        )}
      </div>

      <Console logs={logs} onClear={clearLogs} isOpen={isConsoleOpen} toggleOpen={() => setIsConsoleOpen(!isConsoleOpen)} onCommand={handleConsoleCommand} />
    </div>
  );
}

import { User } from '../types';

const DB_KEY = 'devbrowser_users_db';
const DB_BACKUP_KEY = 'devbrowser_users_db_backup'; // Redundant storage key

interface StoredUser {
  profile: User;
  passwordHash: string;
}

interface UserDatabase {
  [username: string]: StoredUser;
}

// Helper: Normalize username key to lowercase/trim to avoid case-sensitivity issues
const normalizeKey = (username: string) => username.trim().toLowerCase();

// Helper: Get DB safely with corruption handling and Backup recovery
const getDb = (): UserDatabase => {
  try {
    const data = localStorage.getItem(DB_KEY);

    if (data) {
        return JSON.parse(data);
    }

    // Fallback: Try to restore from backup if main DB is missing
    const backup = localStorage.getItem(DB_BACKUP_KEY);
    if (backup) {
        console.warn("Main database missing. Restoring from backup...");
        localStorage.setItem(DB_KEY, backup); // Heal primary
        return JSON.parse(backup);
    }

    return {};
  } catch (e) {
    console.warn("User database corrupted. Attempting backup restore...");
    try {
        const backup = localStorage.getItem(DB_BACKUP_KEY);
        if (backup) return JSON.parse(backup);
    } catch (err) {
        return {};
    }
    return {};
  }
};

// Helper: Save DB safely to BOTH primary and backup locations
const saveDb = (db: UserDatabase) => {
  try {
    const serialized = JSON.stringify(db);
    localStorage.setItem(DB_KEY, serialized);
    localStorage.setItem(DB_BACKUP_KEY, serialized); // Save backup
  } catch (e) {
    console.error("Failed to save user database", e);
    alert("Storage Error: Could not save account data. Your browser storage might be full.");
  }
};

// Helper: Find user key robustly
const findUserKey = (db: UserDatabase, username: string): string | undefined => {
    const target = normalizeKey(username);

    // 1. Direct match
    if (db[target]) return target;

    // 2. Scan match
    const found = Object.keys(db).find(k => normalizeKey(k) === target);
    return found;
};

// Simple hash function (Base64)
const hashPassword = (pwd: string) => btoa(pwd);

export const authService = {
  login: (username: string, password: string): User => {
    const db = getDb();
    const key = findUserKey(db, username);

    // Debug: Log available users to console if login fails
    if (!key || !db[key]) {
      console.error(`Login Failed. User '${username}' not found.`);
      console.log("Available Users in DB:", Object.keys(db));
      throw new Error("Account not found. Please register first.");
    }

    const targetUser = db[key];

    // Verify password
    if (targetUser.passwordHash !== hashPassword(password)) {
      throw new Error("Incorrect password.");
    }

    // Update last login timestamp
    const updatedUser = {
        ...targetUser,
        profile: {
            ...targetUser.profile,
            lastLogin: new Date().toISOString()
        }
    };

    db[key] = updatedUser;
    saveDb(db);

    return updatedUser.profile;
  },

  register: (userProfile: User, password: string): User => {
    const db = getDb();
    // Enforce strict normalized keys for new users
    const key = normalizeKey(userProfile.username);

    if (findUserKey(db, userProfile.username)) {
      throw new Error("Username already taken. Please choose another.");
    }

    // Save new user
    db[key] = {
      profile: {
        ...userProfile,
        lastLogin: new Date().toISOString()
      },
      passwordHash: hashPassword(password)
    };

    console.log(`Registering new user: ${key}`);
    saveDb(db);

    return db[key].profile;
  },

  userExists: (username: string): boolean => {
      const db = getDb();
      return !!findUserKey(db, username);
  },

  getUser: (username: string): User | null => {
      const db = getDb();
      const key = findUserKey(db, username);
      return key && db[key] ? db[key].profile : null;
  }
};

import React, { useState, useEffect } from 'react';
import { ArrowRight, Lock, User, Mail, Calendar, UserCircle, AlertTriangle, ShieldCheck } from 'lucide-react';
import { User as UserType } from '../types';
import { authService } from '../services/authService';
import Logo from './Logo';

interface AuthScreenProps {
  onLogin: (user: Partial<UserType>, remember?: boolean) => void;
}

const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);

  // Form State
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [email, setEmail] = useState('');
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [birthDate, setBirthDate] = useState('');

  // Login Options
  const [rememberMe, setRememberMe] = useState(true);

  // Captcha State
  const [captchaChallenge, setCaptchaChallenge] = useState({ q: '', a: 0 });
  const [captchaInput, setCaptchaInput] = useState('');

  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Generate a random math problem
  const generateCaptcha = () => {
    const n1 = Math.floor(Math.random() * 10) + 1;
    const n2 = Math.floor(Math.random() * 10) + 1;
    setCaptchaChallenge({ q: `What is ${n1} + ${n2}?`, a: n1 + n2 });
    setCaptchaInput('');
  };

  useEffect(() => {
    if (isRegistering) {
        generateCaptcha();
    }
  }, [isRegistering]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    // Clean inputs to avoid whitespace issues
    const cleanUsername = username.trim();
    const cleanPassword = password.trim();

    // Artificial delay for UX
    await new Promise(r => setTimeout(r, 600));

    try {
        // Common Validation
        if (!cleanUsername || !cleanPassword) {
          throw new Error('Username and password are required');
        }

        if (cleanUsername.length < 3) {
          throw new Error('Username must be at least 3 characters');
        }

        if (isRegistering) {
            // REGISTRATION LOGIC

            // 1. Anti-Robot Verification (Only for Register)
            if (parseInt(captchaInput) !== captchaChallenge.a) {
                 generateCaptcha(); // Reset on fail
                 throw new Error("Anti-Robot verification failed. Wrong answer.");
            }

            if (!email.trim() || !firstName.trim() || !lastName.trim() || !birthDate) {
                throw new Error('All fields are required for registration');
            }

            const newUserProfile: UserType = {
                username: cleanUsername,
                email: email.trim(),
                firstName: firstName.trim(),
                lastName: lastName.trim(),
                birthDate,
                lastLogin: new Date().toISOString()
            };

            const createdUser = authService.register(newUserProfile, cleanPassword);
            onLogin(createdUser, rememberMe);

        } else {
            // LOGIN LOGIC - checks persistent storage
            try {
                const user = authService.login(cleanUsername, cleanPassword);
                onLogin(user, rememberMe);
            } catch (loginErr: any) {
                // If account not found, hint the user
                if (loginErr.message.includes('not found')) {
                    console.warn(`Debug: User ${cleanUsername} failed to login.`);
                }
                throw loginErr;
            }
        }
    } catch (err: any) {
        setError(err.message || "Authentication failed");
        setIsLoading(false);
    }
  };

  return (
    <div className="w-screen h-screen bg-[#0f0f0f] flex items-center justify-center font-sans text-gray-300 relative overflow-hidden">
      {/* Background Ambience */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none">
          <div className="absolute -top-[20%] -left-[10%] w-[50%] h-[50%] bg-blue-600/10 rounded-full blur-[120px]"></div>
          <div className="absolute top-[40%] -right-[10%] w-[40%] h-[40%] bg-purple-600/10 rounded-full blur-[120px]"></div>
      </div>

      <div className="w-full max-w-md bg-[#1e1e1e] border border-gray-800 rounded-2xl shadow-2xl p-8 relative z-10 animate-in fade-in zoom-in duration-500 max-h-[95vh] overflow-y-auto custom-scrollbar">
        <div className="text-center mb-6">
          <div className="w-16 h-16 bg-blue-600/10 rounded-2xl flex items-center justify-center mx-auto mb-5 border border-blue-500/20 shadow-lg shadow-blue-500/10">
            <Logo className="text-blue-500" size={32} />
          </div>
          <h1 className="text-2xl font-bold text-white mb-2 tracking-tight">Deploy Studio</h1>
          <p className="text-gray-500 text-sm">
            {isRegistering ? 'Create your workspace account' : 'Welcome back! Sign in to continue.'}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">

          {/* USERNAME & PASSWORD (Always Visible) */}
          <div>
            <label className="block text-xs font-medium text-gray-500 mb-1.5 uppercase tracking-wider">Username</label>
            <div className="relative">
                <User size={16} className="absolute left-3 top-3 text-gray-500" />
                <input 
                  type="text" 
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  className={`w-full bg-[#252526] border rounded-lg py-2.5 pl-10 text-sm text-white focus:border-blue-500 outline-none transition-colors ${error ? 'border-red-500/50' : 'border-gray-700'}`}
                  placeholder="johndoe"
                  autoFocus={!isRegistering}
                />
            </div>
          </div>

          <div>
            <label className="block text-xs font-medium text-gray-500 mb-1.5 uppercase tracking-wider">Password</label>
            <div className="relative">
                <Lock size={16} className="absolute left-3 top-3 text-gray-500" />
                <input 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className={`w-full bg-[#252526] border rounded-lg py-2.5 pl-10 text-sm text-white focus:border-blue-500 outline-none transition-colors ${error ? 'border-red-500/50' : 'border-gray-700'}`}
                  placeholder="••••••••"
                />
            </div>
          </div>

          {/* Remember Me Toggle */}
          {!isRegistering && (
             <div className="flex items-center gap-2">
                 <input 
                    type="checkbox" 
                    id="rememberMe"
                    checked={rememberMe}
                    onChange={(e) => setRememberMe(e.target.checked)}
                    className="w-4 h-4 rounded border-gray-700 bg-[#252526] text-blue-600 focus:ring-blue-500"
                 />
                 <label htmlFor="rememberMe" className="text-xs text-gray-400 select-none cursor-pointer">
                     Remember me
                 </label>
             </div>
          )}

          {/* REGISTRATION EXTRA FIELDS */}
          {isRegistering && (
             <div className="space-y-4 animate-in slide-in-from-top-4 duration-300">
                <div className="w-full h-px bg-gray-800 my-4"></div>

                <div>
                    <label className="block text-xs font-medium text-gray-500 mb-1.5 uppercase tracking-wider">Email Address</label>
                    <div className="relative">
                        <Mail size={16} className="absolute left-3 top-3 text-gray-500" />
                        <input 
                          type="email" 
                          value={email}
                          onChange={(e) => setEmail(e.target.value)}
                          className="w-full bg-[#252526] border border-gray-700 rounded-lg py-2.5 pl-10 text-sm text-white focus:border-blue-500 outline-none transition-colors"
                          placeholder="you@example.com"
                        />
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1.5 uppercase tracking-wider">First Name</label>
                        <div className="relative">
                            <UserCircle size={16} className="absolute left-3 top-3 text-gray-500" />
                            <input 
                              type="text" 
                              value={firstName}
                              onChange={(e) => setFirstName(e.target.value)}
                              className="w-full bg-[#252526] border border-gray-700 rounded-lg py-2.5 pl-10 text-sm text-white focus:border-blue-500 outline-none transition-colors"
                              placeholder="John"
                            />
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1.5 uppercase tracking-wider">Last Name</label>
                        <div className="relative">
                            <UserCircle size={16} className="absolute left-3 top-3 text-gray-500" />
                            <input 
                              type="text" 
                              value={lastName}
                              onChange={(e) => setLastName(e.target.value)}
                              className="w-full bg-[#252526] border border-gray-700 rounded-lg py-2.5 pl-10 text-sm text-white focus:border-blue-500 outline-none transition-colors"
                              placeholder="Doe"
                            />
                        </div>
                    </div>
                </div>

                <div>
                    <label className="block text-xs font-medium text-gray-500 mb-1.5 uppercase tracking-wider">Date of Birth</label>
                    <div className="relative">
                        <Calendar size={16} className="absolute left-3 top-3 text-gray-500" />
                        <input 
                          type="date" 
                          value={birthDate}
                          onChange={(e) => setBirthDate(e.target.value)}
                          className="w-full bg-[#252526] border border-gray-700 rounded-lg py-2.5 pl-10 text-sm text-white focus:border-blue-500 outline-none transition-colors appearance-none"
                        />
                    </div>
                </div>

                {/* CAPTCHA / ANTI-ROBOT VERIFICATION (ONLY REGISTER) */}
                <div className="bg-blue-900/10 border border-blue-500/20 p-3 rounded-lg mt-4 animate-in fade-in">
                    <label className="flex items-center gap-2 text-xs font-medium text-blue-400 mb-2 uppercase tracking-wider">
                        <ShieldCheck size={14} /> Security Check
                    </label>
                    <div className="flex items-center gap-3">
                        <div className="bg-[#252526] px-3 py-2 rounded text-sm text-gray-300 font-mono border border-gray-700 select-none">
                            {captchaChallenge.q}
                        </div>
                        <input 
                            type="number" 
                            value={captchaInput}
                            onChange={(e) => setCaptchaInput(e.target.value)}
                            className="w-20 bg-[#252526] border border-gray-700 rounded-lg py-2 px-3 text-sm text-white focus:border-blue-500 outline-none transition-colors"
                            placeholder="?"
                            required
                        />
                    </div>
                </div>
             </div>
          )}

          {error && (
            <div className="flex items-center gap-2 text-red-400 text-xs bg-red-900/10 p-3 rounded-lg border border-red-900/30 animate-in fade-in slide-in-from-top-1">
              <AlertTriangle size={16} className="flex-shrink-0" />
              <span>{error}</span>
            </div>
          )}

          <button 
            type="submit"
            disabled={isLoading}
            className={`w-full bg-blue-600 hover:bg-blue-500 text-white font-medium py-2.5 rounded-lg flex items-center justify-center gap-2 transition-all mt-6 shadow-lg shadow-blue-900/20 ${isLoading ? 'opacity-70 cursor-wait' : ''}`}
          >
            {isLoading ? 'Processing...' : (isRegistering ? 'Create Account' : 'Enter Studio')} 
            {!isLoading && <ArrowRight size={16} />}
          </button>
        </form>

        <div className="mt-6 text-center text-xs text-gray-500">
          {isRegistering ? 'Already have an account?' : "Don't have an account?"}
          <button 
            onClick={() => { setIsRegistering(!isRegistering); setError(''); }}
            className="text-blue-400 hover:text-blue-300 ml-1 font-medium hover:underline"
          >
            {isRegistering ? 'Sign in' : 'Create one'}
          </button>
        </div>
      </div>
    </div>
  );
};

